let studioAmountDisplayUnit = 'lakhs';
const DEFAULT_TEMPLATE_LIMIT = 4;

function indiaTimestampForFilename(date = new Date()) {
  const parts = new Intl.DateTimeFormat('en-IN', {
    timeZone: 'Asia/Kolkata',
    year: 'numeric',
    month: '2-digit',
    day: '2-digit',
    hour: '2-digit',
    minute: '2-digit',
    hour12: false,
  }).formatToParts(date);
  const map = Object.fromEntries(parts.filter((part) => part.type !== 'literal').map((part) => [part.type, part.value]));
  return `${map.year}${map.month}${map.day}_${map.hour}${map.minute}`;
}

function isDefaultTemplateRow(row) {
  return row?.isDefaultTemplate === true || row?.isDefaultTemplate === 'true';
}

function defaultTemplateRows(rows = []) {
  return rows.filter(isDefaultTemplateRow).slice(0, DEFAULT_TEMPLATE_LIMIT);
}

function findWorkspaceDefaultRow(rows = [], savedValue = '') {
  if (savedValue) {
    const byValue = rows.find((row) => String(row?.value || row?.name || '') === String(savedValue));
    if (byValue) return byValue;
  }
  return defaultTemplateRows(rows)[0] || rows[0] || null;
}

function inferContractServiceType(row = {}) {
  if (row.linkedServiceType || row.serviceType || row.defaultServiceType) return row.linkedServiceType || row.serviceType || row.defaultServiceType;
  const haystack = `${row.value || ''} ${row.name || ''} ${row.type || ''}`.toLowerCase();
  if (haystack.includes('turnkey') || haystack.includes('build')) return 'Design + Build (Turnkey)';
  if (haystack.includes('procurement')) return 'Design + Technical Drawing + Consultation + Procurement';
  return 'Design + Technical Drawing + Consultation';
}

