/* ============= Theme runtime helpers ============= */
function themeToCSS(theme) {
  return `:root {\n${Object.entries(theme).map(([k, v]) => `  --${k}: ${v};`).join('\n')}\n}`;
}

// WCAG AA contrast ratio — 4.5:1 minimum for normal text
function contrastRatio(c1, c2) {
  const lum = (hex) => {
    const h = hex.replace('#', '');
    const r = parseInt(h.substring(0, 2), 16) / 255;
    const g = parseInt(h.substring(2, 4), 16) / 255;
    const b = parseInt(h.substring(4, 6), 16) / 255;
    const [R, G, B] = [r, g, b].map((c) =>
      c <= 0.03928 ? c / 12.92 : Math.pow((c + 0.055) / 1.055, 2.4)
    );
    return 0.2126 * R + 0.7152 * G + 0.0722 * B;
  };
  try {
    const l1 = lum(c1), l2 = lum(c2);
    const [bright, dark] = l1 > l2 ? [l1, l2] : [l2, l1];
    return (bright + 0.05) / (dark + 0.05);
  } catch { return 21; }
}

/* ============= Helpers ============= */

function uid() {
  return Math.floor(Math.random() * 1e9) + Date.now();
}

/* ====================================================================
   Phase 5.1A — Per-record visibility model
   --------------------------------------------------------------------
   Every record carries 3 optional flags:
     - isClientVisible : boolean  (default per record-type — see DEFAULTS below)
     - isVendorVisible : boolean
     - isInternalOnly  : boolean  (overrides — true = ONLY internal team)

   Roles map to "audiences" via roleAudienceFor(roleCode):
     - 'internal' → studio_owner / pm_admin / designer / site_manager
     - 'client'   → client
     - 'vendor'   → vendor / consultant / supplier
     - 'finance'  → accountant (sees internal + finance records; can't see vendor-only)

   recordIsVisibleToRole(record, roleCode) is the single source of truth
   used by every filter on every consumer surface.
==================================================================== */

const RECORD_DEFAULT_VISIBILITY = {
  // tasks: operational by default — internal-only
  task:        { isClientVisible: false, isVendorVisible: false, isInternalOnly: true  },
  // approvals: most decisions need to be shared
  approval:    { isClientVisible: true,  isVendorVisible: false, isInternalOnly: false },
  // specs: technical until approved → internal
  spec:        { isClientVisible: false, isVendorVisible: true,  isInternalOnly: false },
  // checklists: QA items → internal
  checklist:   { isClientVisible: false, isVendorVisible: true,  isInternalOnly: true  },
  // drawings: status-driven (handled below) — default internal until "Client Review" or later
  drawing:     { isClientVisible: false, isVendorVisible: true,  isInternalOnly: false },
  // references: mood/spec catalogues — internal
  reference:   { isClientVisible: false, isVendorVisible: false, isInternalOnly: true  },
  // BOQ items: cost ledger — internal until client BOQ approval
  boqItem:     { isClientVisible: false, isVendorVisible: true,  isInternalOnly: false },
  // milestones: invoicing schedule — visible to client (it's their bill)
  milestone:   { isClientVisible: true,  isVendorVisible: false, isInternalOnly: false },
  // site updates: progress reports — visible by default since the client expects them
  siteUpdate:  { isClientVisible: true,  isVendorVisible: true,  isInternalOnly: false },
  // comms: messages — internal by default, opt-in client/vendor exposure per message
  comm:        { isClientVisible: false, isVendorVisible: false, isInternalOnly: true  },
  // MOM: minutes — visible to attendees by default, internal team always
  mom:         { isClientVisible: true,  isVendorVisible: false, isInternalOnly: false },
};

// Drawing status overrides — once status reaches client-facing stage, flip default to client-visible
const CLIENT_VISIBLE_DRAWING_STATUSES = ['Client Review', 'Approved', 'Issued'];

function roleAudienceFor(roleCode) {
  if (!roleCode) return 'internal';
  if (roleCode === 'client') return 'client';
  if (roleCode === 'vendor' || roleCode === 'consultant' || roleCode === 'supplier') return 'vendor';
  if (roleCode === 'accountant') return 'finance';
  return 'internal';
}

/* === Phase 5.8 Piece 3 — Delegation rules === */
/* Maps role code to delegation tier (1=Admin, 2=Manager, 3=Doer, 0=cannot delegate). */
function delegationTierForRole(roleCode) {
  if (roleCode === 'super_admin') return 1; // L1 platform owner — top admin
  if (roleCode === 'admin') return 1;       // L2 platform team — top admin
  if (roleCode === 'studio_owner') return 1; // Admin
  if (roleCode === 'pm_admin') return 1;     // Admin (can delegate to anyone)
  if (roleCode === 'designer') return 2;     // Manager
  if (roleCode === 'site_manager') return 2; // Manager
  /* Hypothetical doer-tier roles (not seeded) — junior designer, junior site staff */
  if (roleCode === 'junior_designer') return 3;
  if (roleCode === 'junior_site') return 3;
  return 0; // External roles cannot delegate
}

/* Maps a team-master tier string to numeric delegation tier. */
function delegationTierForTeamMember(member) {
  if (!member || !member.tier) return 3; /* Default: doer */
  const t = String(member.tier).toLowerCase();
  if (t === 'admin') return 1;
  if (t === 'manager') return 2;
  if (t === 'doer') return 3;
  return 3;
}

/* Returns true if a person at currentTier can delegate to someone at targetTier.
   Rule: you can delegate to anyone at your tier or below (numerically higher = lower rank). */
function canDelegateTo(currentTier, targetTier) {
  if (!currentTier || currentTier === 0) return false;
  if (!targetTier) targetTier = 3;
  return targetTier >= currentTier;
}

/* Returns true if the current role can delegate tasks at all. */
function canRoleDelegate(roleCode) {
  return delegationTierForRole(roleCode) > 0;
}

function recordIsVisibleToRole(record, roleCode, recordType = null) {
  if (!record) return false;
  const audience = roleAudienceFor(roleCode);

  // Internal audience always sees everything
  if (audience === 'internal') return true;

  // Determine effective flags — apply defaults when missing
  const defaults = recordType ? RECORD_DEFAULT_VISIBILITY[recordType] : null;
  const isClientVisible = record.isClientVisible !== undefined ? !!record.isClientVisible : (defaults?.isClientVisible ?? true);
  const isVendorVisible = record.isVendorVisible !== undefined ? !!record.isVendorVisible : (defaults?.isVendorVisible ?? true);
  const isInternalOnly  = record.isInternalOnly  !== undefined ? !!record.isInternalOnly  : (defaults?.isInternalOnly  ?? false);

  // Drawings: special status-driven default
  let effectiveClientVisible = isClientVisible;
  if (recordType === 'drawing' && record.isClientVisible === undefined) {
    effectiveClientVisible = CLIENT_VISIBLE_DRAWING_STATUSES.includes(record.status);
  }

  // Internal-only flag is hard override
  if (isInternalOnly) return false;

  // Finance audience: sees client-visible OR if record has a finance scope (BOQ/milestones always)
  if (audience === 'finance') {
    if (recordType === 'boqItem' || recordType === 'milestone') return true;
    return effectiveClientVisible;
  }

  if (audience === 'client') return effectiveClientVisible;
  if (audience === 'vendor') return isVendorVisible;
  return true;
}

function recordsForRole(records, roleCode, recordType) {
  if (!Array.isArray(records)) return [];
  return records.filter((r) => recordIsVisibleToRole(r, roleCode, recordType));
}

/* ========================== Spatial cascade builder ==========================
   Returns: levels[] → zones[] → spaces[] → features[] → elements[] →
            { specs[], checklists[], drawings[], references[], boqItems[] }
   Each Element carries 5 sibling leaf arrays — the 5 lenses on the same Element.
   Level → Zone connection: zones with no levelId fall under a synthetic
   "Unassigned" bucket if the property has Levels defined.
============================================================================== */

/* =============================================================
   ===== Phase 8.4 — Assembly-based project bootstrap ==========
   =============================================================
   When a project is created with a property type that has an authored
   assembly in MasterPropertyTypeAssemblies, this function clones the
   assembly into a project-shaped cascade (levels → zones → spaces →
   features → elements → leaves), so the Spaces tab and downstream
   tools see the same shape as legacy projects.

   Returns null when no assembly exists for the property type — the
   caller should then fall back to the legacy buildProjectLevelsFromMasters
   path (which reads from MasterLevels/MasterZones/MasterSpaces).

   Field semantics:
   - masterRef on each cloned record points to its origin in the master library
   - levelType comes from the assembly's level definition
   - displayLabel overrides on zones/spaces win over the library's canonical name
   - Features/Elements still come from the legacy MasterFeatures/MasterElements
     keyed by the library spaceRefId — until Phase 9+ extends assemblies down
     to features/elements, the legacy cascade handles those layers.
   ============================================================= */
function buildProjectLevelsFromAssembly(masters, propertyType) {
  if (!propertyType) return null;

  const assemblies = masters.MasterPropertyTypeAssemblies || [];
  const assembly = assemblies.find((a) => a.propertyType === propertyType);
  if (!assembly) return null;
  if (!assembly.levels || assembly.levels.length === 0) return null;

  const zoneLibrary = masters.MasterZoneLibrary || [];
  const spaceLibrary = masters.MasterSpaceLibrary || [];

  /* Reuse legacy element builder so features/elements still seed correctly.
     Once Phase 9+ extends the assembly down to features+elements, this gets replaced. */
  const buildElement = (el) => ({
    id: uid(), name: el.value, masterRef: el.id, expanded: false,
    specs:      (masters.MasterSpecifications || []).filter((sp) => sp.elementId === el.id).map((sp) => ({
      id: uid(), name: sp.value, masterRef: sp.id, unit: sp.unit || '', baseRate: sp.baseRate || '',
    })),
    checklists: (masters.MasterChecklists    || []).filter((c)  => c.elementId  === el.id).map((c)  => ({
      id: uid(), name: c.value, masterRef: c.id, description: c.description || '',
    })),
    drawings:    [],
    references:  [],
    boqItems:    [],
  });

  /* Build the level → zone → space cascade from the assembly. */
  const built = assembly.levels
    .slice()
    .sort((a, b) => (a.levelOrder || 0) - (b.levelOrder || 0))
    .map((aLevel) => {
      /* Zones under this level — looked up from assembly.zones by levelId match */
      const zonesInLevel = (assembly.zones || []).filter((z) => z.levelId === aLevel.id);

      const builtZones = zonesInLevel.map((aZone) => {
        const zoneRef = zoneLibrary.find((z) => z.id === aZone.zoneRefId);
        const zoneName = aZone.displayLabel || (zoneRef && zoneRef.value) || '(missing zone)';

        /* Spaces under this zone — looked up from assembly.spaces by zoneId match */
        const spacesInZone = (assembly.spaces || []).filter((s) => s.zoneId === aZone.id);

        const builtSpaces = spacesInZone.map((aSpace) => {
          const spaceRef = spaceLibrary.find((s) => s.id === aSpace.spaceRefId);
          const spaceName = aSpace.displayLabel || (spaceRef && spaceRef.value) || '(missing space)';

          /* Features/Elements still come from legacy masters keyed by the library spaceRefId.
             This means a Bathroom in the library inherits all the Features defined for it
             in MasterFeatures (Wall Tiling, Floor Tiling, Sanitary Ware, etc) automatically.
             Phase 9+ will extend assemblies to own these too. */
          const features = (masters.MasterFeatures || [])
            .filter((f) => f.spaceId === aSpace.spaceRefId)
            .map((f) => ({
              id: uid(), name: f.value, masterRef: f.id, expanded: false,
              elements: (masters.MasterElements || [])
                .filter((el) => el.featureId === f.id)
                .map(buildElement),
            }));

          return {
            id: uid(),
            name: spaceName,
            masterRef: aSpace.spaceRefId,
            assemblyRef: aSpace.id,                   // tracks which assembly entry produced this
            displayLabel: aSpace.displayLabel || null, // preserved so edits know if it was overridden
            expanded: false,
            features,
          };
        });

        return {
          id: uid(),
          name: zoneName,
          masterRef: aZone.zoneRefId,
          assemblyRef: aZone.id,
          displayLabel: aZone.displayLabel || null,
          expanded: false,
          spaces: builtSpaces,
        };
      });

      return {
        id: uid(),
        name: aLevel.label || 'Untitled Level',
        masterRef: null,                     // levels are inline-defined in assemblies, no master ref
        assemblyRef: aLevel.id,
        levelType: aLevel.levelType || '',
        levelOrder: aLevel.levelOrder || 0,
        expanded: false,
        zones: builtZones,
      };
    });

  /* First level expanded by default for orientation */
  if (built[0]) built[0].expanded = true;
  return built;
}

function buildProjectLevelsFromMasters(masters, propertyType) {
  if (!propertyType) return [];
  const levelsForType = (masters.MasterLevels || [])
    .filter((l) => l.propertyType === propertyType)
    .sort((a, b) => (parseInt(a.levelOrder, 10) || 0) - (parseInt(b.levelOrder, 10) || 0));

  const zonesForType = (masters.MasterZones || []).filter((z) => z.propertyType === propertyType);

  const buildElement = (el) => ({
    id: uid(), name: el.value, masterRef: el.id, expanded: false,
    specs:      (masters.MasterSpecifications || []).filter((sp) => sp.elementId === el.id).map((sp) => ({
      id: uid(), name: sp.value, masterRef: sp.id, unit: sp.unit || '', baseRate: sp.baseRate || '',
    })),
    checklists: (masters.MasterChecklists    || []).filter((c)  => c.elementId  === el.id).map((c)  => ({
      id: uid(), name: c.value, masterRef: c.id, description: c.description || '',
    })),
    drawings:    [],   // Drawings are added per-element from the catalog (MasterDrawings)
    references:  [],   // References are added per-element from the catalog (MasterReferences)
    boqItems:    [],   // BOQ items are added per-element from the rate library (MasterBOQItems)
  });

  const buildZone = (z) => ({
    id: uid(), name: z.value, masterRef: z.id, expanded: false,
    spaces: (masters.MasterSpaces || []).filter((s) => s.zoneId === z.id).map((s) => ({
      id: uid(), name: s.value, masterRef: s.id, expanded: false,
      features: (masters.MasterFeatures || []).filter((f) => f.spaceId === s.id).map((f) => ({
        id: uid(), name: f.value, masterRef: f.id, expanded: false,
        elements: (masters.MasterElements || []).filter((el) => el.featureId === f.id).map(buildElement),
      })),
    })),
  });

  // If no Levels are defined for this property type, fall back to a single synthetic level
  if (levelsForType.length === 0) {
    return [{
      id: uid(), name: 'Default Level', masterRef: null, levelType: 'Ground', levelOrder: 0, expanded: true,
      zones: zonesForType.map(buildZone),
    }];
  }

  // Otherwise: bucket zones under their level via levelId
  const built = levelsForType.map((l) => ({
    id: uid(), name: l.value, masterRef: l.id, levelType: l.levelType || 'Ground', levelOrder: l.levelOrder || 0, expanded: false,
    zones: zonesForType.filter((z) => z.levelId === l.id).map(buildZone),
  }));

  // Catch any orphan zones (zones with no levelId or pointing to nothing) under a synthetic bucket
  const orphans = zonesForType.filter((z) => !z.levelId || !levelsForType.find((l) => l.id === z.levelId));
  if (orphans.length > 0) {
    built.push({
      id: uid(), name: 'Unassigned', masterRef: null, levelType: 'Ground', levelOrder: 999, expanded: false,
      zones: orphans.map(buildZone),
    });
  }

  // Default: first level expanded
  if (built[0]) built[0].expanded = true;
  return built;
}

/* =============================================================
   Phase 8.4 — Smart project bootstrap
   =============================================================
   Public entry point for project creation logic. Tries the modern
   assembly-based path first; falls back to the legacy path if no
   assembly is authored for the property type.

   This means:
   - Property types with assemblies (Phase 8.2 authored) -> new path
   - Property types without -> legacy path (today's behavior, untouched)
   - Existing projects continue to work either way (backward compatible)

   All three callsites in the wizard use this single entry point.
   ============================================================= */
function buildProjectLevelsForType(masters, propertyType) {
  if (!propertyType) return [];
  const fromAssembly = buildProjectLevelsFromAssembly(masters, propertyType);
  if (fromAssembly && fromAssembly.length > 0) return fromAssembly;
  return buildProjectLevelsFromMasters(masters, propertyType);
}

/* Empty leaf record builders — used by the UI when adding a new leaf manually */
function buildEmptySpec()      { return { id: uid(), name: '', masterRef: null, unit: '', baseRate: '' }; }
function buildEmptyChecklist() { return { id: uid(), name: '', masterRef: null, description: '' }; }
function buildEmptyDrawing()   { return { id: uid(), name: '', masterRef: null, drawingType: 'Plan', status: 'Draft', revision: 'R0', description: '' }; }
function buildEmptyReference() { return { id: uid(), name: '', masterRef: null, referenceType: 'Inspiration', description: '', url: '' }; }
function buildEmptyBOQItem()   { return { id: uid(), name: '', masterRef: null, unit: 'sqft', quantity: '', rate: '', category: '' }; }

/* countTree — walks the new cascade shape (Levels → Zones → Spaces → Features → Elements → 5 leaves)
   Returns a flat object with all branch + leaf counts in a single pass. */
function countTree(levels) {
  let zones = 0, spaces = 0, features = 0, elements = 0;
  let specs = 0, checklists = 0, drawings = 0, references = 0, boqItems = 0;
  (levels || []).forEach((lv) => {
    (lv.zones || []).forEach((z) => {
      zones++;
      (z.spaces || []).forEach((s) => {
        spaces++;
        (s.features || []).forEach((f) => {
          features++;
          (f.elements || []).forEach((el) => {
            elements++;
            (el.specs      || []).forEach(() => specs++);
            (el.checklists || []).forEach(() => checklists++);
            (el.drawings   || []).forEach(() => drawings++);
            (el.references || []).forEach(() => references++);
            (el.boqItems   || []).forEach(() => boqItems++);
          });
        });
      });
    });
  });
  return {
    levels: (levels || []).length,
    zones, spaces, features, elements,
    specs, checklists, drawings, references, boqItems,
  };
}

/* ========================== Move 2: Workflow stage helpers ========================== */

/* ====================================================================
   buildProjectStagesFromMasters (Phase 5.4 — nested with activities + deliverables)
   - Reads matching workflow template (or universal stages fallback)
   - Each project stage carries activities[]
   - Each activity carries deliverables[] (cloned from MasterDeliverables for that activity)
   - Activities carry the masterRef back to MasterActivities so updates propagate
==================================================================== */
/* ====================================================================
   Phase 5.6 — Client & Vendor resolvers (back-compat with v0.8.3 shape)
   These are pure read-side helpers. They handle BOTH:
   - Old shape: project._wizard.primaryClientName (string)
   - New shape: project._wizard.primaryClientId (number) → MasterClients lookup
   This means tabs / panels / aggregations all work whether a project has
   been migrated to ID-references or not. Migration is a one-time pass
   in the seed data; user-uploaded backups from v0.8.3 still work.
==================================================================== */

/* Returns the canonical client record for a project, or null.
   Result shape matches MasterClients entries — caller uses .value, .primaryContact, etc.
   For unmigrated projects, builds a synthetic record from inline _wizard fields. */
function resolveClientForProject(project, masters) {
  const w = project._wizard || {};
  const clients = masters.MasterClients || [];
  if (w.primaryClientId) {
    const found = clients.find((c) => c.id === w.primaryClientId);
    if (found) return found;
  }
  // Fallback — build synthetic client record from inline wizard fields (old shape)
  if (w.primaryClientName) {
    return {
      id: null, // synthetic, no master record
      value: w.primaryClientName,
      initials: (w.primaryClientName || '').split(' ').map((s) => s[0]).filter(Boolean).slice(0, 2).join('').toUpperCase() || '?',
      accent: '#6B7355',
      clientType: 'individual',
      primaryContact: w.primaryContactNumber || '',
      primaryEmail: w.primaryEmail || '',
      secondaryContactName: w.secondaryContactName || '',
      secondaryContactNumber: w.secondaryContactNumber || '',
      secondaryEmail: w.secondaryEmail || '',
      address: '',
      flags: w.clientFlags || [],
      notes: w.clientNotes || '',
      _synthetic: true,
    };
  }
  return null;
}

/* Returns array of vendor records associated with a project.
   Each result: { vendor: <MasterVendor record>, projectRole, projectNotes }
   Handles both new shape ([{ vendorId, projectRole, projectNotes }])
   and old shape ([{ type, name, mobile, email, notes }] — synthesizes a fake vendor). */
function resolveVendorsForProject(project, masters) {
  const w = project._wizard || {};
  const vendors = masters.MasterVendors || [];
  const stakeholders = w.externalStakeholders || [];
  return stakeholders.map((s) => {
    if (s.vendorId) {
      const v = vendors.find((m) => m.id === s.vendorId);
      if (v) return { vendor: v, projectRole: s.projectRole || '', projectNotes: s.projectNotes || '' };
    }
    // Old shape — build synthetic vendor record from inline fields
    if (s.name) {
      return {
        vendor: {
          id: null,
          value: s.name,
          initials: (s.name || '').split(' ').map((x) => x[0]).filter(Boolean).slice(0, 2).join('').toUpperCase() || '?',
          accent: '#A67C5A',
          vendorType: s.type || 'Other',
          primaryContact: s.mobile || '',
          primaryEmail: s.email || '',
          gstin: '',
          tradesProvided: [],
          notes: '',
          _synthetic: true,
        },
        projectRole: s.notes || '',  // old "notes" field becomes new "projectRole"
        projectNotes: '',
      };
    }
    return null;
  }).filter(Boolean);
}

/* Aggregates which projects each client appears on.
   Returns Map<clientId, [{ project, isPM }]>. Used in ClientPanelScreen. */
function aggregateProjectsByClient(projects, masters) {
  const byClient = new Map();
  projects.forEach((p) => {
    const client = resolveClientForProject(p, masters);
    if (!client) return;
    const key = client.id || `synthetic:${client.value}`;
    if (!byClient.has(key)) byClient.set(key, { client, projects: [] });
    byClient.get(key).projects.push(p);
  });
  return byClient;
}

/* ============================================================================
   ===== Phase 9.2.2 — Studio Qualification Form helpers =====================
   ============================================================================
   Pure helper functions for the qualification questionnaire feature.
   All read-only — they take masters/responses and compute derived data.
   Used by Phase 3 (editor), Phase 4 (prospect form), Phase 6 (responses dashboard).
   ============================================================================ */

/* Find the right template for a given project's category + property type.
   Returns the template object, or null if none matches.
   Match priority: category + propertyType in list > category only > nothing. */
function getTemplateForProject(masters, projectCategory, propertyType) {
  const templates = (masters && masters.MasterQuestionnaireTemplates) || [];
  if (!projectCategory) return null;
  const active = templates.filter((t) => t.isActive !== false);
  /* First pass: exact match on both category and propertyType */
  if (propertyType) {
    const exact = active.find((t) =>
      t.propertyCategory === projectCategory
      && Array.isArray(t.propertyType)
      && t.propertyType.includes(propertyType)
    );
    if (exact) return exact;
  }
  /* Second pass: category match with empty propertyType array (= applies to all types within category) */
  const byCategory = active.find((t) =>
    t.propertyCategory === projectCategory
    && (!Array.isArray(t.propertyType) || t.propertyType.length === 0)
  );
  return byCategory || null;
}

function getQuestionnaireCopy(masters, template = {}) {
  const copyRows = masters?.MasterMessageTemplates || [];
  const matched = copyRows.find((row) => (
    row.messageType === 'Questionnaire intro/thank-you'
    && (
      (template.code && row.linkedQuestionnaireCode === template.code)
      || (template.name && row.linkedQuestionnaireName === template.name)
      || (template.propertyCategory && row.linkedCategory === template.propertyCategory)
    )
  ));
  return {
    introText: matched?.introText || template.introText || '',
    thankYouText: matched?.thankYouText || matched?.outroText || template.outroText || '',
  };
}

/* Get questions for a specific template, sorted by order. */
function getQuestionsForTemplate(masters, templateId) {
  const all = (masters && masters.MasterQuestionnaireQuestions) || [];
  return all
    .filter((q) => q.templateId === templateId)
    .sort((a, b) => (a.order || 0) - (b.order || 0));
}

/* Maximum possible score for a template — sum of all question weights.
   Used as denominator for the percentage calculation. */
function getMaxPossibleScore(questions) {
  return questions.reduce((sum, q) => sum + (q.weight || 0), 0);
}

/* Compute the score for a single question given an answer.
   Returns weighted score (weight × multiplier).
   Handles all the scoringMap shapes:
     - select types: { answerValue: multiplier }
     - number with ranges: { ranges: [[min, max, mult], ...] }
     - date with daysFromNow: { daysFromNow: [[minDays, maxDays, mult], ...] }
     - text types: { hasValue: x, empty: y }
     - multi-select: { multiplier: x } — flat multiplier for any non-empty selection */
function scoreSingleAnswer(question, answer) {
  const weight = question.weight || 0;
  if (weight === 0) return 0;
  const map = question.scoringMap;
  if (!map) return 0;

  /* Multi-select with flat multiplier */
  if (map.multiplier !== undefined) {
    const hasSelection = Array.isArray(answer) ? answer.length > 0 : !!answer;
    return hasSelection ? weight * map.multiplier : 0;
  }

  /* Number with ranges */
  if (map.ranges && Array.isArray(map.ranges)) {
    const num = Number(answer);
    if (isNaN(num)) return 0;
    for (const [min, max, mult] of map.ranges) {
      if (num >= min && num < max) return weight * mult;
    }
    return 0;
  }

  /* Date with daysFromNow */
  if (map.daysFromNow && Array.isArray(map.daysFromNow)) {
    if (!answer) return 0;
    const target = new Date(answer);
    if (isNaN(target.getTime())) return 0;
    const now = new Date();
    const days = Math.round((target - now) / (1000 * 60 * 60 * 24));
    for (const [minD, maxD, mult] of map.daysFromNow) {
      if (days >= minD && days < maxD) return weight * mult;
    }
    return 0;
  }

  /* Text types with hasValue / empty */
  if (map.hasValue !== undefined && map.empty !== undefined) {
    const isEmpty = !answer || (typeof answer === 'string' && answer.trim() === '');
    return weight * (isEmpty ? map.empty : map.hasValue);
  }

  /* Single-select: answer value is a key in the map */
  if (typeof answer === 'string' && map[answer] !== undefined) {
    return weight * map[answer];
  }

  return 0;
}

/* Compute total + percentage + tier for a response object.
   Returns { total, maxPossible, pct, tier }. */
function calculateResponseScore(response, template, questions) {
  const max = getMaxPossibleScore(questions);
  if (max === 0) return { total: 0, maxPossible: 0, pct: 0, tier: 'cold' };
  const answers = (response && response.answers) || [];
  const answerMap = {};
  answers.forEach((a) => { answerMap[a.questionId] = a.value; });
  let total = 0;
  questions.forEach((q) => {
    const a = answerMap[q.id];
    if (a !== undefined) total += scoreSingleAnswer(q, a);
  });
  const pct = Math.round((total / max) * 100);
  return { total, maxPossible: max, pct, tier: getResponseTier(pct) };
}

/* Tier from percentage: Hot ≥75 / Warm 40-74.99 / Cold <40 */
function getResponseTier(pct) {
  if (pct >= 75) return 'hot';
  if (pct >= 40) return 'warm';
  return 'cold';
}

/* Generate a unique slug-style ID for a shareable link (e.g., "STD-Q-7K9P2L").
   Used when the studio creates a new prospect link. */
function generateQuestionnaireLinkId() {
  const chars = 'ABCDEFGHJKLMNPQRSTUVWXYZ23456789';
  let id = 'STD-Q-';
  for (let i = 0; i < 6; i++) id += chars[Math.floor(Math.random() * chars.length)];
  return id;
}

/* Aggregates which projects each vendor serves.
   Returns Map<vendorId, [{ project, projectRole, projectNotes }]>. Used in VendorPanelScreen. */
function aggregateProjectsByVendor(projects, masters) {
  const byVendor = new Map();
  projects.forEach((p) => {
    const vendorEntries = resolveVendorsForProject(p, masters);
    vendorEntries.forEach(({ vendor, projectRole, projectNotes }) => {
      const key = vendor.id || `synthetic:${vendor.value}`;
      if (!byVendor.has(key)) byVendor.set(key, { vendor, projects: [] });
      byVendor.get(key).projects.push({ project: p, projectRole, projectNotes });
    });
  });
  return byVendor;
}

/* ==================================================================== */

function buildProjectStagesFromMasters(masters, serviceType, options = {}) {
  const { currentStage, currentProgress, workflowTemplateName } = options;
  const allActivities = masters.MasterActivities || [];
  const allDeliverables = masters.MasterDeliverables || [];

  // Try to find a workflow template matching the picked service type
  const templates = masters.MasterWorkflowTemplates || [];
  const matching = workflowTemplateName
    ? (templates.find((t) => String(t.value || t.name || '') === String(workflowTemplateName)) || templates.find((t) => t.linkedServiceType === serviceType))
    : templates.find((t) => t.linkedServiceType === serviceType);

  // New shape: matching.stages is [{ name, activities: [string] }]
  // Old shape (defensive): matching.stages is [string]
  let templateStages;  // [{ name, activities: [string] }]
  let templateRef = null;
  if (matching && Array.isArray(matching.stages) && matching.stages.length > 0) {
    templateRef = matching.id;
    templateStages = matching.stages.map((s) => {
      if (typeof s === 'string') return { name: s, activities: [] };
      return { name: s.name || '', activities: Array.isArray(s.activities) ? s.activities : [] };
    });
  } else {
    // Fallback: universal MasterWorkflowStages list, no activities
    templateStages = (masters.MasterWorkflowStages || []).map((s) => ({
      name: s.value || s.name || '',
      activities: [],
    }));
  }

  if (templateStages.length === 0) return [];

  const matchIdx = currentStage ? templateStages.findIndex((s) => s.name === currentStage) : -1;
  const validIdx = matchIdx >= 0 ? matchIdx : 0;

  return templateStages.map((stage, idx) => {
    let status, progress;
    if (idx < validIdx) {
      status = 'completed';
      progress = 100;
    } else if (idx === validIdx) {
      status = 'in_progress';
      progress = currentProgress != null ? currentProgress : (idx === 0 ? 5 : 0);
    } else {
      status = 'not_started';
      progress = 0;
    }

    // Build activities from template list, cross-referencing MasterActivities for description
    const activities = (stage.activities || []).map((actName) => {
      const masterAct = allActivities.find((a) => a.value === actName && (a.linkedStage === stage.name || !a.linkedStage));
      // Find deliverables for this activity
      const deliverables = allDeliverables
        .filter((d) => d.linkedActivity === actName)
        .map((d) => buildDeliverableRecord({
          name: d.value,
          format: d.format,
          clientFacing: d.clientFacing,
          description: d.description,
          masterRef: d.id,
        }));
      return buildActivityRecord({
        name: actName,
        description: masterAct ? masterAct.description : '',
        masterRef: masterAct ? masterAct.id : null,
        deliverables,
      });
    });

    return {
      id: uid(),
      name: stage.name,
      status,
      progress,
      activities,
      masterRef: templateRef
        ? { templateId: templateRef, stageIndex: idx }
        : { stageMasterRef: stage.name },
    };
  });
}

/* Activity record factory */
function buildActivityRecord(partial = {}) {
  return {
    id: uid(),
    name: partial.name || '',
    description: partial.description || '',
    status: partial.status || 'not_started',  // not_started | in_progress | done
    masterRef: partial.masterRef || null,
    deliverables: Array.isArray(partial.deliverables) ? partial.deliverables : [],
  };
}

/* Deliverable record factory */
function buildDeliverableRecord(partial = {}) {
  return {
    id: uid(),
    name: partial.name || '',
    format: partial.format || 'Document',
    clientFacing: partial.clientFacing || 'yes',
    description: partial.description || '',
    target: partial.target || '',  // free-text target line e.g. "3 mood boards for client presentation"
    status: partial.status || 'pending',  // pending | in_progress | delivered | approved
    deliveredOn: partial.deliveredOn || '',
    masterRef: partial.masterRef || null,
  };
}

/* Compute roll-up metrics across activities under a stage */
function computeActivityMetrics(activities) {
  const list = activities || [];
  const total = list.length;
  const done = list.filter((a) => a.status === 'done').length;
  const inProgress = list.filter((a) => a.status === 'in_progress').length;
  return { total, done, inProgress };
}

function computeStageMetrics(projectStages) {
  if (!projectStages || projectStages.length === 0) {
    return { currentStage: 'Onboarding', progress: 0 };
  }

  // Current stage: first in_progress, else first not_started, else last stage
  const inProgress = projectStages.find((s) => s.status === 'in_progress');
  let currentStage;
  if (inProgress) {
    currentStage = inProgress.name;
  } else {
    const firstNotStarted = projectStages.find((s) => s.status === 'not_started');
    currentStage = firstNotStarted
      ? firstNotStarted.name
      : projectStages[projectStages.length - 1].name;
  }

  // Overall: completed = 100, in_progress = its progress, not_started = 0
  const totalProgress = projectStages.reduce((sum, s) => {
    if (s.status === 'completed') return sum + 100;
    if (s.status === 'in_progress') return sum + (parseInt(s.progress, 10) || 0);
    return sum;
  }, 0);

  return {
    currentStage,
    progress: Math.round(totalProgress / projectStages.length),
  };
}

/* ========================== Move 3: Approval helpers ========================== */

const APPROVAL_STATUS_OPTIONS = ['pending', 'approved', 'rejected', 'on_hold'];

function buildApprovalRecord(partial = {}) {
  const today = new Date();
  const dueIn = parseInt(partial.slaDays, 10) || 5;
  const due = new Date(today.getTime() + dueIn * 24 * 60 * 60 * 1000);
  return {
    id: uid(),
    title: partial.title || '',
    typeRef: partial.typeRef || null,
    typeName: partial.typeName || '',
    linkedStage: partial.linkedStage || '',
    linkedActivity: partial.linkedActivity || '',  /* Phase 5.4 — optional activity link */
    requestedFrom: partial.requestedFrom || '',
    raisedBy: partial.raisedBy || '',
    status: partial.status || 'pending',
    clientFacing: partial.clientFacing || 'no',
    dueDate: partial.dueDate || due.toISOString().slice(0, 10),
    raisedOn: partial.raisedOn || today.toISOString().slice(0, 10),
    decisionDate: partial.decisionDate || '',
    decisionNotes: partial.decisionNotes || '',
  };
}

function computeApprovalMetrics(approvals) {
  const list = approvals || [];
  const today = new Date().toISOString().slice(0, 10);
  const pending = list.filter((a) => a.status === 'pending').length;
  const overdue = list.filter((a) => a.status === 'pending' && a.dueDate && a.dueDate < today).length;
  return {
    pendingApprovals: pending,
    overdueApprovals: overdue,
    totalApprovals: list.length,
  };
}

/* ========================== Move 4: Task helpers ========================== */

const TASK_STATUS_OPTIONS = ['todo', 'in_progress', 'done', 'blocked'];

function buildTaskRecord(partial = {}) {
  const today = new Date();
  const dueIn = parseInt(partial.dueDays, 10) || 7;
  const due = new Date(today.getTime() + dueIn * 24 * 60 * 60 * 1000);
  return {
    id: uid(),
    title: partial.title || '',
    description: partial.description || '',
    linkedStage: partial.linkedStage || '',
    linkedActivity: partial.linkedActivity || '',  /* Phase 5.4 — task is owned by an activity */
    /* Phase 5.8 Piece 0 — assignee is now an ID into MasterTeamMembers, name cached for display */
    assigneeId: partial.assigneeId || null,
    assigneeName: partial.assigneeName || partial.assignee || '',
    assignedById: partial.assignedById || null,
    assignedAt: partial.assignedAt || today.toISOString().slice(0, 10),
    /* Legacy field — preserved for back-compat with old backups; new code reads assigneeId/Name */
    assignee: partial.assignee || partial.assigneeName || '',
    status: partial.status || 'todo',
    /* Phase 9.0.28 — startDate forms a window with dueDate. Empty by default;
       user fills in via task edit form. */
    startDate: partial.startDate || '',
    dueDate: partial.dueDate || due.toISOString().slice(0, 10),
    createdOn: partial.createdOn || today.toISOString().slice(0, 10),
    completedOn: partial.completedOn || '',
    masterRef: partial.masterRef || null,
    /* Phase 5.8 Piece 4 — review/closure flow */
    reviewLog: partial.reviewLog || [],            /* Array of { event, byId, byName, at, notes } */
    submissionNote: partial.submissionNote || '',  /* Doer's note when marking done */
    rejectionReason: partial.rejectionReason || '',/* Manager's note when rejecting */
    closedAt: partial.closedAt || '',              /* Distinct from completedOn — set on approved_closed */
    closedById: partial.closedById || null,
    /* Phase 5.8 Piece 5 — reminders. In-app surfacing works today.
       reminderChannel saved for future backend wire-up; only 'inapp' is honored now. */
    remindAt: partial.remindAt || '',              /* ISO date string when the reminder should fire */
    reminderChannel: partial.reminderChannel || 'inapp', /* 'inapp' | 'whatsapp' | 'email' | 'all' */
    reminderDismissed: partial.reminderDismissed || false, /* Set true when user dismisses the in-app banner for this task */
    /* Phase 6.2c — Inline checklist items pulled from MasterTasks.defaultChecklist
       at task-creation time. Each item: { text, done, checkedBy, checkedAt }.
       Items are independent of task status — completing all items does not mark the task done. */
    checklistItems: Array.isArray(partial.checklistItems) ? partial.checklistItems : [],
  };
}

/* Phase 6.2c — Parse a multi-line checklist string into checklistItems array */
function parseChecklistText(text) {
  if (!text || typeof text !== 'string') return [];
  return text.split(/\r?\n/).map((l) => l.trim()).filter(Boolean).map((line) => ({
    text: line,
    done: false,
    checkedBy: '',
    checkedAt: '',
  }));
}

function applyChecklistTemplate(checklistRow, masters) {
  if (!checklistRow || !Array.isArray(checklistRow.items)) return [];
  // Derive linkedStage from the activity's master row, for backward-compatible UI grouping
  const allActivities = (masters && masters.MasterActivities) || [];
  const matchingAct = allActivities.find((a) => a.value === checklistRow.linkedActivity);
  const derivedStage = matchingAct ? matchingAct.linkedStage : '';
  return checklistRow.items.map((item, idx) => buildTaskRecord({
    title: item,
    linkedStage: derivedStage,
    linkedActivity: checklistRow.linkedActivity || '',
    masterRef: { checklistId: checklistRow.id, checklistName: checklistRow.value, itemIndex: idx },
  }));
}

