const StatusDot = ({ status }) => {
  const map = { 'on-track': '#6B7355', 'attention': '#B4593C', 'new': '#A67C5A', 'hold': '#9A938A' };
  return <span className="inline-block w-2 h-2 rounded-full" style={{ background: map[status] || '#9A938A' }} />;
};

const Tag = ({ children, tone = 'bone' }) => {
  const tones = { bone: 'bg-muted-warm ink', terra: 'bg-terra-soft text-terra', moss: 'bg-moss-soft text-moss', ink: 'bg-ink text-white' };
  return <span className={`text-[10px] font-ui font-medium tracking-wide uppercase px-2 py-0.5 rounded-full ${tones[tone]}`}>{children}</span>;
};

const StatusPill = ({ status }) => {
  const config = {
    'built': { bg: 'bg-moss-soft', color: 'text-moss', label: 'Built', icon: CheckCircle2 },
    'pending': { bg: 'bg-muted-warm', color: 'ink-faint', label: 'Pending', icon: Circle },
    'mapped': { bg: 'bg-moss-soft', color: 'text-moss', label: 'Ready', icon: CheckCircle2 },
  };
  const c = config[status] || config.pending;
  const Icon = c.icon;
  return (
    <span className={`inline-flex items-center gap-1 text-[10px] font-ui font-medium px-1.5 py-0.5 rounded ${c.bg} ${c.color}`}>
      <Icon className="w-2.5 h-2.5" strokeWidth={2.5} />{c.label}
    </span>
  );
};

function FieldGroup({ label, hint, required, children, span = 'full' }) {
  const colSpan = span === 'half' ? 'col-span-1' : 'col-span-2';
  return (
    <div className={colSpan}>
      <label className="block mb-1.5">
        <span className="text-[11px] font-mono font-medium ink uppercase tracking-wider">
          {label}{required && <span className="text-terra ml-1">*</span>}
        </span>
        {hint && <span className="text-[10px] ink-faint ml-2">{hint}</span>}
      </label>
      {children}
    </div>
  );
}

function TextField({ value, onChange, placeholder, type = 'text', disabled }) {
  return <input type={type} value={value || ''} onChange={(e) => onChange(e.target.value)} placeholder={placeholder} disabled={disabled} className="input-base" />;
}

function TextArea({ value, onChange, placeholder, rows = 3 }) {
  return <textarea value={value || ''} onChange={(e) => onChange(e.target.value)} placeholder={placeholder} rows={rows} className="input-base" style={{ resize: 'none' }} />;
}

function SelectField({ value, onChange, options, placeholder = 'Select…' }) {
  const safeOptions = (options || []).filter((opt) => opt !== undefined && opt !== null && opt !== '');
  return (
    <select value={value || ''} onChange={(e) => onChange(e.target.value)} className="input-base" style={{ cursor: 'pointer' }}>
      <option value="">{placeholder}</option>
      {safeOptions.map((opt, i) => (
        <option key={i} value={typeof opt === 'string' ? opt : opt.value}>{typeof opt === 'string' ? opt : (opt.label || opt.value)}</option>
      ))}
    </select>
  );
}

function masterOptionValue(row) {
  if (row == null) return '';
  if (typeof row === 'string') return row;
  return row.value ?? row.status ?? row.source ?? row.name ?? row.label ?? row.id ?? '';
}

function generatedPropertyTypeSizeBands(row = {}) {
  const value = String(row.value || row.name || '').toLowerCase();
  const category = String(row.category || '').toLowerCase();
  const text = `${value} ${category}`;

  if (/flat|apartment|builder floor|luxury apartment/.test(text)) {
    return ['< 1,000 sq ft', '1,000 - 2,000 sq ft', '2,000 - 5,000 sq ft', '5,000+ sq ft'];
  }
  if (/villa|bunglow|bungalow|kothi|farm|penthouse/.test(text)) {
    return ['< 2,000 sq ft', '2,000 - 5,000 sq ft', '5,000 - 20,000 sq ft', '20,000+ sq ft'];
  }
  if (/cafe|café|qsr|restaurant|fine dine|bar|lounge|f&b|food/.test(text)) {
    return ['< 800 sq ft', '800 - 2,000 sq ft', '2,000 - 5,000 sq ft', '5,000+ sq ft'];
  }
  if (/office|hq|ho|smb|cowork|co-work|studio office|corporate/.test(text)) {
    return ['< 2,000 sq ft', '2,000 - 10,000 sq ft', '10,000 - 50,000 sq ft', '50,000+ sq ft'];
  }
  if (/retail|showroom|store|boutique|mall/.test(text)) {
    return ['< 1,000 sq ft', '1,000 - 5,000 sq ft', '5,000 - 20,000 sq ft', '20,000+ sq ft'];
  }
  if (/clinic|dental|eye|health|hospital|wellness|medical/.test(text)) {
    return ['< 1,500 sq ft', '1,500 - 7,500 sq ft', '7,500 - 50,000 sq ft', '50,000+ sq ft'];
  }
  if (/hotel|resort|hospitality|banquet|leisure/.test(text)) {
    return ['< 5,000 sq ft', '5,000 - 25,000 sq ft', '25,000 - 100,000 sq ft', '100,000+ sq ft'];
  }
  if (/college|school|institution|research|academic|campus|university/.test(text)) {
    return ['< 10,000 sq ft', '10,000 - 50,000 sq ft', '50,000 - 200,000 sq ft', '200,000+ sq ft'];
  }
  if (/factory|industrial|warehouse|plant/.test(text)) {
    return ['< 25,000 sq ft', '25,000 - 100,000 sq ft', '100,000 - 500,000 sq ft', '500,000+ sq ft'];
  }
  if (/airport|railway|metro|port|utility|public/.test(text)) {
    return ['< 50,000 sq ft', '50,000 - 200,000 sq ft', '200,000 - 1,000,000 sq ft', '1,000,000+ sq ft'];
  }
  return ['< 1,000 sq ft', '1,000 - 5,000 sq ft', '5,000 - 20,000 sq ft', '20,000+ sq ft'];
}

function withPropertyTypeSizeDefaults(row = {}) {
  const bands = generatedPropertyTypeSizeBands(row);
  return {
    ...row,
    sizeBand1: row.sizeBand1 || bands[0],
    sizeBand2: row.sizeBand2 || bands[1],
    sizeBand3: row.sizeBand3 || bands[2],
    sizeBand4: row.sizeBand4 || bands[3],
  };
}

function inferBOQCostType(row = {}) {
  const text = `${row.value || ''} ${row.category || ''}`.toLowerCase();
  if (/light|equipment|fixture|appliance|chandelier|fan|ac|hvac|pump|machine|tool/.test(text)) return 'Equipment + Job Work';
  if (/paint|application|laying|laid|installation|installed|polish|labour|labor|work|false ceiling|tiling/.test(text)) return 'Job Work';
  if (/marble|wood|veneer|laminate|tile|stone|fabric|leather|metal|glass|ply|board/.test(text)) return 'Material';
  return 'Material';
}

function withBOQItemDefaults(row = {}) {
  return {
    ...row,
    costType: row.costType || inferBOQCostType(row),
  };
}

function ChipPicker({ values = [], options, onChange, multi = true, tone = 'ink' }) {
  const toggle = (v) => {
    if (multi) onChange(values.includes(v) ? values.filter((x) => x !== v) : [...values, v]);
    else onChange(values[0] === v ? [] : [v]);
  };
  return (
    <div className="flex flex-wrap gap-1.5">
      {options.map((opt) => {
        const v = typeof opt === 'string' ? opt : opt.value;
        const active = values.includes(v);
        return (
          <button key={v} type="button" onClick={() => toggle(v)} className={`chip-pick ${tone} ${active ? 'active' : ''}`}>
            {active && <Check className="w-3 h-3" strokeWidth={2.5} />}{v}
          </button>
        );
      })}
    </div>
  );
}

