function StakeholdersHubScreen({ masters, projects, currentProfile, onOpenLibraryTable, onOpen, onOpenClients, onOpenVendors }) {
  const canOpen = (code) => canSeeNav(currentProfile, code);
  const [activeTab, setActiveTab] = React.useState('clients');
  const clients = masters?.MasterClients || [];
  const team = masters?.MasterTeamMembers || [];
  const vendors = masters?.MasterVendors || [];
  const leads = masters?.MasterLeads || [];
  const clientIdsWithProjects = new Set((projects || []).map((p) => p._wizard?.primaryClientId).filter(Boolean));
  const existingClients = clients.filter((client) => clientIdsWithProjects.has(client.id));
  const prospects = leads.filter((lead) => !lead.convertedToProjectId && !/won/i.test(lead.status || ''));

  const renderTab = () => {
    if (activeTab === 'clients') {
      return (
        <StakeholderListPanel
          title="Existing clients"
          count={existingClients.length}
          empty="No clients linked to projects yet."
          rows={existingClients.map((client) => ({
            id: client.id,
            title: client.value,
            meta: [client.primaryContact, client.mobile, client.city].filter(Boolean).join(' · '),
            action: onOpenClients,
          }))}
        />
      );
    }
    if (activeTab === 'prospects') {
      return (
        <StakeholderListPanel
          title="Prospects"
          count={prospects.length}
          empty="No active prospects yet."
          rows={prospects.map((lead) => ({
            id: lead.id,
            title: lead.name || 'Unnamed lead',
            meta: [lead.status, lead.city, lead.specificSource || lead.sourceCategory].filter(Boolean).join(' · '),
            action: () => onOpen('leads'),
          }))}
        />
      );
    }
    if (activeTab === 'team') {
      return (
        <StakeholderListPanel
          title="Internal team"
          count={team.length}
          empty="No team members yet."
          rows={team.map((member) => ({
            id: member.id,
            title: member.value,
            meta: [member.role, member.department, member.status || 'Active'].filter(Boolean).join(' · '),
            action: () => onOpen('team'),
          }))}
        />
      );
    }
    if (activeTab === 'collaborators') {
      return (
        <StakeholderListPanel
          title="Collaborators"
          count={vendors.length}
          empty="No collaborators or vendors yet."
          rows={vendors.map((vendor) => ({
            id: vendor.id,
            title: vendor.value,
            meta: [vendor.category, vendor.primaryContact, vendor.mobile].filter(Boolean).join(' · '),
            action: onOpenVendors,
          }))}
        />
      );
    }
    return (
      <StudioPlaceholderPanel
        icon={Lock}
        title="Roles · access"
        detail="Role visibility, L1/L2/L3 access, and team permissions are maintained in the existing Roles & Access screen."
        actionLabel="Open roles"
        onAction={() => onOpen('roles')}
      />
    );
  };

  return (
    <div className="flex-1 overflow-auto scrollbar-thin">
      <div className="px-6 py-6 max-w-6xl">
        <div className="mb-5">
          <div className="text-[10px] font-mono uppercase tracking-widest ink-faint mb-1.5">Stakeholders · People network</div>
          <h1 className="font-display text-3xl ink tracking-tight leading-none mb-2">Stakeholders</h1>
          <p className="text-sm ink-soft max-w-2xl leading-relaxed">
            People the studio works with: clients, prospects, internal team, collaborators, and access control.
          </p>
        </div>
        <DataSourceShortcutStrip
          items={[
            { label: 'Clients', table: 'MasterClients', type: 'Library', onClick: () => onOpenLibraryTable?.('MasterClients', 'master') },
            { label: 'Prospects', table: 'MasterLeads', type: 'User data', onClick: () => onOpen('leads') },
            { label: 'Internal team', table: 'MasterTeamMembers', type: 'Library', onClick: () => onOpenLibraryTable?.('MasterTeamMembers', 'master') },
            { label: 'Collaborators', table: 'MasterVendors', type: 'Library', onClick: () => onOpenLibraryTable?.('MasterVendors', 'master') },
            { label: 'Access', table: 'RoleProfiles / permissions', type: 'App config', onClick: () => onOpen('roles') },
          ]}
        />

        <div className="bg-paper border border-line rounded-lg mb-4 overflow-hidden">
          <div className="px-3 py-3 border-b border-line flex flex-wrap items-center gap-2">
            <StakeholderSectionTab active={activeTab === 'clients'} onClick={() => setActiveTab('clients')} icon={BookMarked} label="Existing clients" disabled={!canOpen('clients')} />
            <StakeholderSectionTab active={activeTab === 'prospects'} onClick={() => setActiveTab('prospects')} icon={UserPlus} label="Prospects" disabled={!canOpen('leads')} />
            <StakeholderSectionTab active={activeTab === 'team'} onClick={() => setActiveTab('team')} icon={Users} label="Internal team" disabled={!canOpen('teams')} />
            <StakeholderSectionTab active={activeTab === 'collaborators'} onClick={() => setActiveTab('collaborators')} icon={Truck} label="Collaborators" disabled={!canOpen('vendors')} />
            <StakeholderSectionTab active={activeTab === 'roles'} onClick={() => setActiveTab('roles')} icon={Lock} label="Roles · access" disabled={!canOpen('roles')} />
          </div>
          <div className="p-4">
            {renderTab()}
          </div>
        </div>
      </div>
    </div>
  );
}

