            {item.type && <span className="text-[9px] font-mono uppercase tracking-wider ink-faint">{item.type}</span>}
            <span className="text-[10px] font-mono text-terra whitespace-nowrap">{item.table}</span>
            {item.onClick && <ArrowRight className="w-3 h-3 ink-faint shrink-0" />}
