/* ============================== DASHBOARD ============================== */

function DashboardScreen({ projects, dashboardView, setDashboardView, filterCategory, setFilterCategory, boardColumns, setBoardColumns, editingColumn, setEditingColumn, columnMenu, setColumnMenu, rightRailOpen, setRightRailOpen, onNewProject, onOpenProject, profile, totalProjectCount, currentRoleCode, masters, onJumpToTasks, onJumpToApprovals, onJumpToFinance, onJumpToLeads, onJumpToSales, onJumpToStudio, onUpdateProject, onDeleteProject, onResetDemoProjects }) {
  const [showResetConfirm, setShowResetConfirm] = useState(false);
  const [pulseDetail, setPulseDetail] = useState(null);
  const isAdminTier = currentRoleCode === 'super_admin' || currentRoleCode === 'admin' || currentRoleCode === 'studio_owner';
  const filteredByCategory = filterCategory === 'all' ? projects : projects.filter((p) => p.category === filterCategory);

  /* Phase 6.2e — Sort projects by workflow stage order from MasterWorkflowStages.
     Projects in earlier stages (Onboarding) appear first; later stages (Handover) at the end.
     Tie-breaker: original array order (stable sort). Projects whose currentStage isn't in the
     master list (edge case after a master rename/delete) fall to the bottom. */
  const filtered = React.useMemo(() => {
    const stageList = (masters && masters.MasterWorkflowStages) || [];
    if (stageList.length === 0) return filteredByCategory;
    const stageOrder = new Map();
    stageList.forEach((s, idx) => stageOrder.set(s.value, idx));
    const FALLBACK = stageList.length + 1; /* unknown stages sort last */
    /* Build array with original index for stable tie-break */
    const indexed = filteredByCategory.map((p, originalIdx) => ({ p, originalIdx }));
    indexed.sort((a, b) => {
      const aIdx = stageOrder.has(a.p.currentStage) ? stageOrder.get(a.p.currentStage) : FALLBACK;
      const bIdx = stageOrder.has(b.p.currentStage) ? stageOrder.get(b.p.currentStage) : FALLBACK;
      if (aIdx !== bIdx) return aIdx - bIdx;
      return a.originalIdx - b.originalIdx;
    });
    return indexed.map((x) => x.p);
  }, [filteredByCategory, masters]);
  const addColumn = () => {
    const name = prompt('New column name?');
    if (!name) return;
    setBoardColumns([...boardColumns, { id: `col-${Date.now()}`, name, color: '#9A938A' }]);
  };
  const renameColumn = (id, name) => { setBoardColumns(boardColumns.map((c) => (c.id === id ? { ...c, name } : c))); setEditingColumn(null); };
  const deleteColumn = (id) => { setBoardColumns(boardColumns.filter((c) => c.id !== id)); setColumnMenu(null); };
  const onTrack = projects.filter((p) => p.status === 'on-track').length;
  const attention = projects.filter((p) => p.status === 'attention').length;
  const isFiltered = profile && totalProjectCount && projects.length < totalProjectCount;

  /* ===== Phase 5.7 Feature 5 — Widget aggregations ===== */
  const widgetData = React.useMemo(() => {
    const today = new Date().toISOString().slice(0, 10);
    const todayDate = new Date(today);
    const inDays = (n) => {
      const d = new Date(today);
      d.setDate(d.getDate() + n);
      return d.toISOString().slice(0, 10);
    };
    const horizon30 = inDays(30);

    // ---- Tasks: open + overdue ----
    let openTasks = 0;
    let overdueTasks = 0;
    // ---- Approvals: pending + overdue ----
    let pendingApprovals = 0;
    let overdueApprovals = 0;
    // ---- Payment milestones in next 30 days ----
    let upcomingPaymentTotal = 0;
    let upcomingPaymentCount = 0;
    const upcomingPaymentByProject = []; // { projectName, accent, amount }
    // ---- Recent site updates ----
    const allSiteUpdates = [];

    projects.forEach((p) => {
      const w = p._wizard || {};

      // Tasks (apply role visibility)
      const tasksRaw = w.projectTasks || [];
      const tasksVisible = recordsForRole(tasksRaw, currentRoleCode, 'task');
      tasksVisible.forEach((t) => {
        if (isTaskOpen(t)) {
          openTasks++;
          if (t.dueDate && t.dueDate < today) overdueTasks++;
        }
      });

      // Approvals
      const approvalsRaw = w.projectApprovals || [];
      const approvalsVisible = recordsForRole(approvalsRaw, currentRoleCode, 'approval');
      approvalsVisible.forEach((a) => {
        if (a.status === 'pending') {
          pendingApprovals++;
          if (a.dueDate && a.dueDate < today) overdueApprovals++;
        }
      });

      // Payment terms — sum amounts whose linkedStage matches the current/upcoming stage
      // Simpler proxy: any payment term where reminderEnabled=true counts as "live"
      // and we tally those whose stage isn't yet closed (stage is current or upcoming)
      const stages = w.projectStages || [];
      const upcomingStageNames = new Set();
      stages.forEach((s) => { if (s.status !== 'completed') upcomingStageNames.add(s.name); });
      let projectUpcoming = 0;
      (w.paymentTerms || []).forEach((pt) => {
        if (pt.reminderEnabled && upcomingStageNames.has(pt.linkedStage)) {
          const amt = parseFloat(pt.amount || '0');
          if (!isNaN(amt) && amt > 0) {
            projectUpcoming += amt;
            upcomingPaymentCount++;
          }
        }
      });
      if (projectUpcoming > 0) {
        upcomingPaymentTotal += projectUpcoming;
        upcomingPaymentByProject.push({ projectId: p.id, projectName: p.name, accent: p.accent, amount: projectUpcoming });
      }

      // Site updates
      const siteUpdates = w.siteUpdates || [];
      const siteVisible = recordsForRole(siteUpdates, currentRoleCode, 'siteUpdate');
      siteVisible.forEach((s) => {
        allSiteUpdates.push({
          ...s,
          _projectId: p.id,
          _projectName: p.name,
          _projectAccent: p.accent,
        });
      });
    });

    // ---- Projects needing attention ----
    const attentionProjects = projects.filter((p) => {
      if (p.status === 'attention') return true;
      if ((p.overdueTasks || 0) >= 2) return true;
      return false;
    });

    // Sort site updates by date desc, take top 5
    const recentSiteUpdates = [...allSiteUpdates]
      .sort((a, b) => (b.date || '0').localeCompare(a.date || '0'))
      .slice(0, 5);

    // Sort upcoming payments by amount desc, take top 5
    const topPayments = [...upcomingPaymentByProject].sort((a, b) => b.amount - a.amount).slice(0, 5);

    // Phase 9.0.24 — Upcoming deadlines (tasks + approvals + payment milestones, next 14 days)
    const horizon14 = inDays(14);
    const upcomingDeadlines = [];
    projects.forEach((p) => {
      const w = p._wizard || {};
      // Tasks
      (w.projectTasks || []).forEach((t) => {
        if (!isTaskOpen(t)) return;
        if (!t.dueDate) return;
        if (t.dueDate >= today && t.dueDate <= horizon14) {
          upcomingDeadlines.push({
            kind: 'task',
            label: t.title,
            projectId: p.id, projectName: p.name, projectAccent: p.accent,
            date: t.dueDate,
            assignee: t.assignee || t.assigneeName || '',
          });
        }
      });
      // Approvals
      (w.projectApprovals || []).forEach((a) => {
        if (a.status !== 'pending') return;
        if (!a.dueDate) return;
        if (a.dueDate >= today && a.dueDate <= horizon14) {
          upcomingDeadlines.push({
            kind: 'approval',
            label: a.title,
            projectId: p.id, projectName: p.name, projectAccent: p.accent,
            date: a.dueDate,
            assignee: a.requestedFrom || '',
          });
        }
      });
      // Payment milestones
      (w.paymentTerms || []).forEach((m) => {
        if (!m.targetDate) return;
        const due = parseFloat(m.amount) || 0;
        const recv = parseFloat(m.amountReceived) || 0;
        if (recv >= due && due > 0) return; // already paid
        if (m.targetDate >= today && m.targetDate <= horizon14) {
          upcomingDeadlines.push({
            kind: 'payment',
            label: m.name,
            projectId: p.id, projectName: p.name, projectAccent: p.accent,
            date: m.targetDate,
            assignee: '',
            amount: due - recv,
          });
        }
      });
    });
    upcomingDeadlines.sort((a, b) => (a.date || '9999').localeCompare(b.date || '9999'));

    return {
      openTasks, overdueTasks,
      pendingApprovals, overdueApprovals,
      upcomingPaymentTotal, upcomingPaymentCount, topPayments,
      attentionProjects,
      recentSiteUpdates,
      upcomingDeadlines,
    };
  }, [projects, currentRoleCode]);

  /* Phase 9.1 Part 2 — Calm dashboard rewrite.
     Replaces stat-heavy header + Financial Health section + Activity widgets +
     dense project cards with greeting + 3 attention zones + quiet project table.
     Compute the 3 attention zone summaries inline. */
  const todayStr = new Date().toISOString().slice(0, 10);
  const dayLabel = new Date().toLocaleDateString('en-IN', { weekday: 'long', day: 'numeric', month: 'long' });
  const userFirstName = (profile && profile.user && profile.user.name) ? profile.user.name.split(' ')[0] : 'there';

  /* Zone 1 — Decisions waiting (pending approvals) */
  const pendingApprovalsList = [];
  projects.forEach((p) => {
    (p._wizard?.projectApprovals || []).forEach((a) => {
      if (a.status === 'pending') {
        pendingApprovalsList.push({ ...a, projectName: p.name, projectId: p.id });
      }
    });
  });

  /* Zone 2 — Outstanding payments */
  const portfolioMoney = computePortfolioTotals(projects, masters, todayStr);
  const lateClientNames = [];
  projects.forEach((p) => {
    const f = computeProjectFinancials(p, todayStr);
    if (f.overdueCount > 0) {
      const cName = (p.client || '').split(' ')[0] || p.name.split(' ')[0];
      if (!lateClientNames.includes(cName)) lateClientNames.push(cName);
    }
  });

  /* Zone 3 — Tasks slipping (across all projects) */
  const slippingTasks = [];
  projects.forEach((p) => {
    (p._wizard?.projectTasks || []).forEach((t) => {
      if (isTaskOpen(t) && t.dueDate && t.dueDate < todayStr) {
        slippingTasks.push({
          name: t.title || t.value,
          assignee: (t.assigneeName || t.assignee || 'Unassigned').split(' ')[0],
          projectName: p.name,
        });
      }
    });
  });

  /* Sorted "active projects" — top 5 for the table */
  const sortedProjects = [...filtered].sort((a, b) => {
    const af = computeProjectFinancials(a, todayStr);
    const bf = computeProjectFinancials(b, todayStr);
    if (af.overdueCount !== bf.overdueCount) return bf.overdueCount - af.overdueCount;
    return (b.progress || 0) - (a.progress || 0);
  }).slice(0, 6);

  const pulseData = React.useMemo(() => {
    const MS_DAY = 24 * 60 * 60 * 1000;
    const startOfToday = new Date(todayStr + 'T00:00:00');
    const endOfToday = new Date(todayStr + 'T23:59:59');
    const weekStart = new Date(startOfToday);
    weekStart.setDate(startOfToday.getDate() - ((startOfToday.getDay() + 6) % 7));
    const weekEnd = new Date(weekStart);
    weekEnd.setDate(weekStart.getDate() + 6);
    const monthStart = new Date(startOfToday.getFullYear(), startOfToday.getMonth(), 1);
    const monthEnd = new Date(startOfToday.getFullYear(), startOfToday.getMonth() + 1, 0, 23, 59, 59);
    const next7 = new Date(startOfToday);
    next7.setDate(startOfToday.getDate() + 7);
    const next30 = new Date(startOfToday);
    next30.setDate(startOfToday.getDate() + 30);
    const last90 = new Date(startOfToday);
    last90.setDate(startOfToday.getDate() - 90);

    const dateOf = (value) => {
      if (!value) return null;
      const d = new Date(value);
      return Number.isNaN(d.getTime()) ? null : d;
    };
    const inRange = (value, start, end) => {
      const d = dateOf(value);
      return !!d && d >= start && d <= end;
    };
    const daysSince = (value) => {
      const d = dateOf(value);
      if (!d) return null;
      return Math.floor((startOfToday.getTime() - d.getTime()) / MS_DAY);
    };
    const personName = (value) => (value || 'Unassigned').toString().trim() || 'Unassigned';
    const leadStatus = (lead) => (lead.status || lead.stage || 'New Lead').toString();
    const isTerminalLead = (lead) => /won|lost|closed|archived/i.test(leadStatus(lead));
    const leadDate = (lead) => lead.enquiryDate || lead.createdOn || lead.createdAt || lead.updatedAt;
    const leadBudget = (lead) => parseBudgetToRupees(lead.estimatedBudget || lead.budget || lead.budgetRange || '');
    const stageProbability = (status) => {
      const s = (status || '').toLowerCase();
      if (s.includes('won')) return 1;
      if (s.includes('verbal')) return 0.9;
      if (s.includes('negoti')) return 0.75;
      if (s.includes('proposal')) return 0.65;
      if (s.includes('qualified')) return 0.5;
      if (s.includes('discover')) return 0.35;
      if (s.includes('contact')) return 0.2;
      if (s.includes('lost')) return 0;
      return 0.1;
    };

    const milestones = [];
    const approvals = [];
    const tasks = [];
    projects.forEach((project) => {
      const wizard = project._wizard || {};
      const totalProjectValue = parseFloat(wizard.totalProjectValue) || 0;
      (wizard.paymentTerms || []).forEach((milestone) => {
        const due = computeMilestoneAmount(milestone, totalProjectValue);
        const received = parseFloat(milestone.amountReceived) || 0;
        const balance = Math.max(0, due - received);
        milestones.push({
          ...milestone,
          projectId: project.id,
          projectName: project.name,
          clientName: project.client,
          due,
          received,
          balance,
          targetDate: milestone.targetDate || milestone.dueDate,
        });
      });
      (wizard.projectApprovals || []).forEach((approval) => {
        approvals.push({ ...approval, projectId: project.id, projectName: project.name });
      });
      (wizard.projectTasks || []).forEach((task) => {
        tasks.push({ ...task, projectId: project.id, projectName: project.name });
      });
    });

    const overdueMilestones = milestones
      .filter((m) => m.balance > 0 && m.targetDate && m.targetDate < todayStr)
      .sort((a, b) => b.balance - a.balance);
    const dueSoonMilestones = milestones
      .filter((m) => m.balance > 0 && inRange(m.targetDate, startOfToday, next7))
      .sort((a, b) => (a.targetDate || '').localeCompare(b.targetDate || ''));
    const collectionsThisWeek = milestones.filter((m) => m.received > 0 && inRange(m.receiptDate || m.receivedDate, weekStart, weekEnd));
    const collectionsThisMonth = milestones.filter((m) => m.received > 0 && inRange(m.receiptDate || m.receivedDate, monthStart, monthEnd));

    const pendingApprovals = approvals.filter((a) => a.status === 'pending' || !a.status);
    const overdueApprovals = pendingApprovals
      .filter((a) => a.dueDate && a.dueDate < todayStr)
      .sort((a, b) => (a.dueDate || '').localeCompare(b.dueDate || ''));
    const weekApprovals = pendingApprovals.filter((a) => inRange(a.dueDate, startOfToday, weekEnd));
    const monthApprovals = pendingApprovals.filter((a) => inRange(a.dueDate, startOfToday, monthEnd));

    const openTasks = tasks.filter(isTaskOpen);
    const overdueTasks = openTasks
      .filter((t) => t.dueDate && t.dueDate < todayStr)
      .sort((a, b) => (a.dueDate || '').localeCompare(b.dueDate || ''));
    const completedThisWeek = tasks.filter((t) => isTaskClosed(t) && inRange(t.completedOn || t.closedAt || t.updatedAt, weekStart, weekEnd));
    const completedByPerson = completedThisWeek.reduce((acc, task) => {
      const name = personName(task.assigneeName || task.assignee);
      acc[name] = (acc[name] || 0) + 1;
      return acc;
    }, {});
    const approvalsTurned = approvals
      .filter((a) => (a.status === 'approved' || a.status === 'rejected') && inRange(a.decisionDate || a.updatedAt, weekStart, weekEnd))
      .length;

    const leads = masters?.MasterLeads || [];
    const activeLeads = leads.filter((lead) => !isTerminalLead(lead));
    const overdueLeadFollowups = activeLeads
      .filter((lead) => (lead.nextFollowUpDate || lead.followUpDate) && (lead.nextFollowUpDate || lead.followUpDate) < todayStr)
      .sort((a, b) => (a.nextFollowUpDate || a.followUpDate || '').localeCompare(b.nextFollowUpDate || b.followUpDate || ''));
    const stuckLeads = activeLeads.filter((lead) => {
      const age = daysSince(lead.stageChangedAt || lead.statusChangedAt || lead.updatedAt || leadDate(lead));
      return age !== null && age > 14;
    });
    const newToday = leads.filter((lead) => inRange(leadDate(lead), startOfToday, endOfToday)).length;
    const newThisWeek = leads.filter((lead) => inRange(leadDate(lead), weekStart, weekEnd)).length;

    const openDealValues = activeLeads.map((lead) => ({ lead, value: leadBudget(lead) })).filter((x) => x.value !== null);
    const pipelineValue = openDealValues.reduce((sum, item) => sum + item.value, 0);
    const weightedForecast = openDealValues.reduce((sum, item) => sum + item.value * stageProbability(leadStatus(item.lead)), 0);
    const closingThisMonth = activeLeads.filter((lead) => inRange(lead.expectedCloseDate || lead.closeBy || lead.nextFollowUpDate, startOfToday, next30));
    const recentlyClosed = leads.filter((lead) => {
      const status = leadStatus(lead);
      if (!/won|lost/i.test(status)) return false;
      const closedDate = dateOf(lead.closedAt || lead.updatedAt || leadDate(lead));
      return !closedDate || closedDate >= last90;
    });
    const wonRecently = recentlyClosed.filter((lead) => /won/i.test(leadStatus(lead))).length;
    const winRate = recentlyClosed.length > 0 ? Math.round((wonRecently / recentlyClosed.length) * 100) : 0;

    return {
      finance: {
        overdueAmount: overdueMilestones.reduce((sum, m) => sum + m.balance, 0),
        overdueCount: overdueMilestones.length,
        overdueItems: overdueMilestones,
        overdueTop: overdueMilestones.slice(0, 3),
        dueSoonAmount: dueSoonMilestones.reduce((sum, m) => sum + m.balance, 0),
        dueSoonCount: dueSoonMilestones.length,
        dueSoonItems: dueSoonMilestones,
        doneWeek: collectionsThisWeek.reduce((sum, m) => sum + m.received, 0),
        doneWeekItems: collectionsThisWeek,
        doneMonth: collectionsThisMonth.reduce((sum, m) => sum + m.received, 0),
        doneMonthItems: collectionsThisMonth,
      },
      approvals: {
        overdueCount: overdueApprovals.length,
        overdueItems: overdueApprovals,
        overdueTop: overdueApprovals.slice(0, 3),
        weekCount: weekApprovals.length,
        weekItems: weekApprovals,
        monthCount: monthApprovals.length,
        monthItems: monthApprovals,
      },
      tasks: {
        overdueCount: overdueTasks.length,
        overdueItems: overdueTasks,
        overdueTop: overdueTasks.slice(0, 5),
      },
      leads: {
        overdueCount: overdueLeadFollowups.length,
        overdueItems: overdueLeadFollowups,
        overdueTop: overdueLeadFollowups.slice(0, 5),
        stuckCount: stuckLeads.length,
        stuckItems: stuckLeads,
        newToday,
        newThisWeek,
        newItems: leads.filter((lead) => inRange(leadDate(lead), weekStart, weekEnd)),
      },
      sales: {
        pipelineValue,
        weightedForecast,
        closingCount: closingThisMonth.length,
        winRate,
        dealCount: activeLeads.length,
        dealItems: activeLeads,
        closingItems: closingThisMonth,
      },
      team: {
        completedByPerson: Object.entries(completedByPerson).sort((a, b) => b[1] - a[1]).slice(0, 5),
        approvalsTurned,
        completedItems: completedThisWeek,
      },
    };
  }, [projects, masters, todayStr]);

  const openPulseDetail = (title, subtitle, rows, empty, kind, onOpenAll) => {
    setPulseDetail({ title, subtitle, rows: rows || [], empty, kind, onOpenAll });
  };

  return (
    <>
      <div className="flex-1 overflow-auto scrollbar-thin" style={{ background: 'var(--bone)' }}>
        <div className="px-4 sm:px-8 lg:px-12 py-8 lg:py-10 max-w-[1280px]">

          {/* Greeting */}
          <div className="mb-8 flex flex-col gap-4 lg:flex-row lg:items-end lg:justify-between">
            <div>
              <div className="text-[11px] uppercase tracking-[0.18em] ink-faint mb-2">{dayLabel} · Dashboard Pulse</div>
              <h1 className="text-[28px] sm:text-[34px] font-semibold ink leading-tight">
                Good morning, {userFirstName}.
              </h1>
              <p className="text-sm sm:text-base ink-soft mt-2 max-w-2xl">
                Cross-app pulse for money, decisions, tasks, leads, sales, and team capacity.
              </p>
            </div>
            <button
              onClick={onNewProject}
              className="self-start lg:self-auto inline-flex items-center gap-2 bg-ink text-white rounded-lg px-4 py-2 text-sm font-semibold hover:bg-terra"
            >
              <Plus className="w-4 h-4" /> New
            </button>
          </div>

          <div className="grid grid-cols-1 xl:grid-cols-2 gap-4">
            <DashboardPulseCard
              letter="A"
              icon={Coins}
              title="Finance"
              summary={`${fmtCompactINR(pulseData.finance.overdueAmount)} overdue · ${pulseData.finance.overdueCount} milestone${pulseData.finance.overdueCount === 1 ? '' : 's'}`}
              actionLabel="Open finance"
              onAction={onJumpToFinance}
              tone={pulseData.finance.overdueCount > 0 ? 'danger' : 'good'}
            >
              <div className="grid grid-cols-2 sm:grid-cols-4 gap-2 mb-4">
                <PulseMetric label="Overdues" value={fmtCompactINR(pulseData.finance.overdueAmount)} sub={`${pulseData.finance.overdueCount} flagged`} tone={pulseData.finance.overdueCount > 0 ? 'danger' : 'good'} onClick={() => openPulseDetail('Finance · Top overdues', 'Milestones with outstanding balance past due date.', pulseData.finance.overdueItems, 'No overdue milestones right now.', 'finance', onJumpToFinance)} />
                <PulseMetric label="Due soon" value={fmtCompactINR(pulseData.finance.dueSoonAmount)} sub="next 7 days" tone={pulseData.finance.dueSoonCount > 0 ? 'warn' : 'neutral'} onClick={() => openPulseDetail('Finance · Due soon', 'Collections expected in the next 7 days.', pulseData.finance.dueSoonItems, 'No collections due in the next 7 days.', 'finance', onJumpToFinance)} />
                <PulseMetric label="Done week" value={fmtCompactINR(pulseData.finance.doneWeek)} sub="collected" onClick={() => openPulseDetail('Finance · Done this week', 'Collections recorded this week.', pulseData.finance.doneWeekItems, 'No collections recorded this week.', 'finance', onJumpToFinance)} />
                <PulseMetric label="Done month" value={fmtCompactINR(pulseData.finance.doneMonth)} sub="collected" onClick={() => openPulseDetail('Finance · Done this month', 'Collections recorded this month.', pulseData.finance.doneMonthItems, 'No collections recorded this month.', 'finance', onJumpToFinance)} />
              </div>
              <PulseList empty="No overdue milestones right now.">
                {pulseData.finance.overdueTop.map((m, idx) => (
                  <PulseRow key={`${m.projectId}-${m.id || idx}`} label={m.name || 'Payment milestone'} meta={`${m.projectName} · due ${m.targetDate || '—'}`} value={fmtCompactINR(m.balance)} tone="danger" />
                ))}
              </PulseList>
            </DashboardPulseCard>

            <DashboardPulseCard
              letter="B"
              icon={FileCheck2}
              title="Decisions Waiting"
              summary={`${pulseData.approvals.overdueCount} overdue · ${pulseData.approvals.weekCount} due this week`}
              actionLabel="Open approvals"
              onAction={onJumpToApprovals}
              tone={pulseData.approvals.overdueCount > 0 ? 'danger' : 'neutral'}
            >
              <div className="grid grid-cols-3 gap-2 mb-4">
                <PulseMetric label="Overdue" value={pulseData.approvals.overdueCount} sub="waiting" tone={pulseData.approvals.overdueCount > 0 ? 'danger' : 'good'} onClick={() => openPulseDetail('Approvals · Overdue', 'Pending decisions past their due date.', pulseData.approvals.overdueItems, 'No overdue approvals.', 'approval', onJumpToApprovals)} />
                <PulseMetric label="This week" value={pulseData.approvals.weekCount} sub="due soon" onClick={() => openPulseDetail('Approvals · Due this week', 'Pending decisions due this week.', pulseData.approvals.weekItems, 'No approvals due this week.', 'approval', onJumpToApprovals)} />
                <PulseMetric label="This month" value={pulseData.approvals.monthCount} sub="pending" onClick={() => openPulseDetail('Approvals · Due this month', 'Pending decisions due this month.', pulseData.approvals.monthItems, 'No approvals due this month.', 'approval', onJumpToApprovals)} />
              </div>
              <PulseList empty="No overdue approvals.">
                {pulseData.approvals.overdueTop.map((a, idx) => (
                  <PulseRow key={`${a.projectId}-${a.id || idx}`} label={a.title || 'Approval'} meta={`${a.projectName} · ${a.requestedFrom || 'Decision pending'}`} value={a.dueDate || '—'} tone="danger" />
                ))}
              </PulseList>
            </DashboardPulseCard>

            <DashboardPulseCard
              letter="C"
              icon={CheckSquare}
              title="Tasks Slipping"
              summary={`${pulseData.tasks.overdueCount} overdue tasks`}
              actionLabel="Open tasks"
              onAction={onJumpToTasks}
              tone={pulseData.tasks.overdueCount > 0 ? 'danger' : 'good'}
            >
              <div className="grid grid-cols-2 gap-2 mb-4">
                <PulseMetric label="Overdue tasks" value={pulseData.tasks.overdueCount} sub="top 5 below" tone={pulseData.tasks.overdueCount > 0 ? 'danger' : 'good'} onClick={() => openPulseDetail('Tasks · Slipping', 'Open tasks past due date.', pulseData.tasks.overdueItems, 'No overdue tasks across projects.', 'task', onJumpToTasks)} />
                <PulseMetric label="No activity" value="Future" sub="ready later" />
              </div>
              <PulseList empty="No overdue tasks across projects.">
                {pulseData.tasks.overdueTop.map((t, idx) => (
                  <PulseRow key={`${t.projectId}-${t.id || idx}`} label={t.title || t.value || 'Task'} meta={`${t.projectName} · ${t.assigneeName || t.assignee || 'Unassigned'}`} value={t.dueDate || '—'} tone="danger" />
                ))}
              </PulseList>
            </DashboardPulseCard>

            <DashboardPulseCard
              letter="D"
              icon={UserPlus}
              title="Leads Need Attention"
              summary={`${pulseData.leads.overdueCount} follow-ups overdue · ${pulseData.leads.newThisWeek} new this week`}
              actionLabel="Open leads"
              onAction={onJumpToLeads}
              tone={pulseData.leads.overdueCount > 0 ? 'danger' : 'neutral'}
            >
              <div className="grid grid-cols-3 gap-2 mb-4">
                <PulseMetric label="Follow-ups" value={pulseData.leads.overdueCount} sub="overdue" tone={pulseData.leads.overdueCount > 0 ? 'danger' : 'good'} onClick={() => openPulseDetail('Leads · Follow-ups overdue', 'Active leads whose follow-up date has passed.', pulseData.leads.overdueItems, 'No overdue lead follow-ups.', 'lead', onJumpToLeads)} />
                <PulseMetric label="Stage too long" value={pulseData.leads.stuckCount} sub="over 14 days" tone={pulseData.leads.stuckCount > 0 ? 'warn' : 'neutral'} onClick={() => openPulseDetail('Leads · Stage too long', 'Active leads not updated for more than 14 days.', pulseData.leads.stuckItems, 'No leads stuck over 14 days.', 'lead', onJumpToLeads)} />
                <PulseMetric label="New" value={pulseData.leads.newThisWeek} sub={`${pulseData.leads.newToday} today`} onClick={() => openPulseDetail('Leads · New this week', 'Fresh leads captured this week.', pulseData.leads.newItems, 'No new leads this week.', 'lead', onJumpToLeads)} />
              </div>
              <PulseList empty="No overdue lead follow-ups.">
                {pulseData.leads.overdueTop.map((l, idx) => (
                  <PulseRow key={l.id || idx} label={l.name || l.clientName || 'Lead'} meta={`${l.city || '—'} · ${l.specificSource || l.sourceCategory || 'source pending'}`} value={l.nextFollowUpDate || l.followUpDate || '—'} tone="danger" />
                ))}
              </PulseList>
            </DashboardPulseCard>

            <DashboardPulseCard
              letter="E"
              icon={Briefcase}
              title="Sales in Pipeline"
              summary={`${formatRupees(pulseData.sales.pipelineValue)} open · ${pulseData.sales.closingCount} closing soon`}
              actionLabel="Open sales"
              onAction={onJumpToSales}
              tone="neutral"
            >
              <div className="grid grid-cols-2 sm:grid-cols-4 gap-2">
                <PulseMetric label="Pipeline" value={formatRupees(pulseData.sales.pipelineValue)} sub={`${pulseData.sales.dealCount} open`} onClick={() => openPulseDetail('Sales · Pipeline', 'Open deals currently in the sales process.', pulseData.sales.dealItems, 'No open deals in pipeline.', 'lead', onJumpToSales)} />
                <PulseMetric label="Weighted" value={formatRupees(pulseData.sales.weightedForecast)} sub="forecast" />
                <PulseMetric label="Closing" value={pulseData.sales.closingCount} sub="next 30 days" onClick={() => openPulseDetail('Sales · Closing soon', 'Deals expected to close in the next 30 days.', pulseData.sales.closingItems, 'No deals closing in the next 30 days.', 'lead', onJumpToSales)} />
                <PulseMetric label="Win rate" value={`${pulseData.sales.winRate}%`} sub="last 90 days" />
              </div>
            </DashboardPulseCard>

            <DashboardPulseCard
              letter="F"
              icon={Users}
              title="Team Performance"
              summary={`${pulseData.team.completedByPerson.reduce((sum, item) => sum + item[1], 0)} tasks done this week · ${pulseData.team.approvalsTurned} approvals turned`}
              actionLabel="Open studio"
              onAction={onJumpToStudio}
              tone="neutral"
            >
              <div className="grid grid-cols-2 gap-2 mb-4">
                <PulseMetric label="Tasks completed" value={pulseData.team.completedByPerson.reduce((sum, item) => sum + item[1], 0)} sub="this week" onClick={() => openPulseDetail('Team · Tasks completed', 'Completed tasks grouped from this week.', pulseData.team.completedItems, 'No completed tasks recorded this week.', 'task', onJumpToStudio)} />
                <PulseMetric label="Approvals turned" value={pulseData.team.approvalsTurned} sub="this week" />
              </div>
              <PulseList empty="No completed tasks recorded this week.">
                {pulseData.team.completedByPerson.map(([name, count]) => (
                  <PulseRow key={name} label={name} meta="completed this week" value={count} tone="good" />
                ))}
              </PulseList>
            </DashboardPulseCard>
          </div>

          <div className="mt-6 bg-paper border border-line rounded-xl overflow-hidden">
            <div className="px-5 py-4 border-b border-line-soft flex items-center justify-between gap-3">
              <div>
                <div className="text-sm font-semibold ink">Projects Needing Review</div>
                <div className="text-xs ink-faint mt-0.5">Worst overdue projects stay visible below the pulse.</div>
              </div>
              <button onClick={() => onJumpToStudio && onJumpToStudio()} className="text-xs ink-soft hover:text-terra inline-flex items-center gap-1">
                Studio hub <ArrowRight className="w-3 h-3" />
              </button>
            </div>
            {sortedProjects.map((p) => (
              <CalmProjectRow
                key={p.id}
                project={p}
                onClick={() => onOpenProject(p.id)}
                todayStr={todayStr}
              />
            ))}
          </div>

          {isAdminTier && onResetDemoProjects && (
            <div className="flex items-center justify-end mt-6">
              <button
                onClick={() => setShowResetConfirm(true)}
                className="text-[11px] ink-faint hover:ink-soft flex items-center gap-1.5"
                title="Reset 5 demo projects to baseline state"
              >
                <RotateCcw className="w-3 h-3" /> Reset demo data
              </button>
            </div>
          )}

          {showResetConfirm && (
            <div className="fixed inset-0 z-50 flex items-center justify-center p-6" style={{ background: 'rgba(0,0,0,0.4)' }}>
              <div className="bg-paper rounded-2xl shadow-xl max-w-md w-full p-6">
                <div className="flex items-center gap-2 mb-3">
                  <RotateCcw className="w-5 h-5 text-terra" />
                  <h3 className="text-base font-semibold ink">Reset demo data?</h3>
                </div>
                <p className="text-[13px] ink-soft mb-4 leading-relaxed">
                  This will restore <strong className="ink">Khanna Penthouse</strong>, <strong className="ink">Sharma Residence</strong>, <strong className="ink">Marwah Residence</strong>, <strong className="ink">Kavi Coffee</strong>, and <strong className="ink">Hiranandani Estate</strong> to their baseline state.
                </p>
                <div className="bg-bone border border-line-soft rounded-lg p-3 mb-4 text-[12px] ink-soft space-y-1">
                  <div>• Edits to these 5 projects will be lost</div>
                  <div>• Other projects stay untouched</div>
                </div>
                <div className="flex items-center justify-end gap-2">
                  <button
                    onClick={() => setShowResetConfirm(false)}
                    className="text-[12px] ink-soft hover:ink px-3 py-1.5 border border-line rounded-md hover:bg-bone"
                  >
                    Cancel
                  </button>
                  <button
                    onClick={() => {
                      onResetDemoProjects();
                      setShowResetConfirm(false);
                    }}
                    className="text-[12px] text-white bg-terra hover:bg-ink px-3 py-1.5 rounded-md flex items-center gap-1"
                  >
                    <RotateCcw className="w-3 h-3" /> Reset 5 projects
                  </button>
                </div>
              </div>
            </div>
          )}

          {pulseDetail && (
            <DashboardPulseDetailDrawer
              detail={pulseDetail}
              onClose={() => setPulseDetail(null)}
              onOpenProject={onOpenProject}
            />
          )}

        </div>
      </div>
    </>
  );
}

function DashboardPulseCard({ letter, icon: Icon, title, summary, children, actionLabel, onAction, tone = 'neutral' }) {
  const toneClass = tone === 'danger'
    ? 'border-terra'
    : tone === 'good'
      ? 'border-moss'
      : 'border-line';
  return (
    <section className={`bg-paper border ${toneClass} rounded-xl overflow-hidden`}>
      <div className="px-5 py-4 border-b border-line-soft flex items-start justify-between gap-4">
        <div className="flex items-start gap-3 min-w-0">
          <div className="w-9 h-9 rounded-lg bg-bone border border-line-soft flex items-center justify-center shrink-0">
            <Icon className="w-4 h-4 text-terra" />
          </div>
          <div className="min-w-0">
            <div className="text-[11px] uppercase tracking-[0.18em] ink-faint">Pulse {letter}</div>
            <h2 className="text-lg font-semibold ink leading-tight mt-0.5">{title}</h2>
            <p className="text-xs ink-soft mt-1">{summary}</p>
          </div>
        </div>
        {onAction && (
          <button onClick={onAction} className="text-[11px] ink-soft hover:text-terra inline-flex items-center gap-1 whitespace-nowrap">
            {actionLabel} <ArrowRight className="w-3 h-3" />
          </button>
        )}
      </div>
      <div className="p-5">{children}</div>
    </section>
  );
}

function PulseMetric({ label, value, sub, tone = 'neutral', onClick }) {
  const valueClass = tone === 'danger' ? 'text-terra' : tone === 'good' ? 'text-moss' : 'ink';
  const Tag = onClick ? 'button' : 'div';
  return (
    <Tag onClick={onClick} className={`bg-bone border border-line-soft rounded-lg px-3 py-3 min-w-0 text-left ${onClick ? 'hover:border-terra hover:bg-paper transition-colors cursor-pointer' : ''}`}>
      <div className="text-[10px] uppercase tracking-[0.14em] ink-faint truncate">{label}</div>
      <div className={`text-base sm:text-lg font-semibold mt-1 truncate ${valueClass}`}>{value}</div>
      <div className="text-[11px] ink-faint mt-0.5 truncate">{sub}</div>
    </Tag>
  );
}

function PulseList({ children, empty }) {
  const items = React.Children.toArray(children).filter(Boolean);
  if (items.length === 0) {
    return <div className="text-xs ink-faint bg-bone border border-line-soft rounded-lg px-3 py-3">{empty}</div>;
  }
  return <div className="border border-line-soft rounded-lg divide-y divide-[var(--line-soft)] overflow-hidden">{items}</div>;
}

function PulseRow({ label, meta, value, tone = 'neutral' }) {
  const valueClass = tone === 'danger' ? 'text-terra' : tone === 'good' ? 'text-moss' : 'ink-soft';
  return (
    <div className="px-3 py-2.5 flex items-center justify-between gap-3 bg-paper">
      <div className="min-w-0">
        <div className="text-sm font-medium ink truncate">{label}</div>
        <div className="text-[11px] ink-faint truncate mt-0.5">{meta}</div>
      </div>
      <div className={`text-xs font-semibold whitespace-nowrap ${valueClass}`}>{value}</div>
    </div>
  );
}

function DashboardPulseDetailDrawer({ detail, onClose, onOpenProject }) {
  const rows = detail.rows || [];
  const rowLabel = (row) => row.title || row.name || row.value || row.clientName || row.projectName || 'Untitled';
  const rowMeta = (row) => {
    if (detail.kind === 'finance') return `${row.projectName || 'Project'} · ${row.clientName || 'Client'} · due ${row.targetDate || row.dueDate || '—'}`;
    if (detail.kind === 'approval') return `${row.projectName || 'Project'} · ${row.requestedFrom || 'Decision pending'} · due ${row.dueDate || '—'}`;
    if (detail.kind === 'task') return `${row.projectName || 'Project'} · ${row.assigneeName || row.assignee || 'Unassigned'} · due ${row.dueDate || '—'}`;
    if (detail.kind === 'lead') return `${row.city || '—'} · ${row.status || 'Lead'} · ${row.specificSource || row.sourceCategory || 'source pending'}`;
    return row.projectName || '';
  };
  const rowValue = (row) => {
    if (detail.kind === 'finance') return fmtCompactINR(row.balance ?? row.received ?? row.due ?? 0);
    if (detail.kind === 'approval') return row.dueDate || row.status || 'pending';
    if (detail.kind === 'task') return row.status || 'open';
    if (detail.kind === 'lead') return row.nextFollowUpDate || row.expectedCloseDate || row.enquiryDate || '—';
    return '';
  };

  return (
    <div className="fixed inset-0 z-50 flex justify-end" style={{ background: 'rgba(42,31,21,0.28)' }}>
      <button className="flex-1" onClick={onClose} aria-label="Close pulse detail" />
      <aside className="w-full max-w-[560px] bg-paper border-l border-line shadow-2xl h-full overflow-auto">
        <div className="sticky top-0 bg-paper border-b border-line px-6 py-5 flex items-start justify-between gap-4">
          <div>
            <div className="text-[11px] uppercase tracking-[0.18em] ink-faint">Dashboard drill-down</div>
            <h3 className="text-xl font-semibold ink mt-1">{detail.title}</h3>
            <p className="text-sm ink-soft mt-1">{detail.subtitle}</p>
          </div>
          <button onClick={onClose} className="w-9 h-9 rounded-lg border border-line hover:bg-bone flex items-center justify-center">
            <X className="w-4 h-4" />
          </button>
        </div>
        <div className="p-6">
          <div className="flex items-center justify-between mb-4">
            <div className="text-xs uppercase tracking-[0.16em] ink-faint">{rows.length} record{rows.length === 1 ? '' : 's'}</div>
            {detail.onOpenAll && (
              <button onClick={detail.onOpenAll} className="text-xs text-terra hover:underline inline-flex items-center gap-1">
                Open module <ArrowRight className="w-3 h-3" />
              </button>
            )}
          </div>
          {rows.length === 0 ? (
            <div className="bg-bone border border-line rounded-xl p-5 text-sm ink-soft">{detail.empty}</div>
          ) : (
            <div className="border border-line rounded-xl overflow-hidden divide-y divide-[var(--line-soft)]">
              {rows.map((row, idx) => (
                <div key={row.id || `${detail.title}-${idx}`} className="p-4 bg-paper">
                  <div className="flex items-start justify-between gap-4">
                    <div className="min-w-0">
                      <div className="text-sm font-semibold ink truncate">{rowLabel(row)}</div>
                      <div className="text-xs ink-faint mt-1 leading-relaxed">{rowMeta(row)}</div>
                    </div>
                    <div className="text-xs font-semibold text-terra whitespace-nowrap">{rowValue(row)}</div>
                  </div>
                  {row.projectId && onOpenProject && (
                    <button onClick={() => onOpenProject(row.projectId)} className="mt-3 text-[11px] ink-soft hover:text-terra inline-flex items-center gap-1">
                      Open project <ArrowRight className="w-3 h-3" />
                    </button>
                  )}
                </div>
              ))}
            </div>
          )}
        </div>
      </aside>
    </div>
  );
}

/* ===== Phase 9.1 Part 2 — AttentionZone (one of three on the new dashboard) ===== */
function AttentionZone({ count, countTone, label, detail, onClick }) {
  /* Phase 9.1 Part 2.1 — Strict alignment.
     All three cards must visually align: number row at top, label
     under it, hairline divider at exactly the same Y across all cards,
     detail flowing below. Achieved with a CSS grid template that
     reserves fixed rows for the header zone, then a divider, then
     content fills the rest. minHeight ensures shorter cards still
     reach the same baseline as the longest. */
  const countColor = countTone === 'terra' ? 'text-terra' : 'ink';
  return (
    <button
      onClick={onClick}
      className="bg-paper border border-line rounded-2xl p-6 text-left hover:border-line-deep transition-colors"
      style={{
        minHeight: '200px',
        display: 'grid',
        gridTemplateRows: '34px 24px 1px 1fr',
        rowGap: '14px',
      }}
    >
      {/* Row 1: Number + arrow */}
      <div className="flex items-center justify-between" style={{ height: '34px' }}>
        <span className={`text-[28px] font-semibold leading-none tracking-tight ${countColor}`}>{count}</span>
        <span className="text-xs ink-faint">→</span>
      </div>

      {/* Row 2: Label */}
      <div className="text-sm ink-soft" style={{ height: '24px', lineHeight: '24px' }}>{label}</div>

      {/* Row 3: Divider — pixel-perfect aligned across all cards */}
      <div style={{ height: '1px', background: 'var(--line-soft)' }} />

      {/* Row 4: Detail — fills remaining space */}
      <div className="text-xs ink-soft leading-relaxed">
        {detail}
      </div>
    </button>
  );
}

/* ===== Phase 9.1 Part 2 — CalmProjectRow (quiet table row replacing project cards) ===== */
function CalmProjectRow({ project, onClick, todayStr }) {
  const f = computeProjectFinancials(project, todayStr);
  let statusLabel, statusClass;
  if (f.overdueCount > 0) {
    statusLabel = `🚩 ${f.overdueCount} overdue`;
    statusClass = 'bg-terra-soft text-terra';
  } else if (f.partialCount > 0 || f.dueSoonCount > 0) {
    statusLabel = 'watch';
    statusClass = 'ink-faint';
  } else {
    statusLabel = 'on track';
    statusClass = 'bg-moss-soft text-moss';
  }
  const isPlainText = statusLabel === 'watch';

  return (
    <button
      onClick={onClick}
      className="w-full grid items-center gap-5 px-6 py-4 hover:bg-bone text-left"
      style={{
        gridTemplateColumns: '1fr 200px 110px 32px',
        borderBottom: '1px solid var(--line-soft)',
      }}
    >
      <div className="min-w-0">
        <div className="text-sm font-medium ink truncate">{project.name}</div>
        <div className="text-xs ink-faint truncate mt-0.5">{project.client}{project.city && project.city !== '—' ? ` · ${project.city}` : ''}</div>
      </div>
      <div>
        <div className="text-[13px] ink truncate">{project.currentStage || '—'}</div>
        <div className="text-[11px] ink-faint mt-0.5">{project.progress || 0}% complete</div>
      </div>
      <div>
        {isPlainText ? (
          <span className={`text-[11px] ${statusClass}`}>{statusLabel}</span>
        ) : (
          <span className={`text-[11px] font-medium ${statusClass} px-2.5 py-1 rounded-full`}>{statusLabel}</span>
        )}
      </div>
      <div className="w-6 h-6 rounded-md bg-bone ink-faint flex items-center justify-center text-base font-normal">+</div>
    </button>
  );
}

function GridView({ projects, onNewProject, onOpenProject, onDeleteProject, currentRoleCode }) {
  return (
    <div className="p-6 grid-paper" style={{ minHeight: '100%' }}>
      <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 gap-4">
        {projects.map((p) => <ProjectCard key={p.id} project={p} onClick={() => onOpenProject(p.id)} onDelete={onDeleteProject} currentRoleCode={currentRoleCode} />)}
        <NewProjectCard onClick={onNewProject} />
      </div>
    </div>
  );
}

/* ============================================================================
   ===== Phase 9.0.21 — Financial Health helpers ==============================
   ============================================================================
   Shared helpers used by ProjectCard strip, Dashboard FinancialHealthSection,
   and ClientHealthTable. All amounts in ₹.
   ============================================================================ */

/* Compute a single milestone's amount due, respecting manual override + legacy fallback */
function computeMilestoneAmount(m, totalProjectValue) {
  const tpv = parseFloat(totalProjectValue) || 0;
  const hasAmount = m.amount !== undefined && m.amount !== '' && m.amount !== null;
  const explicitOverride = m.amountManualOverride === true;
  /* If user explicitly set manual override OR legacy data has amount but no TPV: use stored amount */
  if (explicitOverride && hasAmount) return parseFloat(m.amount) || 0;
  if (!explicitOverride && hasAmount && tpv === 0) return parseFloat(m.amount) || 0;
  const pct = parseFloat(m.percentage) || 0;
  return tpv * pct / 100;
}

/* Roll a project's milestones up into financial summary numbers */
function computeProjectFinancials(project, todayStr) {
  const w = project._wizard || {};
  const milestones = w.paymentTerms || [];
  const tpv = parseFloat(w.totalProjectValue) || 0;
  let totalDue = 0, totalReceived = 0, overdueCount = 0, lateReceiptCount = 0;
  let overdueAmount = 0, dueSoonCount = 0, dueSoonAmount = 0, partialCount = 0;
  let nextDue = null;
  let avgDelayDays = 0, delaySamples = 0;

  milestones.forEach((m) => {
    const due = computeMilestoneAmount(m, tpv);
    const recv = parseFloat(m.amountReceived) || 0;
    totalDue += due;
    totalReceived += recv;
    const fullyPaid = due > 0 && recv >= due;
    const partiallyPaid = recv > 0 && recv < due;
    if (partiallyPaid) partialCount++;
    if (m.targetDate && m.targetDate < todayStr && !fullyPaid) {
      overdueCount++;
      overdueAmount += (due - recv);
    }
    if (m.targetDate && m.targetDate >= todayStr && !fullyPaid) {
      const targetTs = new Date(m.targetDate).getTime();
      const todayTs = new Date(todayStr).getTime();
      const days = Math.floor((targetTs - todayTs) / (1000 * 60 * 60 * 24));
      if (days <= 7) {
        dueSoonCount++;
        dueSoonAmount += (due - recv);
      }
      if (!nextDue || (m.targetDate < (nextDue.targetDate || '9999'))) {
        nextDue = m;
      }
    }
    if (m.receiptDate && m.targetDate) {
      const days = Math.floor((new Date(m.receiptDate).getTime() - new Date(m.targetDate).getTime()) / (1000 * 60 * 60 * 24));
      if (days > 7) lateReceiptCount++;
      avgDelayDays += days;
      delaySamples++;
    }
  });

  const totalFee = parseFloat(w.totalProjectValue) || totalDue;
  const billedPct = totalFee > 0 ? Math.round((totalDue / totalFee) * 100) : 0;
  const recvPct = totalDue > 0 ? Math.round((totalReceived / totalDue) * 100) : 0;
  const outstanding = totalDue - totalReceived;
  const avgDelay = delaySamples > 0 ? avgDelayDays / delaySamples : 0;

  /* Project-level health */
  let health = 'grey';
  if (milestones.length > 0) {
    if (overdueCount > 0 || lateReceiptCount > 0) health = 'red';
    else if (partialCount > 0 || dueSoonCount > 0) health = 'yellow';
    else health = 'green';
  }

  return {
    milestoneCount: milestones.length,
    totalFee, totalDue, totalReceived, outstanding,
    billedPct, recvPct,
    overdueCount, overdueAmount,
    dueSoonCount, dueSoonAmount,
    partialCount, lateReceiptCount,
    nextDue, avgDelay, health,
  };
}

/* Roll a SINGLE client's projects into client-level health */
function computeClientFinancials(clientId, projects, masters, todayStr) {
  const projectsForClient = projects.filter((p) => {
    const cid = p._wizard?.primaryClientId;
    return cid === clientId;
  });
  const masterClient = (masters?.MasterClients || []).find((c) => c.id === clientId);
  if (projectsForClient.length === 0) return null;

  let totalFee = 0, totalDue = 0, totalReceived = 0, outstanding = 0;
  let overdueCount = 0, lateReceiptCount = 0, dueSoonCount = 0, partialCount = 0;
  let avgDelaySum = 0, delayProjects = 0;
  let nextDueDate = null;

  projectsForClient.forEach((p) => {
    const f = computeProjectFinancials(p, todayStr);
    totalFee += f.totalFee;
    totalDue += f.totalDue;
    totalReceived += f.totalReceived;
    outstanding += f.outstanding;
    overdueCount += f.overdueCount;
    lateReceiptCount += f.lateReceiptCount;
    dueSoonCount += f.dueSoonCount;
    partialCount += f.partialCount;
    if (f.avgDelay !== 0) {
      avgDelaySum += f.avgDelay;
      delayProjects++;
    }
    if (f.nextDue && f.nextDue.targetDate) {
      if (!nextDueDate || f.nextDue.targetDate < nextDueDate) {
        nextDueDate = f.nextDue.targetDate;
      }
    }
  });

  const avgDelay = delayProjects > 0 ? avgDelaySum / delayProjects : 0;
  const recvPct = totalDue > 0 ? Math.round((totalReceived / totalDue) * 100) : 0;

  /* Client health: take the worst across all their projects */
  let health = 'green';
  if (overdueCount > 0 || lateReceiptCount > 0) health = 'red';
  else if (partialCount > 0 || dueSoonCount > 0) health = 'yellow';

  /* Severity score for sorting (higher = worse) */
  const severityScore =
    overdueCount * 1000
    + lateReceiptCount * 500
    + Math.max(0, avgDelay) * 5
    + (outstanding / 100000); /* ₹100K = 1 point */

  return {
    clientId,
    clientName: masterClient?.value || 'Unknown client',
    projectCount: projectsForClient.length,
    projects: projectsForClient,
    totalFee, totalDue, totalReceived, outstanding,
    recvPct,
    overdueCount, lateReceiptCount, dueSoonCount, partialCount,
    avgDelay,
    nextDueDate,
    health,
    severityScore,
  };
}

/* Roll up totals across ALL projects for the global Totals strip */
function computePortfolioTotals(projects, masters, todayStr) {
  let totalOutstanding = 0;
  let totalReceivedYTD = 0;
  let totalOverdueAmount = 0;
  let totalOverdueCount = 0;
  const clientIdsSeen = new Set();
  const fyStart = todayStr.slice(0, 4) + '-04-01'; /* IN financial year starts Apr 1 */
  const todayYear = parseInt(todayStr.slice(0, 4), 10);
  const todayMonth = parseInt(todayStr.slice(5, 7), 10);
  const fyStartDate = todayMonth >= 4 ? `${todayYear}-04-01` : `${todayYear - 1}-04-01`;

  projects.forEach((p) => {
    const f = computeProjectFinancials(p, todayStr);
    totalOutstanding += f.outstanding;
    totalOverdueAmount += f.overdueAmount;
    totalOverdueCount += f.overdueCount;
    const cid = p._wizard?.primaryClientId;
    if (cid) clientIdsSeen.add(cid);

    /* Received within current FY */
    (p._wizard?.paymentTerms || []).forEach((m) => {
      const recv = parseFloat(m.amountReceived) || 0;
      if (recv > 0 && m.receiptDate && m.receiptDate >= fyStartDate) {
        totalReceivedYTD += recv;
      }
    });
  });

  return {
    totalOutstanding,
    totalReceivedYTD,
    totalOverdueAmount,
    totalOverdueCount,
    activeClientCount: clientIdsSeen.size,
    fyLabel: `FY ${fyStartDate.slice(0, 4)}–${(parseInt(fyStartDate.slice(0, 4), 10) + 1).toString().slice(2)}`,
  };
}

function getAmountDisplayUnit() {
  return studioAmountDisplayUnit === 'crores' ? 'crores' : 'lakhs';
}

function formatLacsValue(value) {
  const numeric = Number(value) || 0;
  const fixed = numeric.toFixed(2);
  return numeric >= 0 && numeric < 10 ? fixed.padStart(5, '0') : fixed;
}

/* Format ₹ using the studio-wide Settings preference: Auto / Lakhs / Crores. */
function fmtCompactINR(n) {
  if (n === undefined || n === null || isNaN(n)) return '₹00.00 Lacs';
  const abs = Math.abs(n);
  const sign = n < 0 ? '-' : '';
  const unit = getAmountDisplayUnit();
  if (unit === 'lakhs') {
    const value = abs / 100000;
    return `${sign}₹${formatLacsValue(value)} Lacs`;
  }
  if (unit === 'crores') {
    const value = abs / 10000000;
    return `${sign}₹${value >= 10 ? value.toFixed(1) : value.toFixed(2)} Cr`;
  }
  if (abs >= 10000000) return `${sign}₹${(abs / 10000000).toFixed(2)}Cr`;
  if (abs >= 100000) return `${sign}₹${(abs / 100000).toFixed(1)}L`;
  if (abs >= 1000) return `${sign}₹${Math.round(abs / 1000)}K`;
  return `${sign}₹${Math.round(abs).toLocaleString('en-IN')}`;
}

function ProjectCard({ project: p, onClick, onDelete, currentRoleCode }) {
  const [menuOpen, setMenuOpen] = useState(false);
  const [confirmingDelete, setConfirmingDelete] = useState(false);
  const isAdmin = currentRoleCode === 'studio_owner' || currentRoleCode === 'admin' || currentRoleCode === 'super_admin';

  return (
    <>
    <div onClick={onClick} className="bg-paper border border-line rounded-lg p-5 hover:border-ink cursor-pointer group relative overflow-hidden">
      <div className="absolute left-0 top-0 bottom-0 w-1" style={{ background: p.accent }} />
      <div className="flex items-start justify-between mb-3">
        <div className="min-w-0 flex-1 pr-3">
          <div className="flex items-center gap-2 mb-1.5">
            <span className="text-[10px] font-mono ink-faint tracking-wider">{p.id}</span>
            <span className="ink-faint">·</span>
            <Tag tone="bone">{p.category}</Tag>
          </div>
          <h3 className="font-display text-lg ink tracking-tight leading-tight">{p.name}</h3>
          <div className="text-[11px] ink-soft mt-1">{p.client}</div>
        </div>
        <div className="relative">
          <button
            onClick={(e) => { e.stopPropagation(); setMenuOpen(!menuOpen); }}
            className="p-1 hover:bg-bone rounded opacity-0 group-hover:opacity-100"
          >
            <MoreHorizontal className="w-4 h-4 ink-soft" />
          </button>
          {menuOpen && (
            <>
              {/* Click-outside catcher */}
              <div className="fixed inset-0 z-10" onClick={(e) => { e.stopPropagation(); setMenuOpen(false); }} />
              <div className="absolute right-0 top-7 z-20 bg-paper border border-line rounded-md shadow-lg w-44 py-1 fade-in">
                {isAdmin && onDelete ? (
                  <button
                    onClick={(e) => { e.stopPropagation(); setMenuOpen(false); setConfirmingDelete(true); }}
                    className="w-full text-left px-3 py-1.5 text-xs text-terra hover:bg-terra-soft flex items-center gap-2"
                  >
                    <Trash2 className="w-3 h-3" /> Delete project…
                  </button>
                ) : (
                  <div className="px-3 py-1.5 text-[11px] ink-faint italic">
                    Admin only — switch role to delete
                  </div>
                )}
              </div>
            </>
          )}
        </div>
      </div>
      <div className="flex items-center gap-3 mb-3 text-[11px] ink-soft">
        <div className="flex items-center gap-1"><Building2 className="w-3 h-3" /><span>{p.propertyType}</span></div>
        <span>·</span>
        <div className="flex items-center gap-1"><MapPin className="w-3 h-3" /><span>{p.city}, {p.state}</span></div>
      </div>
      <div className="space-y-1.5 mb-4 text-[11px]">
        <div className="flex items-start gap-2">
          <span className="ink-faint font-mono uppercase tracking-wider text-[9px] mt-0.5 shrink-0 w-14">Site</span>
          <span className="ink-soft leading-snug">{p.siteCondition}</span>
        </div>
        <div className="flex items-start gap-2">
          <span className="ink-faint font-mono uppercase tracking-wider text-[9px] mt-0.5 shrink-0 w-14">Service</span>
          <span className="ink-soft leading-snug">{p.serviceType}</span>
        </div>
      </div>
      <div className="mb-4">
        <div className="flex items-center justify-between mb-1.5">
          <div className="flex items-center gap-1.5">
            <StatusDot status={p.status} />
            <span className="text-xs font-medium ink">{p.currentStage}</span>
          </div>
          <span className="text-[11px] font-mono ink-soft">{computeProjectProgress(p)}%</span>
        </div>
        <div className="h-1 bg-line rounded-full overflow-hidden">
          <div className="h-full" style={{ width: `${computeProjectProgress(p)}%`, background: p.accent }} />
        </div>
      </div>
      {/* Phase 9.0.19 — Mini payment summary on project card.
          Renders ONLY if the project has milestones AND a totalProjectValue (or computable amounts).
          Keeps card compact: one row of stats + a "next due" line + overdue flag. */}
      {(() => {
        const milestones = p._wizard?.paymentTerms || [];
        if (milestones.length === 0) return null;
        const totalProjectValue = parseFloat(p._wizard?.totalProjectValue) || 0;
        const today = new Date().toISOString().slice(0, 10);
        const computeAmt = (m) => {
          if (m.amountManualOverride && m.amount) return parseFloat(m.amount) || 0;
          if (!m.amountManualOverride && m.amount && !totalProjectValue) return parseFloat(m.amount) || 0; /* legacy fallback */
          const pct = parseFloat(m.percentage) || 0;
          return totalProjectValue * pct / 100;
        };
        const totalFee = totalProjectValue || milestones.reduce((s, m) => s + computeAmt(m), 0);
        const totalRecv = milestones.reduce((s, m) => s + (parseFloat(m.amountReceived) || 0), 0);
        const totalDue = milestones.reduce((s, m) => s + computeAmt(m), 0);
        const outstanding = totalDue - totalRecv;
        const billedPct = totalFee > 0 ? Math.round((totalDue / totalFee) * 100) : 0;
        const overdueCount = milestones.filter((m) => {
          const due = computeAmt(m);
          const recv = parseFloat(m.amountReceived) || 0;
          return m.targetDate && m.targetDate < today && recv < due;
        }).length;
        const upcoming = milestones
          .filter((m) => {
            const due = computeAmt(m);
            const recv = parseFloat(m.amountReceived) || 0;
            return m.targetDate && m.targetDate >= today && recv < due;
          })
          .sort((a, b) => (a.targetDate || '').localeCompare(b.targetDate || ''));
        const nextDue = upcoming[0];
        const fmtL = (n) => n >= 100000 ? `₹${(n / 100000).toFixed(1)}L` : `₹${Math.round(n).toLocaleString('en-IN')}`;
        /* Phase 9.0.20 — Project-level health dot at start of strip.
           RED if any overdue OR any late-paid milestone; YELLOW if any partial or due-soon;
           GREEN if all healthy; GREY if nothing to assess. */
        let projHealth = 'grey';
        const hasPartial = milestones.some((m) => {
          const d = computeAmt(m); const r = parseFloat(m.amountReceived) || 0;
          return r > 0 && r < d;
        });
        const hasLatePaid = milestones.some((m) => {
          if (!m.receiptDate || !m.targetDate) return false;
          const days = Math.floor((new Date(m.receiptDate).getTime() - new Date(m.targetDate).getTime()) / (1000 * 60 * 60 * 24));
          return days > 7;
        });
        const hasDueSoon = milestones.some((m) => {
          if (!m.targetDate) return false;
          const d = computeAmt(m); const r = parseFloat(m.amountReceived) || 0;
          if (r >= d) return false;
          if (m.targetDate < today) return false;
          const days = Math.floor((new Date(m.targetDate).getTime() - new Date(today).getTime()) / (1000 * 60 * 60 * 24));
          return days <= 7;
        });
        const anyMilestone = milestones.length > 0;
        if (overdueCount > 0 || hasLatePaid) projHealth = 'red';
        else if (hasPartial || hasDueSoon) projHealth = 'yellow';
        else if (anyMilestone) projHealth = 'green';

        const healthDotClass =
          projHealth === 'red'    ? 'bg-terra'
          : projHealth === 'yellow' ? 'bg-amber-400'
          : projHealth === 'green'  ? 'bg-moss'
          : 'bg-line';

        return (
          <div className="mb-3 px-2.5 py-2 bg-bone rounded border border-line-soft">
            <div className="flex items-center gap-2 text-[10px] font-mono leading-tight">
              <span className={`w-2.5 h-2.5 rounded-full shrink-0 ${healthDotClass}`} title={`Financial health: ${projHealth}`} />
              <Coins className="w-3 h-3 text-terra shrink-0" />
              <span className="ink font-semibold">{fmtL(totalFee)}</span>
              <span className="ink-faint">·</span>
              <span className="ink-soft">{billedPct}% billed</span>
              <span className="ink-faint">·</span>
              <span className="text-moss font-semibold">{fmtL(totalRecv)}</span>
              <span className="ink-faint">recvd</span>
              <span className="ink-faint">·</span>
              <span className={`font-semibold ${outstanding > 0 ? 'text-terra' : 'text-moss'}`}>{fmtL(outstanding)}</span>
              <span className="ink-faint">due</span>
            </div>
            <div className="flex items-center gap-2 text-[9px] font-mono mt-1 ink-soft">
              {nextDue ? (
                <span>Next: {new Date(nextDue.targetDate).toLocaleDateString('en-IN', { day: '2-digit', month: 'short' })} <span className="ink-faint">· {nextDue.name}</span></span>
              ) : outstanding === 0 ? (
                <span className="text-moss">All milestones cleared</span>
              ) : (
                <span className="ink-faint">No upcoming dates set</span>
              )}
              {overdueCount > 0 && (
                <span className="inline-flex items-center gap-1 text-white bg-terra px-1.5 py-0.5 rounded ml-auto">
                  <Flag className="w-2.5 h-2.5" strokeWidth={2.5} />
                  <span className="font-semibold uppercase tracking-wider text-[8px]">{overdueCount} overdue</span>
                </span>
              )}
              {overdueCount === 0 && hasLatePaid && (
                <span className="inline-flex items-center gap-1 text-white bg-terra px-1.5 py-0.5 rounded ml-auto">
                  <Flag className="w-2.5 h-2.5" strokeWidth={2.5} />
                  <span className="font-semibold uppercase tracking-wider text-[8px]">paid late</span>
                </span>
              )}
            </div>
          </div>
        );
      })()}
      <div className="flex items-center justify-between pt-3 border-t border-line-soft">
        <div className="flex items-center gap-3">
          <div className="flex items-center gap-1 text-[10px] ink-soft"><Calendar className="w-3 h-3" /><span className="font-mono">{p.expCompletion}</span></div>
          {p.pendingApprovals > 0 && <div className="flex items-center gap-1 text-[10px] text-terra"><Shield className="w-3 h-3" /><span className="font-mono font-semibold">{p.pendingApprovals}</span></div>}
          {p.overdueTasks > 0 && <div className="flex items-center gap-1 text-[10px] text-terra"><AlertCircle className="w-3 h-3" /><span className="font-mono font-semibold">{p.overdueTasks}</span></div>}
          {p.paymentDue && <div className="flex items-center gap-1 text-[10px] text-clay"><Receipt className="w-3 h-3" /><span className="font-mono font-semibold">DUE</span></div>}
        </div>
        <div className="flex items-center gap-1.5">
          <span className="text-[10px] ink-faint">PM</span>
          <div className="w-6 h-6 text-white rounded-full flex items-center justify-center text-[10px] font-semibold" style={{ background: p.accent }}>{p.pmInitials}</div>
        </div>
      </div>
    </div>
    {confirmingDelete && (
      <ProjectDeleteConfirmModal
        project={p}
        onClose={() => setConfirmingDelete(false)}
        onConfirm={() => {
          if (onDelete) onDelete(p.id);
          setConfirmingDelete(false);
        }}
      />
    )}
    </>
  );
}

function NewProjectCard({ onClick }) {
  return (
    <button onClick={onClick} className="border-2 border-dashed border-line rounded-lg p-5 hover:border-terra hover:bg-terra-soft flex flex-col items-center justify-center min-h-[280px] group text-left">
      <div className="w-12 h-12 rounded-full bg-bone group-hover:bg-paper border border-line flex items-center justify-center mb-3">
        <Plus className="w-5 h-5 ink-soft group-hover:text-terra" />
      </div>
      <div className="font-display text-lg ink mb-1">Register a new project</div>
      <div className="text-xs ink-soft text-center max-w-xs leading-relaxed">Open the 3-page onboarding wizard.<br />Identity → Property &amp; Scope → Client.</div>
      <span className="mt-3 text-[10px] font-mono tracking-wider text-terra">ProjRegistration →</span>
    </button>
  );
}

function BoardView({ projects, columns, onAddColumn, onRenameColumn, onDeleteColumn, editingColumn, setEditingColumn, columnMenu, setColumnMenu, onOpenProject, onDeleteProject, currentRoleCode }) {
  const columnMap = {};
  columns.forEach((c) => (columnMap[c.name] = []));
  projects.forEach((p) => { if (columnMap[p.currentStage]) columnMap[p.currentStage].push(p); });
  return (
    <div className="grid-paper" style={{ height: '100%' }}>
      <div className="flex gap-3 p-6 overflow-x-auto scrollbar-thin h-full">
        {columns.map((col) => (
          <div key={col.id} className="w-72 shrink-0 flex flex-col">
            <div className="bg-paper border border-line rounded-t-lg p-3 relative">
              <div className="absolute top-0 left-0 right-0 h-0.5 rounded-t-lg" style={{ background: col.color }} />
              <div className="flex items-center justify-between">
                <div className="flex items-center gap-2 flex-1 min-w-0">
                  {editingColumn === col.id ? (
                    <input autoFocus defaultValue={col.name}
                      onBlur={(e) => onRenameColumn(col.id, e.target.value)}
                      onKeyDown={(e) => { if (e.key === 'Enter') onRenameColumn(col.id, e.target.value); if (e.key === 'Escape') setEditingColumn(null); }}
                      className="font-medium text-sm ink bg-bone border border-line rounded px-1.5 py-0.5 outline-none" />
                  ) : <span className="font-medium text-sm ink truncate">{col.name}</span>}
                  <span className="text-[10px] font-mono ink-faint shrink-0">{columnMap[col.name]?.length || 0}</span>
                </div>
                <button onClick={() => setColumnMenu(columnMenu === col.id ? null : col.id)} className="p-1 hover:bg-bone rounded">
                  <MoreHorizontal className="w-3.5 h-3.5 ink-soft" />
                </button>
              </div>
              {columnMenu === col.id && (
                <div className="absolute right-2 top-10 z-10 bg-paper border border-line rounded-md shadow-lg w-44 py-1 fade-in">
                  <button onClick={() => { setEditingColumn(col.id); setColumnMenu(null); }} className="w-full text-left px-3 py-1.5 text-xs ink hover:bg-bone">Rename column</button>
                  <button className="w-full text-left px-3 py-1.5 text-xs ink hover:bg-bone">Change color</button>
                  <div className="border-t border-line-soft my-1" />
                  <button onClick={() => onDeleteColumn(col.id)} className="w-full text-left px-3 py-1.5 text-xs text-terra hover:bg-terra-soft">Delete column</button>
                </div>
              )}
            </div>
            <div className="flex-1 bg-bone border-x border-b border-line rounded-b-lg p-2 space-y-2" style={{ minHeight: '200px' }}>
              {columnMap[col.name]?.map((p) => <BoardCard key={p.id} project={p} onClick={() => onOpenProject(p.id)} onDelete={onDeleteProject} currentRoleCode={currentRoleCode} />)}
              {(!columnMap[col.name] || columnMap[col.name].length === 0) && (
                <div className="text-center py-6"><span className="text-[10px] font-mono ink-faint tracking-wider uppercase">No projects</span></div>
              )}
              <button className="w-full flex items-center justify-center gap-1 py-2 ink-faint hover:ink-soft text-[11px] font-mono uppercase tracking-wider">
                <Plus className="w-3 h-3" /> New task
              </button>
            </div>
          </div>
        ))}
        <button onClick={onAddColumn} className="w-72 shrink-0 flex flex-col items-center justify-center border-2 border-dashed border-line rounded-lg hover:border-terra hover:bg-terra-soft group" style={{ minHeight: '400px' }}>
          <Plus className="w-5 h-5 ink-soft group-hover:text-terra mb-2" />
          <span className="text-xs font-medium ink-soft group-hover:text-terra">Add column</span>
          <span className="text-[10px] ink-faint font-mono mt-1">Editable · Deletable</span>
        </button>
      </div>
    </div>
  );
}

function BoardCard({ project: p, onClick, onDelete, currentRoleCode }) {
  const [confirmingDelete, setConfirmingDelete] = useState(false);
  const isAdmin = currentRoleCode === 'studio_owner' || currentRoleCode === 'admin' || currentRoleCode === 'super_admin';

  return (
    <>
    <div onClick={onClick} className="bg-paper border border-line rounded-md p-3 hover:border-ink cursor-pointer relative group/bcard">
      <div className="absolute left-0 top-0 bottom-0 w-0.5 rounded-l-md" style={{ background: p.accent }} />
      {isAdmin && onDelete && (
        <button
          onClick={(e) => { e.stopPropagation(); setConfirmingDelete(true); }}
          className="absolute top-1.5 right-1.5 p-1 rounded hover:bg-terra-soft opacity-0 group-hover/bcard:opacity-100 z-10"
          title="Delete project (admin only)"
        >
          <Trash2 className="w-3 h-3 text-terra" />
        </button>
      )}
      <div className="flex items-center justify-between mb-1.5">
        <span className="text-[9px] font-mono ink-faint tracking-wider">{p.id}</span>
        <Tag tone="bone">{p.category}</Tag>
      </div>
      <div className="font-display text-sm ink leading-tight mb-1.5">{p.name}</div>
      <div className="text-[10px] ink-soft mb-2 truncate">{p.client}</div>
      <div className="h-0.5 bg-line rounded-full overflow-hidden mb-2">
        <div className="h-full" style={{ width: `${computeProjectProgress(p)}%`, background: p.accent }} />
      </div>
      <div className="flex items-center justify-between">
        <div className="flex items-center gap-2 text-[10px] ink-soft">
          {p.pendingApprovals > 0 && <span className="flex items-center gap-0.5 text-terra"><Shield className="w-2.5 h-2.5" /> {p.pendingApprovals}</span>}
          {p.overdueTasks > 0 && <span className="flex items-center gap-0.5 text-terra"><AlertCircle className="w-2.5 h-2.5" /> {p.overdueTasks}</span>}
          {p.paymentDue && <span className="flex items-center gap-0.5 text-clay"><Receipt className="w-2.5 h-2.5" /></span>}
        </div>
        <div className="w-5 h-5 text-white rounded-full flex items-center justify-center text-[9px] font-semibold" style={{ background: p.accent }}>{p.pmInitials}</div>
      </div>
    </div>
    {confirmingDelete && (
      <ProjectDeleteConfirmModal
        project={p}
        onClose={() => setConfirmingDelete(false)}
        onConfirm={() => {
          if (onDelete) onDelete(p.id);
          setConfirmingDelete(false);
        }}
      />
    )}
    </>
  );
}

function MastersToBuildRail({ onClose, onOpenMasters }) {
  return (
    <aside className="w-80 bg-paper border-l border-line overflow-y-auto scrollbar-thin shrink-0">
      <div className="px-5 py-4 border-b border-line bg-bone">
        <div className="flex items-center justify-between mb-1">
          <div className="text-[10px] font-mono tracking-widest font-semibold uppercase ink-faint">Build Companion</div>
          <button onClick={onClose} className="p-1 hover:bg-paper rounded"><X className="w-3.5 h-3.5 ink-faint" /></button>
        </div>
        <div className="font-display text-xl ink tracking-tight">Masters to Build</div>
        <div className="text-[11px] ink-soft mt-1 leading-relaxed">Every dropdown, picker &amp; cascade in this build needs a Master behind it.</div>
        <button onClick={onOpenMasters} className="mt-3 flex items-center gap-1.5 text-[11px] font-mono text-terra hover:ink">
          <Database className="w-3 h-3" /> Open MasterSettings →
        </button>
      </div>
      <div className="p-5 space-y-5">
        {mastersToBuild.map((group) => (
          <div key={group.group}>
            <div className="text-[10px] font-mono tracking-widest font-semibold uppercase ink-faint mb-2">{group.group}</div>
            <div className="space-y-1.5">
              {group.items.map((item) => (
                <div key={item.code} className="bg-bone border border-line-soft rounded p-2.5 hover:border-terra cursor-pointer">
                  <div className="flex items-start justify-between gap-2">
                    <div className="min-w-0 flex-1">
                      <div className="text-[11px] font-mono ink font-medium truncate">{item.code}</div>
                    </div>
                    <div className="flex flex-col items-end gap-1 shrink-0">
                      <StatusPill status={item.status} />
                      {item.count > 0 && <span className="text-[9px] font-mono ink-faint">{item.count} items</span>}
                    </div>
                  </div>
                  <div className="flex items-center gap-1 mt-1.5 pt-1.5 border-t border-line-soft">
                    <span className="text-[9px] font-mono ink-faint uppercase tracking-wider">Blocks:</span>
                    <span className="text-[9px] font-mono ink-soft">{item.blocks}</span>
                  </div>
                </div>
              ))}
            </div>
          </div>
        ))}
        <div className="mt-6 p-4 border border-terra rounded-md bg-terra-soft">
          <div className="flex items-center gap-2 mb-2">
            <ArrowRight className="w-4 h-4 text-terra" />
            <div className="text-[10px] font-mono tracking-widest font-semibold uppercase text-terra">Next Up</div>
          </div>
          <div className="font-display text-base ink leading-tight mb-1">Roles &amp; Phase 5.1+</div>
          <div className="text-[11px] ink-soft leading-relaxed">
            Per-record visibility flags for client/vendor/internal-only. Internal-vs-client notes split. Tab deepening for the remaining soft tabs (Comms, MOM, Site Updates).
          </div>
        </div>
      </div>
    </aside>
  );
}

/* ================================================================== */
/* ====================== PROJ REGISTRATION ========================= */
/* ================================================================== */

const initialWizardData = {
  clientProjectName: '', projectId: '',
  siteAddress: '', city: '', state: '', pinCode: '', googleMapLink: '',
  siteCondition: '', serviceType: '',
  includedScope: '', excludedScope: '',
  procurementResponsibility: '', executionResponsibility: '',
  startDate: '', expCompletion: '', actCompletion: '',
  projectCategory: '', propertyType: '',
  builtUpArea: '', carpetArea: '', plotArea: '', ceilingHeight: '',
  numberOfLevels: '', numberOfFloors: '', levelNames: '',
  projWorkflowstage: '',
  liftAvailability: '', parkingAvailability: '', serviceEntryAvailability: '',
  siteMeasurementStatus: '', structuralConstraints: '',
  projectLevels: [],
  primaryClientId: null, /* Phase 5.6.1 — picked from MasterClients */
  decisionMakers: [],
  finalApprovalAuthority: '',
  billingContact: { name: '', role: '', mobile: '' }, /* Phase 9.0.2 — mandatory at submit; B2B context */
  siteContact:    { name: '', role: '', mobile: '' }, /* Phase 9.0.2 — site execution touchpoint */
  clientNotes: '', clientFlags: [], onboardingAttentionTags: [],
  paymentTerms: [],
  totalProjectValue: '', /* Phase 9.0.16 — design fee total; auto-splits into milestone amounts via percentages */
  externalStakeholders: [],
  projectManagerId: '',
  projectTeamMemberIds: [],   /* Phase 9.0.30 — picked team members for this project */
  bulkAssignOnSave: false,    /* Phase 9.0.30 — round-robin distribute auto-cloned tasks across selected team */
};

function buildProjectCodeFromPrefix(prefix = 'STD') {
  const cleanPrefix = String(prefix || 'STD').trim().toUpperCase() || 'STD';
  return `${cleanPrefix}-${new Date().getFullYear()}-${String(Math.floor(Math.random() * 900) + 100)}`;
}

function clonePaymentTermsFromTemplate(template) {
  if (!template || !Array.isArray(template.milestones)) return [];
  return template.milestones.map((m, idx) => ({
    id: uid(),
    name: m.name || '',
    linkedStage: m.linkedStage || '',
    percentage: m.percentage || '',
    amount: '',
    amountReceived: 0,
    receiptDate: '',
    targetDate: '',
    amountManualOverride: false,
    triggerCondition: m.triggerCondition || 'On stage completion',
    reminderEnabled: m.reminderEnabled !== false,
    reminderType: m.reminderType || 'WhatsApp',
    masterRef: { template: template.id, milestoneIndex: idx },
  }));
}

function buildInitialWizardData(masters) {
  const settings = (masters.MasterStudioSettings && masters.MasterStudioSettings[0]) || {};
  const serviceRow = findWorkspaceDefaultRow(masters.MasterServiceTypes || [], settings.defaultServiceType);
  const workflowRow = findWorkspaceDefaultRow(masters.MasterWorkflowTemplates || [], settings.defaultWorkflowTemplate);
  const paymentRow = findWorkspaceDefaultRow(masters.MasterPaymentMilestones || [], settings.defaultPaymentTemplate);
  const serviceType = settings.defaultServiceType || serviceRow?.value || workflowRow?.linkedServiceType || '';

  return {
    ...initialWizardData,
    projectId: buildProjectCodeFromPrefix(settings.defaultProjectIdPrefix || 'STD'),
    serviceType,
    defaultWorkflowTemplate: settings.defaultWorkflowTemplate || workflowRow?.value || '',
    defaultPaymentTemplate: settings.defaultPaymentTemplate || paymentRow?.value || '',
    paymentTerms: clonePaymentTermsFromTemplate(paymentRow),
  };
}

function ProjRegistration({ masters, onCancel, onSave, onOpenMasters }) {
  /* Phase 9.0.18 — Wizard draft save.
     On mount: check localStorage for an existing draft; if present, hydrate state from it
     and show a "Draft restored" banner. User can discard via the "Discard draft" button.
     On every state change: debounced write to localStorage so progress isn't lost. */
  const DRAFT_KEY = 'studio-os-wizard-draft';

  const loadDraft = () => {
    try {
      const raw = window.localStorage && window.localStorage.getItem(DRAFT_KEY);
      if (!raw) return null;
      const parsed = JSON.parse(raw);
      if (!parsed || typeof parsed !== 'object') return null;
      if (!parsed.data || typeof parsed.data !== 'object') return null;
      return parsed; // { data, step, savedAt }
    } catch (e) { return null; }
  };

  const [draftRestored, setDraftRestored] = useState(false);
  const [draftSavedAt, setDraftSavedAt] = useState(null);

  const [step, setStep] = useState(() => {
    const d = loadDraft();
    return d?.step || 1;
  });
  const [data, setData] = useState(() => {
    const defaults = buildInitialWizardData(masters);
    const d = loadDraft();
    if (d) {
      setTimeout(() => setDraftRestored(true), 0);
      return { ...defaults, ...d.data };
    }
    return defaults;
  });

  /* Auto-save on every change (debounced ~400ms) */
  React.useEffect(() => {
    const handle = setTimeout(() => {
      try {
        if (window.localStorage) {
          const payload = { data, step, savedAt: new Date().toISOString() };
          window.localStorage.setItem(DRAFT_KEY, JSON.stringify(payload));
          setDraftSavedAt(payload.savedAt);
        }
      } catch (e) { /* quota exceeded etc — silent */ }
    }, 400);
    return () => clearTimeout(handle);
  }, [data, step]);

  const discardDraft = () => {
    try { window.localStorage && window.localStorage.removeItem(DRAFT_KEY); } catch (e) {}
    setData(buildInitialWizardData(masters));
    setStep(1);
    setDraftRestored(false);
    setDraftSavedAt(null);
  };

  /* Wrap onSave so the draft clears when project saves successfully */
  const clearDraftAndSave = (finalData) => {
    try { window.localStorage && window.localStorage.removeItem(DRAFT_KEY); } catch (e) {}
    onSave(finalData);
  };
  /* Wrap onCancel so user keeps the draft (it auto-restores next time) — they can manually
     discard if they want a clean slate. */

  useMemo(() => {
    if (!data.projectId) {
      const settings = (masters.MasterStudioSettings && masters.MasterStudioSettings[0]) || {};
      const next = buildProjectCodeFromPrefix(settings.defaultProjectIdPrefix || 'STD');
      setData((d) => ({ ...d, projectId: next }));
    }
  }, []);

  const update = (k, v) => setData((d) => ({ ...d, [k]: v }));

  const filteredPropertyTypes = data.projectCategory
    ? masters.MasterPropertyType.filter((p) => p.category === data.projectCategory).map((p) => p.value)
    : [];

  const handlePropertyTypeChange = (newType) => {
    setData((d) => ({
      ...d,
      propertyType: newType,
      projectLevels: newType ? buildProjectLevelsForType(masters, newType) : [],
    }));
  };

  const applyProjectTemplate = (templateId) => {
    const propertyTemplateRows = (masters.MasterPropertyTemplates || []).map((template) => {
      const propertyType = (masters.MasterPropertyType || []).find((pt) => (pt.value || pt.name) === template.linkedPropertyType);
      return {
        ...template,
        id: `property-template-${template.id}`,
        linkedCategory: template.linkedCategory || propertyType?.category || propertyType?.linkedCategory || '',
        linkedPropertyType: template.linkedPropertyType || propertyType?.value || propertyType?.name || '',
      };
    });
    const propertyTemplate = propertyTemplateRows.find((t) => String(t.id) === String(templateId));
    const masterTemplate = (masters.MasterProjectTemplates || []).find((t) => String(t.id) === String(templateId));
    const generatedTemplate = (masters.MasterPropertyType || []).map((propertyType, index) => ({
      id: `property-type-${propertyType.id || index + 1}`,
      value: propertyType.value || propertyType.name || `Property Type ${index + 1}`,
      linkedCategory: propertyType.category || propertyType.linkedCategory || '',
      linkedPropertyType: propertyType.value || propertyType.name || '',
      linkedServiceType: '',
    })).find((t) => String(t.id) === String(templateId));
    const tmpl = propertyTemplate || masterTemplate || generatedTemplate;
    if (!tmpl) return;
    const dirtyFields = [
      data.projectCategory && 'category', data.propertyType && 'property type',
      data.serviceType && 'service type', data.includedScope && 'scope',
    ].filter(Boolean);
    if (dirtyFields.length > 0 && !window.confirm(`This will overwrite: ${dirtyFields.join(', ')}.\n\nApply template "${tmpl.value}"?`)) return;

    setData((d) => {
      const next = { ...d };
      if (tmpl.linkedCategory) next.projectCategory = tmpl.linkedCategory;
      if (tmpl.linkedServiceType) next.serviceType = tmpl.linkedServiceType;
      if (tmpl.includedScopeDefault) next.includedScope = tmpl.includedScopeDefault;
      if (tmpl.excludedScopeDefault) next.excludedScope = tmpl.excludedScopeDefault;
      if (tmpl.linkedPropertyType) {
        next.propertyType = tmpl.linkedPropertyType;
        next.projectLevels = buildProjectLevelsForType(masters, tmpl.linkedPropertyType);
      }
      next._appliedTemplate = { id: tmpl.id, name: tmpl.value };
      return next;
    });
  };

  const resetCascadeFromMasters = () => {
    if (!data.propertyType) return;
    if ((data.projectLevels || []).length > 0 && !window.confirm('Reset to master defaults? Your edits will be lost.')) return;
    update('projectLevels', buildProjectLevelsForType(masters, data.propertyType));
  };

  const steps = [
    { n: 1, name: 'Project Identity', code: 'ProjectIdentityPage' },
    { n: 2, name: 'Property & Scope', code: 'PropertyScopePage' },
    { n: 3, name: 'Client & Decision Makers', code: 'ClientDetailsPage' },
  ];

  const canContinue = () => {
    if (step === 1) return data.clientProjectName && data.projectId && data.serviceType;
    if (step === 2) return data.startDate && data.projectCategory && data.propertyType;
    return true;
  };

  const handleSave = () => {
    const hasPickedClient = !!data.primaryClientId;
    const hasPendingClient = data._pendingClientCreate && data._pendingClientFields?.value?.trim();
    if (!hasPickedClient && !hasPendingClient) {
      alert('Pick a client from the directory or fill in a new client name before saving.');
      return;
    }
    clearDraftAndSave(data);
  };

  return (
    <div className="flex-1 overflow-auto scrollbar-thin">
      {/* Phase 9.0.18 — Draft restored banner (one-time, on top of wizard) */}
      {draftRestored && (
        <div className="bg-amber-50 border-b border-amber-300 px-6 py-2">
          <div className="flex items-center justify-between gap-3">
            <div className="flex items-center gap-2 text-[11px]">
              <Sparkles className="w-3.5 h-3.5 text-amber-700" />
              <span className="ink font-medium">Draft restored.</span>
              <span className="ink-soft">You picked up where you left off. Continue editing, or discard to start fresh.</span>
            </div>
            <div className="flex items-center gap-2">
              <button onClick={() => setDraftRestored(false)} className="text-[10px] font-mono ink-soft hover:ink px-2 py-1 hover:bg-amber-100 rounded">
                Got it
              </button>
              <button onClick={discardDraft} className="text-[10px] font-mono text-terra hover:ink px-2 py-1 border border-terra/40 rounded hover:bg-terra/10">
                Discard draft
              </button>
            </div>
          </div>
        </div>
      )}
      <div className="bg-paper border-b border-line px-6 py-3">
        <div className="flex items-start justify-between mb-3">
          <div>
            <div className="flex items-center gap-2 mb-1">
              <button onClick={onCancel} className="flex items-center gap-1 text-[11px] font-mono ink-faint hover:ink uppercase tracking-wider">
                <ArrowLeft className="w-3 h-3" /> Dashboard
              </button>
              <span className="ink-faint text-xs">/</span>
              <span className="text-[11px] font-mono ink-soft uppercase tracking-wider">ProjRegistration</span>
            </div>
            <h1 className="text-[22px] font-semibold ink tracking-tight leading-none">{steps[step - 1].name}</h1>
            <div className="flex items-center gap-2 mt-1.5">
              <span className="text-[11px] ink-soft">Step <span className="ink font-semibold">{step}</span> of 3</span>
              <span className="ink-faint">·</span>
              <span className="text-[11px] font-mono ink-faint">{steps[step - 1].code}</span>
              {/* Phase 9.0.18 — Draft auto-save indicator */}
              {draftSavedAt && (
                <>
                  <span className="ink-faint">·</span>
                  <span className="text-[10px] font-mono text-moss flex items-center gap-1" title={`Draft auto-saved at ${new Date(draftSavedAt).toLocaleTimeString('en-IN')}`}>
                    <Check className="w-2.5 h-2.5" /> draft saved
                  </span>
                </>
              )}
            </div>
          </div>
          <div className="flex items-center gap-2">
            {/* Phase 9.0.18 — Manual discard button (visible always when there's saved data) */}
            {draftSavedAt && (
              <button onClick={discardDraft} className="flex items-center gap-1.5 text-[10px] font-mono text-terra hover:ink px-3 py-1.5 border border-terra/40 rounded hover:bg-terra/10" title="Discard the saved draft and start fresh">
                <X className="w-3 h-3" /> Discard draft
              </button>
            )}
            <button onClick={onOpenMasters} className="flex items-center gap-1.5 text-[11px] font-mono ink-soft hover:ink px-3 py-1.5 border border-line rounded-md hover:bg-bone">
              <Database className="w-3 h-3" /> Edit Masters
            </button>
          </div>
        </div>
        <div className="flex items-center gap-2">
          {steps.map((s, i) => {
            const isActive = step === s.n;
            const isDone = step > s.n;
            return (
              <React.Fragment key={s.n}>
                <button onClick={() => (isDone || isActive) && setStep(s.n)} className={`flex items-center gap-1.5 px-2.5 py-1.5 rounded-md ${isActive ? 'bg-ink text-white' : isDone ? 'bg-moss-soft text-moss cursor-pointer hover:bg-moss hover:text-white' : 'bg-bone ink-faint cursor-not-allowed'}`}>
                  <div className={`w-4 h-4 rounded-full flex items-center justify-center text-[9px] font-mono font-semibold ${isActive ? 'bg-white text-ink' : isDone ? 'bg-moss text-white' : 'bg-line ink-faint'}`}>
                    {isDone ? <Check className="w-2.5 h-2.5" strokeWidth={3} /> : s.n}
                  </div>
                  <span className="text-[11px] font-medium">{s.name}</span>
                </button>
                {i < steps.length - 1 && <div className={`flex-1 h-px max-w-12 ${step > s.n ? 'bg-moss' : 'bg-line'}`} />}
              </React.Fragment>
            );
          })}
        </div>
      </div>

      <div className="px-6 py-4" style={{ maxWidth: '1100px' }}>
        {step === 1 && <ProjectIdentityPage data={data} update={update} masters={masters} onApplyTemplate={applyProjectTemplate} />}
        {step === 2 && <PropertyScopePage data={data} update={update} masters={masters} filteredPropertyTypes={filteredPropertyTypes} onPropertyTypeChange={handlePropertyTypeChange} onResetCascade={resetCascadeFromMasters} />}
        {step === 3 && <ClientDetailsPage data={data} update={update} masters={masters} />}
      </div>

      <div className="sticky bottom-0 bg-paper border-t border-line px-6 py-4 flex items-center justify-between">
        <button onClick={onCancel} className="text-xs font-mono ink-soft hover:ink uppercase tracking-wider">Cancel</button>
        <div className="flex items-center gap-2">
          {step > 1 && (
            <button onClick={() => setStep(step - 1)} className="flex items-center gap-1.5 px-4 py-2 border border-line rounded-md text-xs font-medium ink hover:bg-bone">
              <ChevronLeft className="w-3.5 h-3.5" /> Back
            </button>
          )}
          <button className="px-4 py-2 border border-line rounded-md text-xs font-medium ink-soft hover:bg-bone hover:ink">Save Draft</button>
          {step < 3 ? (
            <button onClick={() => canContinue() && setStep(step + 1)} disabled={!canContinue()}
              className={`flex items-center gap-1.5 px-4 py-2 rounded-md text-xs font-mono tracking-wider font-semibold uppercase ${canContinue() ? 'bg-ink text-white hover:bg-terra' : 'bg-line ink-faint cursor-not-allowed'}`}>
              Continue <ChevronRight className="w-3.5 h-3.5" />
            </button>
          ) : (
            <button onClick={handleSave} className="flex items-center gap-1.5 px-4 py-2 rounded-md text-xs font-mono tracking-wider font-semibold uppercase bg-terra text-white hover:bg-ink">
              <Save className="w-3.5 h-3.5" /> Save Project
            </button>
          )}
        </div>
      </div>
    </div>
  );
}

function Section({ title, subtitle, action, children }) {
  /* Phase 9.1.18 — Compressed: smaller padding, smaller heading, mb-3 inside */
  return (
    <div className="bg-paper border border-line rounded-lg p-4">
      <div className="flex items-start justify-between mb-3">
        <div>
          <h3 className="text-[15px] font-semibold ink tracking-tight leading-tight">{title}</h3>
          {subtitle && <div className="text-[11px] ink-faint mt-0.5">{subtitle}</div>}
        </div>
        {action}
      </div>
      {children}
    </div>
  );
}

/* ===== Page 1 ===== */
function ProjectIdentityPage({ data, update, masters, onApplyTemplate }) {
  const selectedQuickstartRows = (masters.MasterPropertyTemplates || [])
    .filter((row) => row?.showInQuickstart !== false && row?.showInQuickstart !== 'false')
    .map((template) => {
      const propertyType = (masters.MasterPropertyType || []).find((pt) => (pt.value || pt.name) === template.linkedPropertyType);
      return {
        ...template,
        id: `property-template-${template.id}`,
        linkedCategory: template.linkedCategory || propertyType?.category || propertyType?.linkedCategory || '',
        linkedPropertyType: template.linkedPropertyType || propertyType?.value || propertyType?.name || '',
      };
    })
    .slice(0, 6);
  const projectTemplates = selectedQuickstartRows.length > 0
    ? selectedQuickstartRows
    : (masters.MasterPropertyType || []).slice(0, 6).map((propertyType, index) => ({
      id: `property-type-${propertyType.id || index + 1}`,
      value: propertyType.value || propertyType.name || `Property Type ${index + 1}`,
      linkedCategory: propertyType.category || propertyType.linkedCategory || '',
      linkedPropertyType: propertyType.value || propertyType.name || '',
      linkedServiceType: '',
      isGeneratedQuickStart: true,
    }));
  const studioSettings = (masters.MasterStudioSettings && masters.MasterStudioSettings[0]) || {};
  const projectIdPrefix = studioSettings.defaultProjectIdPrefix || 'STD';
  return (
    <div className="space-y-3 fade-in">
      {projectTemplates.length > 0 && (
        <div className="bg-paper border border-terra rounded-lg p-3 relative overflow-hidden">
          <div className="absolute top-0 right-0 w-20 h-20 rounded-full" style={{ background: '#F2DDD0', opacity: 0.4, transform: 'translate(40%, -40%)' }} />
          <div className="relative">
            <div className="flex items-start justify-between mb-2 flex-wrap gap-2">
              <div>
                <div className="flex items-center gap-2">
                  <Sparkles className="w-3.5 h-3.5 text-terra" />
                  <h3 className="text-[14px] font-semibold ink tracking-tight leading-tight">Start from a template</h3>
                </div>
                <div className="text-[11px] ink-faint mt-0.5">Up to 6 quickstarts pulled from Property Templates. Toggle them in Libraries → Message templates → Property Templates.</div>
              </div>
              {data._appliedTemplate && (
                <div className="flex items-center gap-1.5 px-2 py-1 bg-moss-soft rounded text-[11px] font-mono">
                  <CheckCircle2 className="w-3 h-3 text-moss" strokeWidth={2.5} />
                  <span className="text-moss">Applied: {data._appliedTemplate.name}</span>
                </div>
              )}
            </div>
            <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-5 gap-2">
              {projectTemplates.map((t) => {
                const isApplied = data._appliedTemplate?.id === t.id;
                return (
                  <button
                    key={t.id}
                    onClick={() => onApplyTemplate(t.id)}
                    className={`text-left p-2.5 border rounded-md transition-all ${
                      isApplied ? 'border-moss bg-moss-soft' : 'border-line bg-bone hover:border-ink hover:bg-paper'
                    }`}
                  >
                    <div className="flex items-start justify-between gap-2 mb-1">
                      <div className="flex items-center gap-1.5 min-w-0">
                        <span className={`w-3.5 h-3.5 rounded-full border flex items-center justify-center shrink-0 ${isApplied ? 'border-moss bg-moss' : 'border-line-deep bg-paper'}`}>
                          {isApplied && <span className="w-1.5 h-1.5 rounded-full bg-white" />}
                        </span>
                        <div className="font-medium text-[12px] ink leading-tight truncate">{t.value}</div>
                      </div>
                      {isApplied && <CheckCircle2 className="w-3 h-3 text-moss shrink-0 mt-0.5" strokeWidth={2.5} />}
                    </div>
                    <div className="text-[10px] font-mono ink-faint truncate">
                      {t.linkedCategory || ''}{t.linkedPropertyType ? ` · ${t.linkedPropertyType}` : ''}
                    </div>
                  </button>
                );
              })}
            </div>
          </div>
        </div>
      )}

      <Section title="Project basics" subtitle="Name, code & where the site lives.">
        <div className="grid grid-cols-12 gap-3">
          <div className="col-span-7">
            <FieldGroup label="Project Name" required>
              <TextField value={data.clientProjectName} onChange={(v) => update('clientProjectName', v)} placeholder="e.g. Marwah Residence" />
            </FieldGroup>
          </div>
          <div className="col-span-5">
            <FieldGroup label="Project ID / Code" hint="auto · editable" required>
              <div className="flex gap-1.5">
                <TextField value={data.projectId} onChange={(v) => update('projectId', v)} placeholder="STD-2026-018" />
                <button onClick={() => update('projectId', buildProjectCodeFromPrefix(projectIdPrefix))} className="px-2.5 border border-line rounded-md hover:bg-bone shrink-0" title="Regenerate">
                  <RefreshCw className="w-3.5 h-3.5 ink-soft" />
                </button>
              </div>
            </FieldGroup>
          </div>
        </div>
      </Section>

      <Section
        title="Project Team"
        subtitle="Click to add. First selected becomes the lead — drives the avatar on the project card."
      >
        {(masters.MasterTeamMembers || []).length === 0 ? (
          <div className="bg-bone rounded border border-line-soft p-4 text-center">
            <ContactRound className="w-5 h-5 ink-faint mx-auto mb-1" />
            <div className="text-[12px] ink-soft">No team members in MasterTeamMembers yet.</div>
            <div className="text-[10px] ink-faint mt-0.5">Add team members in MasterSettings → Team.</div>
          </div>
        ) : (
          <>
            {/* Phase 9.1.18 — Elegant avatar row. Generous spacing, larger circles
               (44px), name appears under selected only. Lead gets terra ring +
               LEAD caption. Unselected stay clean (small ink-faint name on hover
               via title). One band of faces, not a grid of cards. */}
            <div className="flex flex-wrap gap-x-5 gap-y-3 py-1">
              {masters.MasterTeamMembers.map((m) => {
                const teamIds = Array.isArray(data.projectTeamMemberIds) ? data.projectTeamMemberIds : [];
                const isSelected = teamIds.map(String).includes(String(m.id));
                const isLead = teamIds.length > 0 && String(teamIds[0]) === String(m.id);
                return (
                  <button
                    key={m.id}
                    onClick={() => {
                      const cur = Array.isArray(data.projectTeamMemberIds) ? [...data.projectTeamMemberIds] : [];
                      const idx = cur.findIndex((x) => String(x) === String(m.id));
                      let next;
                      if (idx === -1) {
                        next = [...cur, m.id];
                      } else {
                        next = cur.filter((x) => String(x) !== String(m.id));
                      }
                      update('projectTeamMemberIds', next);
                      update('projectManagerId', next.length > 0 ? String(next[0]) : '');
                    }}
                    className="group flex flex-col items-center gap-1 transition-all"
                    style={{ width: '64px' }}
                    title={`${m.value}${m.role ? ' · ' + m.role : ''}`}
                  >
                    <div
                      className={`relative w-11 h-11 text-white rounded-full flex items-center justify-center text-[13px] font-semibold transition-all ${
                        isLead ? 'ring-2 ring-terra ring-offset-2 ring-offset-paper' :
                        isSelected ? 'ring-2 ring-ink ring-offset-2 ring-offset-paper' :
                        'opacity-50 group-hover:opacity-100'
                      }`}
                      style={{ background: m.accent || '#9A938A' }}
                    >
                      {m.initials || m.value?.slice(0, 2).toUpperCase()}
                      {isSelected && (
                        <div className={`absolute -top-0.5 -right-0.5 w-3.5 h-3.5 rounded-full flex items-center justify-center ${
                          isLead ? 'bg-terra' : 'bg-ink'
                        }`}>
                          <Check className="w-2 h-2 text-white" strokeWidth={3.5} />
                        </div>
                      )}
                    </div>
                    {/* Name shows on selected always; on unselected only on hover */}
                    <div className={`text-[10px] leading-tight text-center truncate w-full ${
                      isSelected ? 'ink font-medium' : 'ink-faint opacity-0 group-hover:opacity-100 transition-opacity'
                    }`}>
                      {(m.value || '').split(' ')[0]}
                    </div>
                    {isLead && (
                      <div className="text-[8px] font-mono uppercase tracking-widest text-terra font-semibold leading-none">Lead</div>
                    )}
                  </button>
                );
              })}
            </div>
            {(!data.projectTeamMemberIds || data.projectTeamMemberIds.length === 0) && (
              <div className="text-[11px] ink-faint mt-2 italic">No team picked — card will show "Unassigned".</div>
            )}
            {Array.isArray(data.projectTeamMemberIds) && data.projectTeamMemberIds.length > 1 && (
              <div className="text-[11px] ink-soft mt-2">
                <span className="text-terra font-medium">{data.projectTeamMemberIds.length}</span> picked · lead drives the project card.
              </div>
            )}
          </>
        )}
      </Section>

      <Section title="Project location" subtitle="Site address, city, and pin.">
        <div className="space-y-3">
          <FieldGroup label="Site Address">
            <TextArea value={data.siteAddress} onChange={(v) => update('siteAddress', v)} placeholder="Full site address" rows={2} />
          </FieldGroup>
          <div className="grid grid-cols-12 gap-3">
            <div className="col-span-6">
              <FieldGroup label="City"><TextField value={data.city} onChange={(v) => update('city', v)} placeholder="Mumbai" /></FieldGroup>
            </div>
            <div className="col-span-4">
              <FieldGroup label="State"><TextField value={data.state} onChange={(v) => update('state', v)} placeholder="Maharashtra" /></FieldGroup>
            </div>
            <div className="col-span-2">
              <FieldGroup label="Pin"><TextField value={data.pinCode} onChange={(v) => update('pinCode', v)} placeholder="400050" /></FieldGroup>
            </div>
          </div>
          <FieldGroup label="Google Map Link" hint="optional"><TextField value={data.googleMapLink} onChange={(v) => update('googleMapLink', v)} placeholder="https://maps.google.com/…" /></FieldGroup>
        </div>
      </Section>

      <Section title="Site & Service" subtitle="Decides which workflow template loads downstream.">
        <div className="grid grid-cols-2 gap-3">
          <FieldGroup label="Existing Site Condition" hint="MasterSiteCondition">
            <SelectField value={data.siteCondition} onChange={(v) => update('siteCondition', v)} options={masters.MasterSiteCondition.map((s) => s.value)} />
          </FieldGroup>
          <FieldGroup label="Core Service" hint="MasterServiceTypes" required>
            <SelectField value={data.serviceType} onChange={(v) => update('serviceType', v)} options={masters.MasterServiceTypes.map((s) => s.value)} />
          </FieldGroup>
          {data.siteCondition && (
            <div className="col-span-2 text-[11px] ink-soft px-2 py-1.5 bg-bone rounded border border-line-soft">
              {masters.MasterSiteCondition.find((s) => s.value === data.siteCondition)?.desc}
            </div>
          )}
        </div>
      </Section>

      <Section title="Scope of Work" subtitle="Click a row to edit. Skeleton — deepen later with full responsibility matrix.">
        <ScopeOfWorkCollapsible data={data} update={update} />
      </Section>
    </div>
  );
}

/* Phase 9.1.18 — Collapsible Scope rows.
   Default: each scope shows as a single-line summary you can click to expand.
   Open state: textarea (3 rows) + auto-grows on focus.
   Below: Procurement + Execution responsibility on one row. */
function ScopeOfWorkCollapsible({ data, update }) {
  const [openInc, setOpenInc] = useState(false);
  const [openExc, setOpenExc] = useState(false);
  const truncate = (s, n = 100) => {
    if (!s) return '';
    return s.length > n ? s.slice(0, n) + '…' : s;
  };
  return (
    <div className="space-y-2.5">
      {/* Included scope row */}
      <div className="border border-line rounded-md bg-bone">
        <button
          onClick={() => setOpenInc((v) => !v)}
          className="w-full flex items-center gap-2 px-3 py-2 text-left hover:bg-paper transition-colors"
        >
          {openInc ? <ChevronDown className="w-3 h-3 ink-soft shrink-0" /> : <ChevronRight className="w-3 h-3 ink-soft shrink-0" />}
          <span className="text-[10px] font-mono uppercase tracking-wider ink-soft font-medium shrink-0">Included</span>
          {!openInc && (
            <span className="text-[12px] ink truncate flex-1">
              {data.includedScope ? truncate(data.includedScope) : <span className="ink-faint italic">empty — click to add what the studio will deliver</span>}
            </span>
          )}
        </button>
        {openInc && (
          <div className="px-3 pb-3 -mt-1">
            <TextArea
              value={data.includedScope}
              onChange={(v) => update('includedScope', v)}
              placeholder="What the studio will deliver…"
              rows={3}
            />
          </div>
        )}
      </div>

      {/* Excluded scope row */}
      <div className="border border-line rounded-md bg-bone">
        <button
          onClick={() => setOpenExc((v) => !v)}
          className="w-full flex items-center gap-2 px-3 py-2 text-left hover:bg-paper transition-colors"
        >
          {openExc ? <ChevronDown className="w-3 h-3 ink-soft shrink-0" /> : <ChevronRight className="w-3 h-3 ink-soft shrink-0" />}
          <span className="text-[10px] font-mono uppercase tracking-wider ink-soft font-medium shrink-0">Excluded</span>
          {!openExc && (
            <span className="text-[12px] ink truncate flex-1">
              {data.excludedScope ? truncate(data.excludedScope) : <span className="ink-faint italic">empty — click to add what the studio will not deliver</span>}
            </span>
          )}
        </button>
        {openExc && (
          <div className="px-3 pb-3 -mt-1">
            <TextArea
              value={data.excludedScope}
              onChange={(v) => update('excludedScope', v)}
              placeholder="What the studio will not deliver…"
              rows={3}
            />
          </div>
        )}
      </div>

      {/* Responsibility row */}
      <div className="grid grid-cols-2 gap-3 pt-1">
        <FieldGroup label="Procurement Responsibility">
          <SelectField value={data.procurementResponsibility} onChange={(v) => update('procurementResponsibility', v)} options={['Client', 'Studio', 'Hybrid']} />
        </FieldGroup>
        <FieldGroup label="Execution Responsibility">
          <SelectField value={data.executionResponsibility} onChange={(v) => update('executionResponsibility', v)} options={['Client', 'Contractor', 'Studio', 'Hybrid']} />
        </FieldGroup>
      </div>
    </div>
  );
}

/* ===== Page 2 ===== */
function PropertyScopePage({ data, update, masters, filteredPropertyTypes, onPropertyTypeChange, onResetCascade }) {
  return (
    <div className="space-y-3 fade-in">
      <Section title="Timeline" subtitle="Project start, expected & actual completion.">
        <div className="grid grid-cols-3 gap-3">
          <FieldGroup label="Start Date" required><TextField type="date" value={data.startDate} onChange={(v) => update('startDate', v)} /></FieldGroup>
          <FieldGroup label="Expected Completion"><TextField type="date" value={data.expCompletion} onChange={(v) => update('expCompletion', v)} /></FieldGroup>
          <FieldGroup label="Actual Completion" hint="optional"><TextField type="date" value={data.actCompletion} onChange={(v) => update('actCompletion', v)} /></FieldGroup>
        </div>
      </Section>

      <Section title="Project & Property" subtitle="Property type options depend on the selected category.">
        <div className="grid grid-cols-2 gap-3">
          <FieldGroup label="Project Category" hint="MasterProjectCategory" required>
            <SelectField value={data.projectCategory} onChange={(v) => { update('projectCategory', v); onPropertyTypeChange(''); }} options={masters.MasterProjectCategory.map((c) => c.value)} />
          </FieldGroup>
          <FieldGroup label="Property Type" hint={data.projectCategory ? 'mapped to category' : 'pick a category first'} required>
            <SelectField value={data.propertyType} onChange={(v) => onPropertyTypeChange(v)} options={filteredPropertyTypes} placeholder={data.projectCategory ? 'Select…' : '— select category —'} />
          </FieldGroup>
        </div>
      </Section>

      <PropertyHierarchyEditor data={data} update={update} onResetCascade={onResetCascade} masters={masters} />

      <Section title="Property size" subtitle="Leave blank for 'Yet to be measured'.">
        <div className="grid grid-cols-4 gap-3">
          <FieldGroup label="Built-up Area"><TextField value={data.builtUpArea} onChange={(v) => update('builtUpArea', v)} placeholder="sq ft" /></FieldGroup>
          <FieldGroup label="Carpet Area"><TextField value={data.carpetArea} onChange={(v) => update('carpetArea', v)} placeholder="sq ft" /></FieldGroup>
          <FieldGroup label="Plot Area"><TextField value={data.plotArea} onChange={(v) => update('plotArea', v)} placeholder="sq ft" /></FieldGroup>
          <FieldGroup label="Ceiling Height"><TextField value={data.ceilingHeight} onChange={(v) => update('ceilingHeight', v)} placeholder="ft" /></FieldGroup>
        </div>
      </Section>

      <Section title="Levels & Floors" subtitle="Each level can later contain zones and spaces.">
        <div className="grid grid-cols-12 gap-3">
          <div className="col-span-3"><FieldGroup label="Levels"><TextField value={data.numberOfLevels} onChange={(v) => update('numberOfLevels', v)} placeholder="3" /></FieldGroup></div>
          <div className="col-span-3"><FieldGroup label="Floors"><TextField value={data.numberOfFloors} onChange={(v) => update('numberOfFloors', v)} placeholder="3" /></FieldGroup></div>
          <div className="col-span-6"><FieldGroup label="Level Names" hint="comma-separated">
            <TextField value={data.levelNames} onChange={(v) => update('levelNames', v)} placeholder="Stilt, Ground Floor, First Floor, Terrace" />
          </FieldGroup></div>
        </div>
      </Section>

      <Section title="Workflow & Site notes">
        <div className="grid grid-cols-2 gap-3">
          <FieldGroup label="Current Workflow Stage" hint="MasterWorkflowStages"><SelectField value={data.projWorkflowstage} onChange={(v) => update('projWorkflowstage', v)} options={masters.MasterWorkflowStages.map((s) => s.value)} /></FieldGroup>
          <FieldGroup label="Site Measurement Status"><SelectField value={data.siteMeasurementStatus} onChange={(v) => update('siteMeasurementStatus', v)} options={['Pending', 'Completed', 'Verified']} /></FieldGroup>
          <FieldGroup label="Lift"><SelectField value={data.liftAvailability} onChange={(v) => update('liftAvailability', v)} options={['Yes', 'No', 'Limited', 'Not Applicable']} /></FieldGroup>
          <FieldGroup label="Parking"><SelectField value={data.parkingAvailability} onChange={(v) => update('parkingAvailability', v)} options={['Yes', 'No', 'Limited', 'Not Applicable']} /></FieldGroup>
          <FieldGroup label="Service Entry"><SelectField value={data.serviceEntryAvailability} onChange={(v) => update('serviceEntryAvailability', v)} options={['Yes', 'No', 'Limited', 'Not Applicable']} /></FieldGroup>
          <div /> {/* spacer to balance row */}
          <div className="col-span-2"><FieldGroup label="Structural Constraints"><TextArea value={data.structuralConstraints} onChange={(v) => update('structuralConstraints', v)} placeholder="Load-bearing walls, column grids, beam depth restrictions…" rows={2} /></FieldGroup></div>
        </div>
      </Section>
    </div>
  );
}

/* ===== Page 3 ===== */
function ClientDetailsPage({ data, update, masters }) {
  const updateDM = (i, key, val) => {
    const arr = [...data.decisionMakers];
    arr[i] = { ...arr[i], [key]: val };
    update('decisionMakers', arr);
  };
  const addDM = () => {
    if (data.decisionMakers.length >= 10) return;
    update('decisionMakers', [...data.decisionMakers, { name: '', role: '', contact: '', email: '', commPref: [] }]);
  };
  const removeDM = (i) => update('decisionMakers', data.decisionMakers.filter((_, idx) => idx !== i));

  return (
    <div className="space-y-3 fade-in">
      <ClientPickerSection data={data} update={update} masters={masters} />

      <Section
        title={`Decision makers (${data.decisionMakers.length}/10)`}
        subtitle="Decision-makers are project-specific (often family or org-internal). They live on the project, not on the master client record."
        action={data.decisionMakers.length < 10 && (
          <button onClick={addDM} className="flex items-center gap-1.5 text-[11px] font-mono text-terra hover:ink"><Plus className="w-3 h-3" /> Add decision maker</button>
        )}
      >
        {data.decisionMakers.length === 0 ? (
          <div className="bg-bone rounded border border-line-soft p-6 text-center">
            <Users className="w-6 h-6 ink-faint mx-auto mb-2" />
            <div className="text-sm ink-soft mb-2">No decision-makers added yet.</div>
            <div className="text-[11px] ink-faint mb-3 max-w-md mx-auto leading-relaxed">
              Optional, but useful when sign-offs need a spouse, parent, business partner, or committee — folks beyond the primary client.
            </div>
            <button onClick={addDM} className="text-[11px] font-mono text-terra hover:ink">+ Add the first decision-maker</button>
          </div>
        ) : (
          <div className="space-y-3">
            {data.decisionMakers.map((dm, i) => (
              <div key={i} className="border border-line rounded-md p-4 bg-bone relative">
                <button onClick={() => removeDM(i)} className="absolute top-2 right-2 p-1 hover:bg-paper rounded" title="Remove decision-maker">
                  <X className="w-3 h-3 ink-soft" />
                </button>
                <div className="text-[10px] font-mono ink-faint tracking-wider uppercase mb-3">Decision Maker {i + 1}</div>
                <div className="grid grid-cols-2 gap-3">
                  <FieldGroup label="Name"><TextField value={dm.name} onChange={(v) => updateDM(i, 'name', v)} placeholder="Full name" /></FieldGroup>
                  <FieldGroup label="Role"><TextField value={dm.role} onChange={(v) => updateDM(i, 'role', v)} placeholder="Father, Spouse, Architect, etc." /></FieldGroup>
                  <FieldGroup label="Contact"><TextField value={dm.contact} onChange={(v) => updateDM(i, 'contact', v)} placeholder="+91 …" /></FieldGroup>
                  <FieldGroup label="Email"><TextField type="email" value={dm.email} onChange={(v) => updateDM(i, 'email', v)} /></FieldGroup>
                  <FieldGroup label="Communication Preference" span="full">
                    <ChipPicker values={dm.commPref} options={['WhatsApp', 'Email', 'Call', 'App Notification']} onChange={(v) => updateDM(i, 'commPref', v)} />
                  </FieldGroup>
                </div>
              </div>
            ))}
          </div>
        )}
      </Section>

      <Section title="Approval & contacts">
        <div className="grid grid-cols-1 gap-5">
          <FieldGroup label="Final Approval Authority">
            <div className="max-w-xs">
              <SelectField value={data.finalApprovalAuthority} onChange={(v) => update('finalApprovalAuthority', v)} options={['Single', 'Multiple', 'Committee']} />
            </div>
          </FieldGroup>

          {/* Phase 9.0.2 — Billing Contact: 3 fields, mandatory at submit */}
          <div className="border border-line rounded-md p-3 bg-bone">
            <div className="text-[11px] font-mono ink uppercase tracking-wider mb-2 flex items-center gap-1">
              Billing Contact <span className="text-terra">*</span>
              <span className="text-[9px] ink-faint normal-case font-sans ml-2">(mandatory · the person we invoice and chase payments from)</span>
            </div>
            <div className="grid grid-cols-3 gap-3">
              <FieldGroup label="Name">
                <TextField value={data.billingContact?.name || ''} onChange={(v) => update('billingContact', { ...data.billingContact, name: v })} placeholder="e.g. Sita Ram" />
              </FieldGroup>
              <FieldGroup label="Role">
                <TextField value={data.billingContact?.role || ''} onChange={(v) => update('billingContact', { ...data.billingContact, role: v })} placeholder="e.g. Accounts Head" />
              </FieldGroup>
              <FieldGroup label="Mobile Number">
                <TextField value={data.billingContact?.mobile || ''} onChange={(v) => update('billingContact', { ...data.billingContact, mobile: v })} placeholder="+91 98XXXXXXXX" />
              </FieldGroup>
            </div>
          </div>

          {/* Phase 9.0.2 — Site Contact: 3 fields */}
          <div className="border border-line rounded-md p-3 bg-bone">
            <div className="text-[11px] font-mono ink uppercase tracking-wider mb-2">
              Site Contact
              <span className="text-[9px] ink-faint normal-case font-sans ml-2">(person on site for execution coordination)</span>
            </div>
            <div className="grid grid-cols-3 gap-3">
              <FieldGroup label="Name">
                <TextField value={data.siteContact?.name || ''} onChange={(v) => update('siteContact', { ...data.siteContact, name: v })} placeholder="e.g. Ramesh Yadav" />
              </FieldGroup>
              <FieldGroup label="Role">
                <TextField value={data.siteContact?.role || ''} onChange={(v) => update('siteContact', { ...data.siteContact, role: v })} placeholder="e.g. Site Caretaker" />
              </FieldGroup>
              <FieldGroup label="Mobile Number">
                <TextField value={data.siteContact?.mobile || ''} onChange={(v) => update('siteContact', { ...data.siteContact, mobile: v })} placeholder="+91 98XXXXXXXX" />
              </FieldGroup>
            </div>
          </div>
        </div>
      </Section>

      <Section title="Client flags & attention tags" subtitle="Helps the team prep for what to expect.">
        <FieldGroup label="Client Flags" hint="MasterClientFlags" span="full">
          <ChipPicker values={data.clientFlags} options={masters.MasterClientFlags.map((f) => f.value)} onChange={(v) => update('clientFlags', v)} tone="terra" />
        </FieldGroup>
        <div className="mt-4">
          <FieldGroup label="Onboarding Attention Tags" hint="MasterOnboardingAttentionTags" span="full">
            <ChipPicker values={data.onboardingAttentionTags} options={masters.MasterOnboardingAttentionTags.map((t) => t.value)} onChange={(v) => update('onboardingAttentionTags', v)} tone="terra" />
          </FieldGroup>
        </div>
        <div className="mt-4">
          <FieldGroup label="Client Notes" span="full"><TextArea value={data.clientNotes} onChange={(v) => update('clientNotes', v)} placeholder="Anything the team should know before kickoff…" rows={3} /></FieldGroup>
        </div>
      </Section>

      <ProjectTeamPickerSection data={data} update={update} masters={masters} />
      <PaymentTermsEditor data={data} update={update} masters={masters} />
      <VendorPickerSection data={data} update={update} masters={masters} />
    </div>
  );
}

/* ============================================================================
   ===== Phase 9.0.30 — ProjectTeamPickerSection ==============================
   ============================================================================
   Wizard step 3 — pick the project team.
     - Default Assignees: multi-select team members → these become the restricted
       pool that's later used in TaskRow assignee dropdowns
     - Bulk Assign on save: optional — when enabled, after the project saves,
       round-robin distribute auto-cloned tasks across selected team members
       (per-activity grouping)
   Saves to data.projectTeamMemberIds (array of IDs) and data.bulkAssignOnSave (bool).
   ============================================================================ */
function ProjectTeamPickerSection({ data, update, masters }) {
  const teamMembers = (masters.MasterTeamMembers || []).filter((m) => m.status !== 'Inactive');
  const selectedIds = Array.isArray(data.projectTeamMemberIds) ? data.projectTeamMemberIds : [];
  const bulkAssignOnSave = data.bulkAssignOnSave === true;

  const toggleMember = (memberId) => {
    const id = memberId;
    const isSelected = selectedIds.includes(id);
    const next = isSelected ? selectedIds.filter((x) => x !== id) : [...selectedIds, id];
    update('projectTeamMemberIds', next);
  };

  const selectAll = () => update('projectTeamMemberIds', teamMembers.map((m) => m.id));
  const clearAll = () => update('projectTeamMemberIds', []);

  return (
    <Section
      title={`Project Team (${selectedIds.length} selected)`}
      subtitle="Pick the team members who'll work on this project. They become the default assignee pool — task dropdowns inside this project will show only these people. You can change later from inside the project."
      action={(
        <div className="flex items-center gap-2">
          {selectedIds.length > 0 && (
            <button onClick={clearAll} className="text-[11px] font-mono ink-faint hover:ink">Clear</button>
          )}
          {selectedIds.length < teamMembers.length && (
            <button onClick={selectAll} className="text-[11px] font-mono text-terra hover:ink">Select all</button>
          )}
        </div>
      )}
    >
      {teamMembers.length === 0 ? (
        <div className="bg-bone rounded border border-line-soft p-6 text-center">
          <Users className="w-6 h-6 ink-faint mx-auto mb-2" />
          <div className="text-sm ink-soft mb-2">No active team members yet.</div>
          <div className="text-[11px] ink-faint">Add team members in Team Panel before staking out the project team.</div>
        </div>
      ) : (
        <>
          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-2">
            {teamMembers.map((m) => {
              const isSelected = selectedIds.includes(m.id);
              return (
                <button
                  key={m.id}
                  onClick={() => toggleMember(m.id)}
                  className={`text-left p-3 rounded-md border transition-all flex items-center gap-3 ${isSelected ? 'border-terra bg-terra-soft' : 'border-line bg-paper hover:bg-bone'}`}
                >
                  <div className="w-8 h-8 rounded-full flex items-center justify-center text-[10px] font-semibold text-white shrink-0" style={{ background: m.accent || '#1A1815' }}>
                    {m.initials || (m.value || '??').split(' ').map((s) => s[0]).join('').slice(0, 2).toUpperCase()}
                  </div>
                  <div className="flex-1 min-w-0">
                    <div className={`text-xs font-semibold truncate ${isSelected ? 'ink' : 'ink'}`}>{m.value}</div>
                    <div className="text-[10px] ink-soft font-mono truncate">{m.role || m.tier || '—'}{m.dept ? ` · ${m.dept}` : ''}</div>
                  </div>
                  {isSelected ? (
                    <Check className="w-4 h-4 text-terra shrink-0" strokeWidth={2.5} />
                  ) : (
                    <span className="w-4 h-4 rounded border border-line shrink-0" />
                  )}
                </button>
              );
            })}
          </div>

          {/* Bulk assign toggle */}
          <div className="mt-4 pt-4 border-t border-line-soft">
            <label className={`flex items-start gap-3 cursor-pointer p-3 rounded-md border ${bulkAssignOnSave ? 'border-terra bg-terra-soft' : 'border-line bg-bone hover:bg-paper'}`}>
              <input
                type="checkbox"
                checked={bulkAssignOnSave}
                onChange={(e) => update('bulkAssignOnSave', e.target.checked)}
                className="mt-0.5 shrink-0"
                disabled={selectedIds.length === 0}
              />
              <div className="flex-1">
                <div className="text-xs ink font-semibold">Bulk-assign tasks across selected team on save</div>
                <div className="text-[11px] ink-soft mt-0.5 leading-relaxed">
                  When the project is saved, auto-cloned tasks (from your master templates) get distributed round-robin across these {selectedIds.length} team member{selectedIds.length === 1 ? '' : 's'}, grouped by activity. So all tasks in "Concept Direction" go to one person, all tasks in "Moodboard Creation" go to another, and so on. You can override individual tasks later.
                </div>
                {selectedIds.length === 0 && (
                  <div className="text-[10px] text-terra font-mono mt-1">Select at least one team member to enable bulk assign.</div>
                )}
              </div>
            </label>
          </div>
        </>
      )}
    </Section>
  );
}

/* ===== Phase 5.6.1 — Client picker (replaces Primary client + Secondary contact sections) ===== */
function ClientPickerSection({ data, update, masters }) {
  const clients = masters.MasterClients || [];
  const [mode, setMode] = useState(() => {
    if (data.primaryClientId) return 'picked';
    if (data._pendingClientCreate) return 'create';
    return 'choose';
  });
  const [search, setSearch] = useState('');

  const pickedClient = data.primaryClientId ? clients.find((c) => c.id === data.primaryClientId) : null;

  const filtered = clients.filter((c) => {
    const q = search.trim().toLowerCase();
    if (!q) return true;
    return c.value.toLowerCase().includes(q) || (c.primaryEmail || '').toLowerCase().includes(q);
  });

  const pickClient = (clientId) => {
    update('primaryClientId', clientId);
    update('_pendingClientCreate', false);
    update('_pendingClientFields', null);
    setMode('picked');
  };

  const startCreate = () => {
    update('primaryClientId', null);
    update('_pendingClientCreate', true);
    update('_pendingClientFields', { value: '', clientType: 'individual', primaryContact: '', primaryEmail: '', secondaryContactName: '', secondaryContactNumber: '', secondaryEmail: '' });
    setMode('create');
  };

  const reset = () => {
    update('primaryClientId', null);
    update('_pendingClientCreate', false);
    update('_pendingClientFields', null);
    setMode('choose');
    setSearch('');
  };

  const updatePending = (key, val) => {
    update('_pendingClientFields', { ...(data._pendingClientFields || {}), [key]: val });
  };

  // === MODE: picked existing client ===
  if (mode === 'picked' && pickedClient) {
    return (
      <Section title="Primary client" subtitle="This project will reference the client below by ID. Edits to client info live in the Client Panel.">
        <div className="bg-bone border border-moss rounded-lg p-4">
          <div className="flex items-start gap-3">
            <div
              className="w-12 h-12 rounded-md flex items-center justify-center text-sm font-mono font-semibold text-white shrink-0"
              style={{ background: pickedClient.accent || '#1A1815' }}
            >
              {pickedClient.initials || '?'}
            </div>
            <div className="flex-1 min-w-0">
              <div className="flex items-center gap-2 mb-0.5 flex-wrap">
                <span className="font-display text-xl ink leading-tight">{pickedClient.value}</span>
                <span className="text-[9px] font-mono uppercase tracking-wider px-1.5 py-0.5 rounded bg-paper text-terra border border-terra">{pickedClient.clientType || 'individual'}</span>
                <span className="text-[9px] font-mono uppercase tracking-wider px-1.5 py-0.5 rounded bg-moss-soft text-moss border border-moss flex items-center gap-1">
                  <Check className="w-2.5 h-2.5" strokeWidth={3} /> Linked
                </span>
              </div>
              <div className="grid grid-cols-2 gap-x-4 gap-y-1 text-[12px] mt-2">
                {pickedClient.primaryContact && <div><span className="text-[10px] font-mono uppercase ink-faint">Phone</span><div className="ink font-mono">{pickedClient.primaryContact}</div></div>}
                {pickedClient.primaryEmail && <div><span className="text-[10px] font-mono uppercase ink-faint">Email</span><div className="ink">{pickedClient.primaryEmail}</div></div>}
                {pickedClient.secondaryContactName && <div className="col-span-2 mt-1"><span className="text-[10px] font-mono uppercase ink-faint">Secondary</span><div className="ink">{pickedClient.secondaryContactName} {pickedClient.secondaryContactNumber && <span className="ink-faint">· {pickedClient.secondaryContactNumber}</span>}</div></div>}
              </div>
            </div>
            <button onClick={reset} className="text-[10px] font-mono text-terra hover:ink shrink-0 px-2 py-1 border border-line rounded hover:bg-bone">
              Change client
            </button>
          </div>
        </div>
      </Section>
    );
  }

  // === MODE: create new client (inline form) ===
  if (mode === 'create') {
    const pending = data._pendingClientFields || {};
    return (
      <Section title="New client" subtitle="A new master client record will be created when you save the project. You can edit it later in the Client Panel.">
        <div className="bg-bone border border-terra rounded-lg p-4">
          <div className="flex items-center justify-between mb-3">
            <div className="flex items-center gap-2">
              <Plus className="w-3.5 h-3.5 text-terra" />
              <span className="text-[10px] font-mono uppercase tracking-widest text-terra font-semibold">New client (will be created)</span>
            </div>
            <button onClick={reset} className="text-[10px] font-mono ink-soft hover:ink">
              ← Pick existing instead
            </button>
          </div>
          <div className="grid grid-cols-3 gap-4">
            <FieldGroup label="Client name" required>
              <TextField value={pending.value || ''} onChange={(v) => updatePending('value', v)} placeholder="Aakash Marwah · or · Acme Corp" />
            </FieldGroup>
            <FieldGroup label="Client type">
              <SelectField value={pending.clientType || 'individual'} onChange={(v) => updatePending('clientType', v)} options={['individual', 'organization']} />
            </FieldGroup>
            <FieldGroup label="Primary phone">
              <TextField value={pending.primaryContact || ''} onChange={(v) => updatePending('primaryContact', v)} placeholder="+91 …" />
            </FieldGroup>
            <FieldGroup label="Primary email" span="full">
              <TextField type="email" value={pending.primaryEmail || ''} onChange={(v) => updatePending('primaryEmail', v)} placeholder="name@example.com" />
            </FieldGroup>
          </div>
          <div className="mt-3 pt-3 border-t border-line-soft">
            <div className="text-[10px] font-mono uppercase tracking-wider ink-faint mb-2">Secondary contact (optional)</div>
            <div className="grid grid-cols-3 gap-4">
              <FieldGroup label="Name"><TextField value={pending.secondaryContactName || ''} onChange={(v) => updatePending('secondaryContactName', v)} placeholder="Spouse / partner / assistant" /></FieldGroup>
              <FieldGroup label="Phone"><TextField value={pending.secondaryContactNumber || ''} onChange={(v) => updatePending('secondaryContactNumber', v)} placeholder="+91 …" /></FieldGroup>
              <FieldGroup label="Email"><TextField type="email" value={pending.secondaryEmail || ''} onChange={(v) => updatePending('secondaryEmail', v)} /></FieldGroup>
            </div>
          </div>
        </div>
      </Section>
    );
  }

  // === MODE: choose (default) ===
  return (
    <Section title="Primary client" subtitle="Pick a client from the directory, or add a new one. Required before saving.">
      <div className="space-y-3">
        <div className="flex items-center gap-2 px-3 py-2 bg-bone rounded border border-line">
          <Search className="w-3.5 h-3.5 ink-faint" />
          <input
            value={search}
            onChange={(e) => setSearch(e.target.value)}
            placeholder={`Search ${clients.length} client${clients.length === 1 ? '' : 's'}…`}
            className="bg-transparent outline-none text-sm w-full ink placeholder:ink-faint"
          />
          <button
            onClick={startCreate}
            className="flex items-center gap-1 text-[11px] font-mono text-terra hover:ink px-2 py-1 border border-terra rounded hover:bg-terra-soft shrink-0"
          >
            <Plus className="w-3 h-3" /> New
          </button>
        </div>
        {filtered.length === 0 ? (
          <div className="text-[11px] ink-faint italic text-center py-6 bg-bone rounded">
            {search ? 'No matches.' : 'No clients in the directory yet.'} Click <span className="text-terra font-semibold">+ New</span> to create one.
          </div>
        ) : (
          <div className="space-y-1.5 max-h-72 overflow-auto">
            {filtered.map((c) => (
              <button
                key={c.id}
                onClick={() => pickClient(c.id)}
                className="w-full text-left p-3 bg-bone hover:bg-terra-soft hover:border-terra border border-line-soft rounded transition-colors"
              >
                <div className="flex items-start gap-3">
                  <div
                    className="w-9 h-9 rounded flex items-center justify-center text-[11px] font-mono font-semibold text-white shrink-0"
                    style={{ background: c.accent || '#1A1815' }}
                  >
                    {c.initials || '?'}
                  </div>
                  <div className="flex-1 min-w-0">
                    <div className="flex items-center gap-2 flex-wrap">
                      <span className="text-[13px] ink font-medium">{c.value}</span>
                      <span className="text-[9px] font-mono uppercase tracking-wider px-1.5 py-0.5 rounded bg-paper text-terra border border-terra">{c.clientType || 'individual'}</span>
                    </div>
                    <div className="flex items-center gap-3 text-[11px] font-mono ink-faint mt-0.5 flex-wrap">
                      {c.primaryContact && <span>{c.primaryContact}</span>}
                      {c.primaryEmail && <span>· {c.primaryEmail}</span>}
                    </div>
                  </div>
                </div>
              </button>
            ))}
          </div>
        )}
      </div>
    </Section>
  );
}

/* ===== Phase 5.6.1 — Vendor picker (replaces ExternalStakeholdersEditor for new shape) ===== */
function VendorPickerSection({ data, update, masters }) {
  const vendors = masters.MasterVendors || [];
  const stakeholders = data.externalStakeholders || [];
  const [showPicker, setShowPicker] = useState(false);
  const [search, setSearch] = useState('');
  const [creatingVendor, setCreatingVendor] = useState(null); // { value, vendorType, primaryContact, primaryEmail }

  const availableVendors = vendors.filter((v) => {
    if (stakeholders.some((s) => s.vendorId === v.id)) return false;
    const q = search.trim().toLowerCase();
    if (!q) return true;
    return v.value.toLowerCase().includes(q) || (v.vendorType || '').toLowerCase().includes(q) || (v.tradesProvided || []).some((t) => t.toLowerCase().includes(q));
  });

  const addExistingVendor = (vendorId) => {
    update('externalStakeholders', [...stakeholders, { vendorId, projectRole: '', projectNotes: '' }]);
    setShowPicker(false);
    setSearch('');
  };

  const startVendorCreate = () => {
    setCreatingVendor({ value: '', vendorType: 'Contractor', primaryContact: '', primaryEmail: '' });
  };

  const commitVendorCreate = () => {
    if (!creatingVendor || !creatingVendor.value.trim()) return;
    const tempId = `pending-${Date.now()}-${Math.floor(Math.random() * 1000)}`;
    const pending = { ...creatingVendor, _tempId: tempId };
    update('_pendingVendorCreates', [...(data._pendingVendorCreates || []), pending]);
    update('externalStakeholders', [...stakeholders, { _tempVendorId: tempId, projectRole: '', projectNotes: '' }]);
    setCreatingVendor(null);
    setShowPicker(false);
    setSearch('');
  };

  const removeStakeholder = (idx) => {
    const removed = stakeholders[idx];
    const next = stakeholders.filter((_, i) => i !== idx);
    update('externalStakeholders', next);
    // If it was a pending create, also drop from _pendingVendorCreates
    if (removed?._tempVendorId) {
      update('_pendingVendorCreates', (data._pendingVendorCreates || []).filter((p) => p._tempId !== removed._tempVendorId));
    }
  };

  const updateStakeholder = (idx, key, val) => {
    const next = stakeholders.map((s, i) => (i === idx ? { ...s, [key]: val } : s));
    update('externalStakeholders', next);
  };

  // Resolve display info for a stakeholder
  const resolveDisplay = (s) => {
    if (s.vendorId) {
      const v = vendors.find((vv) => vv.id === s.vendorId);
      if (v) return { name: v.value, type: v.vendorType, accent: v.accent, initials: v.initials, contact: v.primaryContact, email: v.primaryEmail, isPending: false };
    }
    if (s._tempVendorId) {
      const pending = (data._pendingVendorCreates || []).find((p) => p._tempId === s._tempVendorId);
      if (pending) return { name: pending.value, type: pending.vendorType, accent: '#A67C5A', initials: (pending.value || 'NV').split(' ').map((x) => x[0]).filter(Boolean).slice(0, 2).join('').toUpperCase() || 'NV', contact: pending.primaryContact, email: pending.primaryEmail, isPending: true };
    }
    return null;
  };

  return (
    <Section
      title={`External vendors (${stakeholders.length})`}
      subtitle="Contractors, consultants, suppliers serving this project. Each links to a master vendor record (or stages a new one for creation on save)."
      action={(
        <button onClick={() => setShowPicker(!showPicker)} className="flex items-center gap-1.5 text-[11px] font-mono text-terra hover:ink"><Plus className="w-3 h-3" /> Add vendor</button>
      )}
    >
      {/* Picker */}
      {showPicker && !creatingVendor && (
        <div className="bg-bone border border-terra rounded-lg p-3 mb-3">
          <div className="flex items-center gap-2 mb-2">
            <Search className="w-3.5 h-3.5 ink-faint" />
            <input
              value={search}
              onChange={(e) => setSearch(e.target.value)}
              placeholder={`Search ${vendors.length} vendor${vendors.length === 1 ? '' : 's'}…`}
              className="bg-transparent outline-none text-sm w-full ink placeholder:ink-faint"
              autoFocus
            />
            <button onClick={startVendorCreate} className="text-[11px] font-mono text-terra hover:ink px-2 py-1 border border-terra rounded shrink-0">+ New</button>
            <button onClick={() => { setShowPicker(false); setSearch(''); }} className="ink-faint hover:ink shrink-0"><X className="w-4 h-4" /></button>
          </div>
          {availableVendors.length === 0 ? (
            <div className="text-[11px] ink-faint italic text-center py-4">
              {search ? 'No vendors match.' : 'No vendors available — already added all, or directory is empty.'}
            </div>
          ) : (
            <div className="space-y-1 max-h-56 overflow-auto">
              {availableVendors.map((v) => (
                <button
                  key={v.id}
                  onClick={() => addExistingVendor(v.id)}
                  className="w-full text-left p-2 bg-paper hover:bg-terra-soft border border-line-soft rounded"
                >
                  <div className="flex items-center gap-2">
                    <div className="w-7 h-7 rounded flex items-center justify-center text-[10px] font-mono font-semibold text-white" style={{ background: v.accent || '#1A1815' }}>{v.initials || '?'}</div>
                    <div className="flex-1 min-w-0">
                      <div className="flex items-center gap-2 flex-wrap">
                        <span className="text-[12px] ink font-medium">{v.value}</span>
                        <span className="text-[9px] font-mono uppercase tracking-wider px-1.5 py-0.5 rounded bg-bone text-terra border border-terra">{v.vendorType}</span>
                      </div>
                    </div>
                  </div>
                </button>
              ))}
            </div>
          )}
        </div>
      )}

      {/* Inline vendor create */}
      {creatingVendor && (
        <div className="bg-bone border border-terra rounded-lg p-3 mb-3">
          <div className="flex items-center gap-2 mb-3">
            <Plus className="w-3.5 h-3.5 text-terra" />
            <span className="text-[10px] font-mono uppercase tracking-widest text-terra font-semibold">Create new vendor (will be added to project on save)</span>
            <button onClick={() => setCreatingVendor(null)} className="ml-auto ink-faint hover:ink"><X className="w-4 h-4" /></button>
          </div>
          <div className="grid grid-cols-2 gap-3">
            <FieldGroup label="Vendor name" required>
              <TextField value={creatingVendor.value} onChange={(v) => setCreatingVendor({ ...creatingVendor, value: v })} placeholder="e.g. Atlas Build Co." />
            </FieldGroup>
            <FieldGroup label="Type">
              <SelectField value={creatingVendor.vendorType} onChange={(v) => setCreatingVendor({ ...creatingVendor, vendorType: v })} options={['Contractor', 'Consultant', 'Supplier', 'PMC', 'Architect', 'Other']} />
            </FieldGroup>
            <FieldGroup label="Phone">
              <TextField value={creatingVendor.primaryContact} onChange={(v) => setCreatingVendor({ ...creatingVendor, primaryContact: v })} placeholder="+91 …" />
            </FieldGroup>
            <FieldGroup label="Email">
              <TextField type="email" value={creatingVendor.primaryEmail} onChange={(v) => setCreatingVendor({ ...creatingVendor, primaryEmail: v })} />
            </FieldGroup>
          </div>
          <div className="flex justify-end gap-2 mt-3">
            <button onClick={() => setCreatingVendor(null)} className="text-[11px] font-mono ink-soft hover:ink px-3 py-1.5 border border-line rounded">Cancel</button>
            <button onClick={commitVendorCreate} disabled={!creatingVendor.value.trim()} className={`text-[11px] font-mono uppercase tracking-wider px-3 py-1.5 rounded font-semibold ${creatingVendor.value.trim() ? 'bg-ink text-white hover:bg-terra' : 'bg-bone ink-faint cursor-not-allowed'}`}>
              Stage vendor
            </button>
          </div>
        </div>
      )}

      {/* Existing stakeholders list */}
      {stakeholders.length === 0 ? (
        <div className="text-[11px] ink-faint italic text-center py-4 bg-bone rounded">
          No vendors linked yet. Click <span className="text-terra font-semibold">+ Add vendor</span> to start.
        </div>
      ) : (
        <div className="space-y-2">
          {stakeholders.map((s, idx) => {
            const display = resolveDisplay(s);
            if (!display) return null;
            return (
              <div key={idx} className="border border-line rounded-md p-3 bg-paper relative">
                <div className="flex items-start gap-3">
                  <div className="w-9 h-9 rounded flex items-center justify-center text-[11px] font-mono font-semibold text-white shrink-0" style={{ background: display.accent }}>{display.initials}</div>
                  <div className="flex-1 min-w-0">
                    <div className="flex items-center gap-2 flex-wrap mb-1">
                      <span className="text-[13px] ink font-medium">{display.name}</span>
                      <span className="text-[9px] font-mono uppercase tracking-wider px-1.5 py-0.5 rounded bg-bone text-terra border border-terra">{display.type}</span>
                      {display.isPending && (
                        <span className="text-[9px] font-mono uppercase tracking-wider px-1.5 py-0.5 rounded bg-terra-soft text-terra border border-terra">Will be created</span>
                      )}
                    </div>
                    <div className="grid grid-cols-2 gap-2">
                      <FieldGroup label="Role on this project">
                        <TextField value={s.projectRole || ''} onChange={(v) => updateStakeholder(idx, 'projectRole', v)} placeholder="e.g. Civil + finishing — primary contractor" />
                      </FieldGroup>
                      <FieldGroup label="Project notes">
                        <TextField value={s.projectNotes || ''} onChange={(v) => updateStakeholder(idx, 'projectNotes', v)} placeholder="Site contact, terms, anything else…" />
                      </FieldGroup>
                    </div>
                  </div>
                  <button onClick={() => removeStakeholder(idx)} className="p-1 hover:bg-bone rounded ink-faint hover:text-terra shrink-0">
                    <X className="w-3.5 h-3.5" />
                  </button>
                </div>
              </div>
            );
          })}
        </div>
      )}
    </Section>
  );
}

/* ================================================================== */
/* ===================== PROPERTY HIERARCHY ========================= */
/* ================================================================== */

/* ====================================================================
   Step 3 — Spatial cascade tree editor
   Branches: Level → Zone → Space → Feature → Element
   Element leaves: 5 sibling lists (Specs, Checklists, Drawings, Refs, BOQ)
   ==================================================================== */

const hierarchyConfig = [
  { key: 'level',   label: 'Level',   plural: 'levels',   childKey: 'zones',    icon: Layers,   marker: 'L',  defaultExpanded: true,  accent: '#1A1815' },
  { key: 'zone',    label: 'Zone',    plural: 'zones',    childKey: 'spaces',   icon: Folder,   marker: 'Z',  defaultExpanded: true,  accent: '#B4593C' },
  { key: 'space',   label: 'Space',   plural: 'spaces',   childKey: 'features', icon: Box,      marker: 'S',  defaultExpanded: false, accent: '#6B7355' },
  { key: 'feature', label: 'Feature', plural: 'features', childKey: 'elements', icon: Layers,   marker: 'F',  defaultExpanded: false, accent: '#A67C5A' },
  { key: 'element', label: 'Element', plural: 'elements', childKey: null,       icon: Palette,  marker: 'E',  defaultExpanded: false, accent: '#7A4A4A' },
];

const leafConfig = {
  specs: {
    label: 'Specifications', singular: 'spec', icon: FileCheck2, color: 'text-moss', bg: 'bg-moss-soft', tone: '#6B7355',
    catalogMaster: 'MasterSpecifications', editMode: 'inline', empty: () => buildEmptySpec(),
    summary: (it) => it.unit && it.baseRate ? `${it.unit} · ₹${it.baseRate}` : (it.unit || it.baseRate ? (it.unit || `₹${it.baseRate}`) : null),
    fromCatalog: (row) => ({ id: uid(), name: row.value, masterRef: row.id, unit: row.unit || '', baseRate: row.baseRate || '' }),
  },
  checklists: {
    label: 'Checklists', singular: 'checklist', icon: ListChecks, color: 'text-terra', bg: 'bg-terra-soft', tone: '#B4593C',
    catalogMaster: 'MasterChecklists', editMode: 'inline', empty: () => buildEmptyChecklist(),
    summary: (it) => it.description ? it.description.slice(0, 60) + (it.description.length > 60 ? '…' : '') : null,
    fromCatalog: (row) => ({ id: uid(), name: row.value, masterRef: row.id, description: row.description || '' }),
  },
  drawings: {
    label: 'Drawings', singular: 'drawing', icon: FileText, color: 'text-clay', bg: 'bg-bone', tone: '#A67C5A',
    catalogMaster: 'MasterDrawings', editMode: 'modal', empty: () => buildEmptyDrawing(),
    summary: (it) => `${it.drawingType || 'Plan'} · ${it.revision || 'R0'}${it.status ? ' · ' + it.status : ''}`,
    fromCatalog: (row) => ({ id: uid(), name: row.value, masterRef: row.id, drawingType: row.drawingType || 'Plan', status: 'Draft', revision: 'R0', description: row.description || '' }),
  },
  references: {
    label: 'References', singular: 'reference', icon: BookOpen, color: 'text-moss', bg: 'bg-bone', tone: '#5A7A4F',
    catalogMaster: 'MasterReferences', editMode: 'modal', empty: () => buildEmptyReference(),
    summary: (it) => it.referenceType ? it.referenceType + (it.url ? ' · linked' : '') : null,
    fromCatalog: (row) => ({ id: uid(), name: row.value, masterRef: row.id, referenceType: row.referenceType || 'Inspiration', description: row.description || '', url: '' }),
  },
  boqItems: {
    label: 'BOQ Items', singular: 'BOQ item', icon: Coins, color: 'text-terra', bg: 'bg-bone', tone: '#C4602B',
    catalogMaster: 'MasterBOQItems', editMode: 'modal', empty: () => buildEmptyBOQItem(),
    summary: (it) => {
      const qty = parseFloat(it.quantity) || 0;
      const rate = parseFloat(it.rate) || 0;
      const total = qty * rate;
      if (total > 0) return `${qty} ${it.unit || 'sqft'} × ₹${rate} = ₹${total.toLocaleString('en-IN')}`;
      if (qty || rate) return `${qty} ${it.unit || 'sqft'} · ₹${rate || '?'}`;
      return null;
    },
    fromCatalog: (row) => ({ id: uid(), name: row.value, masterRef: row.id, unit: row.unit || 'sqft', quantity: '', rate: row.baseRate || '', category: row.category || '' }),
  },
};

const LEAF_ORDER = ['specs', 'checklists', 'drawings', 'references', 'boqItems'];

/* ===== Tree mutation helpers — find a node by path and update its subtree ===== */
function pathReplace(rootArr, path, updater) {
  // path = [{ branchKey, idx }, ...] descending into the tree
  if (path.length === 0) return updater(rootArr);
  const [head, ...rest] = path;
  return rootArr.map((node, i) => {
    if (i !== head.idx) return node;
    if (rest.length === 0) return updater(node);
    const childKey = hierarchyConfig.find(h => h.key === head.branchKey)?.childKey;
    if (!childKey) return node;
    return { ...node, [childKey]: pathReplace(node[childKey] || [], rest, updater) };
  });
}

function PropertyHierarchyEditor({ data, update, onResetCascade, masters }) {
  const levels = data.projectLevels || [];
  const [catalogPicker, setCatalogPicker] = useState(null);
  const [leafEditor, setLeafEditor] = useState(null);
  /* Phase 9.0.7 — Custom modals because Claude artifact iframe blocks
     window.prompt() and window.confirm() (sandbox restriction). */
  const [pasteManyModal, setPasteManyModal] = useState(null); // { parentPath, branchKey, childLabel }
  const [confirmModal, setConfirmModal] = useState(null);     // { message, onConfirm }

  if (!data.propertyType) {
    return (
      <div className="bg-paper border border-line rounded-lg p-5">
        <h3 className="font-display text-lg ink tracking-tight leading-tight">Spatial program</h3>
        <div className="text-[11px] ink-soft mt-0.5 mb-4">Level → Zone → Space → Feature → Element → 5 leaves</div>
        <div className="bg-bone rounded border border-line-soft p-6 text-center">
          <Folder className="w-6 h-6 ink-faint mx-auto mb-2" />
          <div className="text-sm ink-soft">Pick a Property Type above to load the spatial cascade.</div>
          <div className="text-[10px] ink-faint font-mono mt-1">Levels are auto-fetched from MasterLevels, then become editable per-project.</div>
        </div>
      </div>
    );
  }

  const updateTree = (newLevels) => update('projectLevels', newLevels);
  const counts = countTree(levels);
  const totalLeaves = counts.specs + counts.checklists + counts.drawings + counts.references + counts.boqItems;

  /* ===== Branch mutations ===== */
  const renameNode = (path, newName) => {
    updateTree(pathReplace(levels, path, (n) => ({ ...n, name: newName })));
  };
  const toggleExpand = (path) => {
    updateTree(pathReplace(levels, path, (n) => ({ ...n, expanded: !n.expanded })));
  };
  const addChild = (parentPath, branchKey, customName) => {
    const config = hierarchyConfig.find(h => h.key === branchKey);
    if (!config || !config.childKey) return;
    /* Phase 9.0.2 — Fix: lookup the child row by `plural === config.childKey`, not by `childKey === config.childKey`.
       Previously this returned the WRONG row (or none), causing 'New Level' to appear under Zones, etc. */
    const childRow = hierarchyConfig.find(h => h.plural === config.childKey);
    const childLabel = childRow?.label || 'item';
    const finalName = (customName && customName.trim()) || `New ${childLabel}`;
    const child = config.key === 'element'
      ? { id: uid(), name: finalName, expanded: true, [config.childKey]: [] }
      : { id: uid(), name: finalName, expanded: true, [config.childKey]: [] };
    // Element children are leaf groups, not branches:
    if (config.key === 'feature') {
      child.expanded = false;
      child.specs = []; child.checklists = []; child.drawings = []; child.references = []; child.boqItems = [];
      delete child[config.childKey]; // element doesn't use childKey at all
    }
    updateTree(pathReplace(levels, parentPath, (parent) => {
      const childArr = parent[config.childKey] || [];
      return { ...parent, [config.childKey]: [...childArr, child] };
    }));
  };

  /* Phase 9.0.2 — Batch add multiple children in ONE state update.
     Solves the stale-state issue when calling addChild repeatedly in a forEach. */
  const addChildrenBatch = (parentPath, branchKey, names) => {
    const config = hierarchyConfig.find(h => h.key === branchKey);
    if (!config || !config.childKey) return;
    if (!Array.isArray(names) || names.length === 0) return;
    const childRow = hierarchyConfig.find(h => h.plural === config.childKey);
    const childLabel = childRow?.label || 'item';
    const newChildren = names.map((nm) => {
      const finalName = (nm && nm.trim()) || `New ${childLabel}`;
      const child = { id: uid(), name: finalName, expanded: true, [config.childKey]: [] };
      if (config.key === 'feature') {
        child.expanded = false;
        child.specs = []; child.checklists = []; child.drawings = []; child.references = []; child.boqItems = [];
        delete child[config.childKey];
      }
      return child;
    });
    updateTree(pathReplace(levels, parentPath, (parent) => {
      const childArr = parent[config.childKey] || [];
      return { ...parent, [config.childKey]: [...childArr, ...newChildren] };
    }));
  };
  const removeNode = (path) => {
    /* Phase 9.0.7 — replace window.confirm (blocked by sandbox) with custom modal */
    setConfirmModal({
      message: 'Remove this node and everything inside it?',
      onConfirm: () => {
        if (path.length === 0) return;
        const parentPath = path.slice(0, -1);
        const last = path[path.length - 1];
        const parentBranch = parentPath.length === 0 ? 'root' : parentPath[parentPath.length - 1].branchKey;
        const childKey = parentPath.length === 0 ? null : hierarchyConfig.find(h => h.key === parentBranch)?.childKey;
        if (parentPath.length === 0) {
          // top-level removal (a Level)
          updateTree(levels.filter((_, i) => i !== last.idx));
        } else {
          updateTree(pathReplace(levels, parentPath, (parent) => ({
            ...parent,
            [childKey]: (parent[childKey] || []).filter((_, i) => i !== last.idx),
          })));
        }
      },
    });
  };

  /* Phase 9.0.3 — Move a node up or down within its parent's siblings.
     direction: -1 (up) or +1 (down). No-op if already at edge. */
  const moveSibling = (path, direction) => {
    if (path.length === 0) return;
    const parentPath = path.slice(0, -1);
    const last = path[path.length - 1];
    const parentBranch = parentPath.length === 0 ? 'root' : parentPath[parentPath.length - 1].branchKey;
    const childKey = parentPath.length === 0 ? null : hierarchyConfig.find(h => h.key === parentBranch)?.childKey;

    const swap = (arr, from, to) => {
      if (to < 0 || to >= arr.length) return arr;
      const next = [...arr];
      [next[from], next[to]] = [next[to], next[from]];
      return next;
    };

    if (parentPath.length === 0) {
      updateTree(swap(levels, last.idx, last.idx + direction));
    } else {
      updateTree(pathReplace(levels, parentPath, (parent) => ({
        ...parent,
        [childKey]: swap(parent[childKey] || [], last.idx, last.idx + direction),
      })));
    }
  };
  const addTopLevel = () => {
    updateTree([...levels, { id: uid(), name: 'New Level', expanded: true, levelType: 'Ground', levelOrder: levels.length, zones: [] }]);
  };

  /* ===== Leaf mutations ===== */
  // elementPath: path to the element node
  const updateLeafItem = (elementPath, leafKey, leafIdx, updates) => {
    updateTree(pathReplace(levels, elementPath, (el) => ({
      ...el,
      [leafKey]: (el[leafKey] || []).map((item, i) => i === leafIdx ? { ...item, ...updates } : item),
    })));
  };
  const addLeafItem = (elementPath, leafKey, item) => {
    updateTree(pathReplace(levels, elementPath, (el) => ({
      ...el,
      [leafKey]: [...(el[leafKey] || []), item],
    })));
  };
  const removeLeafItem = (elementPath, leafKey, leafIdx) => {
    updateTree(pathReplace(levels, elementPath, (el) => ({
      ...el,
      [leafKey]: (el[leafKey] || []).filter((_, i) => i !== leafIdx),
    })));
  };

  return (
    <div className="bg-paper border border-line rounded-lg p-5">
      {/* Header */}
      <div className="flex items-start justify-between mb-4 flex-wrap gap-3">
        <div>
          <div className="flex items-center gap-2 mb-0.5">
            <h3 className="font-display text-lg ink tracking-tight leading-tight">Spatial program</h3>
            <Tag tone="terra">Project copy</Tag>
          </div>
          <div className="text-[11px] ink-soft">
            <code className="font-mono ink">Level → Zone → Space → Feature → Element → 5 leaves</code> · loaded from masters · edits stay on this project
          </div>
        </div>
        <div className="flex items-center gap-2">
          <button onClick={addTopLevel} className="text-[11px] font-mono text-terra hover:ink flex items-center gap-1 px-2 py-1.5 border border-terra rounded hover:bg-terra-soft">
            <Plus className="w-3 h-3" /> Add level
          </button>
          {onResetCascade && (
            <button onClick={onResetCascade} className="text-[11px] font-mono ink-soft hover:ink flex items-center gap-1 px-2 py-1.5 border border-line rounded hover:bg-bone">
              <RefreshCw className="w-3 h-3" /> Reset
            </button>
          )}
        </div>
      </div>

      {/* Counts strip */}
      <div className="grid grid-cols-5 gap-1.5 mb-2">
        {hierarchyConfig.map((h) => (
          <div key={h.key} className="px-2 py-1.5 bg-bone rounded border border-line-soft text-center">
            <div className="text-base font-display ink leading-none">{counts[h.plural] || 0}</div>
            <div className="text-[9px] font-mono ink-faint mt-0.5 uppercase tracking-wider">{h.plural}</div>
          </div>
        ))}
      </div>
      <div className="grid grid-cols-5 gap-1.5 mb-4">
        {LEAF_ORDER.map((k) => (
          <div key={k} className="px-2 py-1.5 bg-paper rounded border border-line-soft text-center" style={{ borderLeftWidth: '2px', borderLeftColor: leafConfig[k].tone }}>
            <div className="text-sm font-display ink leading-none">{counts[k] || 0}</div>
            <div className="text-[9px] font-mono ink-faint mt-0.5 uppercase tracking-wider">{leafConfig[k].label}</div>
          </div>
        ))}
      </div>

      {/* Empty state */}
      {levels.length === 0 ? (
        <div className="bg-bone rounded border border-line-soft p-6 text-center">
          <Layers className="w-6 h-6 ink-faint mx-auto mb-2" />
          <div className="text-sm ink-soft mb-1">No levels yet</div>
          <div className="text-[10px] ink-faint font-mono">Add a Level to start building the spatial program.</div>
        </div>
      ) : (
        <div className="space-y-1">
          {levels.map((node, i) => (
            <BranchNode
              key={node.id}
              node={node}
              depth={0}
              path={[{ branchKey: 'level', idx: i }]}
              siblingCount={levels.length}
              onRename={renameNode}
              onToggle={toggleExpand}
              onAddChild={addChild}
              onAddChildrenBatch={addChildrenBatch}
              onOpenPasteMany={(parentPath, branchKey, childLabel, childPlural) =>
                setPasteManyModal({ parentPath, branchKey, childLabel, childPlural })
              }
              onMove={moveSibling}
              onRemove={removeNode}
              onUpdateLeaf={updateLeafItem}
              onAddLeaf={addLeafItem}
              onRemoveLeaf={removeLeafItem}
              onOpenCatalog={(elPath, leafKey) => setCatalogPicker({ elementPath: elPath, leafKey })}
              onOpenLeafEditor={(elPath, leafKey, leafIdx, item) => setLeafEditor({ elementPath: elPath, leafKey, leafIdx, item })}
            />
          ))}
        </div>
      )}

      <div className="mt-3 text-[10px] ink-faint font-mono">
        Total: <span className="ink font-semibold">{counts.elements}</span> elements · <span className="ink font-semibold">{totalLeaves}</span> leaves across 5 lenses
      </div>

      {/* Catalog picker modal */}
      {catalogPicker && (
        <CatalogPicker
          masters={masters}
          leafKey={catalogPicker.leafKey}
          onPick={(item) => {
            addLeafItem(catalogPicker.elementPath, catalogPicker.leafKey, item);
            setCatalogPicker(null);
          }}
          onCustom={() => {
            const empty = leafConfig[catalogPicker.leafKey].empty();
            empty.name = `New ${leafConfig[catalogPicker.leafKey].singular}`;
            addLeafItem(catalogPicker.elementPath, catalogPicker.leafKey, empty);
            setCatalogPicker(null);
            // Open editor for modal-edit leaves so the user can fill in details
            if (leafConfig[catalogPicker.leafKey].editMode === 'modal') {
              const element = (() => {
                let cur = levels;
                for (let i = 0; i < catalogPicker.elementPath.length; i++) {
                  const step = catalogPicker.elementPath[i];
                  const branchCfg = hierarchyConfig.find(h => h.key === step.branchKey);
                  cur = cur[step.idx];
                  if (branchCfg && branchCfg.childKey && i < catalogPicker.elementPath.length - 1) cur = cur[branchCfg.childKey];
                }
                return cur;
              })();
              const newIdx = (element[catalogPicker.leafKey] || []).length; // post-add index
              setLeafEditor({ elementPath: catalogPicker.elementPath, leafKey: catalogPicker.leafKey, leafIdx: newIdx, item: empty });
            }
          }}
          onClose={() => setCatalogPicker(null)}
        />
      )}

      {/* Modal leaf editor */}
      {leafEditor && (
        <LeafModal
          leafKey={leafEditor.leafKey}
          item={leafEditor.item}
          onSave={(updates) => {
            updateLeafItem(leafEditor.elementPath, leafEditor.leafKey, leafEditor.leafIdx, updates);
            setLeafEditor(null);
          }}
          onClose={() => setLeafEditor(null)}
        />
      )}

      {/* Phase 9.0.7 — Custom modals (window.prompt/confirm blocked by sandbox) */}
      {pasteManyModal && (
        <PasteManyModal
          childLabel={pasteManyModal.childLabel}
          childPlural={pasteManyModal.childPlural}
          onClose={() => setPasteManyModal(null)}
          onSubmit={(lines) => {
            if (lines.length === 0) {
              setPasteManyModal(null);
              return;
            }
            addChildrenBatch(pasteManyModal.parentPath, pasteManyModal.branchKey, lines);
            setPasteManyModal(null);
          }}
        />
      )}

      {confirmModal && (
        <ConfirmModal
          message={confirmModal.message}
          onConfirm={() => {
            confirmModal.onConfirm();
            setConfirmModal(null);
          }}
          onCancel={() => setConfirmModal(null)}
        />
      )}
    </div>
  );
}

/* ============================================================================
   ===== Phase 9.0.7 — PasteManyModal =========================================
   Custom modal because window.prompt() is blocked in Claude artifact sandbox.
   ============================================================================ */
function PasteManyModal({ childLabel, childPlural, onClose, onSubmit }) {
  const [text, setText] = useState('');
  const submit = () => {
    const lines = text.split('\n').map((l) => l.trim()).filter(Boolean);
    onSubmit(lines);
  };
  return (
    <div className="fixed inset-0 bg-black/40 flex items-center justify-center z-50" onClick={onClose}>
      <div className="bg-paper border border-line rounded-lg p-5 max-w-lg w-full mx-4" onClick={(e) => e.stopPropagation()}>
        <div className="flex items-center justify-between mb-3">
          <div>
            <h3 className="font-display text-lg ink leading-tight">Paste many {childPlural}</h3>
            <div className="text-[11px] ink-soft mt-0.5">One {childLabel.toLowerCase()} per line. Empty lines are skipped.</div>
          </div>
          <button onClick={onClose} className="ink-faint hover:ink p-1"><X className="w-4 h-4" /></button>
        </div>
        <textarea
          value={text}
          onChange={(e) => setText(e.target.value)}
          placeholder={`e.g.\nEntrance Gate\nSecurity Cabin\nDrop-off Porch`}
          autoFocus
          rows={10}
          className="w-full bg-bone border border-line rounded px-3 py-2 text-sm ink font-mono resize-y focus:outline-none focus:border-terra"
        />
        <div className="flex items-center justify-between mt-3">
          <div className="text-[10px] font-mono ink-faint">
            {text.split('\n').map((l) => l.trim()).filter(Boolean).length} {childPlural} ready to add
          </div>
          <div className="flex gap-2">
            <button onClick={onClose} className="px-3 py-1.5 text-[11px] font-mono ink-soft hover:ink rounded border border-line-soft hover:bg-bone">Cancel</button>
            <button onClick={submit} className="px-3 py-1.5 text-[11px] font-mono bg-terra text-white rounded hover:bg-ink">Add all</button>
          </div>
        </div>
      </div>
    </div>
  );
}

/* ============================================================================
   ===== Phase 9.0.7 — ConfirmModal ===========================================
   Custom modal because window.confirm() is blocked in Claude artifact sandbox.
   ============================================================================ */
function ConfirmModal({ message, onConfirm, onCancel, confirmLabel, cancelLabel }) {
  return (
    <div className="fixed inset-0 bg-black/40 flex items-center justify-center z-50" onClick={onCancel}>
      <div className="bg-paper border border-line rounded-lg p-5 max-w-md w-full mx-4" onClick={(e) => e.stopPropagation()}>
        <div className="flex items-start gap-3 mb-4">
          <div className="w-8 h-8 rounded-full bg-terra-soft flex items-center justify-center shrink-0">
            <AlertCircle className="w-4 h-4 text-terra" />
          </div>
          <div className="flex-1 pt-0.5">
            <div className="text-sm ink">{message}</div>
          </div>
        </div>
        <div className="flex justify-end gap-2">
          <button onClick={onCancel}  className="px-3 py-1.5 text-[11px] font-mono ink-soft hover:ink rounded border border-line-soft hover:bg-bone">
            {cancelLabel || 'Cancel'}
          </button>
          <button onClick={onConfirm} className="px-3 py-1.5 text-[11px] font-mono bg-terra text-white rounded hover:bg-ink">
            {confirmLabel || 'Confirm'}
          </button>
        </div>
      </div>
    </div>
  );
}

/* ============== BranchNode — recursive Level/Zone/Space/Feature/Element ============== */
function BranchNode({ node, depth, path, siblingCount, onRename, onToggle, onAddChild, onAddChildrenBatch, onOpenPasteMany, onMove, onRemove, onUpdateLeaf, onAddLeaf, onRemoveLeaf, onOpenCatalog, onOpenLeafEditor }) {
  const config = hierarchyConfig[depth];
  if (!config) return null;
  const Icon = config.icon;
  const isElement = config.key === 'element';
  const childKey = config.childKey;
  const children = isElement ? null : (node[childKey] || []);
  const childCount = isElement
    ? LEAF_ORDER.reduce((sum, k) => sum + ((node[k] || []).length), 0)
    : (children || []).length;
  const isExpanded = !!node.expanded;

  const [isEditing, setIsEditing] = useState(false);
  const [editName, setEditName] = useState(node.name || '');
  React.useEffect(() => { setEditName(node.name || ''); }, [node.name]);

  const commitName = () => {
    const trimmed = (editName || '').trim();
    if (trimmed && trimmed !== node.name) onRename(path, trimmed);
    else setEditName(node.name || '');
    setIsEditing(false);
  };

  // Indentation: 16px per depth (5 levels max → 0/16/32/48/64px)
  const indent = depth * 16;
  const childConfig = !isElement ? hierarchyConfig[depth + 1] : null;

  return (
    <div className="group" style={{ marginLeft: depth === 0 ? 0 : indent }}>
      <div
        className={`flex items-center gap-2 py-1.5 px-2 rounded transition-colors ${
          isExpanded ? 'bg-bone' : 'hover:bg-bone'
        }`}
        style={{ borderLeft: depth > 0 ? `2px solid ${config.accent}33` : 'none' }}
      >
        {/* Expand/collapse toggle */}
        {!isElement && (
          <button onClick={() => onToggle(path)} className="ink-soft hover:ink shrink-0">
            {isExpanded ? <ChevronDown className="w-3.5 h-3.5" /> : <ChevronRight className="w-3.5 h-3.5" />}
          </button>
        )}
        {isElement && <div className="w-3.5 shrink-0" />}

        {/* Marker chip */}
        <div
          className="px-1.5 py-0.5 rounded text-[9px] font-mono uppercase tracking-wider font-semibold shrink-0"
          style={{ background: `${config.accent}15`, color: config.accent }}
          title={config.label}
        >
          {config.marker}
        </div>

        {/* Icon */}
        <Icon className="w-3.5 h-3.5 shrink-0" style={{ color: config.accent }} strokeWidth={2} />

        {/* Name (inline-editable) */}
        {isEditing ? (
          <input
            autoFocus
            value={editName}
            onChange={(e) => setEditName(e.target.value)}
            onBlur={commitName}
            onKeyDown={(e) => {
              if (e.key === 'Enter') commitName();
              if (e.key === 'Escape') { setEditName(node.name || ''); setIsEditing(false); }
            }}
            className="input-sm flex-1 min-w-0 text-xs"
          />
        ) : (
          <span
            onClick={() => setIsEditing(true)}
            className="text-xs ink font-medium flex-1 min-w-0 truncate cursor-text hover:bg-paper -mx-1 px-1 rounded"
            title="Click to rename"
          >
            {node.name || `(unnamed ${config.label.toLowerCase()})`}
          </span>
        )}

        {/* Count badge */}
        <span className="text-[9px] font-mono ink-faint shrink-0 px-1.5 py-0.5 bg-paper rounded">
          {isElement ? `${childCount} leaves` : `${childCount} ${(childConfig?.plural) || 'children'}`}
        </span>

        {/* Action buttons */}
        <div className="flex items-center gap-0.5 shrink-0 opacity-0 group-hover:opacity-100">
          {!isElement && childKey && (
            <button
              onClick={() => onAddChild(path, config.key)}
              className="text-[10px] font-mono text-terra hover:ink p-1 rounded hover:bg-paper"
              title={`Add ${childConfig?.label || 'child'}`}
            >
              + {childConfig?.label.toLowerCase()}
            </button>
          )}
          {/* Phase 9.0.3 — Multi-line paste available at every non-element parent
               (Level → Zones, Zone → Spaces, Space → Features, Feature → Elements)
               Phase 9.0.7 — uses custom modal (window.prompt blocked by sandbox) */}
          {!isElement && childConfig && (
            <button
              onClick={() => {
                if (onOpenPasteMany) {
                  onOpenPasteMany(path, config.key, childConfig.label, childConfig.plural);
                }
              }}
              className="text-[10px] font-mono ink-soft hover:text-terra p-1 rounded hover:bg-paper"
              title={`Paste multiple ${childConfig.plural}, one per line`}
            >
              ⊕ paste many
            </button>
          )}
          {/* Phase 9.0.3 — up/down arrows to reorder this node within its siblings */}
          {onMove && (() => {
            const myIdx = path[path.length - 1]?.idx ?? 0;
            const total = siblingCount ?? 1;
            return (
              <>
                <button
                  onClick={() => onMove(path, -1)}
                  disabled={myIdx === 0}
                  className="p-1 rounded hover:bg-paper disabled:opacity-30 disabled:cursor-not-allowed"
                  title="Move up"
                >
                  <ChevronUp className="w-3 h-3 ink-soft" />
                </button>
                <button
                  onClick={() => onMove(path, 1)}
                  disabled={myIdx >= total - 1}
                  className="p-1 rounded hover:bg-paper disabled:opacity-30 disabled:cursor-not-allowed"
                  title="Move down"
                >
                  <ChevronDown className="w-3 h-3 ink-soft" />
                </button>
              </>
            );
          })()}
          <button
            onClick={() => onRemove(path)}
            className="p-1 rounded hover:bg-paper"
            title="Remove"
          >
            <Trash2 className="w-3 h-3 text-terra" />
          </button>
        </div>
      </div>

      {/* Expanded body */}
      {isExpanded && !isElement && children && children.length > 0 && (
        <div className="mt-1 mb-1">
          {children.map((child, i) => (
            <BranchNode
              key={child.id}
              node={child}
              depth={depth + 1}
              path={[...path, { branchKey: childConfig.key, idx: i }]}
              siblingCount={children.length}
              onRename={onRename}
              onToggle={onToggle}
              onAddChild={onAddChild}
              onAddChildrenBatch={onAddChildrenBatch}
              onOpenPasteMany={onOpenPasteMany}
              onMove={onMove}
              onRemove={onRemove}
              onUpdateLeaf={onUpdateLeaf}
              onAddLeaf={onAddLeaf}
              onRemoveLeaf={onRemoveLeaf}
              onOpenCatalog={onOpenCatalog}
              onOpenLeafEditor={onOpenLeafEditor}
            />
          ))}
        </div>
      )}

      {/* Element leaf grid */}
      {isElement && (
        <ElementLeafGrid
          node={node}
          path={path}
          onUpdate={(leafKey, leafIdx, updates) => onUpdateLeaf(path, leafKey, leafIdx, updates)}
          onAdd={(leafKey, item) => onAddLeaf(path, leafKey, item)}
          onRemove={(leafKey, leafIdx) => onRemoveLeaf(path, leafKey, leafIdx)}
          onOpenCatalog={(leafKey) => onOpenCatalog(path, leafKey)}
          onOpenEditor={(leafKey, leafIdx, item) => onOpenLeafEditor(path, leafKey, leafIdx, item)}
        />
      )}
    </div>
  );
}

/* ============== ElementLeafGrid — 5 leaf-type tabs under an Element ============== */
function ElementLeafGrid({ node, path, onUpdate, onAdd, onRemove, onOpenCatalog, onOpenEditor }) {
  const [activeLeaf, setActiveLeaf] = useState('specs');
  const indent = 5 * 16; // depth 5 indent (under Element which is depth 4)

  return (
    <div style={{ marginLeft: indent }} className="mt-1 mb-2 bg-paper border border-line-soft rounded-md overflow-hidden">
      {/* Leaf-type tab bar */}
      <div className="flex items-center border-b border-line-soft bg-bone">
        {LEAF_ORDER.map((k) => {
          const cfg = leafConfig[k];
          const Icon = cfg.icon;
          const count = (node[k] || []).length;
          const isActive = activeLeaf === k;
          return (
            <button
              key={k}
              onClick={() => setActiveLeaf(k)}
              className={`flex-1 flex items-center justify-center gap-1.5 px-2 py-1.5 text-[10px] font-mono uppercase tracking-wider transition-colors border-b-2 ${
                isActive ? 'bg-paper border-current ' + cfg.color + ' font-semibold' : 'ink-soft border-transparent hover:bg-paper'
              }`}
              style={isActive ? { borderBottomColor: cfg.tone } : {}}
            >
              <Icon className="w-3 h-3" />
              <span>{cfg.label}</span>
              {count > 0 && <span className="ml-0.5 font-semibold">{count}</span>}
            </button>
          );
        })}
      </div>

      {/* Leaf list */}
      <div className="p-2.5 space-y-1.5">
        {(node[activeLeaf] || []).length === 0 && (
          <div className="text-[10px] ink-faint italic text-center py-2">
            No {leafConfig[activeLeaf].label.toLowerCase()} yet for this element.
          </div>
        )}

        {(node[activeLeaf] || []).map((item, i) => (
          leafConfig[activeLeaf].editMode === 'inline' ? (
            <InlineLeafRow
              key={item.id || i}
              item={item}
              leafKey={activeLeaf}
              onUpdate={(updates) => onUpdate(activeLeaf, i, updates)}
              onRemove={() => onRemove(activeLeaf, i)}
            />
          ) : (
            <ModalLeafRow
              key={item.id || i}
              item={item}
              leafKey={activeLeaf}
              onClick={() => onOpenEditor(activeLeaf, i, item)}
              onUpdate={(updates) => onUpdate(activeLeaf, i, updates)}
              onRemove={() => onRemove(activeLeaf, i)}
            />
          )
        ))}

        <div className="flex items-center justify-center pt-1">
          <button
            onClick={() => onOpenCatalog(activeLeaf)}
            className="text-[10px] font-mono text-terra hover:ink flex items-center gap-1 px-2 py-1 rounded hover:bg-bone"
          >
            <Plus className="w-3 h-3" /> Add {leafConfig[activeLeaf].singular}
          </button>
        </div>
      </div>
    </div>
  );
}

/* ============== InlineLeafRow — for Specs and Checklists (click name to edit) ============== */
function InlineLeafRow({ item, leafKey, onUpdate, onRemove }) {
  const cfg = leafConfig[leafKey];
  const [editing, setEditing] = useState(false);
  const [name, setName] = useState(item.name || '');
  React.useEffect(() => { setName(item.name || ''); }, [item.name]);

  const commit = () => {
    const trimmed = (name || '').trim();
    if (trimmed && trimmed !== item.name) onUpdate({ name: trimmed });
    else setName(item.name || '');
    setEditing(false);
  };

  const summary = cfg.summary(item);

  const recordType = leafKey === 'specs' ? 'spec'
    : leafKey === 'checklists' ? 'checklist'
    : leafKey === 'drawings' ? 'drawing'
    : leafKey === 'references' ? 'reference'
    : leafKey === 'boqItems' ? 'boqItem'
    : 'spec';

  return (
    <div className="flex items-center gap-2 py-1.5 px-2 bg-bone rounded text-xs hover:bg-paper group/row" style={{ borderLeft: `2px solid ${cfg.tone}` }}>
      <cfg.icon className="w-3 h-3 shrink-0" style={{ color: cfg.tone }} />
      {editing ? (
        <input
          autoFocus
          value={name}
          onChange={(e) => setName(e.target.value)}
          onBlur={commit}
          onKeyDown={(e) => {
            if (e.key === 'Enter') commit();
            if (e.key === 'Escape') { setName(item.name || ''); setEditing(false); }
          }}
          className="input-sm flex-1 min-w-0 text-[11px]"
        />
      ) : (
        <span
          onClick={() => setEditing(true)}
          className="ink flex-1 min-w-0 truncate cursor-text hover:bg-paper -mx-1 px-1 rounded"
        >
          {item.name || <span className="ink-faint italic">(unnamed)</span>}
        </span>
      )}
      {summary && <span className="text-[10px] font-mono ink-faint shrink-0">{summary}</span>}
      <VisibilityChip record={item} recordType={recordType} onChange={(updates) => onUpdate(updates)} compact />
      {item.masterRef && (
        <span className="text-[9px] font-mono ink-faint shrink-0" title="Linked to catalog">
          <Database className="w-2.5 h-2.5 inline" />
        </span>
      )}
      <button
        onClick={onRemove}
        className="opacity-0 group-hover/row:opacity-100 p-0.5 rounded hover:bg-bone shrink-0"
        title="Remove"
      >
        <Trash2 className="w-3 h-3 text-terra" />
      </button>
    </div>
  );
}

/* ============== ModalLeafRow — for Drawings, References, BOQ (click row to edit) ============== */
function ModalLeafRow({ item, leafKey, onClick, onUpdate, onRemove }) {
  const cfg = leafConfig[leafKey];
  const summary = cfg.summary(item);
  const recordType = leafKey === 'drawings' ? 'drawing'
    : leafKey === 'references' ? 'reference'
    : leafKey === 'boqItems' ? 'boqItem'
    : 'spec';

  return (
    <div className="flex items-center gap-2 py-1.5 px-2 bg-bone rounded text-xs hover:bg-paper group/row cursor-pointer" style={{ borderLeft: `2px solid ${cfg.tone}` }} onClick={onClick}>
      <cfg.icon className="w-3 h-3 shrink-0" style={{ color: cfg.tone }} />
      <span className="ink flex-1 min-w-0 truncate font-medium">
        {item.name || <span className="ink-faint italic">(unnamed)</span>}
      </span>
      {summary && <span className="text-[10px] font-mono ink-faint shrink-0">{summary}</span>}
      <span onClick={(e) => e.stopPropagation()}>
        <VisibilityChip record={item} recordType={recordType} onChange={(updates) => onUpdate && onUpdate(updates)} compact />
      </span>
      {item.masterRef && (
        <span className="text-[9px] font-mono ink-faint shrink-0" title="Linked to catalog">
          <Database className="w-2.5 h-2.5 inline" />
        </span>
      )}
      <Edit3 className="w-3 h-3 ink-faint shrink-0" />
      <button
        onClick={(e) => { e.stopPropagation(); onRemove(); }}
        className="opacity-0 group-hover/row:opacity-100 p-0.5 rounded hover:bg-bone shrink-0"
        title="Remove"
      >
        <Trash2 className="w-3 h-3 text-terra" />
      </button>
    </div>
  );
}

/* ============== CatalogPicker — modal showing master catalog entries ============== */
function CatalogPicker({ masters, leafKey, onPick, onCustom, onClose }) {
  const cfg = leafConfig[leafKey];
  const Icon = cfg.icon;
  const catalogRows = masters[cfg.catalogMaster] || [];

  return (
    <div className="modal-backdrop" onClick={onClose}>
      <div className="modal-card" onClick={(e) => e.stopPropagation()} style={{ maxWidth: '560px' }}>
        <div className="flex items-center justify-between px-5 py-3 border-b border-line">
          <div className="flex items-center gap-2">
            <Icon className="w-4 h-4" style={{ color: cfg.tone }} />
            <h3 className="font-display text-base ink">Add {cfg.singular} from {cfg.catalogMaster}</h3>
          </div>
          <button onClick={onClose} className="ink-soft hover:ink"><X className="w-4 h-4" /></button>
        </div>
        <div className="p-4 max-h-96 overflow-y-auto scrollbar-thin">
          {catalogRows.length === 0 ? (
            <div className="text-center py-8">
              <div className="text-sm ink-soft mb-1">No catalog entries in {cfg.catalogMaster}.</div>
              <div className="text-[10px] ink-faint font-mono">Add catalog entries in MasterSettings → {cfg.label}.</div>
            </div>
          ) : (
            <div className="space-y-1.5">
              {catalogRows.map((row) => {
                const candidate = cfg.fromCatalog(row);
                const summary = cfg.summary(candidate);
                return (
                  <button
                    key={row.id}
                    onClick={() => onPick(candidate)}
                    className="w-full text-left p-3 bg-bone rounded border border-line-soft hover:border-terra hover:bg-paper transition-all"
                    style={{ borderLeftWidth: '3px', borderLeftColor: cfg.tone }}
                  >
                    <div className="flex items-center justify-between gap-2 mb-0.5">
                      <span className="text-sm ink font-medium">{row.value}</span>
                      {summary && <span className="text-[10px] font-mono ink-faint shrink-0">{summary}</span>}
                    </div>
                    {row.description && <div className="text-[10px] ink-soft leading-relaxed">{row.description}</div>}
                  </button>
                );
              })}
            </div>
          )}
        </div>
        <div className="px-4 py-3 border-t border-line bg-bone flex items-center justify-between">
          <span className="text-[10px] font-mono ink-faint">{catalogRows.length} catalog entries available</span>
          <button onClick={onCustom} className="flex items-center gap-1 text-[11px] font-mono text-terra hover:ink">
            <Plus className="w-3 h-3" /> Custom (not from catalog)
          </button>
        </div>
      </div>
    </div>
  );
}

/* ============== LeafModal — rich edit for Drawings/References/BOQ ============== */
function LeafModal({ leafKey, item, onSave, onClose, readOnly = false }) {
  const cfg = leafConfig[leafKey];
  const Icon = cfg.icon;
  const [draft, setDraft] = useState({ ...item });
  const [sendingApproval, setSendingApproval] = useState(null);

  const update = (key, value) => setDraft((d) => ({ ...d, [key]: value }));
  const save = () => {
    onSave(draft);
  };
  const approvalLabel = leafKey === 'drawings' ? 'drawing'
    : leafKey === 'references' ? 'reference'
    : leafKey === 'boqItems' ? 'BOQ item'
    : leafKey === 'specs' ? 'specification'
    : 'file';
  const approvalMessage = () => {
    const notes = draft.clientNotes || draft.description || draft.notes || '';
    return [
      `Approval requested: ${draft.name || `Untitled ${approvalLabel}`}`,
      `Type: ${approvalLabel}`,
      notes && `Notes: ${notes}`,
      draft.url && `Link: ${draft.url}`,
      '',
      'Please review and reply Approved / Changes required.',
    ].filter(Boolean).join('\n');
  };
  const markSentForApproval = (channel, recipient) => {
    const nextDraft = {
      ...draft,
      sentForApproval: true,
      approvalStatus: 'pending',
      approvalChannel: channel,
      approvalRecipient: recipient,
      approvalSentAt: new Date().toISOString(),
    };
    setDraft(nextDraft);
    onSave(nextDraft);
  };
  const sendApprovalWhatsApp = async () => {
    const number = window.prompt('WhatsApp number with country code');
    if (!number || !number.trim()) return;
    const message = approvalMessage();
    setSendingApproval('whatsapp');
    try {
      await sendWhatsAppViaBackend(number, message);
      markSentForApproval('whatsapp', number.trim());
      alert('Approval request sent via connected WhatsApp.');
    } catch (error) {
      const wa = buildWhatsAppUrl(number, message);
      if (wa) window.open(wa, '_blank');
      markSentForApproval('whatsapp', number.trim());
      alert(`WhatsApp backend could not send directly: ${error.message}. I opened WhatsApp with the approval message ready.`);
    } finally {
      setSendingApproval(null);
    }
  };
  const sendApprovalEmail = () => {
    const email = window.prompt('Client email address');
    if (!email || !email.trim()) return;
    const subject = encodeURIComponent(`Approval requested — ${draft.name || approvalLabel}`);
    const body = encodeURIComponent(approvalMessage());
    window.location.href = `mailto:${email.trim()}?subject=${subject}&body=${body}`;
    markSentForApproval('email', email.trim());
  };

  // Field schema per leaf type
  const fields = {
    drawings: [
      { key: 'name', label: 'Drawing Name', type: 'text', placeholder: 'e.g. Living Room Floor Plan', span: 'full' },
      { key: 'drawingType', label: 'Type', type: 'select', options: ['Plan', 'Elevation', 'Section', 'Detail', 'Schedule', 'As-Built'] },
      { key: 'status', label: 'Status', type: 'select', options: ['Draft', 'Internal Review', 'Client Review', 'Approved', 'Issued', 'Revised'] },
      { key: 'revision', label: 'Revision', type: 'text', placeholder: 'R0, R1, R2…' },
      { key: '__notes', label: 'Description / Notes', type: 'notesSplit', span: 'full', placeholder: 'Drawing description visible to client.' },
    ],
    references: [
      { key: 'name', label: 'Reference Name', type: 'text', placeholder: 'e.g. Pinterest mood image — coastal living', span: 'full' },
      { key: 'referenceType', label: 'Type', type: 'select', options: ['Inspiration', 'Physical', 'Catalogue', 'Site', 'Precedent'] },
      { key: 'url', label: 'Link / URL', type: 'text', placeholder: 'https://...' },
      { key: '__notes', label: 'Notes', type: 'notesSplit', span: 'full', placeholder: 'Reference description visible to client.' },
    ],
    boqItems: [
      { key: 'name', label: 'Description', type: 'text', placeholder: 'e.g. PU lacquer joinery — sprayed finish', span: 'full' },
      { key: 'category', label: 'Category', type: 'text', placeholder: 'Joinery / Finish / Stone…' },
      { key: 'unit', label: 'Unit', type: 'select', options: ['sqft', 'sqm', 'rft', 'no', 'lot', 'kg'] },
      { key: 'quantity', label: 'Quantity', type: 'text', placeholder: '0' },
      { key: 'rate', label: 'Rate (₹)', type: 'text', placeholder: '0' },
      { key: '__notes', label: 'Costing notes', type: 'notesSplit', span: 'full', placeholder: 'Line-item description visible to client.' },
    ],
  };

  const fieldList = fields[leafKey] || [];

  // BOQ live total
  const boqTotal = leafKey === 'boqItems'
    ? (parseFloat(draft.quantity) || 0) * (parseFloat(draft.rate) || 0)
    : null;

  return (
    <div className="modal-backdrop" onClick={onClose}>
      <div className="modal-card" onClick={(e) => e.stopPropagation()} style={{ maxWidth: '600px' }}>
        <div className="flex items-center justify-between px-5 py-3 border-b border-line">
          <div className="flex items-center gap-2 min-w-0">
            <Icon className="w-4 h-4 shrink-0" style={{ color: cfg.tone }} />
            <h3 className="font-display text-base ink truncate">{item.name ? 'Edit' : 'New'} {cfg.singular}</h3>
            {item.masterRef && <Tag tone="moss">From catalog</Tag>}
            <VisibilityChip
              record={draft}
              recordType={leafKey === 'drawings' ? 'drawing' : leafKey === 'references' ? 'reference' : leafKey === 'boqItems' ? 'boqItem' : leafKey === 'specs' ? 'spec' : 'checklist'}
              onChange={(updates) => setDraft((d) => ({ ...d, ...updates }))}
            />
          </div>
          <button onClick={onClose} className="ink-soft hover:ink shrink-0"><X className="w-4 h-4" /></button>
        </div>

        <div className="p-5 max-h-[28rem] overflow-y-auto scrollbar-thin">
          <div className="grid grid-cols-2 gap-3">
            {fieldList.filter((f) => f.type !== 'notesSplit').map((f) => (
              <FieldGroup key={f.key} label={f.label} span={f.span}>
                {f.type === 'select' ? (
                  <SelectField value={draft[f.key] || ''} onChange={(v) => update(f.key, v)} options={f.options} />
                ) : f.type === 'textarea' ? (
                  <TextArea value={draft[f.key] || ''} onChange={(v) => update(f.key, v)} placeholder={f.placeholder} rows={3} />
                ) : (
                  <TextField value={draft[f.key] || ''} onChange={(v) => update(f.key, v)} placeholder={f.placeholder} />
                )}
              </FieldGroup>
            ))}
          </div>

          {/* Notes split fields render below the grid as full-width */}
          {fieldList.filter((f) => f.type === 'notesSplit').map((f) => (
            <div key={f.key} className="mt-3">
              <NotesSplitEditor
                record={draft}
                onChange={(updates) => setDraft((d) => ({ ...d, ...updates }))}
                label={f.label}
                placeholder={f.placeholder}
                rows={3}
              />
            </div>
          ))}

          {leafKey === 'boqItems' && boqTotal !== null && boqTotal > 0 && (
            <div className="mt-4 p-3 bg-moss-soft border border-moss rounded-md text-center">
              <div className="text-[10px] font-mono uppercase tracking-wider text-moss font-semibold mb-1">Calculated total</div>
              <div className="text-2xl font-display ink">₹{boqTotal.toLocaleString('en-IN')}</div>
              <div className="text-[10px] font-mono ink-faint mt-1">{draft.quantity} {draft.unit} × ₹{draft.rate}</div>
            </div>
          )}
        </div>

        <div className="px-5 py-3 border-t border-line bg-bone flex items-center justify-end gap-2">
          {readOnly && (
            <div className="flex items-center gap-1.5 mr-auto text-[10px] font-mono ink-soft">
              <Lock className="w-3 h-3" />
              <span>Read-only — your role can view but not edit this record</span>
            </div>
          )}
          {!readOnly && (
            <div className="flex items-center gap-1.5 mr-auto flex-wrap">
              <button
                onClick={sendApprovalWhatsApp}
                disabled={sendingApproval === 'whatsapp'}
                className="px-3 py-1.5 text-[11px] font-mono text-terra border border-terra rounded hover:bg-terra-soft disabled:opacity-60"
                title="Send this record for approval through the connected WhatsApp backend"
              >
                <Send className="w-3 h-3 inline mr-1" /> WhatsApp approval
              </button>
              <button
                onClick={sendApprovalEmail}
                className="px-3 py-1.5 text-[11px] font-mono ink-soft border border-line rounded hover:bg-paper hover:ink"
                title="Open an email draft for approval"
              >
                <Send className="w-3 h-3 inline mr-1" /> Email approval
              </button>
              {draft.sentForApproval && (
                <span className="text-[10px] font-mono uppercase tracking-wider text-terra">
                  sent · {draft.approvalChannel || 'approval'} · {draft.approvalStatus || 'pending'}
                </span>
              )}
            </div>
          )}
          <button onClick={onClose} className="px-3 py-1.5 text-[11px] font-mono ink-soft hover:ink">{readOnly ? 'Close' : 'Cancel'}</button>
          {!readOnly && (
            <button onClick={save} className="flex items-center gap-1 px-4 py-1.5 bg-ink text-white rounded text-[11px] font-mono uppercase tracking-wider font-semibold hover:bg-terra">
              <Check className="w-3 h-3" /> Save
            </button>
          )}
        </div>
      </div>
    </div>
  );
}

/* ================================================================== */
/* ======================== PAYMENT TERMS =========================== */
/* ================================================================== */

function PaymentTermsEditor({ data, update, masters }) {
  const milestones = data.paymentTerms || [];
  const totalProjectValue = parseFloat(data.totalProjectValue) || 0;
  const paymentTemplates = masters.MasterPaymentMilestones || [];
  const updateMilestones = (newList) => update('paymentTerms', newList);

  /* Phase 9.0.16 — derived amount = totalProjectValue × percentage / 100, unless user has manually overridden */
  const computedAmount = (m) => {
    if (m.amountManualOverride && m.amount) return parseFloat(m.amount) || 0;
    const pct = parseFloat(m.percentage) || 0;
    return totalProjectValue * pct / 100;
  };

  const addMilestone = () => {
    updateMilestones([
      ...milestones,
      { id: uid(), name: '', linkedStage: '', percentage: '', amount: '',
        amountReceived: 0, receiptDate: '', targetDate: '', amountManualOverride: false,
        triggerCondition: 'On stage completion', reminderEnabled: true, reminderType: 'WhatsApp' },
    ]);
  };
  const updateMilestone = (id, updates) => {
    updateMilestones(milestones.map((m) => (m.id === id ? { ...m, ...updates } : m)));
  };
  const removeMilestone = (id) => updateMilestones(milestones.filter((m) => m.id !== id));

  const applyTemplate = (templateId) => {
    const tmpl = paymentTemplates.find((t) => t.id === parseInt(templateId, 10));
    if (!tmpl) return;
    if (milestones.length > 0 && !window.confirm(`Replace ${milestones.length} existing milestone${milestones.length > 1 ? 's' : ''} with "${tmpl.value}"?`)) return;
    const fresh = (tmpl.milestones || []).map((m, idx) => ({
      id: uid(),
      name: m.name || '',
      linkedStage: m.linkedStage || '',
      percentage: m.percentage || '',
      amount: '',
      amountReceived: 0,
      receiptDate: '',
      targetDate: '',
      amountManualOverride: false,
      triggerCondition: m.triggerCondition || 'On stage completion',
      reminderEnabled: m.reminderEnabled !== false,
      reminderType: m.reminderType || 'WhatsApp',
      masterRef: { template: tmpl.id, milestoneIndex: idx },
    }));
    updateMilestones(fresh);
  };

  const totalPct = milestones.reduce((sum, m) => sum + (parseFloat(m.percentage) || 0), 0);
  const totalAmt = milestones.reduce((sum, m) => sum + computedAmount(m), 0);
  const totalReceived = milestones.reduce((sum, m) => sum + (parseFloat(m.amountReceived) || 0), 0);
  const triggerOptions = ['On stage start', 'On stage completion', 'On client approval', 'On signed contract', 'Custom'];
  const reminderOptions = ['WhatsApp', 'Email', 'Call', 'App Notification'];

  return (
    <Section
      title="Payment milestones"
      subtitle="Set the total project value, then split across stages by percentage. Amounts auto-compute."
      action={
        <div className="flex items-center gap-2">
          {paymentTemplates.length > 0 && (
            <select
              onChange={(e) => { if (e.target.value) { applyTemplate(e.target.value); e.target.value = ''; } }}
              defaultValue=""
              className="input-sm"
              style={{ cursor: 'pointer', maxWidth: '200px' }}
              title="Apply preset payment template"
            >
              <option value="">Apply template…</option>
              {paymentTemplates.map((t) => (
                <option key={t.id} value={t.id}>{t.value}</option>
              ))}
            </select>
          )}
          <button onClick={addMilestone} className="flex items-center gap-1.5 text-[11px] font-mono text-terra hover:ink">
            <Plus className="w-3 h-3" /> Add milestone
          </button>
        </div>
      }
    >
      {/* Phase 9.0.16 — Total Project Value at top */}
      <div className="bg-bone rounded-md border border-line p-3 mb-3">
        <div className="flex items-center gap-3">
          <div className="flex-1">
            <div className="text-[10px] font-mono ink-faint uppercase tracking-wider mb-1">Total Project Value (Design Fee)</div>
            <div className="flex items-center gap-2">
              <span className="text-sm font-mono ink-soft">₹</span>
              <input
                value={data.totalProjectValue || ''}
                onChange={(e) => update('totalProjectValue', e.target.value)}
                placeholder="e.g. 1500000"
                type="number"
                className="input-sm flex-1 max-w-xs"
              />
              <span className="text-[11px] ink-faint">
                {totalProjectValue > 0 ? `(₹ ${totalProjectValue.toLocaleString('en-IN')})` : ''}
              </span>
            </div>
          </div>
          <div className="text-right">
            <div className="text-[10px] font-mono ink-faint uppercase tracking-wider">Splits across</div>
            <div className="text-sm font-mono ink">{milestones.length} milestone{milestones.length === 1 ? '' : 's'}</div>
          </div>
        </div>
        <div className="text-[10px] font-mono ink-faint mt-2">
          Once you set a total, every milestone's amount = total × percentage. Override an amount manually to lock that row's value.
        </div>
      </div>

      {milestones.length === 0 ? (
        <div className="bg-bone rounded border border-line-soft p-6 text-center">
          <Coins className="w-6 h-6 ink-faint mx-auto mb-2" />
          <div className="text-sm ink-soft mb-2">No milestones added yet.</div>
          <button onClick={addMilestone} className="text-[11px] font-mono text-terra hover:ink">+ Add the first milestone</button>
        </div>
      ) : (
        <>
          <div className="border border-line rounded-md overflow-hidden">
            <div className="grid bg-bone border-b border-line px-3 py-2 gap-2 text-[10px] font-mono ink-faint uppercase tracking-wider"
              style={{ gridTemplateColumns: '36px 1.4fr 1.3fr 56px 120px 120px 110px 28px' }}>
              <div>#</div><div>Milestone</div><div>Linked Stage</div><div>%</div><div>Amount Due (₹)</div><div>Received (₹) / Date</div><div>Target Date</div><div></div>
            </div>
            {milestones.map((m, i) => {
              const dueAmt = computedAmount(m);
              const recvAmt = parseFloat(m.amountReceived) || 0;
              const isAuto = !m.amountManualOverride;
              return (
                <div key={m.id} className="grid items-center px-3 py-2 gap-2 border-b border-line-soft hover:bg-bone group"
                  style={{ gridTemplateColumns: '36px 1.4fr 1.3fr 56px 120px 120px 110px 28px' }}>
                  <div className="text-[10px] font-mono ink-faint">M{String(i + 1).padStart(2, '0')}</div>
                  <input value={m.name} onChange={(e) => updateMilestone(m.id, { name: e.target.value })} placeholder="e.g. Concept signoff" className="input-sm" />
                  <select value={m.linkedStage} onChange={(e) => updateMilestone(m.id, { linkedStage: e.target.value })} className="input-sm" style={{ cursor: 'pointer' }}>
                    <option value="">Select stage…</option>
                    {masters.MasterWorkflowStages.map((s) => (
                      <option key={s.id} value={s.value}>{s.value}</option>
                    ))}
                  </select>
                  <input value={m.percentage} onChange={(e) => updateMilestone(m.id, { percentage: e.target.value, amountManualOverride: false })} placeholder="20" className="input-sm" type="number" />
                  <div>
                    <input
                      value={isAuto ? (dueAmt > 0 ? Math.round(dueAmt) : '') : m.amount}
                      onChange={(e) => updateMilestone(m.id, { amount: e.target.value, amountManualOverride: e.target.value !== '' })}
                      placeholder="auto"
                      className={`input-sm ${isAuto ? 'opacity-60' : ''}`}
                      type="number"
                      title={isAuto ? `Auto-computed from ${m.percentage || 0}% of total. Type to override.` : 'Manual override — clear to revert to auto'}
                    />
                    {!isAuto && (
                      <button
                        onClick={() => updateMilestone(m.id, { amount: '', amountManualOverride: false })}
                        className="text-[8px] font-mono text-terra hover:ink mt-0.5"
                        title="Reset to auto-computed"
                      >reset auto</button>
                    )}
                  </div>
                  <div className="space-y-0.5">
                    <input
                      value={m.amountReceived || ''}
                      onChange={(e) => updateMilestone(m.id, { amountReceived: e.target.value })}
                      placeholder="0"
                      className="input-sm"
                      type="number"
                    />
                    <input
                      value={m.receiptDate || ''}
                      onChange={(e) => updateMilestone(m.id, { receiptDate: e.target.value })}
                      className="input-sm text-[9px]"
                      type="date"
                      title="Receipt date"
                    />
                  </div>
                  <input
                    value={m.targetDate || ''}
                    onChange={(e) => updateMilestone(m.id, { targetDate: e.target.value })}
                    className="input-sm"
                    type="date"
                    title="Expected payment date"
                  />
                  <button onClick={() => removeMilestone(m.id)} className="p-1 hover:bg-paper rounded opacity-0 group-hover:opacity-100">
                    <Trash2 className="w-3 h-3 text-terra" />
                  </button>
                </div>
              );
            })}
            <div className="grid items-center px-3 py-2 gap-2 bg-bone text-[11px] font-mono"
              style={{ gridTemplateColumns: '36px 1.4fr 1.3fr 56px 120px 120px 110px 28px' }}>
              <div></div>
              <div className="ink-faint uppercase tracking-wider text-[10px]">Totals</div>
              <div></div>
              <div className={`font-semibold ${totalPct === 100 ? 'text-moss' : totalPct > 100 ? 'text-terra' : 'ink-soft'}`}>
                {totalPct.toFixed(1)}%
              </div>
              <div className="ink-soft">₹ {Math.round(totalAmt).toLocaleString('en-IN')}</div>
              <div className="ink-soft">₹ {Math.round(totalReceived).toLocaleString('en-IN')}</div>
              <div></div><div></div>
            </div>
          </div>
          {totalPct !== 100 && totalPct > 0 && (
            <div className="mt-2 text-[10px] ink-faint font-mono">
              {totalPct > 100 ? '⚠ Total exceeds 100%' : `Total is ${totalPct.toFixed(1)}% — ${(100 - totalPct).toFixed(1)}% remaining.`}
            </div>
          )}
          {totalProjectValue > 0 && totalAmt > 0 && Math.abs(totalAmt - totalProjectValue) > 1 && (
            <div className="mt-1 text-[10px] ink-faint font-mono">
              Sum of amounts (₹ {Math.round(totalAmt).toLocaleString('en-IN')}) {totalAmt > totalProjectValue ? 'exceeds' : 'is less than'} project value (₹ {totalProjectValue.toLocaleString('en-IN')}). {totalPct === 100 ? 'Manual overrides may be drifting.' : 'Adjust percentages to align.'}
            </div>
          )}
        </>
      )}
    </Section>
  );
}

/* ExternalStakeholdersEditor was removed in Phase 5.6.1 — replaced by VendorPickerSection
   which uses MasterVendors via vendorId references instead of inline {type, name, mobile, ...} */


/* ================================================================== */
/* ======================== MASTER SETTINGS ========================= */
/* ================================================================== */

function normalizeContractTemplateForEditor(row = {}, index = 0) {
  const seed = (initialMasters.MasterContractTemplates || [])[index] || {};
  const seedByName = (initialMasters.MasterContractTemplates || []).find((item) => item.value === row.value) || {};
  const sections = Array.isArray(row.sections) && row.sections.length
    ? row.sections
    : (seedByName.sections || seed.sections || []);
  return {
    ...row,
    value: row.value || row.name || seed.value || 'Untitled contract',
    type: row.type || seedByName.type || seed.type || 'Contract',
    linkedServiceType: inferContractServiceType(row),
    description: row.description || seedByName.description || seed.description || '',
    sections: sections.map((section, sectionIndex) => ({
      title: section?.title || `Clause ${sectionIndex + 1}`,
      body: section?.body || '',
    })),
  };
}

function ContractTemplateLibraryPanel({ masters, setMasters }) {
  const templates = masters.MasterContractTemplates || [];
  const contractServiceTypes = templates.map((template) => inferContractServiceType(template)).filter(Boolean);
  const serviceTypes = Array.from(new Set([
    ...(masters.MasterServiceTypes || []).map(masterOptionValue).filter(Boolean),
    ...contractServiceTypes,
  ]));
  const [activeId, setActiveId] = React.useState(() => templates[0]?.id || null);
  const [draft, setDraft] = React.useState(null);
  const [saveState, setSaveState] = React.useState('idle');

  const activeIndex = Math.max(0, templates.findIndex((template) => String(template.id) === String(activeId)));
  const activeTemplate = templates[activeIndex] || templates[0] || null;

  React.useEffect(() => {
    if (!templates.length) {
      setActiveId(null);
      setDraft(null);
      return;
    }
    if (!templates.some((template) => String(template.id) === String(activeId))) {
      setActiveId(templates[0].id);
      return;
    }
    setDraft(normalizeContractTemplateForEditor(activeTemplate, activeIndex));
    setSaveState('idle');
  }, [activeId, templates.length, activeTemplate?.id]);

  const updateDraft = (updates) => setDraft((current) => ({ ...(current || {}), ...updates }));
  const updateSection = (sectionIndex, updates) => {
    setDraft((current) => {
      const nextSections = [...(current?.sections || [])];
      nextSections[sectionIndex] = { ...(nextSections[sectionIndex] || {}), ...updates };
      return { ...(current || {}), sections: nextSections };
    });
  };
  const addSection = () => {
    setDraft((current) => ({
      ...(current || {}),
      sections: [
        ...((current && current.sections) || []),
        { title: 'New Clause', body: 'Add the contract wording here.' },
      ],
    }));
  };
  const removeSection = (sectionIndex) => {
    setDraft((current) => ({
      ...(current || {}),
      sections: ((current && current.sections) || []).filter((_, idx) => idx !== sectionIndex),
    }));
  };
  const saveDraft = () => {
    if (!draft || !setMasters) return;
    const clean = {
      ...draft,
      value: String(draft.value || '').trim() || 'Untitled contract',
      linkedServiceType: draft.linkedServiceType || inferContractServiceType(draft),
      sections: (draft.sections || []).map((section) => ({
        title: String(section.title || '').trim() || 'Clause',
        body: String(section.body || '').trim(),
      })).filter((section) => section.title || section.body),
      updatedAt: new Date().toISOString(),
    };
    setMasters((current) => ({
      ...current,
      MasterContractTemplates: (current.MasterContractTemplates || []).map((row, idx) => (
        String(row.id) === String(clean.id) || (!clean.id && idx === activeIndex) ? clean : row
      )),
    }));
    setSaveState('saved');
    window.setTimeout(() => setSaveState('idle'), 1600);
  };

  if (!templates.length) {
    return (
      <div className="bg-paper border border-line rounded-xl p-5 mb-4">
        <div className="text-[10px] font-mono uppercase tracking-widest ink-faint mb-1">Client contracts</div>
        <h2 className="font-display text-xl ink tracking-tight">No contract formats yet</h2>
        <p className="text-xs ink-soft mt-1">Add contract rows below first. The A4 editor will appear once the main copies exist.</p>
      </div>
    );
  }

  return (
    <div className="bg-paper border border-line rounded-xl p-4 mb-4">
      <div className="flex items-start justify-between gap-3 flex-wrap mb-4">
        <div>
          <div className="text-[10px] font-mono uppercase tracking-widest ink-faint mb-1">Client contracts · Phase 1</div>
          <h2 className="font-display text-xl ink tracking-tight leading-tight">Editable A4 contract formats</h2>
          <p className="text-xs ink-soft mt-1 max-w-3xl">
            These are the main copies that sales and project contract flows can pull from. Each format is linked to a default service type; Phase 2 will add curly-bracket merge fields.
          </p>
        </div>
        <div className="px-3 py-2 rounded-lg bg-bone border border-line-soft text-[11px] ink-soft">
          <span className="font-semibold ink">{templates.length}</span> contract formats stored in MasterContractTemplates
        </div>
      </div>

      <div className="grid grid-cols-1 xl:grid-cols-[340px_1fr] gap-4">
        <div className="space-y-2">
          {templates.map((template, index) => {
            const normalized = normalizeContractTemplateForEditor(template, index);
            const isActive = String(activeTemplate?.id) === String(template.id);
            return (
              <button
                key={template.id || normalized.value}
                type="button"
                onClick={() => setActiveId(template.id)}
                className={`w-full text-left rounded-xl border p-3 transition-colors ${isActive ? 'bg-terra-soft border-terra' : 'bg-paper border-line hover:border-terra hover:bg-bone'}`}
              >
                <div className="flex items-start justify-between gap-3">
                  <div className="min-w-0">
                    <div className="text-sm font-semibold ink leading-tight">{normalized.value}</div>
                    <div className="text-[11px] ink-soft mt-1">{normalized.linkedServiceType}</div>
                  </div>
                  {isActive && <CheckCircle2 className="w-4 h-4 text-terra shrink-0" strokeWidth={2.5} />}
                </div>
                <div className="flex items-center gap-2 mt-3 text-[10px] font-mono uppercase tracking-wider ink-faint">
                  <span>{normalized.type}</span>
                  <span>·</span>
                  <span>{normalized.sections.length} clauses</span>
                </div>
              </button>
            );
          })}
        </div>

        {draft && (
          <div className="grid grid-cols-1 2xl:grid-cols-[minmax(0,1fr)_360px] gap-4">
            <div className="rounded-xl border border-line bg-bone p-4">
              <div className="grid grid-cols-1 md:grid-cols-2 gap-3 mb-3">
                <div>
                  <label className="text-[10px] font-mono uppercase tracking-wider ink-faint block mb-1">Contract name</label>
                  <input
                    value={draft.value || ''}
                    onChange={(event) => updateDraft({ value: event.target.value })}
                    className="input-base"
                    placeholder="Contract format name"
                  />
                </div>
                <div>
                  <label className="text-[10px] font-mono uppercase tracking-wider ink-faint block mb-1">Default service type</label>
                  <select
                    value={draft.linkedServiceType || ''}
                    onChange={(event) => updateDraft({ linkedServiceType: event.target.value })}
                    className="input-base"
                  >
                    <option value="">Select service type...</option>
                    {serviceTypes.map((service) => <option key={service} value={service}>{service}</option>)}
                  </select>
                </div>
                <div>
                  <label className="text-[10px] font-mono uppercase tracking-wider ink-faint block mb-1">Contract type</label>
                  <input
                    value={draft.type || ''}
                    onChange={(event) => updateDraft({ type: event.target.value })}
                    className="input-base"
                    placeholder="Design Services / Turnkey / Addendum"
                  />
                </div>
                <div>
                  <label className="text-[10px] font-mono uppercase tracking-wider ink-faint block mb-1">Description</label>
                  <input
                    value={draft.description || ''}
                    onChange={(event) => updateDraft({ description: event.target.value })}
                    className="input-base"
                    placeholder="What this contract covers"
                  />
                </div>
              </div>

              <div className="flex items-center justify-between gap-3 mb-3">
                <div>
                  <div className="text-[10px] font-mono uppercase tracking-widest ink-faint">A4 copy editor</div>
                  <div className="text-xs ink-soft">Edit clause titles and body text. These are the legal/client-facing copies.</div>
                </div>
                <button
                  type="button"
                  onClick={addSection}
                  className="inline-flex items-center gap-1.5 px-3 py-2 rounded-md border border-line bg-paper hover:border-terra hover:text-terra text-xs font-semibold ink"
                >
                  <Plus className="w-3.5 h-3.5" strokeWidth={2.5} />
                  Add clause
                </button>
              </div>

              <div className="space-y-3">
                {(draft.sections || []).map((section, sectionIndex) => (
                  <div key={`${draft.id}-${sectionIndex}`} className="rounded-lg border border-line bg-paper p-3">
                    <div className="flex items-start gap-2">
                      <div className="w-8 h-8 rounded-lg bg-terra-soft text-terra flex items-center justify-center text-xs font-bold shrink-0">
                        {sectionIndex + 1}
                      </div>
                      <div className="flex-1 min-w-0 space-y-2">
                        <input
                          value={section.title || ''}
                          onChange={(event) => updateSection(sectionIndex, { title: event.target.value })}
                          className="input-sm text-sm font-semibold"
                          placeholder="Clause title"
                        />
                        <textarea
                          value={section.body || ''}
                          onChange={(event) => updateSection(sectionIndex, { body: event.target.value })}
                          rows={5}
                          className="input-sm text-xs leading-relaxed"
                          style={{ resize: 'vertical', fontFamily: 'inherit' }}
                          placeholder="Clause body..."
                        />
                      </div>
                      <button
                        type="button"
                        onClick={() => removeSection(sectionIndex)}
                        className="p-2 rounded-md hover:bg-terra-soft text-terra"
                        title="Delete clause"
                      >
                        <Trash2 className="w-4 h-4" />
                      </button>
                    </div>
                  </div>
                ))}
              </div>

              <div className="flex justify-end mt-4">
                <button
                  type="button"
                  onClick={saveDraft}
                  className={`inline-flex items-center gap-2 px-4 py-2.5 rounded-md text-xs font-mono uppercase tracking-wider font-semibold ${saveState === 'saved' ? 'bg-moss text-white' : 'bg-ink text-white hover:bg-terra'}`}
                >
                  {saveState === 'saved' ? <CheckCircle2 className="w-4 h-4" /> : <Save className="w-4 h-4" />}
                  {saveState === 'saved' ? 'Saved' : 'Save contract copy'}
                </button>
              </div>
            </div>

            <div className="rounded-xl border border-line bg-paper p-4">
              <div className="text-[10px] font-mono uppercase tracking-widest ink-faint mb-3">A4 preview</div>
              <div className="bg-white border border-line shadow-sm rounded-sm p-5 min-h-[520px]">
                <div className="text-[10px] font-mono uppercase tracking-widest text-terra mb-2">{draft.type || 'Contract'}</div>
                <h3 className="font-display text-2xl ink leading-tight">{draft.value}</h3>
                <p className="text-xs ink-soft mt-2 leading-relaxed">{draft.description}</p>
                <div className="h-px bg-line my-4" />
                <div className="space-y-4">
                  {(draft.sections || []).map((section, sectionIndex) => (
                    <div key={`preview-${sectionIndex}`}>
                      <div className="text-[11px] font-semibold ink">{sectionIndex + 1}. {section.title || 'Clause'}</div>
                      <p className="text-[11px] ink-soft leading-relaxed mt-1">{section.body || 'Clause body will appear here.'}</p>
                    </div>
                  ))}
                </div>
              </div>
              <div className="mt-3 rounded-lg bg-bone border border-line-soft p-3 text-[11px] ink-soft leading-relaxed">
                <span className="font-semibold ink">Phase 2 ready:</span> curly-bracket fields like client name, project address, fees, and milestones will be mapped here after the master copies are approved.
              </div>
            </div>
          </div>
        )}
      </div>
    </div>
  );
}

function MasterSettings({ masters, setMasters, projects = [], setProjects, currentProfile, onAdd, onUpdate, onDelete, onReorder, onClearTable, onBulkAdd, currentTheme, setCurrentTheme, activeThemePreset, setActiveThemePreset, currentRoleCode, onForceSave }) {
  /* Phase 9.0.24 — Per-role hiding of master tables.
     Each schema can declare hiddenForRoles: ['studio_owner', 'pm_admin', etc.].
     The sidebar filters those out for the current role. Empty array = visible to all.
     Future-proof: when MasterDataModel / MasterFeatureFlags etc. are added,
     just include hiddenForRoles in their schema entry. */
  const isHiddenForCurrentRole = (tableName) => {
    const schema = masterSchemas[tableName];
    if (!schema || !Array.isArray(schema.hiddenForRoles)) return false;
    return schema.hiddenForRoles.includes(currentRoleCode);
  };
  const [libraryTab, setLibraryTab] = useState('pipeline');
  const libraryTabMatches = (group) => {
    if (libraryTab === 'pipeline') return ['Workflow', 'Leads', 'Leads & Sales'].includes(group.title);
    if (libraryTab === 'messages') return group.title === 'Templates (Phase 4)';
    if (libraryTab === 'forms') return group.title === 'Forms';
    if (libraryTab === 'contracts') return group.title === 'Contracts & Quickstarts';
    if (libraryTab === 'services') return group.title === 'Service Types';
    if (libraryTab === 'rates') return group.title === 'BOQ Zone';
    if (libraryTab === 'master') return ['Wizard — Page 1 & 2', 'Spatial Cascade — Branches', 'Spatial Support Libraries', 'Universal Library (Phase 8)', 'Team', 'People — Clients & Vendors'].includes(group.title);
    if (libraryTab === 'flags') return group.title === 'Wizard — Page 3' || group.title === 'Approvals (Move 3)';
    return true;
  };
  const visibleMasterGroups = masterGroups
    .map((group) => ({
      ...group,
      items: group.items.filter((tn) => !isHiddenForCurrentRole(tn)),
    }))
    .filter(libraryTabMatches)
    .filter((group) => group.items.length > 0);
  const [activeTable, setActiveTable] = useState('MasterProjectCategory');
  const [editingId, setEditingId] = useState(null);
  const [newRow, setNewRow] = useState({});
  const [showClearModal, setShowClearModal] = useState(false);
  const [showBulkAddModal, setShowBulkAddModal] = useState(false);
  const [manualSaveState, setManualSaveState] = useState('idle');
  const [sortConfig, setSortConfig] = useState({ table: '', key: '', direction: 'asc' });
  const [tableExportFile, setTableExportFile] = useState(null);
  const libraryDefaultTable = {
    pipeline: 'MasterWorkflowStages',
    messages: 'MasterMessageTemplates',
    forms: 'MasterQuestionnaireTemplates',
    contracts: 'MasterContractTemplates',
    services: 'MasterServiceTypes',
    rates: 'MasterBOQItems',
    master: 'MasterProjectCategory',
    flags: 'MasterClientFlags',
  };
  const openLibraryTab = (tabName) => {
    setLibraryTab(tabName);
    const preferredTable = libraryDefaultTable[tabName];
    if (preferredTable && masterSchemas[preferredTable] && !isHiddenForCurrentRole(preferredTable)) {
      setActiveTable(preferredTable);
      setEditingId(null);
      setNewRow({});
    }
  };

  const schema = masterSchemas[activeTable];
  const rows = masters[activeTable] || [];
  const Icon = schema?.icon || Database;
  const isThemeActive = activeTable === '__theme';
  /* Phase 8.2 — Property Type Assemblies has its own dedicated screen,
     not the standard table view. Per Q5 the standard table view is hidden. */
  const isAssemblyActive = activeTable === 'MasterPropertyTypeAssemblies';
  const normalizeSortValue = (value) => {
    if (value === undefined || value === null) return '';
    if (typeof value === 'number') return value;
    if (typeof value === 'boolean') return value ? 1 : 0;
    if (Array.isArray(value)) return value.map((item) => (typeof item === 'object' && item !== null ? (item.value || item.name || item.label || item.id || JSON.stringify(item)) : String(item))).join(', ').toLowerCase();
    if (typeof value === 'object') return String(value.value || value.name || value.label || value.id || JSON.stringify(value)).toLowerCase();
    const text = String(value).trim();
    const numeric = text !== '' && !Number.isNaN(Number(text.replace(/,/g, ''))) ? Number(text.replace(/,/g, '')) : null;
    return numeric !== null ? numeric : text.toLowerCase();
  };
  const sortedRows = React.useMemo(() => {
    if (sortConfig.table !== activeTable || !sortConfig.key) return rows;
    const direction = sortConfig.direction === 'desc' ? -1 : 1;
    return [...rows].sort((a, b) => {
      const rowA = activeTable === 'MasterPropertyType' ? withPropertyTypeSizeDefaults(a) : activeTable === 'MasterBOQItems' ? withBOQItemDefaults(a) : a;
      const rowB = activeTable === 'MasterPropertyType' ? withPropertyTypeSizeDefaults(b) : activeTable === 'MasterBOQItems' ? withBOQItemDefaults(b) : b;
      const av = normalizeSortValue(rowA?.[sortConfig.key]);
      const bv = normalizeSortValue(rowB?.[sortConfig.key]);
      if (typeof av === 'number' && typeof bv === 'number') return (av - bv) * direction;
      return String(av).localeCompare(String(bv), undefined, { numeric: true, sensitivity: 'base' }) * direction;
    });
  }, [rows, activeTable, sortConfig]);
  const toggleColumnSort = (key) => {
    setSortConfig((current) => ({
      table: activeTable,
      key,
      direction: current.table === activeTable && current.key === key && current.direction === 'asc' ? 'desc' : 'asc',
    }));
  };

  const libraryTabForTable = (tableName) => {
    if (['MasterLeadStatuses', 'MasterLeadSources', 'MasterSalesStages', 'MasterSalesDeals', 'MasterWorkflowStages', 'MasterActivities', 'MasterTasks', 'MasterDeliverables'].includes(tableName)) return 'pipeline';
    if (['MasterQuestionnaireTemplates', 'QuestionnaireResponses'].includes(tableName)) return 'forms';
    if (['MasterProjectTemplates', 'MasterContractTemplates'].includes(tableName)) return 'contracts';
    if (['MasterMessageTemplates', 'MasterTaskChecklists', 'MasterPropertyTemplates', 'MasterWorkflowTemplates', 'MasterPaymentMilestones'].includes(tableName)) return 'messages';
    if (tableName === 'MasterServiceTypes') return 'services';
    if (['MasterBOQItems', 'MasterSpecifications'].includes(tableName)) return 'rates';
    if (['MasterChecklists', 'MasterDrawings', 'MasterReferences'].includes(tableName)) return 'master';
    if (['MasterClientFlags', 'MasterOnboardingAttentionTags', 'MasterApprovalTypes'].includes(tableName)) return 'flags';
    return 'master';
  };

  React.useEffect(() => {
    const visibleTables = visibleMasterGroups.flatMap((group) => group.items);
    if (visibleTables.length > 0 && !visibleTables.includes(activeTable)) {
      setActiveTable(visibleTables[0]);
      setEditingId(null);
      setNewRow({});
    }
  }, [libraryTab]);

  React.useEffect(() => {
    const handler = (event) => {
      const tableName = event.detail?.tableName;
      if (!tableName || !masterSchemas[tableName]) return;
      setLibraryTab(event.detail?.libraryTab || libraryTabForTable(tableName));
      setActiveTable(tableName);
      setEditingId(null);
      setNewRow({});
    };
    window.addEventListener('studio-os-open-library-table', handler);
    return () => window.removeEventListener('studio-os-open-library-table', handler);
  }, []);

  /* Phase 5.10.1 — Tables where row order is meaningful (workflow templates clone in order) */
  const REORDERABLE_TABLES = [
    'MasterWorkflowStages',
    'MasterActivities',
    'MasterTasks',
    'MasterDeliverables',
    'MasterTaskChecklists',
    'MasterPaymentMilestones',
    /* Phase 8.1 — Universal libraries support reorder for stable display ordering */
    'MasterZoneLibrary',
    'MasterSpaceLibrary',
    'MasterPropertyTypeAssemblies',
    /* Phase 8.2.2 — Level Types reorder controls dropdown order in assembly editor */
    'MasterLevelTypes',
    /* Phase 9.3.5 — Lead pipeline order matters: Kanban renders columns in seed order,
       Add Lead source dropdown shows in this order, dashboard groupings respect it */
    'MasterLeadStatuses',
    'MasterLeadSources',
  ];
  const isReorderable = REORDERABLE_TABLES.includes(activeTable);

  const moveMasterRow = (fromIdx, toIdx) => {
    if (!onReorder || !isReorderable) return;
    if (toIdx < 0 || toIdx >= rows.length) return;
    onReorder(activeTable, reorderArray(rows, fromIdx, toIdx));
  };

  /* Phase 9.3.6 — Primary required field is the FIRST column in the schema, not hardcoded
     'value'. This was breaking adds on tables like MasterLeadStatuses where the primary
     field is 'status' (and 'source' for MasterLeadSources). Without this fix, clicking
     ADD silently no-oped because newRow.value was undefined.

     Also: auto-default any missing boolean-like fields (isActive, isTerminal, isWin)
     and coerce 'true'/'false' string options to actual booleans so the downstream filters
     in Lead components work correctly. */
  const coerceBooleanFields = (row, columns) => {
    const out = { ...row };
    columns.forEach((col) => {
      if (col.options && col.options.length === 2 && col.options.includes('true') && col.options.includes('false')) {
        if (out[col.key] === 'true') out[col.key] = true;
        else if (out[col.key] === 'false') out[col.key] = false;
        else if (out[col.key] === undefined || out[col.key] === '') {
          /* Sensible defaults: isActive defaults to true; isTerminal/isWin default to false */
          out[col.key] = col.key === 'isActive' ? true : false;
        }
      }
    });
    return out;
  };

  const handleAdd = () => {
    if (!schema || !schema.columns || schema.columns.length === 0) return;
    const primaryKey = schema.columns[0].key;
    const primaryVal = newRow[primaryKey];
    if (!primaryVal || (typeof primaryVal === 'string' && !primaryVal.trim())) return;
    let cleaned = coerceBooleanFields(
      { ...newRow, [primaryKey]: typeof primaryVal === 'string' ? primaryVal.trim() : primaryVal },
      schema.columns
    );
    if (activeTable === 'MasterPropertyType') cleaned = withPropertyTypeSizeDefaults(cleaned);
    if (activeTable === 'MasterBOQItems') cleaned = withBOQItemDefaults(cleaned);
    onAdd(activeTable, cleaned);
    setNewRow({});
  };
  const handleSaveEdit = (id, updated) => {
    /* Phase 9.3.6 — Same boolean coercion on inline edit save so values stored as
       'true'/'false' strings from the select dropdown become real booleans. */
    let cleaned = schema?.columns ? coerceBooleanFields(updated, schema.columns) : updated;
    if (activeTable === 'MasterPropertyType') cleaned = withPropertyTypeSizeDefaults(cleaned);
    if (activeTable === 'MasterBOQItems') cleaned = withBOQItemDefaults(cleaned);
    onUpdate(activeTable, id, cleaned);
    setEditingId(null);
  };

  const handleManualSave = async () => {
    if (!onForceSave || manualSaveState === 'saving') return;
    setManualSaveState('saving');
    const result = await onForceSave();
    setManualSaveState(result?.ok ? 'saved' : 'error');
    window.setTimeout(() => setManualSaveState('idle'), 1800);
  };

  React.useEffect(() => {
    setTableExportFile(null);
  }, [activeTable, rows.length, sortConfig.key, sortConfig.direction]);

  const buildTableCsv = (tableName, tableRows) => {
    const tableSchema = masterSchemas[tableName];
    const exportRows = tableName === 'MasterPropertyType' ? tableRows.map(withPropertyTypeSizeDefaults) : tableRows;
    const columns = [
      { key: 'id', label: 'ID' },
      ...((tableSchema?.columns || [])
        .filter((col) => col.type !== 'preview' && col.key !== 'id')
        .map((col) => ({ key: col.key, label: col.label || col.key }))),
    ];
    const csvCell = (value) => {
      if (value === undefined || value === null) return '';
      const text = Array.isArray(value) || typeof value === 'object' ? JSON.stringify(value) : String(value);
      return `"${text.replace(/"/g, '""')}"`;
    };
    const lines = [
      [csvCell(tableName), csvCell(tableSchema?.label || tableName), csvCell(`${exportRows.length} rows`)].join(','),
      columns.map((col) => csvCell(col.label)).join(','),
      ...exportRows.map((row) => columns.map((col) => csvCell(row?.[col.key])).join(',')),
    ];
    return `\ufeff${lines.join('\r\n')}`;
  };

  const preparePropertyTypeExport = async () => {
    const csv = buildTableCsv('MasterPropertyType', sortedRows);
    const filename = `StudioOS_MasterPropertyType_${indiaTimestampForFilename()}.csv`;
    const fallbackFile = {
      tableName: 'MasterPropertyType',
      filename,
      csv,
      url: `data:text/csv;charset=utf-8,${encodeURIComponent(csv)}`,
      rowCount: sortedRows.length,
      savedPath: '',
      mode: 'browser',
    };
    try {
      const response = await fetch(`${WHATSAPP_API_BASE}/table-csv-export`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ tableName: 'MasterPropertyType', filename, csv }),
      });
      if (!response.ok) {
        const details = await response.json().catch(() => null);
        throw new Error(details?.details || details?.error || `Backend returned ${response.status}`);
      }
      const serverCsv = await response.text();
      const savedPathHeader = response.headers.get('x-studioos-csv-path') || '';
      const savedPath = savedPathHeader ? decodeURIComponent(savedPathHeader) : '';
      setTableExportFile({
        ...fallbackFile,
        csv: serverCsv || csv,
        url: `data:text/csv;charset=utf-8,${encodeURIComponent(serverCsv || csv)}`,
        savedPath,
        mode: 'backend',
      });
    } catch (error) {
      console.warn('[Studio/OS] Property type backend CSV export failed:', error);
      setTableExportFile({
        ...fallbackFile,
        error: `Backend save failed. Browser export is ready instead. ${error.message}`,
      });
    }
  };

  return (
    <div className="flex h-full overflow-hidden">
      <div className="w-72 bg-paper border-r border-line overflow-y-auto scrollbar-thin shrink-0">
        <div className="px-5 py-4 border-b border-line bg-bone">
          <div className="text-[11px] font-mono tracking-wider uppercase ink-faint mb-1">Libraries · L3 Studio Owner</div>
          <h2 className="font-display text-xl ink tracking-tight leading-tight">Studio Libraries</h2>
          <div className="text-[11px] ink-soft mt-1 leading-relaxed">Edit reusable studio defaults, templates, dropdowns, and operating libraries.</div>
        </div>
        <div className="p-3 border-b border-line bg-paper">
          <div className="text-[10px] font-mono tracking-widest font-semibold uppercase ink-faint px-1 mb-2">Library sections</div>
          <div className="grid grid-cols-1 gap-1">
            <LibrarySectionButton active={libraryTab === 'pipeline'} onClick={() => openLibraryTab('pipeline')} label="Pipeline stages" />
            <LibrarySectionButton active={libraryTab === 'messages'} onClick={() => openLibraryTab('messages')} label="Message templates" />
            <LibrarySectionButton active={libraryTab === 'forms'} onClick={() => openLibraryTab('forms')} label="Forms" />
            <LibrarySectionButton active={libraryTab === 'contracts'} onClick={() => openLibraryTab('contracts')} label="Contracts" />
            <LibrarySectionButton active={libraryTab === 'services'} onClick={() => openLibraryTab('services')} label="Service types" />
            <LibrarySectionButton active={libraryTab === 'rates'} onClick={() => openLibraryTab('rates')} label="BOQ zone" />
            <LibrarySectionButton active={libraryTab === 'master'} onClick={() => openLibraryTab('master')} label="Master data" />
            <LibrarySectionButton active={libraryTab === 'flags'} onClick={() => openLibraryTab('flags')} label="Flags stages" />
          </div>
        </div>
        <div className="p-3 space-y-4">
          {visibleMasterGroups.map((group) => (
            <div key={group.title}>
              <div className="text-[10px] font-mono tracking-widest font-semibold uppercase ink-faint px-2 mb-1.5">{group.title}</div>
              <div className="space-y-0.5">
                {group.items.map((tableName) => {
                  const ts = masterSchemas[tableName];
                  const Tin = ts.icon;
                  const isActive = activeTable === tableName;
                  const rowCount = ts.isCustom ? null : (masters[tableName] || []).length;
                  return (
                    <button key={tableName} onClick={() => setActiveTable(tableName)} className={`w-full flex items-center justify-between px-2.5 py-2 rounded-md text-left ${isActive ? 'bg-bone' : 'hover:bg-bone'}`}>
                      <div className="flex items-center gap-2 min-w-0">
                        <Tin className="w-3.5 h-3.5 ink-soft shrink-0" strokeWidth={1.7} />
                        <div className="min-w-0">
                          <div className={`text-xs truncate ${isActive ? 'ink font-semibold' : 'ink'}`}>{ts.label}</div>
                          <div className="text-[9px] font-mono ink-faint truncate">{tableName}</div>
                        </div>
                      </div>
                      {rowCount !== null && <span className="text-[10px] font-mono ink-faint shrink-0 ml-2">{rowCount}</span>}
                      {ts.isCustom && <Sparkles className="w-3 h-3 text-terra shrink-0 ml-2" />}
                    </button>
                  );
                })}
              </div>
            </div>
          ))}
        </div>
      </div>

      {isThemeActive ? (
        <ThemeSettings
          currentTheme={currentTheme}
          setCurrentTheme={setCurrentTheme}
          activeThemePreset={activeThemePreset}
          setActiveThemePreset={setActiveThemePreset}
        />
      ) : isAssemblyActive ? (
        <PropertyTypeAssemblyEditor
          masters={masters}
          onAdd={onAdd}
          onUpdate={onUpdate}
          onDelete={onDelete}
        />
      ) : (
      <div className="flex-1 overflow-auto scrollbar-thin">
        <div className="px-6 py-5 border-b border-line bg-paper">
          <div className="flex items-end justify-between">
            <div>
              <div className="flex items-center gap-2 mb-1">
                <Icon className="w-4 h-4 text-terra" />
                <span className="text-[11px] font-mono ink-faint uppercase tracking-wider">{activeTable}</span>
              </div>
              <h1 className="font-display text-3xl ink tracking-tight leading-none">{schema.label}</h1>
              <div className="flex items-center gap-3 mt-2">
                <span className="text-xs ink-soft"><span className="ink font-semibold">{rows.length}</span> rows</span>
                <span className="ink-faint">·</span>
                <span className="text-[11px] font-mono ink-soft">Blocks: {schema.blocks}</span>
              </div>
            </div>
            <button
              onClick={handleManualSave}
              disabled={!onForceSave || manualSaveState === 'saving'}
              className={`inline-flex items-center gap-1.5 px-2.5 py-1.5 rounded-md border text-[10px] font-mono uppercase tracking-wider font-semibold transition-colors ${
                manualSaveState === 'saving'
                  ? 'bg-terra text-white border-terra'
                  : manualSaveState === 'saved'
                    ? 'bg-moss text-white border-moss'
                    : manualSaveState === 'error'
                      ? 'bg-terra-soft text-terra border-terra'
                      : 'bg-ink text-white border-ink hover:bg-terra hover:border-terra'
              }`}
              title="Save current library/table edits as the real workspace data and suppress demo fallback."
            >
              {manualSaveState === 'saving' ? <RefreshCw className="w-3 h-3 animate-spin" /> : <Save className="w-3 h-3" />}
              {manualSaveState === 'saving' ? 'Saving' : manualSaveState === 'saved' ? 'Saved' : manualSaveState === 'error' ? 'Retry' : 'Save'}
            </button>
            {activeTable === 'MasterPropertyType' && (
              <button
                onClick={preparePropertyTypeExport}
                className="inline-flex items-center gap-1.5 px-2.5 py-1.5 rounded-md border border-line bg-paper text-ink hover:border-terra hover:text-terra text-[10px] font-mono uppercase tracking-wider font-semibold transition-colors"
                title="Download a CSV table backup for MasterPropertyType, including editable size bands"
              >
                <Download className="w-3 h-3" />
                Table Backup CSV
              </button>
            )}
          </div>
        </div>

        <div className="p-6">
          {activeTable === 'MasterQuestionnaireTemplates' && (
            <div className="bg-paper border border-line rounded-xl p-4 mb-4">
              <div className="flex items-start justify-between gap-3 flex-wrap mb-4">
                <div>
                  <div className="text-[10px] font-mono uppercase tracking-widest ink-faint mb-1">Discovery questionnaires</div>
                  <h2 className="font-display text-xl ink tracking-tight leading-tight">Shareable qualification forms</h2>
                  <p className="text-xs ink-soft mt-1">
                    These cards are powered by MasterQuestionnaireTemplates. Intro and thank-you copy comes from Message Templates.
                  </p>
                </div>
                <button
                  type="button"
                  onClick={() => setActiveTable('MasterMessageTemplates')}
                  className="px-3 py-2 rounded-lg border border-line-soft hover:bg-bone text-xs font-semibold ink"
                >
                  Edit message copy
                </button>
              </div>
              <QualificationFormsScreen
                masters={masters}
                setMasters={setMasters || (() => {})}
                projects={projects}
                setProjects={setProjects || (() => {})}
                currentRoleCode={currentRoleCode}
                currentProfile={currentProfile}
                embedded
              />
            </div>
          )}
          {activeTable === 'MasterContractTemplates' && (
            <ContractTemplateLibraryPanel
              masters={masters}
              setMasters={setMasters || (() => {})}
            />
          )}
          {activeTable === 'MasterPropertyType' && (
            <div className="bg-bone border border-line rounded-lg p-3 mb-4 flex items-start gap-3">
              <div className="w-9 h-9 rounded-lg bg-paper border border-line-soft flex items-center justify-center shrink-0">
                <Ruler className="w-4 h-4 text-terra" strokeWidth={2.4} />
              </div>
              <div>
                <div className="text-[11px] font-mono uppercase tracking-wider font-semibold ink-faint">Editable size bands</div>
                <div className="text-xs ink-soft mt-1 leading-relaxed">
                  Each property type now carries up to 4 editable size bands. Blank size cells auto-fill from sample ranges based on the linked category and property type, and the table backup CSV includes these values.
                </div>
              </div>
            </div>
          )}
          {activeTable === 'MasterPropertyType' && tableExportFile?.tableName === 'MasterPropertyType' && (
            <div className="bg-moss-soft border border-moss rounded-lg p-3 mb-4 flex items-center justify-between gap-3">
              <div>
                <div className="text-[11px] font-mono uppercase tracking-wider font-semibold text-moss">Property Type CSV ready</div>
                <div className="text-[11px] ink-soft mt-0.5">
                  {tableExportFile.rowCount} rows · {tableExportFile.filename}
                  {tableExportFile.savedPath ? ` · saved at ${tableExportFile.savedPath}` : ''}
                </div>
                {tableExportFile.error && <div className="text-[11px] text-terra mt-1">{tableExportFile.error}</div>}
              </div>
              <div className="flex items-center gap-2 shrink-0">
                <a
                  href={tableExportFile.url}
                  download={tableExportFile.filename}
                  className="inline-flex items-center gap-1.5 px-3 py-2 rounded-md bg-paper border border-line text-ink hover:border-terra hover:text-terra text-[10px] font-mono uppercase tracking-wider font-semibold"
                >
                  <Download className="w-3 h-3" />
                  Download Table CSV
                </a>
                <button
                  onClick={() => navigator.clipboard.writeText(tableExportFile.csv || '')}
                  className="inline-flex items-center gap-1.5 px-3 py-2 rounded-md bg-paper border border-line text-ink hover:border-terra hover:text-terra text-[10px] font-mono uppercase tracking-wider font-semibold"
                >
                  <Copy className="w-3 h-3" />
                  Copy CSV
                </button>
              </div>
            </div>
          )}
          <div className="bg-paper border border-line rounded-lg p-4 mb-4">
            <div className="text-[10px] font-mono tracking-widest font-semibold uppercase ink-faint mb-3">Add new row</div>
            <div className="flex gap-3 items-end">
              {schema.columns.filter((c) => c.type !== 'preview').map((col) => (
                <div key={col.key} className="flex-1">
                  <label className="text-[11px] font-mono ink-soft uppercase tracking-wider block mb-1">{col.label}</label>
                  {col.type === 'select' ? (
                    <SelectField value={typeof newRow[col.key] === 'boolean' ? String(newRow[col.key]) : (newRow[col.key] || '')} onChange={(v) => setNewRow({ ...newRow, [col.key]: v })} options={col.options || (masters[col.sourceMaster] || []).map(masterOptionValue)} />
                  ) : col.type === 'textarea' ? (
                    (() => {
                      const value = newRow[col.key] || '';
                      const lineCount = (value.match(/\n/g) || []).length + 1;
                      const dynamicRows = Math.max(4, Math.min(12, lineCount));
                      return (
                        <textarea
                          value={value}
                          onChange={(e) => setNewRow({ ...newRow, [col.key]: e.target.value })}
                          placeholder={col.placeholder || `New ${col.label.toLowerCase()}…`}
                          rows={dynamicRows}
                          className="input-sm w-full text-sm"
                          style={{ resize: 'vertical', fontFamily: 'inherit', whiteSpace: 'pre-wrap', wordBreak: 'break-word' }}
                        />
                      );
                    })()
                  ) : (
                    <TextField value={newRow[col.key] || ''} onChange={(v) => setNewRow({ ...newRow, [col.key]: v })} placeholder={`New ${col.label.toLowerCase()}…`} />
                  )}
                </div>
              ))}
              <button onClick={handleAdd} className="flex items-center gap-1.5 px-4 py-2.5 bg-ink text-white rounded-md text-xs font-mono tracking-wider font-semibold uppercase hover:bg-terra">
                <Plus className="w-3.5 h-3.5" /> Add
              </button>
              {onBulkAdd && (
                <button
                  onClick={() => setShowBulkAddModal(true)}
                  className="flex items-center gap-1.5 px-3 py-2.5 bg-bone border border-line text-ink rounded-md text-xs font-mono tracking-wider hover:border-terra hover:text-terra"
                  title="Paste a list of names — each line becomes a new row"
                >
                  <Clipboard className="w-3.5 h-3.5" /> Paste list…
                </button>
              )}
              <button
                onClick={handleManualSave}
                disabled={!onForceSave || manualSaveState === 'saving'}
                className={`flex items-center gap-1.5 px-3 py-2.5 rounded-md text-xs font-mono tracking-wider font-semibold uppercase border ${
                  manualSaveState === 'saving'
                    ? 'bg-terra text-white border-terra'
                    : manualSaveState === 'saved'
                      ? 'bg-moss text-white border-moss'
                      : manualSaveState === 'error'
                        ? 'bg-terra-soft text-terra border-terra'
                        : 'bg-paper text-ink border-line hover:border-terra hover:text-terra'
                }`}
                title="Commit these table edits as saved workspace data."
              >
                {manualSaveState === 'saving' ? <RefreshCw className="w-3.5 h-3.5 animate-spin" /> : <Save className="w-3.5 h-3.5" />}
                {manualSaveState === 'saving' ? 'Saving' : manualSaveState === 'saved' ? 'Saved' : manualSaveState === 'error' ? 'Retry' : 'Save'}
              </button>
            </div>
          </div>

          <div className="bg-paper border border-line rounded-lg overflow-hidden">
            {/* Phase 6.2i — Build grid template: textarea columns get 3fr (wider for multi-line content),
                everything else gets 1fr. Header and data rows must use the SAME template. */}
            <div className="grid border-b border-line bg-bone px-4 py-1.5 gap-3" style={{
              gridTemplateColumns: `${isReorderable ? '64px' : '40px'} ${schema.columns.map((c) => c.type === 'textarea' ? '3fr' : '1fr').join(' ')} 80px`
            }}>
              <div className="text-[10px] font-mono ink-faint uppercase tracking-wider">#</div>
              {schema.columns.map((col) => {
                const isSortable = activeTable !== 'MasterPropertyType' || ['value', 'category'].includes(col.key);
                return isSortable ? (
                  <button
                    key={col.key}
                    onClick={() => toggleColumnSort(col.key)}
                    className={`group inline-flex items-center gap-1 justify-start text-left text-[10px] font-mono uppercase tracking-wider transition-colors ${
                      sortConfig.table === activeTable && sortConfig.key === col.key ? 'text-terra' : 'ink-faint hover:text-terra'
                    }`}
                    title={`Sort ${col.label}`}
                  >
                    <span className="truncate">{col.label}</span>
                    <span className="inline-flex flex-col leading-none -space-y-1 shrink-0">
                      <ChevronUp className={`w-3 h-3 ${sortConfig.table === activeTable && sortConfig.key === col.key && sortConfig.direction === 'asc' ? 'text-terra' : 'ink-faint group-hover:text-terra'}`} strokeWidth={2.4} />
                      <ChevronDown className={`w-3 h-3 ${sortConfig.table === activeTable && sortConfig.key === col.key && sortConfig.direction === 'desc' ? 'text-terra' : 'ink-faint group-hover:text-terra'}`} strokeWidth={2.4} />
                    </span>
                  </button>
                ) : (
                  <div key={col.key} className="text-left text-[10px] font-mono uppercase tracking-wider ink-faint truncate">
                    {col.label}
                  </div>
                );
              })}
              <div></div>
            </div>
            {rows.length === 0 && (
              <div className="px-6 py-12 text-center"><div className="text-sm ink-soft">No rows yet — add the first one above.</div></div>
            )}
            {sortedRows.map((row, idx) => (
              <MasterRow key={row.id} row={row} index={idx} schema={schema}
                tableName={activeTable}
                isEditing={editingId === row.id}
                onEdit={() => setEditingId(row.id)} onCancel={() => setEditingId(null)}
                onSave={(updated) => handleSaveEdit(row.id, updated)}
                onDelete={() => onDelete(activeTable, row.id)} masters={masters}
                canMoveUp={isReorderable && rows.findIndex((candidate) => candidate.id === row.id) > 0}
                canMoveDown={isReorderable && rows.findIndex((candidate) => candidate.id === row.id) < rows.length - 1}
                onMoveUp={isReorderable ? () => {
                  const originalIdx = rows.findIndex((candidate) => candidate.id === row.id);
                  moveMasterRow(originalIdx, originalIdx - 1);
                } : null}
                onMoveDown={isReorderable ? () => {
                  const originalIdx = rows.findIndex((candidate) => candidate.id === row.id);
                  moveMasterRow(originalIdx, originalIdx + 1);
                } : null}
              />
            ))}
          </div>

          {/* Phase 5.10.2 — Clear all rows danger zone */}
          {onClearTable && rows.length > 0 && (
            <div className="mt-4 bg-paper border-2 border-terra border-dashed rounded-lg p-4">
              <div className="flex items-center gap-2 mb-2">
                <AlertTriangle className="w-3.5 h-3.5 text-terra" strokeWidth={2.5} />
                <div className="text-[10px] font-mono tracking-widest font-semibold uppercase text-terra">Danger zone</div>
              </div>
              <div className="flex items-start justify-between gap-4">
                <div className="flex-1">
                  <div className="text-[12px] ink font-medium mb-1">Clear all rows in this table</div>
                  <div className="text-[11px] ink-soft leading-relaxed">
                    Deletes all <span className="ink font-semibold">{rows.length}</span> rows from <span className="ink font-semibold">{schema.label}</span>. This cannot be undone. Workflow templates and projects that reference these rows by name will keep working but the "Used in" link will go dark.
                  </div>
                </div>
                <button
                  onClick={() => setShowClearModal(true)}
                  className="px-3 py-2 text-[11px] font-mono uppercase tracking-wider bg-terra text-white rounded font-semibold hover:opacity-90 shrink-0"
                >
                  Clear all…
                </button>
              </div>
            </div>
          )}

          {/* Phase 5.10.2 — Clear all confirmation modal */}
          {showClearModal && (
            <ClearTableConfirmModal
              tableName={activeTable}
              tableLabel={schema.label}
              rowCount={rows.length}
              onClose={() => setShowClearModal(false)}
              onConfirm={() => {
                onClearTable(activeTable);
                setShowClearModal(false);
              }}
            />
          )}

          {/* Phase 5.10.2 — Bulk add (paste list) modal */}
          {showBulkAddModal && (
            <BulkAddModal
              tableLabel={schema.label}
              schema={schema}
              masters={masters}
              onClose={() => setShowBulkAddModal(false)}
              onConfirm={(items) => {
                onBulkAdd(activeTable, items);
                setShowBulkAddModal(false);
              }}
            />
          )}
        </div>
      </div>
      )}
    </div>
  );
}

/* Phase 6.2j — Word-count truncation helper.
   Returns { display, truncated, full }. If word count <= maxWords, display === full
   and truncated === false. Otherwise, display is the first maxWords joined by spaces
   plus an ellipsis; the caller can attach `title={full}` for the hover tooltip. */
function LibrarySectionButton({ active, onClick, label }) {
  return (
    <button
      onClick={onClick}
      className={`w-full text-left px-2.5 py-2 rounded-md text-xs font-medium ${
        active ? 'bg-ink text-white' : 'ink-soft hover:ink hover:bg-bone'
      }`}
    >
      {label}
    </button>
  );
}

function truncateWords(text, maxWords) {
  if (typeof text !== 'string' || !text) return { display: text || '', truncated: false, full: text || '' };
  const words = text.trim().split(/\s+/);
  if (words.length <= maxWords) return { display: text, truncated: false, full: text };
  return { display: words.slice(0, maxWords).join(' ') + '…', truncated: true, full: text };
}

function MasterRow({ row, index, schema, tableName, isEditing, onEdit, onCancel, onSave, onDelete, masters, canMoveUp, canMoveDown, onMoveUp, onMoveDown }) {
  const displayRow = React.useMemo(
    () => tableName === 'MasterPropertyType' ? withPropertyTypeSizeDefaults(row) : tableName === 'MasterBOQItems' ? withBOQItemDefaults(row) : row,
    [row, tableName]
  );
  const [edit, setEdit] = useState(displayRow);
  const [editingItemsModal, setEditingItemsModal] = useState(false);
  React.useEffect(() => { setEdit(displayRow); }, [isEditing, displayRow]);

  /* Phase 5.9 Fix-pack — "Used in" indicator for stages, activities, deliverables.
     Computed only for the master tables that matter; null otherwise. */
  const usage = React.useMemo(() => {
    if (isEditing) return null;
    if (tableName === 'MasterWorkflowStages') return countUsageInTemplates('stage', row.value, masters);
    if (tableName === 'MasterActivities') return countUsageInTemplates('activity', row.value, masters);
    if (tableName === 'MasterDeliverables') return countUsageInTemplates('deliverable', row.value, masters);
    return null;
  }, [tableName, row.value, isEditing, masters]);

  /* Save items array back through the standard onSave path */
  const saveItems = (newItems) => {
    onSave({ ...row, items: newItems });
    setEditingItemsModal(false);
  };

  const showMove = onMoveUp && onMoveDown && !isEditing;
  const indexColWidth = showMove ? '64px' : '40px';
  /* Phase 6.2i — Detect whether any column is multi-line; if so, top-align cells so
     short fields stay at the top of the row when neighbour cells expand vertically. */
  const hasTextarea = schema.columns.some((c) => c.type === 'textarea');
  const alignClass = hasTextarea ? 'items-start' : 'items-center';
  /* Same grid-template formula as the header row above */
  const rowGridTemplate = `${indexColWidth} ${schema.columns.map((c) => c.type === 'textarea' ? '3fr' : '1fr').join(' ')} 80px`;

  return (
    <div className={`grid border-b border-line-soft px-4 py-1 gap-3 ${alignClass} hover:bg-bone group ${isEditing ? 'bg-terra-soft' : ''}`}
      style={{ gridTemplateColumns: rowGridTemplate }}>
      <div className="flex items-center gap-1.5">
        {showMove && (
          <MoveButtons
            canUp={canMoveUp}
            canDown={canMoveDown}
            onUp={onMoveUp}
            onDown={onMoveDown}
            size="xs"
          />
        )}
        <span className="text-[10px] font-mono ink-faint">{String(index + 1).padStart(2, '0')}</span>
      </div>
      {schema.columns.map((col) => (
        <div key={col.key}>
          {col.type === 'preview' ? (
            tableName === 'MasterTaskChecklists' && col.key === 'items' && !isEditing ? (
              <button
                onClick={() => setEditingItemsModal(true)}
                className="text-xs font-mono text-terra hover:ink underline-offset-2 hover:underline cursor-pointer text-left"
                title="Click to edit items"
              >
                {col.preview ? col.preview(row) : '—'} ›
              </button>
            ) : (
              <span className="text-xs font-mono ink-soft">{col.preview ? col.preview(row) : '—'}</span>
            )
          ) : isEditing ? (
            col.type === 'select' ? (
              <SelectField value={typeof edit[col.key] === 'boolean' ? String(edit[col.key]) : edit[col.key]} onChange={(v) => setEdit({ ...edit, [col.key]: v })} options={col.options || (masters[col.sourceMaster] || []).map(masterOptionValue)} />
            ) : col.type === 'textarea' ? (
              (() => {
                const value = edit[col.key] || '';
                const lineCount = (value.match(/\n/g) || []).length + 1;
                const dynamicRows = Math.max(4, Math.min(12, lineCount));
                return (
                  <textarea
                    value={value}
                    onChange={(e) => setEdit({ ...edit, [col.key]: e.target.value })}
                    placeholder={col.placeholder || ''}
                    rows={dynamicRows}
                    className="input-sm w-full text-sm"
                    style={{ resize: 'vertical', fontFamily: 'inherit', whiteSpace: 'pre-wrap', wordBreak: 'break-word' }}
                  />
                );
              })()
            ) : (
              <TextField value={edit[col.key]} onChange={(v) => setEdit({ ...edit, [col.key]: v })} />
            )
          ) : col.type === 'textarea' ? (
            /* Phase 6.2i — Full bulleted list rendering. Each item on its own line.
               Phase 6.2j — Each item truncated to 10 words; full text on hover. Tighter spacing. */
            (() => {
              const raw = displayRow[col.key];
              if (!raw || typeof raw !== 'string' || !raw.trim()) {
                return <span className="ink-faint" style={{ fontStyle: 'italic' }}>—</span>;
              }
              const lines = raw.split(/\r?\n/).map((l) => l.trim()).filter(Boolean);
              if (lines.length === 0) return <span className="ink-faint" style={{ fontStyle: 'italic' }}>—</span>;
              return (
                <div className="text-[12px] ink leading-tight">
                  {lines.map((line, lineIdx) => {
                    const t = truncateWords(line, 10);
                    return (
                      <div key={lineIdx} className="flex items-start gap-1.5" title={t.truncated ? t.full : undefined}>
                        <span className="text-terra shrink-0 leading-tight">•</span>
                        <span className="flex-1 min-w-0">{t.display}</span>
                      </div>
                    );
                  })}
                  <div className="text-[10px] font-mono ink-faint">{lines.length} item{lines.length === 1 ? '' : 's'}</div>
                </div>
              );
            })()
          ) : (
            /* Phase 6.2j — Generic text cell with 10-word truncation for long-form columns.
               Description-style fields wrap on hover; short fields (names, dropdowns) stay full. */
            (() => {
              const raw = displayRow[col.key];
              if (tableName === 'MasterProjectTemplates' && col.key === 'isQuickStart' && raw === undefined) {
                return <span className="text-sm ink">true</span>;
              }
              if (tableName === 'MasterPropertyTemplates' && col.key === 'showInQuickstart' && raw === undefined) {
                return <span className="text-sm ink">true</span>;
              }
              if (tableName === 'MasterContractTemplates' && col.key === 'linkedServiceType' && !raw) {
                return <span className="text-sm ink">{inferContractServiceType(row)}</span>;
              }
              if (raw === undefined || raw === '') {
                return <span className="ink-faint" style={{ fontStyle: 'italic' }}>—</span>;
              }
              if (typeof raw === 'boolean') {
                return <span className="text-sm ink">{raw ? 'true' : 'false'}</span>;
              }
              if (typeof raw !== 'string') {
                const display = raw == null
                  ? '—'
                  : Array.isArray(raw)
                    ? raw.map((item) => (typeof item === 'object' && item !== null ? (item.name || item.value || item.label || item.id || JSON.stringify(item)) : String(item))).join(', ')
                    : (raw.name || raw.value || raw.label || raw.id || JSON.stringify(raw));
                return <span className="text-sm ink" title={display}>{display}</span>;
              }
              /* Apply truncation only to columns flagged as long-form (key === 'description') */
              const isLongForm = col.key === 'description';
              if (isLongForm) {
                const t = truncateWords(raw, 10);
                return <span className="text-sm ink" title={t.truncated ? t.full : undefined}>{t.display}</span>;
              }
              return <span className="text-sm ink">{raw}</span>;
            })()
          )}
        </div>
      ))}
      <div className="flex items-center gap-1 justify-end">
        {usage && (
          <UsedInChip usage={usage} />
        )}
        {isEditing ? (
          <>
            <button onClick={() => onSave(edit)} className="p-1.5 hover:bg-paper rounded" title="Save"><Check className="w-3.5 h-3.5 text-moss" strokeWidth={2.5} /></button>
            <button onClick={onCancel} className="p-1.5 hover:bg-paper rounded" title="Cancel"><X className="w-3.5 h-3.5 ink-soft" /></button>
          </>
        ) : (
          <>
            <button onClick={onEdit} className="p-1.5 hover:bg-paper rounded opacity-0 group-hover:opacity-100" title="Edit"><Edit3 className="w-3.5 h-3.5 ink-soft" /></button>
            <button onClick={onDelete} className="p-1.5 hover:bg-paper rounded opacity-0 group-hover:opacity-100" title="Delete"><Trash2 className="w-3.5 h-3.5 text-terra" /></button>
          </>
        )}
      </div>

      {/* Phase 5.9 Fix-pack v2 — Checklist items editor modal */}
      {editingItemsModal && (
        <ChecklistItemsModal
          checklist={row}
          onClose={() => setEditingItemsModal(false)}
          onSave={saveItems}
        />
      )}
    </div>
  );
}

/* ================================================================== */
/* ===================== BACKUP & RESTORE SCREEN ==================== */
/* ================================================================== */

function formatBytes(bytes) {
  if (bytes < 1024) return `${bytes} B`;
  if (bytes < 1024 * 1024) return `${(bytes / 1024).toFixed(1)} KB`;
  return `${(bytes / (1024 * 1024)).toFixed(2)} MB`;
}

const BACKUP_STANDARD_ITEMS = [
  {
    title: 'Full Source ZIP',
    detail: 'Restores app code, React JSX modules, backend source, SQL schema files, package files, and the latest bundled data JSON.',
    included: 'Included in Full Source ZIP',
  },
  {
    title: 'Data Backup JSON',
    detail: 'Contains projects, master tables, settings, theme, board columns, forms, contracts, and other workspace content.',
    included: 'Included as studio-os-data-backup-*.json',
  },
  {
    title: 'Supabase Credentials',
    detail: 'Keep VITE_SUPABASE_URL, VITE_SUPABASE_ANON_KEY, table name, row ID, and bucket name separately. They are intentionally not exported in normal backups.',
    included: 'Not included for safety',
  },
];

function BackupStandardGuardrail({ mode = 'settings' }) {
  const isBackupRoute = mode === 'backup';
  return (
    <div className="bg-paper border border-line rounded-xl overflow-hidden">
      <div className="px-5 py-4 border-b border-line bg-bone flex items-start justify-between gap-4">
        <div>
          <div className="text-[10px] font-mono uppercase tracking-widest ink-faint mb-1">Backup standard guardrail</div>
          <h2 className="font-display text-xl ink tracking-tight leading-tight">
            {isBackupRoute ? 'Level 3 export must follow this standard' : 'Level 1 & 2 backup policy'}
          </h2>
          <p className="text-xs ink-soft mt-1 max-w-3xl leading-relaxed">
            A crash-safe StudioOS backup needs source, data, and separately stored Supabase credentials. The export buttons should always make this visible before download or restore.
          </p>
        </div>
        <div className="hidden md:flex items-center gap-2 px-3 py-2 rounded-lg bg-paper border border-line-soft text-[11px] font-mono ink-soft">
          <ShieldCheck className="w-4 h-4 text-moss" />
          Standard
        </div>
      </div>
      <div className="grid grid-cols-1 md:grid-cols-3 divide-y md:divide-y-0 md:divide-x divide-line-soft">
        {BACKUP_STANDARD_ITEMS.map((item, index) => (
          <div key={item.title} className="p-4">
            <div className="flex items-start gap-3">
              <div className={`w-8 h-8 rounded-lg flex items-center justify-center shrink-0 ${index === 2 ? 'bg-terra-soft text-terra' : 'bg-moss-soft text-moss'}`}>
                {index === 0 ? <Code2 className="w-4 h-4" /> : index === 1 ? <Database className="w-4 h-4" /> : <Lock className="w-4 h-4" />}
              </div>
              <div>
                <div className="text-sm font-semibold ink">{item.title}</div>
                <div className="text-[11px] ink-soft leading-relaxed mt-1">{item.detail}</div>
                <div className={`inline-flex mt-3 px-2 py-1 rounded text-[9px] font-mono uppercase tracking-wider ${index === 2 ? 'bg-terra-soft text-terra' : 'bg-moss-soft text-moss'}`}>
                  {item.included}
                </div>
              </div>
            </div>
          </div>
        ))}
      </div>
      <div className="px-5 py-3 border-t border-line-soft bg-bone text-[11px] ink-soft leading-relaxed">
        <strong className="ink">Standing rule:</strong> regular button backup should produce a clean source ZIP plus the current JSON data backup. The `.env.local` secrets stay outside the ZIP and must be stored in your password manager or Supabase setup note.
      </div>
    </div>
  );
}

function BackupRestoreScreen({ projects, masters, boardColumns, theme, themePreset, onRestore }) {
  const [importPreview, setImportPreview] = useState(null);
  const [showPasteModal, setShowPasteModal] = useState(false);
  const [pasteText, setPasteText] = useState('');
  const [showRawDump, setShowRawDump] = useState(false);
  const [showResetModal, setShowResetModal] = useState(false);
  const [lastExportedAt, setLastExportedAt] = useState(null);
  const [toast, setToast] = useState(null);
  const [sourceExporting, setSourceExporting] = useState(false);
  const [developerShareMessages, setDeveloperShareMessages] = useState(null);

  const showToast = (msg, kind = 'success') => {
    setToast({ msg, kind });
    setTimeout(() => setToast(null), 3000);
  };

  const stats = useMemo(() => {
    const projectsJson = JSON.stringify(projects);
    const mastersJson = JSON.stringify(masters);
    const columnsJson = JSON.stringify(boardColumns);
    const themeJson = JSON.stringify(theme || {});

    const items = [
      { key: 'studio-projects', size: projectsJson.length, count: projects.length, type: 'app' },
      { key: 'studio-masters', size: mastersJson.length, count: Object.keys(masters).length, type: 'app' },
      { key: 'studio-board-columns', size: columnsJson.length, count: boardColumns.length, type: 'app' },
      { key: 'studio-theme', size: themeJson.length, count: theme ? Object.keys(theme).length : 0, type: 'app' },
    ];
    if (lastExportedAt) {
      items.push({ key: 'last-export-at', size: lastExportedAt.length, count: null, type: 'extra' });
    }

    const totalSize = items.reduce((sum, i) => sum + i.size, 0);
    const appKeys = items.filter((i) => i.type === 'app').length;
    const totalKeys = items.length;
    return { items, totalSize, appKeys, totalKeys };
  }, [projects, masters, boardColumns, theme, lastExportedAt]);

  const buildBackup = () => ({
    exportedAt: new Date().toISOString(),
    version: '6',
    appVersion: 'v0.11.3',
    appName: 'Studio/OS',
    data: { projects, masters, boardColumns, theme, themePreset },
  });

  const buildDeveloperShareMessages = ({ sourceZipFilename = '', dataJsonFilename = '', exportedAt = new Date().toISOString() } = {}) => {
    const currentEnv = import.meta.env || {};
    const envValue = (key, fallback) => currentEnv[key] || fallback;
    const packageLines = [
      'Developer handoff package for StudioOS',
      '',
      sourceZipFilename
        ? `1. Full Source ZIP: ${sourceZipFilename}`
        : '1. Full Source ZIP: attach the latest StudioOS_full_backup_*.zip',
      dataJsonFilename
        ? `2. Data Backup JSON: ${dataJsonFilename}`
        : '2. Data Backup JSON: included inside the Full Source ZIP as studio-os-data-backup-*.json',
      '3. Supabase env values: sent separately in the private message below',
      '',
      'Local run steps:',
      'npm install',
      'npm run dev',
      '',
      'Open:',
      'http://127.0.0.1:5174/',
      '',
      `Exported at: ${new Date(exportedAt).toLocaleString('en-IN', { timeZone: 'Asia/Kolkata' })} IST`,
    ].join('\n');
    const envLines = [
      'PRIVATE ENV MESSAGE - send separately, not in public chat',
      '',
      'Create a file named .env.local in the app folder and paste:',
      '',
      `VITE_SUPABASE_URL=${envValue('VITE_SUPABASE_URL', 'PASTE_SUPABASE_PROJECT_URL_HERE')}`,
      `VITE_SUPABASE_ANON_KEY=${envValue('VITE_SUPABASE_ANON_KEY', 'PASTE_SUPABASE_ANON_PUBLIC_KEY_HERE')}`,
      `VITE_SUPABASE_TABLE=${envValue('VITE_SUPABASE_TABLE', 'studio_workspace')}`,
      `VITE_SUPABASE_ROW_ID=${envValue('VITE_SUPABASE_ROW_ID', 'khanna-case-20260508')}`,
      `VITE_SUPABASE_FILE_BUCKET=${envValue('VITE_SUPABASE_FILE_BUCKET', 'studio-os-files')}`,
      '',
      'Then restart the app with:',
      'npm run dev',
    ].join('\n');
    return { packageMessage: packageLines, envMessage: envLines, exportedAt };
  };

  const handleExport = () => {
    const data = buildBackup();
    const json = JSON.stringify(data, null, 2);
    const blob = new Blob([json], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    const dateStr = new Date().toISOString().split('T')[0];
    const filename = `studio-os-backup-${dateStr}.json`;
    a.href = url;
    a.download = filename;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
    setLastExportedAt(data.exportedAt);
    setDeveloperShareMessages(buildDeveloperShareMessages({ dataJsonFilename: filename, exportedAt: data.exportedAt }));
    showToast('Backup downloaded.');
  };

  const handleSourceExport = async () => {
    setSourceExporting(true);
    try {
      const dataBackup = buildBackup();
      const response = await fetch(`${WHATSAPP_API_BASE}/source-backup`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ dataBackup }),
      });
      if (!response.ok) {
        const details = await response.json().catch(() => null);
        throw new Error(details?.details || details?.error || `Backend returned ${response.status}`);
      }

      const blob = await response.blob();
      const disposition = response.headers.get('content-disposition') || '';
      const filenameMatch = disposition.match(/filename="?([^"]+)"?/i);
      const fallbackStamp = new Date().toISOString().slice(0, 16).replace(/-|:|T/g, '').replace(/^(\d{8})(\d{4})$/, '$1_$2');
      const filename = filenameMatch?.[1] || `StudioOS_full_backup_${fallbackStamp}.zip`;
      const mirroredPathHeader = response.headers.get('x-studioos-mirrored-path') || '';
      const mirroredPath = mirroredPathHeader ? decodeURIComponent(mirroredPathHeader) : '';
      const url = URL.createObjectURL(blob);
      const a = document.createElement('a');
      a.href = url;
      a.download = filename;
      document.body.appendChild(a);
      a.click();
      document.body.removeChild(a);
      URL.revokeObjectURL(url);
      setLastExportedAt(dataBackup.exportedAt);
      setDeveloperShareMessages(buildDeveloperShareMessages({ sourceZipFilename: filename, exportedAt: dataBackup.exportedAt }));
      showToast('Full source + data ZIP downloaded.');
    } catch (error) {
      showToast(`Could not create source ZIP: ${error.message}`, 'error');
    } finally {
      setSourceExporting(false);
    }
  };

  const handleFileImport = (e) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (ev) => processImport(ev.target.result);
    reader.onerror = () => showToast('Failed to read file.', 'error');
    reader.readAsText(file);
    e.target.value = '';
  };

  const processImport = (jsonString) => {
    try {
      const parsed = JSON.parse(jsonString);
      if (!parsed.data || typeof parsed.data !== 'object') {
        showToast('Invalid backup — missing "data" field.', 'error');
        return;
      }
      // Phase 5.6.3 — schema migration warning, two layers:
      //   v1, v2: pre-Activities (Phase 5.4)
      //   v3: pre-Clients/Vendors masters (Phase 5.6)
      const ver = String(parsed.version || '0');
      if (ver === '1' || ver === '2') {
        const proceed = window.confirm(
          `This backup is version ${ver} (old schema). The current build is version 5 — Workflow ` +
          `(Activities & Deliverables, added in v3), Client/Vendor (master records, added in v4), and ` +
          `Task delegation tracking (added in v5) have all been restructured since this backup was made.` +
          `\n\nIf you restore: projects will load but Activities/Deliverables will be empty (re-initialise ` +
          `from masters per project), clients/vendors will appear in legacy "synthetic" mode, and tasks ` +
          `will use legacy assignee strings (delegation history blank).` +
          `\n\nContinue?`
        );
        if (!proceed) return;
      } else if (ver === '3') {
        const proceed = window.confirm(
          `This backup is version 3 (pre-Phase 5.6 schema). The current build is version 5 — Clients and ` +
          `Vendors are now first-class master entities, but this backup stores them as inline strings on each project.` +
          `\n\nIf you restore: projects will load and remain functional, but clients and vendors will appear ` +
          `as "synthetic" records (read-only, with a callout asking you to migrate them to masters). The ` +
          `Workflow / Activities / Deliverables structure (introduced in v3) is preserved fully.` +
          `\n\nTask delegation tracking (added in v5) will use the legacy assignee strings — performance analytics may be incomplete.` +
          `\n\nContinue?`
        );
        if (!proceed) return;
      } else if (ver === '4') {
        const proceed = window.confirm(
          `This backup is version 4 (pre-Phase 5.8 schema). The current build is version 5 — Tasks now track ` +
          `assignee as a team member ID (assigneeId) rather than a name string, plus assignedById and assignedAt for delegation history.` +
          `\n\nIf you restore: tasks will load and remain functional via the legacy assignee string. Performance ` +
          `analytics (added in v5) will rely on string matching to associate tasks with team members — this works ` +
          `for the seeded names but may miss tasks where the assignee name has typos or different formatting.` +
          `\n\nContinue?`
        );
        if (!proceed) return;
      }
      setImportPreview(parsed);
    } catch (e) {
      showToast('Could not parse JSON: ' + e.message, 'error');
    }
  };

  const confirmImport = () => {
    onRestore(importPreview.data);
    setImportPreview(null);
    setShowPasteModal(false);
    setPasteText('');
    showToast('Backup restored successfully.');
  };

  const handleCopyDump = () => {
    const json = JSON.stringify(buildBackup(), null, 2);
    if (navigator.clipboard?.writeText) {
      navigator.clipboard.writeText(json).then(
        () => showToast('Copied to clipboard.'),
        () => showToast('Could not copy. Select the text manually.', 'error')
      );
    } else {
      showToast('Clipboard not available — select manually.', 'error');
    }
  };

  const copyShareMessage = (text, label) => {
    if (navigator.clipboard?.writeText) {
      navigator.clipboard.writeText(text).then(
        () => showToast(`${label} copied.`),
        () => showToast('Could not copy. Select the text manually.', 'error')
      );
    } else {
      showToast('Clipboard not available — select manually.', 'error');
    }
  };

  return (
    <div className="flex-1 overflow-auto scrollbar-thin">
      {/* Page header */}
      <div className="bg-paper border-b border-line px-6 py-5">
        <div className="flex items-center justify-between mb-3">
          <div className="flex items-center gap-3">
            <div className="w-12 h-12 bg-blue-vibrant rounded-lg flex items-center justify-center" style={{ boxShadow: '0 4px 12px rgba(37, 99, 235, 0.25)' }}>
              <ShieldCheck className="w-6 h-6 text-white" strokeWidth={2} />
            </div>
            <div>
              <div className="flex items-center gap-2">
                <h1 className="font-display text-3xl ink tracking-tight leading-none">Backup &amp; Restore</h1>
                {lastExportedAt && (
                  <span className="flex items-center gap-1 text-[11px] text-moss font-mono">
                    <CheckCircle2 className="w-3 h-3" /> Saved
                  </span>
                )}
              </div>
              <div className="text-[11px] font-mono ink-soft mt-1">Export and restore Studio/OS data · v1</div>
            </div>
          </div>
        </div>
        <p className="text-sm ink-soft leading-relaxed" style={{ maxWidth: '780px' }}>
          Export everything in this Studio/OS workspace as a JSON file, or restore from one. Use this before any risky operation, and to move data between conversations or environments.
        </p>
      </div>

      <div className="p-6 space-y-5" style={{ maxWidth: '1100px' }}>

        <BackupStandardGuardrail mode="backup" />

        {/* Storage overview */}
        <div className="bg-paper border border-line rounded-lg overflow-hidden">
          <div className="flex items-center justify-between px-5 py-3 border-b border-line bg-bone">
            <div className="text-[10px] font-mono tracking-widest font-semibold uppercase ink-faint">Storage in this workspace</div>
            <button className="flex items-center gap-1 text-[11px] font-mono ink-soft hover:ink">
              <RefreshCw className="w-3 h-3" /> Refresh
            </button>
          </div>

          <div className="grid grid-cols-3 border-b border-line-soft">
            <div className="px-5 py-4">
              <div className="text-[10px] font-mono ink-faint uppercase tracking-wider mb-1">Total Keys</div>
              <div className="font-display text-3xl ink leading-none">{stats.totalKeys}</div>
            </div>
            <div className="px-5 py-4 border-l border-line-soft">
              <div className="text-[10px] font-mono ink-faint uppercase tracking-wider mb-1">App Keys</div>
              <div className="font-display text-3xl leading-none">
                <span className="text-blue-vibrant font-semibold">{stats.appKeys}</span>
                <span className="ink-faint" style={{ fontSize: '24px' }}>/{stats.totalKeys}</span>
              </div>
            </div>
            <div className="px-5 py-4 border-l border-line-soft">
              <div className="text-[10px] font-mono ink-faint uppercase tracking-wider mb-1">Size</div>
              <div className="font-display text-3xl ink leading-none">{formatBytes(stats.totalSize)}</div>
            </div>
          </div>

          <div className="px-5 py-3">
            {stats.items.map((item) => (
              <div key={item.key} className="flex items-center justify-between py-1.5">
                <div className="flex items-center gap-2.5">
                  <span className={`w-1.5 h-1.5 rounded-full ${item.type === 'app' ? 'bg-blue-vibrant' : 'bg-line'}`} />
                  <span className="text-sm font-mono ink">{item.key}</span>
                  {item.count !== null && <span className="text-[10px] font-mono ink-faint">({item.count})</span>}
                  {item.type === 'extra' && (
                    <span className="text-[9px] font-mono ink-faint uppercase tracking-wider px-1.5 py-0.5 bg-bone rounded">extra</span>
                  )}
                </div>
                <span className="text-xs font-mono ink-faint">{formatBytes(item.size)}</span>
              </div>
            ))}
          </div>
        </div>

        {/* Auto-snapshots */}
        <div className="bg-paper border border-line rounded-lg overflow-hidden">
          <div className="flex items-center justify-between px-5 py-3 border-b border-line bg-bone">
            <div className="flex items-center gap-2">
              <History className="w-3.5 h-3.5 text-terra" />
              <div className="text-[10px] font-mono tracking-widest font-semibold uppercase ink-faint">Rolling Auto-Snapshots</div>
              <span className="text-[10px] font-mono ink-faint">· last 5 saves, throttled to 30 min</span>
            </div>
            <button className="flex items-center gap-1 text-[11px] font-mono ink-soft hover:ink">
              <RefreshCw className="w-3 h-3" /> Refresh
            </button>
          </div>
          <div className="px-5 py-8 text-center">
            <div className="text-sm ink-soft">
              No auto-snapshots yet. They&apos;re written automatically when you click <span className="font-semibold ink">Save</span> in the header.
            </div>
          </div>
        </div>

        {/* Warning callout */}
        <div className="bg-amber-soft border border-amber rounded-lg p-4">
          <div className="flex gap-3">
            <AlertCircle className="w-5 h-5 shrink-0 mt-0.5 text-amber-mid" />
            <div className="flex-1">
              <div className="font-semibold text-sm text-amber-deep">Use the standard: Full Source ZIP + Data JSON + separate Supabase credentials.</div>
              <p className="text-xs mt-1.5 leading-relaxed text-amber-mid">
                <strong>Export Backup</strong> is the data-only safety file. <strong>Full Source ZIP</strong> is the complete app package and now includes the latest JSON data backup plus a manifest. Keep `.env.local` values separately.
              </p>
            </div>
          </div>
        </div>

        {/* Vibrant action cards */}
        <div className="grid grid-cols-1 md:grid-cols-3 gap-3">
          <button onClick={handleExport} className="action-card-blue p-5 rounded-lg text-left text-white relative overflow-hidden group">
            <div className="flex items-center justify-between mb-8">
              <Download className="w-6 h-6" strokeWidth={2} />
              <ArrowRight className="w-5 h-5" style={{ opacity: 0.6, transition: 'opacity 0.15s, transform 0.15s' }} />
            </div>
            <div className="font-display text-xl tracking-tight mb-1">Export Backup</div>
            <div className="text-xs" style={{ opacity: 0.9 }}>Download all storage as a JSON file</div>
          </button>

          <button
            onClick={handleSourceExport}
            disabled={sourceExporting}
            className="action-card-blue p-5 rounded-lg text-left text-white relative overflow-hidden group disabled:opacity-60 disabled:cursor-not-allowed"
          >
            <div className="flex items-center justify-between mb-8">
              {sourceExporting ? <RefreshCw className="w-6 h-6 animate-spin" strokeWidth={2} /> : <Code2 className="w-6 h-6" strokeWidth={2} />}
              <ArrowRight className="w-5 h-5" style={{ opacity: 0.6 }} />
            </div>
            <div className="font-display text-xl tracking-tight mb-1">Full Source ZIP</div>
            <div className="text-xs" style={{ opacity: 0.9 }}>
              {sourceExporting ? 'Preparing clean ZIP…' : 'Code modules + SQL + latest JSON data'}
            </div>
          </button>

          {/* Phase 5.9 — File input is now the actual click target (label-wrapped),
              avoiding programmatic .click() which sandboxed iframes may block. */}
          <label
            className="action-card-green p-5 rounded-lg text-left text-white relative overflow-hidden group cursor-pointer block"
            title="Click to choose a backup JSON file"
          >
            <input
              type="file"
              accept="application/json,.json"
              onChange={handleFileImport}
              style={{ position: 'absolute', width: 0, height: 0, opacity: 0, pointerEvents: 'none' }}
            />
            <div className="flex items-center justify-between mb-8">
              <Upload className="w-6 h-6" strokeWidth={2} />
              <ArrowRight className="w-5 h-5" style={{ opacity: 0.6 }} />
            </div>
            <div className="font-display text-xl tracking-tight mb-1">Import from File</div>
            <div className="text-xs" style={{ opacity: 0.9 }}>Restore from a previously exported JSON</div>
          </label>
        </div>

        {developerShareMessages && (
          <div className="bg-paper border border-line rounded-lg overflow-hidden">
            <div className="px-5 py-4 border-b border-line bg-bone flex items-start justify-between gap-3">
              <div>
                <div className="text-[10px] font-mono uppercase tracking-widest ink-faint mb-1">Developer handoff messages</div>
                <h2 className="font-display text-xl ink tracking-tight leading-tight">Copy these as two separate messages</h2>
                <p className="text-xs ink-soft mt-1 leading-relaxed">
                  Message 1 tells the developer which backup files to use. Message 2 is private and carries the `.env.local` values separately.
                </p>
              </div>
              <span className="hidden sm:inline-flex px-2 py-1 rounded bg-moss-soft text-moss text-[9px] font-mono uppercase tracking-wider">
                Ready
              </span>
            </div>
            <div className="grid grid-cols-1 lg:grid-cols-2 divide-y lg:divide-y-0 lg:divide-x divide-line-soft">
              <div className="p-4">
                <div className="flex items-center justify-between gap-2 mb-2">
                  <div>
                    <div className="text-sm font-semibold ink">Message 1 - Files package</div>
                    <div className="text-[10px] ink-faint">Send with the ZIP / JSON attachment.</div>
                  </div>
                  <button
                    onClick={() => copyShareMessage(developerShareMessages.packageMessage, 'Files message')}
                    className="inline-flex items-center gap-1.5 px-3 py-2 rounded-md bg-ink text-white text-[10px] font-mono uppercase tracking-wider font-semibold hover:bg-terra"
                  >
                    <Copy className="w-3 h-3" />
                    Copy
                  </button>
                </div>
                <pre className="bg-bone border border-line-soft rounded p-3 text-[11px] font-mono ink-soft whitespace-pre-wrap leading-relaxed max-h-64 overflow-auto">
                  {developerShareMessages.packageMessage}
                </pre>
              </div>
              <div className="p-4">
                <div className="flex items-center justify-between gap-2 mb-2">
                  <div>
                    <div className="text-sm font-semibold ink">Message 2 - Private env values</div>
                    <div className="text-[10px] text-terra">Send separately, not inside the public backup note.</div>
                  </div>
                  <button
                    onClick={() => copyShareMessage(developerShareMessages.envMessage, 'Private env message')}
                    className="inline-flex items-center gap-1.5 px-3 py-2 rounded-md bg-terra text-white text-[10px] font-mono uppercase tracking-wider font-semibold hover:opacity-90"
                  >
                    <Copy className="w-3 h-3" />
                    Copy
                  </button>
                </div>
                <pre className="bg-terra-soft border border-terra rounded p-3 text-[11px] font-mono ink whitespace-pre-wrap leading-relaxed max-h-64 overflow-auto">
                  {developerShareMessages.envMessage}
                </pre>
              </div>
            </div>
          </div>
        )}

        {/* Secondary action cards */}
        <div className="grid grid-cols-2 gap-3">
          <button onClick={() => setShowPasteModal(true)} className="bg-paper border border-line rounded-lg p-5 text-left hover:border-ink relative group" style={{ transition: 'border-color 0.15s' }}>
            <div className="flex items-center justify-between mb-8">
              <Clipboard className="w-6 h-6 ink-soft" strokeWidth={2} />
              <ArrowRight className="w-5 h-5 ink-faint" />
            </div>
            <div className="font-display text-xl ink tracking-tight mb-1">Paste JSON</div>
            <div className="text-xs ink-soft">Restore by pasting JSON text directly</div>
          </button>

          <button onClick={() => setShowRawDump(true)} className="bg-paper border border-line rounded-lg p-5 text-left hover:border-ink relative group" style={{ transition: 'border-color 0.15s' }}>
            <div className="flex items-center justify-between mb-8">
              <Eye className="w-6 h-6 ink-soft" strokeWidth={2} />
              <ArrowRight className="w-5 h-5 ink-faint" />
            </div>
            <div className="font-display text-xl ink tracking-tight mb-1">Show Raw Dump</div>
            <div className="text-xs ink-soft">View / copy storage as plain text</div>
          </button>
        </div>

        {/* Phase 5.10 — Storage management */}
        <div className="bg-paper border-2 border-terra border-dashed rounded-lg p-5 mt-4">
          <div className="flex items-center gap-2 mb-3">
            <AlertTriangle className="w-4 h-4 text-terra" strokeWidth={2.5} />
            <div className="text-[10px] font-mono tracking-widest font-semibold uppercase text-terra">Danger zone</div>
          </div>
          <div className="flex items-start justify-between gap-4">
            <div className="flex-1">
              <div className="text-sm ink font-medium mb-1">Reset to seed data</div>
              <div className="text-[11px] ink-soft leading-relaxed mb-2">
                Wipes all your projects, masters, themes, and edits from persistent storage and reloads the original demo data. Use this if your workspace is in a bad state or you want a fresh start. <strong className="ink">Cannot be undone — export a backup first if you want to keep your work.</strong>
              </div>
            </div>
            <button
              onClick={() => setShowResetModal(true)}
              className="px-3 py-2 text-[11px] font-mono uppercase tracking-wider bg-terra text-white rounded font-semibold hover:opacity-90 shrink-0"
            >
              Reset…
            </button>
          </div>
        </div>

        {/* How it works */}
        <div className="bg-paper border border-line rounded-lg p-5">
          <div className="flex items-center gap-2 mb-4">
            <FileText className="w-4 h-4 ink-soft" />
            <div className="text-[10px] font-mono tracking-widest font-semibold uppercase ink-faint">How it works</div>
          </div>
          <ol className="space-y-3">
            <li className="flex gap-3 text-sm ink-soft leading-relaxed">
              <span className="font-mono ink-faint shrink-0">1.</span>
              <span><strong className="ink">Export</strong> downloads a timestamped JSON containing every record in your workspace — projects, masters, board columns, all of it.</span>
            </li>
            <li className="flex gap-3 text-sm ink-soft leading-relaxed">
              <span className="font-mono ink-faint shrink-0">2.</span>
              <span><strong className="ink">Import</strong> overwrites matching keys with the contents of the file/paste. Preview before write. The live UI re-hydrates automatically — no reload needed for the main state.</span>
            </li>
            <li className="flex gap-3 text-sm ink-soft leading-relaxed">
              <span className="font-mono ink-faint shrink-0">3.</span>
              <span><strong className="ink">Cross-conversation transfer:</strong> in the source conversation, click <em>Show Raw Dump</em> → copy. Come here, click <em>Paste JSON</em> → paste → restore.</span>
            </li>
          </ol>
        </div>
      </div>

      {/* Toast */}
      {toast && (
        <div className="fixed bottom-6 right-6 px-4 py-3 rounded-lg text-white font-medium text-sm fade-in z-50"
          style={{ background: toast.kind === 'error' ? '#B4593C' : '#16A34A', boxShadow: '0 8px 24px rgba(0,0,0,0.15)' }}>
          {toast.msg}
        </div>
      )}

      {/* Modals */}
      {importPreview && (
        <ImportPreviewModal preview={importPreview} onConfirm={confirmImport} onCancel={() => setImportPreview(null)} />
      )}
      {showPasteModal && (
        <PasteJSONModal text={pasteText} setText={setPasteText} onClose={() => { setShowPasteModal(false); setPasteText(''); }} onSubmit={() => processImport(pasteText)} />
      )}
      {showRawDump && (
        <RawDumpModal data={buildBackup()} onClose={() => setShowRawDump(false)} onCopy={handleCopyDump} />
      )}
      {showResetModal && (
        <ResetStorageModal
          onClose={() => setShowResetModal(false)}
          onConfirm={async () => {
            await clearPersistedState();
            setShowResetModal(false);
            /* Hard reload so the App component re-runs the load effect and falls
               back to seed data. Soft reset is harder because we'd need a way to
               re-run all the useState initializers. */
            window.location.reload();
          }}
        />
      )}
    </div>
  );
}

function ImportPreviewModal({ preview, onConfirm, onCancel }) {
  const data = preview.data || {};
  const projectCount = Array.isArray(data.projects) ? data.projects.length : 0;
  const masterCount = data.masters && typeof data.masters === 'object' ? Object.keys(data.masters).length : 0;
  const columnCount = Array.isArray(data.boardColumns) ? data.boardColumns.length : 0;
  const hasTheme = data.theme && typeof data.theme === 'object' && Object.keys(data.theme).length > 0;
  const themeLabel = data.themePreset
    ? `preset · ${data.themePreset}`
    : (hasTheme ? 'custom palette' : null);

  return (
    <div className="modal-backdrop" onClick={onCancel}>
      <div className="modal-card" onClick={(e) => e.stopPropagation()}>
        <div className="flex items-center justify-between mb-4">
          <div className="flex items-center gap-2">
            <ShieldCheck className="w-5 h-5 text-blue-vibrant" />
            <h2 className="font-display text-xl ink tracking-tight">Confirm restore</h2>
          </div>
          <button onClick={onCancel} className="p-1 hover:bg-bone rounded"><X className="w-4 h-4 ink-soft" /></button>
        </div>

        <div className="bg-bone rounded p-3 mb-4 space-y-1 border border-line-soft">
          <div className="text-[10px] font-mono ink-faint uppercase tracking-wider mb-1">From backup</div>
          {preview.exportedAt && (
            <div className="text-xs ink">Exported: <span className="font-mono">{new Date(preview.exportedAt).toLocaleString()}</span></div>
          )}
          {preview.appVersion && (
            <div className="text-xs ink">App version: <span className="font-mono">{preview.appVersion}</span></div>
          )}
          {preview.appName && (
            <div className="text-xs ink">App: <span className="font-mono">{preview.appName}</span></div>
          )}
        </div>

        <div className="space-y-1 mb-4">
          <div className="text-[10px] font-mono ink-faint uppercase tracking-wider mb-2">Will restore</div>
          <div className="flex justify-between py-2 border-b border-line-soft text-sm">
            <span className="ink-soft">Projects</span>
            <span className="font-mono ink font-semibold">{projectCount}</span>
          </div>
          <div className="flex justify-between py-2 border-b border-line-soft text-sm">
            <span className="ink-soft">Master tables</span>
            <span className="font-mono ink font-semibold">{masterCount}</span>
          </div>
          <div className="flex justify-between py-2 border-b border-line-soft text-sm">
            <span className="ink-soft">Board columns</span>
            <span className="font-mono ink font-semibold">{columnCount}</span>
          </div>
          <div className="flex justify-between py-2 text-sm items-center">
            <span className="ink-soft">Theme</span>
            {hasTheme ? (
              <div className="flex items-center gap-1.5">
                {data.theme.terra && <span className="w-3 h-3 rounded-full border border-line" style={{ background: data.theme.terra }} />}
                {data.theme.moss && <span className="w-3 h-3 rounded-full border border-line" style={{ background: data.theme.moss }} />}
                {data.theme.ink && <span className="w-3 h-3 rounded-full border border-line" style={{ background: data.theme.ink }} />}
                <span className="font-mono ink font-semibold text-[11px] ml-1">{themeLabel}</span>
              </div>
            ) : (
              <span className="font-mono ink-faint text-[11px] italic">not in this backup</span>
            )}
          </div>
        </div>

        <div className="bg-amber-soft border border-amber p-3 rounded mb-4">
          <div className="flex gap-2">
            <AlertCircle className="w-4 h-4 shrink-0 mt-0.5 text-amber-mid" />
            <div className="text-xs text-amber-mid leading-relaxed">
              <strong className="text-amber-deep">This will replace</strong> all current projects, masters, board columns{hasTheme ? ', and theme' : ''} in this workspace. Export a backup first if you want to keep the current state.
            </div>
          </div>
        </div>

        <div className="flex justify-end gap-2">
          <button onClick={onCancel} className="px-4 py-2 border border-line rounded-md text-xs font-medium ink hover:bg-bone">Cancel</button>
          <button onClick={onConfirm} className="px-4 py-2 bg-green-vibrant text-white rounded-md text-xs font-mono tracking-wider font-semibold uppercase hover:opacity-90">Restore now</button>
        </div>
      </div>
    </div>
  );
}

function PasteJSONModal({ text, setText, onClose, onSubmit }) {
  return (
    <div className="modal-backdrop" onClick={onClose}>
      <div className="modal-card" onClick={(e) => e.stopPropagation()} style={{ maxWidth: '640px' }}>
        <div className="flex items-center justify-between mb-4">
          <div className="flex items-center gap-2">
            <Clipboard className="w-5 h-5 ink-soft" />
            <h2 className="font-display text-xl ink tracking-tight">Paste backup JSON</h2>
          </div>
          <button onClick={onClose} className="p-1 hover:bg-bone rounded"><X className="w-4 h-4 ink-soft" /></button>
        </div>
        <div className="text-xs ink-soft mb-3">Paste the entire JSON content from a previous backup. We&apos;ll show a preview before applying.</div>
        <textarea
          value={text}
          onChange={(e) => setText(e.target.value)}
          placeholder='{"data": {"projects": [...], "masters": {...}, "boardColumns": [...]}}'
          rows={14}
          className="input-base font-mono"
          style={{ resize: 'vertical', fontSize: '11px' }}
        />
        <div className="flex justify-end gap-2 mt-4">
          <button onClick={onClose} className="px-4 py-2 border border-line rounded-md text-xs font-medium ink hover:bg-bone">Cancel</button>
          <button onClick={onSubmit} disabled={!text.trim()} className="px-4 py-2 bg-green-vibrant text-white rounded-md text-xs font-mono tracking-wider font-semibold uppercase hover:opacity-90" style={{ opacity: text.trim() ? 1 : 0.5, cursor: text.trim() ? 'pointer' : 'not-allowed' }}>
            Preview restore
          </button>
        </div>
      </div>
    </div>
  );
}

function RawDumpModal({ data, onClose, onCopy }) {
  const json = useMemo(() => JSON.stringify(data, null, 2), [data]);
  const sizeKB = (json.length / 1024).toFixed(1);

  return (
    <div className="modal-backdrop" onClick={onClose}>
      <div className="modal-card" onClick={(e) => e.stopPropagation()} style={{ maxWidth: '900px' }}>
        <div className="flex items-center justify-between mb-4">
          <div className="flex items-center gap-2">
            <Eye className="w-5 h-5 ink-soft" />
            <h2 className="font-display text-xl ink tracking-tight">Raw storage dump</h2>
            <span className="text-[10px] font-mono ink-faint">{sizeKB} KB</span>
          </div>
          <div className="flex items-center gap-2">
            <button onClick={onCopy} className="flex items-center gap-1.5 px-3 py-1.5 bg-blue-vibrant text-white rounded text-xs font-mono tracking-wider font-semibold uppercase hover:opacity-90">
              <Clipboard className="w-3 h-3" /> Copy all
            </button>
            <button onClick={onClose} className="p-1 hover:bg-bone rounded"><X className="w-4 h-4 ink-soft" /></button>
          </div>
        </div>
        <pre className="bg-bone p-3 rounded text-[11px] font-mono ink leading-relaxed overflow-auto border border-line-soft" style={{ maxHeight: '60vh' }}>{json}</pre>
        <div className="text-[10px] font-mono ink-faint mt-2">
          Tip: Use <strong>Copy all</strong> then paste in another conversation&apos;s Backup &amp; Restore screen.
        </div>
      </div>
    </div>
  );
}

