function Projhub({ project, masters, onClose, onOpenMasters, onOpenLibraryTable, profile, onUpdateProject, initialTab, onJumpToClientPanel, onJumpToVendorPanel }) {
  /* Phase 9.0 — Default to Project Journey when entering a project.
     Falls back through workflow → overview if Journey isn't available for the role.
     Phase 9.1.7 — initialTab prop overrides default if provided AND allowed for role
     (e.g. Finance row click → 'payments'). */
  const initialAllowedCodes = profile ? visibleProjhubTabs(profile) : ALL_PROJHUB_TABS;
  /* Phase 9.1.34 — Plan Property ('spaces') is now the primary landing tab for
     a project, since it carries the full setup wizard. Journey demoted to More. */
  const initialDefault = (initialTab && initialAllowedCodes.includes(initialTab))
    ? initialTab
    : initialAllowedCodes.includes('spaces')
      ? 'spaces'
      : initialAllowedCodes.includes('workflow')
        ? 'workflow'
        : 'overview';
  const [activeTab, setActiveTab] = useState(initialDefault);
  /* Phase 5.8 Piece 1c — Workspace jump target (set by other tabs to pre-select a stage/activity) */
  const [workspaceTarget, setWorkspaceTarget] = useState(null);

  // Filter tabs by role permissions
  const allowedCodes = profile ? visibleProjhubTabs(profile) : ALL_PROJHUB_TABS;
  const visibleTabs = projhubTabs.filter((t) => allowedCodes.includes(t.code));

  // If active tab is no longer allowed, fall back through spaces → workflow → overview
  React.useEffect(() => {
    if (!allowedCodes.includes(activeTab)) {
      setActiveTab(
        allowedCodes.includes('spaces') ? 'spaces'
          : allowedCodes.includes('workflow') ? 'workflow'
          : 'overview'
      );
    }
  }, [profile?.code]); // eslint-disable-line

  /* Smart jump — accepts optional payload like { stageId, activityId } when jumping to workspace */
  const jumpTo = (tab, payload) => {
    if (!allowedCodes.includes(tab)) return;
    if (tab === 'workspace' && payload) {
      setWorkspaceTarget(payload);
    }
    setActiveTab(tab);
  };
  /* Clear the workspace target after WorkspaceTab consumes it (so user can navigate freely after) */
  const clearWorkspaceTarget = () => setWorkspaceTarget(null);

  if (!project) {
    return (
      <div className="flex-1 flex items-center justify-center bg-bone">
        <div className="text-center">
          <div className="text-sm ink-soft mb-3">Project not found.</div>
          <button onClick={onClose} className="px-4 py-2 bg-ink text-white rounded text-xs font-mono uppercase tracking-wider">Back to Dashboard</button>
        </div>
      </div>
    );
  }

  // Curry update handler so each tab gets a simple onUpdate(updates) function
  const onUpdate = (updates) => onUpdateProject && onUpdateProject(project.id, updates);

  return (
    <div className="flex-1 overflow-auto scrollbar-thin" style={{ background: 'var(--bone)' }}>
      <ProjhubHeader project={project} onClose={onClose} />
      <ProjhubTabBar tabs={visibleTabs} active={activeTab} onChange={setActiveTab} />
      {profile && visibleTabs.length < projhubTabs.length && (
        <div className="px-4 sm:px-6 lg:px-12 pt-3">
          <div className="inline-flex items-center gap-2 text-[11px] ink-faint">
            <Lock className="w-3 h-3" />
            <span>Viewing as <span className="ink font-medium">{profile.shortLabel}</span> · {visibleTabs.length} of {projhubTabs.length} tabs visible</span>
          </div>
        </div>
      )}
      <div className="px-4 sm:px-6 lg:px-12 py-5 sm:py-8 max-w-[1200px]">
        {activeTab === 'journey' ? (
          /* Phase 9.0 — Project Journey: the unified lifecycle landing screen */
          <ProjectJourneyTab project={project} masters={masters} onUpdate={onUpdate} onJumpTo={(t) => allowedCodes.includes(t) && setActiveTab(t)} roleCode={profile?.code} profile={profile} />
        ) : activeTab === 'overview' ? (
          <OverviewTab project={project} masters={masters} onJumpTo={(t) => allowedCodes.includes(t) && setActiveTab(t)} roleCode={profile?.code} />
        ) : activeTab === 'stages' ? (
          /* Phase 7.1 — 'stages' renders the stage-configurator (was the old 'workflow' tab) */
          <WorkflowStagesTab project={project} masters={masters} onUpdate={onUpdate} onJumpTo={jumpTo} />
        ) : activeTab === 'workspace' ? (
          <WorkspaceTab project={project} masters={masters} onUpdate={onUpdate} roleCode={profile?.code} onJumpTo={jumpTo} workspaceTarget={workspaceTarget} clearWorkspaceTarget={clearWorkspaceTarget} />
        ) : activeTab === 'approvals' ? (
          <ApprovalsTab project={project} masters={masters} onUpdate={onUpdate} roleCode={profile?.code} />
        ) : activeTab === 'workflow' ? (
          /* Phase 7.1 — 'workflow' is now the operational hierarchy (Stage → Activity → Task → Checklist) */
          <TasksTab project={project} masters={masters} onUpdate={onUpdate} roleCode={profile?.code} profile={profile} />
        ) : activeTab === 'files' ? (
          <FilesTab project={project} masters={masters} onUpdate={onUpdate} onJumpTo={(t) => allowedCodes.includes(t) && setActiveTab(t)} roleCode={profile?.code} />
        ) : activeTab === 'payments' ? (
          <PaymentsTab project={project} masters={masters} onUpdate={onUpdate} onJumpTo={(t) => allowedCodes.includes(t) && setActiveTab(t)} roleCode={profile?.code} />
        ) : activeTab === 'site' ? (
          <SiteUpdatesTab project={project} masters={masters} onUpdate={onUpdate} roleCode={profile?.code} />
        ) : activeTab === 'comms' ? (
          <CommsTab project={project} masters={masters} onUpdate={onUpdate} roleCode={profile?.code} />
        ) : activeTab === 'mom' ? (
          <MomTab project={project} masters={masters} onUpdate={onUpdate} roleCode={profile?.code} />
        ) : activeTab === 'details' ? (
          <ProjectDetailsTab project={project} masters={masters} onUpdate={onUpdate} roleCode={profile?.code} />
        ) : activeTab === 'client' ? (
          <ClientTab project={project} masters={masters} onUpdate={onUpdate} roleCode={profile?.code} onJumpToClientPanel={onJumpToClientPanel} />
        ) : activeTab === 'vendors' ? (
          <VendorsTab project={project} masters={masters} onUpdate={onUpdate} roleCode={profile?.code} onJumpToVendorPanel={onJumpToVendorPanel} />
        ) : activeTab === 'scope' ? (
          <ScopeTab project={project} masters={masters} onUpdate={onUpdate} roleCode={profile?.code} onJumpTo={(t) => allowedCodes.includes(t) && setActiveTab(t)} />
        ) : activeTab === 'spatial' ? (
          <SpatialTab project={project} masters={masters} onUpdate={onUpdate} onOpenLibraryTable={onOpenLibraryTable} onJumpTo={(t) => allowedCodes.includes(t) && setActiveTab(t)} />
        ) : activeTab === 'spaces' ? (
          /* Phase 9.1.34 — Plan Property: 4-step elegant wizard.
             Step 1 Category → Step 2 Property Type → Step 3 Particulars
             → Step 4 Levels & Spaces (existing SpacesTabFromHub). */
          <PlanPropertyWizard project={project} masters={masters} onUpdate={onUpdate} />
        ) : (
          <PlaceholderTab
            tab={projhubTabs.find((t) => t.code === activeTab)}
            project={project}
            masters={masters}
            onOpenMasters={onOpenMasters}
          />
        )}
      </div>
    </div>
  );
}

