function ProjhubTabBar({ tabs, active, onChange }) {
  /* Phase 9.1 Part 3 — Tab grouping for calmer UI.
     16 tabs is too many. Group into 6 primary + "More" overflow:
       Primary: Plan Property / Workflow / Files / Approvals / MOM / Payments
       More:    Journey, Overview, Workspace, Project Details, Client, Vendors,
                Scope, Stages, Comms, Site Updates
     Phase 9.1.34 — "Plan Property" (formerly Property Levels & Spaces) is the
     new primary onboarding/setup flow and gets a visible slot. Journey moves
     to More as a deprecated-but-accessible view (per user direction). */
  const PRIMARY_TAB_CODES = ['spatial', 'spaces', 'workflow', 'files', 'approvals', 'payments'];
  const visibleByCode = Object.fromEntries(tabs.map((t) => [t.code, t]));
  const primary = PRIMARY_TAB_CODES.map((c) => visibleByCode[c]).filter(Boolean);
  const moreTabs = tabs.filter((t) => !PRIMARY_TAB_CODES.includes(t.code));

  const [moreOpen, setMoreOpen] = useState(false);
  const moreRef = React.useRef(null);

  /* Close the More menu on outside click */
  React.useEffect(() => {
    if (!moreOpen) return;
    const handler = (e) => {
      if (moreRef.current && !moreRef.current.contains(e.target)) setMoreOpen(false);
    };
    document.addEventListener('mousedown', handler);
    return () => document.removeEventListener('mousedown', handler);
  }, [moreOpen]);

  /* Is the active tab inside the More group? Highlight More if so. */
  const activeInMore = moreTabs.some((t) => t.code === active);

  return (
    <div className="sticky top-0 z-10" style={{ background: 'var(--bone)', borderBottom: '1px solid var(--line)' }}>
      <div className="flex items-center flex-wrap px-4 sm:px-6 lg:px-12 gap-1">
        {primary.map((t) => {
          const isActive = active === t.code;
          return (
            <button
              key={t.code}
              onClick={() => onChange(t.code)}
              className={`px-3 sm:px-4 py-3 transition-colors whitespace-nowrap text-[13px] ${
                isActive
                  ? 'ink font-medium border-b-2 border-terra -mb-px'
                  : 'ink-soft hover:ink'
              }`}
            >
              {t.label}
            </button>
          );
        })}
        {moreTabs.length > 0 && (
          <div className="relative" ref={moreRef}>
            <button
              onClick={() => setMoreOpen(!moreOpen)}
              className={`px-3 sm:px-4 py-3 transition-colors whitespace-nowrap text-[13px] flex items-center gap-1 ${
                activeInMore
                  ? 'ink font-medium border-b-2 border-terra -mb-px'
                  : 'ink-soft hover:ink'
              }`}
            >
              {activeInMore
                ? (visibleByCode[active]?.label || 'More')
                : 'More'}
              <ChevronDown className="w-3 h-3" strokeWidth={2} />
            </button>
            {moreOpen && (
              <div
                className="absolute right-0 top-full mt-1 bg-paper border border-line rounded-xl py-1.5 min-w-[200px] z-20"
                style={{ boxShadow: '0 4px 16px rgba(0,0,0,0.06)' }}
              >
                {moreTabs.map((t) => (
                  <button
                    key={t.code}
                    onClick={() => {
                      onChange(t.code);
                      setMoreOpen(false);
                    }}
                    className={`w-full text-left px-4 py-2 text-[13px] hover:bg-bone ${
                      active === t.code ? 'ink font-medium' : 'ink-soft'
                    }`}
                  >
                    {t.label}
                  </button>
                ))}
              </div>
            )}
          </div>
        )}
      </div>
    </div>
  );
}

