function AddCustomModal({ title, onClose, onAdd }) {
  const [value, setValue] = React.useState('');
  return (
    <div className="fixed inset-0 z-[150] flex items-center justify-center p-4">
      <button type="button" className="absolute inset-0 bg-black/40" onClick={onClose} aria-label="Close custom item modal" />
      <div className="relative bg-paper border border-line rounded-xl shadow-2xl p-5 w-full max-w-sm">
        <div className="flex items-center justify-between gap-3 mb-4">
          <h3 className="font-semibold ink">{title}</h3>
          <button type="button" onClick={onClose} className="w-8 h-8 rounded-lg hover:bg-bone flex items-center justify-center"><X className="w-4 h-4" /></button>
        </div>
        <input autoFocus value={value} onChange={(e) => setValue(e.target.value)} onKeyDown={(e) => { if (e.key === 'Enter') onAdd(value); }} placeholder="Type name..." className="input-base" />
        <div className="flex justify-end gap-2 mt-4">
          <button type="button" onClick={onClose} className="px-3 py-2 rounded-lg border border-line-soft text-sm ink">Cancel</button>
          <button type="button" onClick={() => onAdd(value)} className="px-3 py-2 rounded-lg bg-ink text-white text-sm font-semibold">Add</button>
        </div>
      </div>
    </div>
  );
}

/* ===================== OVERVIEW TAB (full build) ===================== */

function OverviewTab({ project, masters, onJumpTo, roleCode }) {
  const w = project._wizard || {};
  const attentionTags = w.onboardingAttentionTags || [];
  const clientFlags = w.clientFlags || [];
  const decisionMakers = w.decisionMakers || [];
  const externalStakeholders = w.externalStakeholders || [];
  const paymentTerms = w.paymentTerms || [];

  return (
    <div className="space-y-5">
      {/* Hero metrics strip */}
      <div className="grid grid-cols-3 gap-3">
        <MetricCard
          icon={Shield}
          label="Pending Approvals"
          value={project.pendingApprovals}
          tone={project.pendingApprovals > 0 ? 'terra' : 'moss'}
          onClick={() => onJumpTo('approvals')}
        />
        <MetricCard
          icon={AlertCircle}
          label="Overdue Tasks"
          value={project.overdueTasks}
          tone={project.overdueTasks > 0 ? 'terra' : 'moss'}
          onClick={() => onJumpTo('workflow')}
        />
        <MetricCard
          icon={Receipt}
          label="Payment Status"
          value={project.paymentDue ? 'Due' : 'On track'}
          tone={project.paymentDue ? 'clay' : 'moss'}
          onClick={() => onJumpTo('payments')}
        />
      </div>

      {/* At a glance + Attention */}
      <div className="grid grid-cols-2 gap-4">
        <Section title="At a glance" subtitle="Core project facts">
          <div className="space-y-2.5">
            <FactRow label="Client" value={project.client} />
            <FactRow label="Site condition" value={project.siteCondition} />
            <FactRow label="Service" value={project.serviceType} small />
            <FactRow label="Started" value={formatDate(project.startDate)} mono />
            <FactRow label="Expected" value={formatDate(project.expCompletion)} mono />
            {w.builtUpArea && <FactRow label="Built-up area" value={`${w.builtUpArea} sq ft`} mono />}
            {(() => {
              const cascadeCounts = (w.projectLevels && w.projectLevels.length > 0) ? countTree(w.projectLevels) : null;
              if (cascadeCounts) {
                return <FactRow label="Spatial program" value={`${cascadeCounts.levels} lv · ${cascadeCounts.zones} zn · ${cascadeCounts.spaces} sp`} mono />;
              }
              if (w.numberOfLevels) {
                return <FactRow label="Levels" value={w.numberOfLevels} mono />;
              }
              return null;
            })()}
          </div>
        </Section>

        <Section title="Attention" subtitle="Flags &amp; tags from onboarding">
          {attentionTags.length === 0 && clientFlags.length === 0 ? (
            <EmptyHint>
              No attention tags or client flags set. They&apos;d normally appear here from <em>wizard Page 3</em>.
            </EmptyHint>
          ) : (
            <div className="space-y-3">
              {attentionTags.length > 0 && (
                <div>
                  <div className="text-[10px] font-mono ink-faint uppercase tracking-wider mb-1.5">Attention tags</div>
                  <div className="flex flex-wrap gap-1.5">
                    {attentionTags.map((t) => (
                      <span key={t} className="text-[11px] font-medium px-2 py-1 rounded-full bg-terra-soft text-terra">{t}</span>
                    ))}
                  </div>
                </div>
              )}
              {clientFlags.length > 0 && (
                <div>
                  <div className="text-[10px] font-mono ink-faint uppercase tracking-wider mb-1.5">Client flags</div>
                  <div className="flex flex-wrap gap-1.5">
                    {clientFlags.map((t) => (
                      <span key={t} className="text-[11px] font-medium px-2 py-1 rounded-full bg-muted-warm ink">{t}</span>
                    ))}
                  </div>
                </div>
              )}
            </div>
          )}
        </Section>
      </div>

      {/* Pending decisions */}
      <Section
        title="Pending decisions"
        subtitle="What's blocking progress right now"
        action={<JumpToButton onClick={() => onJumpTo('approvals')}>Open Approvals</JumpToButton>}
      >
        {(() => {
          const approvalsAll = (project._wizard && project._wizard.projectApprovals) || [];
          const approvals = recordsForRole(approvalsAll, roleCode, 'approval');
          const pending = approvals.filter((a) => a.status === 'pending');
          if (pending.length === 0 && project.pendingApprovals === 0) {
            return (
              <EmptyHint>
                Nothing pending. New decisions raised on this project will surface here with full context — what&apos;s blocked, who needs to approve, by when.
              </EmptyHint>
            );
          }
          if (pending.length === 0 && project.pendingApprovals > 0) {
            // Seed-project case: card has count but no underlying records yet
            return (
              <div className="space-y-2">
                <div className="flex items-center justify-between p-3 bg-bone rounded border border-line-soft">
                  <div className="flex items-center gap-2.5">
                    <Shield className="w-4 h-4 text-terra shrink-0" />
                    <div>
                      <div className="text-sm ink font-medium">{project.pendingApprovals} pending approval{project.pendingApprovals === 1 ? '' : 's'}</div>
                      <div className="text-[11px] ink-faint font-mono mt-0.5">Initialize the Approvals queue to see them in detail</div>
                    </div>
                  </div>
                  <JumpToButton onClick={() => onJumpTo('approvals')}>Initialize</JumpToButton>
                </div>
              </div>
            );
          }
          const today = new Date().toISOString().slice(0, 10);
          return (
            <div className="space-y-2">
              {pending.slice(0, 5).map((a) => {
                const overdue = a.dueDate && a.dueDate < today;
                return (
                  <div key={a.id} className={`flex items-center justify-between p-3 rounded border ${overdue ? 'bg-terra-soft border-terra' : 'bg-bone border-line-soft'}`}>
                    <div className="flex items-center gap-2.5 min-w-0">
                      <div className={`w-2 h-2 rounded-full shrink-0 ${overdue ? 'bg-terra' : 'bg-clay'}`} />
                      <div className="min-w-0">
                        <div className="text-sm ink font-medium truncate">{a.title || a.typeName || 'Untitled approval'}</div>
                        <div className="text-[11px] ink-faint font-mono mt-0.5 truncate">
                          {a.linkedStage && <span>{a.linkedStage}</span>}
                          {a.requestedFrom && <span> · awaiting {a.requestedFrom}</span>}
                          {a.dueDate && <span> · due {formatDate(a.dueDate)}</span>}
                        </div>
                      </div>
                    </div>
                    {overdue && <span className="text-[10px] font-mono text-terra uppercase tracking-wider font-semibold shrink-0 ml-2">Overdue</span>}
                  </div>
                );
              })}
              {pending.length > 5 && (
                <div className="text-[11px] font-mono ink-soft text-center pt-1">
                  + {pending.length - 5} more · <button onClick={() => onJumpTo('approvals')} className="text-terra hover:ink">view all</button>
                </div>
              )}
            </div>
          );
        })()}
      </Section>

      {/* Upcoming deadlines */}
      <Section
        title="Upcoming deadlines"
        subtitle="Next 14 days"
        action={<JumpToButton onClick={() => onJumpTo('workflow')}>Open Workflow</JumpToButton>}
      >
        {(() => {
          const tasksAll = (project._wizard && project._wizard.projectTasks) || [];
          const tasks = recordsForRole(tasksAll, roleCode, 'task');
          const todayDate = new Date();
          const todayStr = todayDate.toISOString().slice(0, 10);
          const horizonDate = new Date(todayDate.getTime() + 14 * 24 * 60 * 60 * 1000);
          const horizonStr = horizonDate.toISOString().slice(0, 10);

          const upcoming = tasks
            .filter((t) => isTaskOpen(t) && t.dueDate)
            .filter((t) => t.dueDate <= horizonStr)
            .sort((a, b) => (a.dueDate || '').localeCompare(b.dueDate || ''));

          if (tasks.length === 0 && project.overdueTasks === 0) {
            return (
              <EmptyHint>
                No tasks yet. Apply a Task Checklist template to a stage in Tasks to populate this view.
              </EmptyHint>
            );
          }

          if (upcoming.length === 0) {
            return (
              <EmptyHint>
                Nothing due in the next 14 days. Headline date: {project.expCompletion}.
              </EmptyHint>
            );
          }

          return (
            <div className="space-y-2">
              {upcoming.slice(0, 5).map((t) => {
                const overdue = t.dueDate < todayStr;
                return (
                  <div key={t.id} className={`flex items-center justify-between p-3 rounded border ${overdue ? 'bg-terra-soft border-terra' : 'bg-bone border-line-soft'}`}>
                    <div className="flex items-center gap-2.5 min-w-0">
                      <Calendar className={`w-3.5 h-3.5 shrink-0 ${overdue ? 'text-terra' : 'ink-soft'}`} />
                      <div className="min-w-0">
                        <div className="text-sm ink font-medium truncate">{t.title}</div>
                        <div className="text-[11px] ink-faint font-mono mt-0.5 truncate">
                          {t.linkedStage && <span>{t.linkedStage}</span>}
                          {t.assignee && <span> · {t.assignee}</span>}
                          <span> · due {formatDate(t.dueDate)}</span>
                        </div>
                      </div>
                    </div>
                    {overdue && <span className="text-[10px] font-mono text-terra uppercase tracking-wider font-semibold shrink-0 ml-2">Overdue</span>}
                  </div>
                );
              })}
              {upcoming.length > 5 && (
                <div className="text-[11px] font-mono ink-soft text-center pt-1">
                  + {upcoming.length - 5} more · <button onClick={() => onJumpTo('workflow')} className="text-terra hover:ink">view all</button>
                </div>
              )}
            </div>
          );
        })()}
      </Section>

      {/* Latest activity row */}
      <div className="grid grid-cols-2 gap-4">
        <Section
          title="Latest site update"
          action={<JumpToButton onClick={() => onJumpTo('site')}>View all</JumpToButton>}
        >
          <EmptyHint>
            Site updates from <code className="font-mono text-[11px]">SiteUpdatesTab</code> will land here. Photos, snag entries, contractor notes.
          </EmptyHint>
        </Section>
        <Section
          title="Latest design file"
          action={<JumpToButton onClick={() => onJumpTo('files')}>View all</JumpToButton>}
        >
          <EmptyHint>
            Most recent drawing or presentation will preview here with version stamp.
          </EmptyHint>
        </Section>
      </div>

      {/* Stakeholders summary (only if data exists) */}
      {(decisionMakers.length > 0 || externalStakeholders.length > 0) && (
        <Section
          title="Stakeholder roll-call"
          subtitle="From the onboarding wizard"
          action={<JumpToButton onClick={() => onJumpTo('client')}>Open Client tab</JumpToButton>}
        >
          <div className="grid grid-cols-2 gap-3">
            <div>
              <div className="text-[10px] font-mono ink-faint uppercase tracking-wider mb-2">Decision makers ({decisionMakers.length})</div>
              {decisionMakers.length === 0 ? (
                <div className="text-xs ink-faint">None set</div>
              ) : (
                <div className="space-y-1.5">
                  {decisionMakers.slice(0, 4).map((dm, i) => (
                    <div key={i} className="text-xs ink">
                      <span className="font-medium">{dm.name || `Decision Maker ${i + 1}`}</span>
                      {dm.role && <span className="ink-soft"> — {dm.role}</span>}
                    </div>
                  ))}
                  {decisionMakers.length > 4 && (
                    <div className="text-[10px] ink-faint font-mono">+{decisionMakers.length - 4} more</div>
                  )}
                </div>
              )}
            </div>
            <div>
              <div className="text-[10px] font-mono ink-faint uppercase tracking-wider mb-2">External stakeholders ({externalStakeholders.length})</div>
              {externalStakeholders.length === 0 ? (
                <div className="text-xs ink-faint">None set</div>
              ) : (
                <div className="space-y-1.5">
                  {externalStakeholders.slice(0, 4).map((s, i) => (
                    <div key={i} className="text-xs ink">
                      <span className="font-medium">{s.name || `Stakeholder ${i + 1}`}</span>
                      {s.type && <span className="ink-soft"> — {s.type}</span>}
                    </div>
                  ))}
                  {externalStakeholders.length > 4 && (
                    <div className="text-[10px] ink-faint font-mono">+{externalStakeholders.length - 4} more</div>
                  )}
                </div>
              )}
            </div>
          </div>
        </Section>
      )}

      {/* Payment summary (only if data exists)
          Phase 9.0.16 — Rich table: Code | Milestone+Date | Amount Due (₹+target date) | Received (₹+receipt date) | Status pill + Balance
          Plus bottom totals row with progress bar. */}
      {paymentTerms.length > 0 && (() => {
        const totalProjectValue = parseFloat(w.totalProjectValue) || 0;
        const today = new Date().toISOString().slice(0, 10);
        const computeAmt = (m) => {
          if (m.amountManualOverride && m.amount) return parseFloat(m.amount) || 0;
          const pct = parseFloat(m.percentage) || 0;
          return totalProjectValue * pct / 100;
        };
        const computeStatus = (m) => {
          const due = computeAmt(m);
          const recv = parseFloat(m.amountReceived) || 0;
          if (due > 0 && recv >= due) return { label: 'Paid', tone: 'moss' };
          if (recv > 0 && recv < due) return { label: 'Partial', tone: 'amber' };
          if (m.targetDate && m.targetDate < today) return { label: 'Overdue', tone: 'terra' };
          if (m.targetDate && m.targetDate >= today) {
            const targetTs = new Date(m.targetDate).getTime();
            const todayTs = new Date(today).getTime();
            const days = Math.floor((targetTs - todayTs) / (1000 * 60 * 60 * 24));
            if (days <= 7) return { label: 'Due Soon', tone: 'amber' };
          }
          return { label: 'Pending', tone: 'neutral' };
        };

        /* Phase 9.0.19 — Receipt timing flag (for the inline label next to receipt date).
           - early   = received before due (or same day)
           - on_time = received within 7 days after due
           - late    = received more than 7 days after due */
        const computeReceiptTiming = (m) => {
          if (!m.receiptDate || !m.targetDate) return null;
          const recvTs = new Date(m.receiptDate).getTime();
          const targetTs = new Date(m.targetDate).getTime();
          if (isNaN(recvTs) || isNaN(targetTs)) return null;
          const days = Math.floor((recvTs - targetTs) / (1000 * 60 * 60 * 24));
          if (days <= 0) return { label: 'Early', tone: 'moss', icon: 'check', daysText: days === 0 ? 'on due date' : `${Math.abs(days)}d early` };
          if (days <= 7) return { label: 'On time', tone: 'moss', icon: 'check', daysText: `${days}d after due` };
          return { label: 'Late', tone: 'terra', icon: 'flag', daysText: `${days}d late` };
        };

        /* Phase 9.0.20 — Severity / Health icon (the BIG visible flag).
           One prominent visual per milestone combining status AND receipt timing.
           Used for the leftmost flag column.
             RED    — Overdue OR Late receipt (received >7 days after due) — DEMANDS ATTENTION
             YELLOW — Partial OR Due Soon (within 7 days) — needs eyes-on
             GREEN  — Paid + on time/early
             GREY   — Pending / future, nothing actionable */
        const computeSeverity = (m) => {
          const due = computeAmt(m);
          const recv = parseFloat(m.amountReceived) || 0;
          const targetPassed = m.targetDate && m.targetDate < today;
          const fullyPaid = due > 0 && recv >= due;
          const partiallyPaid = recv > 0 && recv < due;

          let lateReceipt = false;
          if (m.receiptDate && m.targetDate) {
            const days = Math.floor((new Date(m.receiptDate).getTime() - new Date(m.targetDate).getTime()) / (1000 * 60 * 60 * 24));
            if (days > 7) lateReceipt = true;
          }

          if (targetPassed && !fullyPaid) return { tone: 'red', label: 'Overdue', icon: 'flag' };
          if (lateReceipt) return { tone: 'red', label: 'Paid late', icon: 'flag' };
          if (partiallyPaid) return { tone: 'yellow', label: 'Partial', icon: 'flag' };
          if (m.targetDate && m.targetDate >= today && !fullyPaid) {
            const days = Math.floor((new Date(m.targetDate).getTime() - new Date(today).getTime()) / (1000 * 60 * 60 * 24));
            if (days <= 7) return { tone: 'yellow', label: 'Due soon', icon: 'flag' };
          }
          if (fullyPaid) return { tone: 'green', label: 'Paid', icon: 'check' };
          return { tone: 'grey', label: 'Pending', icon: 'dot' };
        };

        const totalDue = paymentTerms.reduce((sum, m) => sum + computeAmt(m), 0);
        const totalReceived = paymentTerms.reduce((sum, m) => sum + (parseFloat(m.amountReceived) || 0), 0);
        const totalBalance = totalDue - totalReceived;
        const recvPct = totalDue > 0 ? Math.round((totalReceived / totalDue) * 100) : 0;

        const toneClass = (tone) =>
          tone === 'moss' ? 'bg-moss/15 text-moss border border-moss/30'
          : tone === 'amber' ? 'bg-amber-100 text-amber-800 border border-amber-300'
          : tone === 'terra' ? 'bg-terra/15 text-terra border border-terra/30'
          : 'bg-bone ink-soft border border-line-soft';

        return (
          <Section
            title="Payment milestones"
            subtitle={
              totalProjectValue > 0
                ? `${paymentTerms.length} milestones · Total ₹ ${totalProjectValue.toLocaleString('en-IN')}`
                : `${paymentTerms.length} milestone${paymentTerms.length > 1 ? 's' : ''} from wizard`
            }
            action={<JumpToButton onClick={() => onJumpTo('payments')}>Open Payments tab</JumpToButton>}
          >
            <div className="border border-line rounded-md overflow-hidden">
              {/* Header */}
              <div className="grid bg-bone border-b border-line px-3 py-2 gap-2 text-[10px] font-mono ink-faint uppercase tracking-wider"
                style={{ gridTemplateColumns: '32px 36px 2fr 1.3fr 1.3fr 1.4fr' }}>
                <div></div>
                <div>#</div>
                <div>Milestone</div>
                <div>Amount Due</div>
                <div>Received</div>
                <div>Status / Balance</div>
              </div>
              {paymentTerms.map((m, i) => {
                const due = computeAmt(m);
                const recv = parseFloat(m.amountReceived) || 0;
                const balance = due - recv;
                const status = computeStatus(m);
                const timing = computeReceiptTiming(m);
                const severity = computeSeverity(m);
                /* Big visible flag styles */
                const sevBg =
                  severity.tone === 'red'    ? 'bg-terra text-white'
                  : severity.tone === 'yellow' ? 'bg-amber-400 text-amber-900'
                  : severity.tone === 'green'  ? 'bg-moss text-white'
                  : 'bg-line ink-soft';
                return (
                  <div key={m.id} className="grid items-center px-3 py-2 gap-2 border-b border-line-soft text-xs"
                    style={{ gridTemplateColumns: '32px 36px 2fr 1.3fr 1.3fr 1.4fr' }}>
                    <div className="flex items-center justify-center">
                      <div
                        className={`w-7 h-7 rounded-full flex items-center justify-center shadow-sm ${sevBg}`}
                        title={severity.label}
                      >
                        {severity.icon === 'flag' ? <Flag className="w-3.5 h-3.5" strokeWidth={2.5} /> :
                         severity.icon === 'check' ? <Check className="w-3.5 h-3.5" strokeWidth={3} /> :
                         <Circle className="w-2 h-2" />}
                      </div>
                    </div>
                    <div className="font-mono ink-faint text-[10px]">M{String(i + 1).padStart(2, '0')}</div>
                    <div>
                      <div className="ink font-medium">{m.name || 'Untitled milestone'}</div>
                      {m.linkedStage && <div className="text-[10px] ink-soft">{m.linkedStage}</div>}
                    </div>
                    <div>
                      <div className="ink font-mono">{due > 0 ? `₹ ${Math.round(due).toLocaleString('en-IN')}` : '—'}</div>
                      <div className="text-[10px] ink-faint font-mono">
                        {m.targetDate ? `Due ${new Date(m.targetDate).toLocaleDateString('en-IN', { day: '2-digit', month: 'short', year: 'numeric' })}` : (m.percentage ? `${m.percentage}% of total` : 'date not set')}
                      </div>
                    </div>
                    <div>
                      <div className={`font-mono ${recv > 0 ? 'text-moss font-semibold' : 'ink-faint'}`}>
                        {recv > 0 ? `₹ ${Math.round(recv).toLocaleString('en-IN')}` : '— not received —'}
                      </div>
                      {m.receiptDate && (
                        <div className="text-[10px] ink-faint font-mono flex items-center gap-1">
                          <span>on {new Date(m.receiptDate).toLocaleDateString('en-IN', { day: '2-digit', month: 'short', year: 'numeric' })}</span>
                          {timing && (
                            <span
                              className={`inline-flex items-center gap-0.5 px-1 py-0.5 rounded text-[8px] uppercase tracking-wider ${
                                timing.tone === 'moss' ? 'bg-moss/15 text-moss' : 'bg-terra/15 text-terra'
                              }`}
                              title={`Receipt timing: ${timing.daysText}`}
                            >
                              {timing.icon === 'flag' ? <Flag className="w-2 h-2" /> : <Check className="w-2 h-2" />}
                              {timing.label}
                            </span>
                          )}
                        </div>
                      )}
                    </div>
                    <div>
                      <span className={`inline-block text-[9px] font-mono uppercase tracking-wider px-1.5 py-0.5 rounded ${toneClass(status.tone)}`}>
                        {status.label}
                      </span>
                      <div className={`text-[11px] font-mono mt-0.5 ${balance > 0 ? 'ink' : 'ink-faint'}`}>
                        Balance: ₹ {Math.round(balance).toLocaleString('en-IN')}
                      </div>
                    </div>
                  </div>
                );
              })}
              {/* Totals row */}
              <div className="grid items-start px-3 py-2.5 gap-2 bg-bone text-[11px] font-mono"
                style={{ gridTemplateColumns: '32px 36px 2fr 1.3fr 1.3fr 1.4fr' }}>
                <div></div>
                <div></div>
                <div className="ink-faint uppercase tracking-wider text-[10px]">Totals</div>
                <div>
                  <div className="ink font-semibold">₹ {Math.round(totalDue).toLocaleString('en-IN')}</div>
                  <div className="text-[9px] ink-faint">total due</div>
                </div>
                <div>
                  <div className="text-moss font-semibold">₹ {Math.round(totalReceived).toLocaleString('en-IN')}</div>
                  <div className="text-[9px] ink-faint">received</div>
                </div>
                <div>
                  <div className={`font-semibold ${totalBalance > 0 ? 'text-terra' : 'text-moss'}`}>
                    ₹ {Math.round(totalBalance).toLocaleString('en-IN')}
                  </div>
                  <div className="text-[9px] ink-faint">balance · {recvPct}% received</div>
                </div>
              </div>
              {/* Progress bar */}
              <div className="px-3 pb-2 bg-bone">
                <div className="h-1.5 bg-paper rounded-full overflow-hidden">
                  <div className="h-full bg-moss transition-all" style={{ width: `${Math.min(recvPct, 100)}%` }} />
                </div>
              </div>
            </div>
            {totalProjectValue === 0 && (
              <div className="mt-2 text-[10px] font-mono ink-faint">
                Set the Total Project Value in the wizard's payment section to enable auto-split of amounts.
              </div>
            )}
          </Section>
        );
      })()}

      {/* Quick jump grid */}
      <Section title="Jump to" subtitle="All 13 tabs in this Projhub">
        <div className="grid grid-cols-3 gap-2">
          {projhubTabs.filter((t) => t.code !== 'overview').map((t) => {
            const Icon = t.icon;
            return (
              <button
                key={t.code}
                onClick={() => onJumpTo(t.code)}
                className="flex items-center gap-2 p-2.5 bg-bone hover:bg-paper border border-line-soft hover:border-ink rounded text-left group"
                style={{ transition: 'all 0.15s' }}
              >
                <Icon className="w-3.5 h-3.5 ink-soft group-hover:text-terra shrink-0" strokeWidth={1.7} />
                <span className="text-xs ink truncate">{t.label}</span>
                <ArrowRight className="w-3 h-3 ink-faint group-hover:ink ml-auto shrink-0" />
              </button>
            );
          })}
        </div>
      </Section>
    </div>
  );
}

/* ===================== PLACEHOLDER TAB (×12) ===================== */

function PlaceholderTab({ tab, project, masters, onOpenMasters }) {
  const config = placeholderConfig[tab.code] || {};
  const Icon = tab.icon;
  const w = project._wizard || {};

  // detect if data exists for this tab from wizard
  let dataPreview = null;
  if (tab.code === 'spaces' && w.projectLevels && w.projectLevels.length > 0) {
    const c = countTree(w.projectLevels);
    const branchLine = `${c.levels} lv · ${c.zones} zn · ${c.spaces} sp · ${c.features} ft · ${c.elements} el`;
    const leafTotal = c.specs + c.checklists + c.drawings + c.references + c.boqItems;
    dataPreview = leafTotal > 0
      ? `${branchLine} · ${leafTotal} leaves (${c.specs} sp · ${c.checklists} ch · ${c.drawings} dw · ${c.references} rf · ${c.boqItems} bq)`
      : branchLine;
  } else if (tab.code === 'client' && (w.primaryClientName || (w.decisionMakers || []).length > 0)) {
    const dms = w.decisionMakers || [];
    const stk = w.externalStakeholders || [];
    dataPreview = `${w.primaryClientName ? '1 primary' : 'No primary'} · ${dms.filter(d => d.name).length} decision makers · ${stk.length} external stakeholders`;
  } else if (tab.code === 'payments' && (w.paymentTerms || []).length > 0) {
    const total = w.paymentTerms.reduce((sum, m) => sum + (parseFloat(m.percentage) || 0), 0);
    dataPreview = `${w.paymentTerms.length} milestones · ${total.toFixed(0)}% allocated`;
  } else if (tab.code === 'details' && (w.clientProjectName || project.name)) {
    const fields = [
      w.builtUpArea && 'built-up area',
      w.numberOfLevels && 'levels',
      w.includedScope && 'scope',
      project.startDate && 'timeline',
    ].filter(Boolean);
    dataPreview = fields.length > 0
      ? `Captured: ${fields.join(', ')}`
      : 'Wizard Page 1 + Page 2 data captured';
  } else if (tab.code === 'scope' && (w.includedScope || w.excludedScope)) {
    dataPreview = `${w.includedScope ? 'Included' : ''}${w.includedScope && w.excludedScope ? ' + ' : ''}${w.excludedScope ? 'Excluded' : ''} scope captured`;
  }

  return (
    <div className="space-y-4">
      <div className="bg-paper border border-line rounded-lg p-6">
        <div className="flex items-start gap-3 mb-4">
          <div className="w-10 h-10 bg-bone rounded-lg flex items-center justify-center border border-line">
            <Icon className="w-5 h-5 ink-soft" strokeWidth={1.7} />
          </div>
          <div className="flex-1">
            <div className="flex items-center gap-2 mb-1">
              <h2 className="font-display text-2xl ink tracking-tight leading-none">{tab.label}</h2>
              <Tag tone="bone">Placeholder · Phase 3.1</Tag>
            </div>
            <div className="text-[11px] font-mono ink-faint">{tab.sourceCode}</div>
          </div>
        </div>

        <div className="text-sm ink-soft leading-relaxed mb-5" style={{ maxWidth: '720px' }}>
          {config.description}
        </div>

        {/* Data preview if available */}
        {dataPreview && (
          <div className="mb-5 p-4 bg-moss-soft border border-line-soft rounded">
            <div className="flex items-start gap-2.5">
              <CheckCircle2 className="w-4 h-4 text-moss shrink-0 mt-0.5" strokeWidth={2.5} />
              <div className="flex-1">
                <div className="text-xs ink font-semibold mb-0.5">Data already collected</div>
                <div className="text-xs ink-soft">{dataPreview}</div>
                <div className="text-[10px] font-mono ink-faint mt-1">Source: {config.sourceData}</div>
              </div>
            </div>
          </div>
        )}

        {/* Source data origin */}
        {!dataPreview && config.sourceData && (
          <div className="mb-5 flex items-center gap-2 text-[11px] ink-faint">
            <span className="font-mono uppercase tracking-wider">Source:</span>
            <span className="font-mono ink-soft">{config.sourceData}</span>
          </div>
        )}

        {/* Required masters */}
        {config.masters.length > 0 && (
          <div className="mb-5">
            <div className="text-[10px] font-mono tracking-widest font-semibold uppercase ink-faint mb-2">Required masters</div>
            <div className="flex flex-wrap gap-1.5">
              {config.masters.map((m) => {
                const isReady = masters[m] && masters[m].length > 0;
                return (
                  <span
                    key={m}
                    className={`inline-flex items-center gap-1 text-[11px] font-mono px-2 py-1 rounded ${
                      isReady ? 'bg-moss-soft text-moss' : 'bg-muted-warm ink-faint'
                    }`}
                  >
                    {isReady ? <CheckCircle2 className="w-2.5 h-2.5" strokeWidth={2.5} /> : <Circle className="w-2.5 h-2.5" />}
                    {m}
                    {isReady && <span className="ink-faint">· {masters[m].length}</span>}
                  </span>
                );
              })}
            </div>
            {config.masters.some((m) => !masters[m] || masters[m].length === 0) && (
              <button onClick={onOpenMasters} className="mt-3 flex items-center gap-1.5 text-[11px] font-mono text-terra hover:ink">
                <Database className="w-3 h-3" /> Open MasterSettings to seed missing masters →
              </button>
            )}
          </div>
        )}

        {/* Empty state visual */}
        <div className="bg-bone border border-line-soft rounded p-8 text-center">
          <Icon className="w-8 h-8 ink-faint mx-auto mb-3" strokeWidth={1.5} />
          <div className="font-display text-base ink mb-1">Coming in Phase 3.1</div>
          <div className="text-xs ink-soft" style={{ maxWidth: '420px', margin: '0 auto' }}>
            This tab is registered in the build, ready to be deepened. The structure, masters, and data flow are mapped — only the UI is pending.
          </div>
        </div>
      </div>
    </div>
  );
}

/* ===================== Overview helpers ===================== */

function MetricCard({ icon: Icon, label, value, tone = 'ink', onClick }) {
  const toneStyles = {
    terra: 'border-terra bg-terra-soft',
    moss: 'border-line bg-paper',
    clay: 'border-clay bg-paper',
    ink: 'border-line bg-paper',
  };
  const valueColor = { terra: 'text-terra', moss: 'ink', clay: 'text-clay', ink: 'ink' };
  return (
    <button onClick={onClick} className={`border rounded-lg p-4 text-left hover:shadow-sm group ${toneStyles[tone]}`} style={{ transition: 'all 0.15s' }}>
      <div className="flex items-center justify-between mb-3">
        <Icon className={`w-4 h-4 ${tone === 'terra' ? 'text-terra' : tone === 'clay' ? 'text-clay' : 'ink-soft'}`} strokeWidth={1.7} />
        <ArrowRight className="w-3 h-3 ink-faint group-hover:ink" />
      </div>
      <div className="text-[10px] font-mono ink-faint uppercase tracking-wider mb-1">{label}</div>
      <div className={`font-display text-2xl tracking-tight leading-none ${valueColor[tone]}`}>{value}</div>
    </button>
  );
}

function FactRow({ label, value, mono, small }) {
  return (
    <div className="flex items-start gap-3 text-[12px]">
      <span className="ink-faint font-mono uppercase tracking-wider text-[10px] mt-0.5 shrink-0" style={{ width: '90px' }}>{label}</span>
      <span className={`flex-1 ink ${mono ? 'font-mono' : ''} ${small ? 'text-[11px] leading-snug' : ''}`}>{value || <span className="ink-faint">—</span>}</span>
    </div>
  );
}

function EmptyHint({ children }) {
  return (
    <div className="bg-bone rounded border border-line-soft p-4 text-xs ink-soft leading-relaxed">
      {children}
    </div>
  );
}

function JumpToButton({ children, onClick }) {
  return (
    <button onClick={onClick} className="flex items-center gap-1 text-[11px] font-mono text-terra hover:ink">
      {children} <ArrowRight className="w-3 h-3" />
    </button>
  );
}

function formatDate(d) {
  if (!d) return '—';
  // already formatted seed dates ('14 Jan 2026') stay as-is
  if (typeof d === 'string' && d.includes(' ')) return d;
  // wizard dates are ISO 'YYYY-MM-DD'
  if (typeof d === 'string' && /^\d{4}-\d{2}-\d{2}$/.test(d)) {
    const date = new Date(d + 'T00:00:00');
    return date.toLocaleDateString('en-GB', { day: '2-digit', month: 'short', year: 'numeric' });
  }
  return d;
}

