function RoleSwitcherDropdown({ current, onPick, onClose, onOpenRoles }) {
  // Click outside to close
  React.useEffect(() => {
    const handler = (e) => {
      if (!e.target.closest('[data-role-switcher]')) onClose();
    };
    setTimeout(() => document.addEventListener('click', handler), 0);
    return () => document.removeEventListener('click', handler);
  }, [onClose]);

  return (
    <div
      data-role-switcher
      className="absolute right-0 top-full mt-1 w-80 bg-paper border border-line rounded-md shadow-lg z-50 fade-in overflow-hidden"
      style={{ maxHeight: '480px' }}
    >
      <div className="px-3 py-2.5 border-b border-line bg-bone">
        <div className="text-[10px] font-mono uppercase tracking-widest ink-faint">View as</div>
        <div className="text-[11px] ink-soft mt-0.5">Switch role to see what each user sees on the dashboard, projhub, and nav.</div>
      </div>
      <div className="overflow-y-auto scrollbar-thin" style={{ maxHeight: '380px' }}>
        {Object.values(roleProfiles).map((p) => {
          const Icon = p.icon;
          const isActive = p.code === current.code;
          const firstName = (p.user.name || '').split(/\s+/).filter(Boolean)[0] || p.user.name;
          return (
            <button
              key={p.code}
              onClick={() => onPick(p.code)}
              className={`w-full text-left px-3 py-2.5 hover:bg-bone border-l-2 transition-colors ${
                isActive ? 'border-terra bg-bone' : 'border-transparent'
              }`}
            >
              <div className="flex items-start gap-2.5">
                <div
                  className="w-8 h-8 text-white rounded-full flex items-center justify-center text-[11px] font-semibold shrink-0"
                  style={{ background: p.accent }}
                >
                  {p.user.initials}
                </div>
                <div className="min-w-0 flex-1">
                  <div className="flex items-center gap-1.5 mb-0.5">
                    <Icon className="w-3 h-3 ink-soft shrink-0" strokeWidth={1.7} />
                    <span className="text-xs ink font-semibold truncate">{firstName}</span>
                    {isActive && <span className="text-[9px] font-mono text-terra shrink-0">· active</span>}
                  </div>
                  <div className="text-[10px] font-mono ink-soft truncate">{p.shortLabel}</div>
                  <div className="text-[10px] ink-faint mt-0.5">{p.level}</div>
                </div>
              </div>
            </button>
          );
        })}
      </div>
      <div className="px-3 py-2 border-t border-line bg-bone">
        <button
          onClick={onOpenRoles}
          className="w-full flex items-center justify-between text-[11px] font-mono ink-soft hover:ink"
        >
          <span>Open Roles &amp; Access</span>
          <ArrowRight className="w-3 h-3" />
        </button>
      </div>
    </div>
  );
}

