function buildProposalSharePayload(deal, masters) {
  const lead = (masters.MasterLeads || []).find((item) => String(item.id) === String(deal.linkedLeadId));
  const studio = masters.MasterStudioSettings?.[0] || {};
  const value = parseBudgetToRupees(deal.dealValue);
  return {
    studioName: studio.studioName || studio.value || 'Studio/OS',
    proposalName: `${deal.name || lead?.name || 'Project'} Proposal`,
    clientName: lead?.name || deal.name || 'Client',
    clientEmail: lead?.email || '',
    clientMobile: lead?.phone || '',
    projectLocation: [deal.city, deal.propertyType].filter(Boolean).join(' · '),
    dealValue: value ? formatRupees(value) : deal.dealValue || '',
    salesOwner: deal.salesOwner || '',
    expectedCloseDate: deal.expectedCloseDate || '',
    status: deal.stage || 'Proposal',
    notes: deal.notes || lead?.notes || '',
    sections: [
      { title: 'Scope direction', body: lead?.brief || deal.brief || 'A focused proposal prepared for the discussed architecture and interior design scope.' },
      { title: 'Commercial direction', body: value ? `Estimated project opportunity: ${formatRupees(value)}.` : 'Commercial details can be refined after scope confirmation.' },
      { title: 'Next step', body: deal.expectedCloseDate ? `Target close date: ${formatDate(deal.expectedCloseDate)}.` : 'Review the proposal and confirm the next discussion.' },
    ],
  };
}

function getProposalShareStatus(link) {
  if (!link) return { label: 'Not Viewed', className: 'bg-bone text-ink-soft' };
  if (link.expiresAt && new Date(link.expiresAt).getTime() < Date.now()) return { label: 'Expired', className: 'bg-red-50 text-red-700' };
  if (link.isActive === false) return { label: 'Disabled', className: 'bg-bone text-ink-faint' };
  if ((link.currentlyViewingCount || 0) > 0) return { label: 'Currently Viewing', className: 'bg-moss-soft text-moss' };
  if ((link.totalViews || 0) > Math.max(link.uniqueViews || 0, 1)) return { label: 'Revisited', className: 'bg-terra-soft text-terra' };
  if ((link.totalViews || 0) > 0) return { label: 'Viewed', className: 'bg-moss-soft text-moss' };
  return { label: 'Not Viewed', className: 'bg-bone text-ink-soft' };
}

function formatProposalDate(value) {
  if (!value) return '-';
  const date = new Date(value);
  if (Number.isNaN(date.getTime())) return formatDate(value);
  return date.toLocaleDateString('en-GB', { day: '2-digit', month: 'short', year: 'numeric' });
}

function formatProposalDateTime(value) {
  if (!value) return '-';
  const date = new Date(value);
  if (Number.isNaN(date.getTime())) return String(value);
  return date.toLocaleString('en-GB', { day: '2-digit', month: 'short', hour: '2-digit', minute: '2-digit' });
}

function formatProposalDuration(seconds) {
  const safe = Math.max(0, Number(seconds) || 0);
  if (safe < 60) return `${Math.round(safe)}s`;
  const mins = Math.floor(safe / 60);
  const secs = Math.round(safe % 60);
  if (mins < 60) return `${mins}m ${secs}s`;
  const hours = Math.floor(mins / 60);
  return `${hours}h ${mins % 60}m`;
}

async function copyText(text) {
  if (!text) return;
  if (navigator.clipboard?.writeText) {
    await navigator.clipboard.writeText(text);
    return;
  }
  const el = document.createElement('textarea');
  el.value = text;
  document.body.appendChild(el);
  el.select();
  document.execCommand('copy');
  document.body.removeChild(el);
}

function EngagementTabButton({ active, onClick, icon: Icon, label, count }) {
  return (
    <button
      onClick={onClick}
      className={`text-[12px] font-medium px-3 py-1.5 rounded-md transition-all flex items-center gap-1.5 ${
        active ? 'bg-ink text-white shadow-sm' : 'ink-soft hover:ink hover:bg-paper'
      }`}
    >
      <Icon className="w-3.5 h-3.5" />
      {label}
      {count !== undefined && (
        <span className={`text-[10px] font-mono ${active ? 'text-white/70' : 'ink-faint'}`}>({count})</span>
      )}
    </button>
  );
}

