function EngagementAssetsPanel({ assetType, masters, setMasters, currentProfile }) {
  const [showAdd, setShowAdd] = React.useState(false);
  const [editingAsset, setEditingAsset] = React.useState(null);
  const [sendingAsset, setSendingAsset] = React.useState(null);
  /* Phase 9.8 — PPT versioning: when set, AddModal opens pre-filled with this
     asset's metadata to become a new version under the same chain. */
  const [addingVersionFor, setAddingVersionFor] = React.useState(null);
  const [filterCategory, setFilterCategory] = React.useState('all');
  const [search, setSearch] = React.useState('');

  const allAssets = (masters.MasterEngagementAssets) || [];
  const typeAssets = allAssets.filter((a) => a.type === assetType);
  const projectCategories = (masters.MasterProjectCategory || []).map((c) => c.value);

  /* Phase 9.8 — PPT versioning. For PPT type, collapse version chains so only
     the LATEST version of each chain is shown in the grid. Versions are linked
     via parentId — the first version has no parentId (it's the canonical/root),
     and subsequent versions point to the root via parentId. */
  const versionChainMap = React.useMemo(() => {
    /* Returns: rootId → [all versions in chain, oldest first] */
    if (assetType !== 'ppt') return null;
    const chains = new Map();
    typeAssets.forEach((a) => {
      const rootId = a.parentId || a.id;
      if (!chains.has(rootId)) chains.set(rootId, []);
      chains.get(rootId).push(a);
    });
    /* Sort each chain by createdOn ascending (oldest first) */
    chains.forEach((list) => list.sort((a, b) => new Date(a.createdOn) - new Date(b.createdOn)));
    return chains;
  }, [typeAssets, assetType]);

  /* Filter */
  const visible = typeAssets.filter((a) => {
    /* For PPT: hide non-latest versions from the grid (they're shown in the
       version history accordion on the latest card). */
    if (assetType === 'ppt' && versionChainMap) {
      const rootId = a.parentId || a.id;
      const chain = versionChainMap.get(rootId) || [];
      const latest = chain[chain.length - 1];
      if (latest && latest.id !== a.id) return false;
    }
    if (filterCategory !== 'all' && filterCategory !== '__uncat__' && a.projectCategory !== filterCategory) return false;
    if (filterCategory === '__uncat__' && a.projectCategory) return false;
    if (search.trim()) {
      const q = search.toLowerCase();
      const match = (a.name || '').toLowerCase().includes(q)
        || (a.description || '').toLowerCase().includes(q)
        || (a.tags || []).some((t) => t.toLowerCase().includes(q));
      if (!match) return false;
    }
    return true;
  });

  const labels = {
    pdf:   { title: 'Asset PDFs',         add: 'Add PDF',       empty: 'No PDFs yet — add your studio portfolio, fee schedule, or process brochure.' },
    video: { title: 'Videos',             add: 'Add Video',     empty: 'No videos yet — add testimonial clips, project walkthroughs, or behind-the-scenes content.' },
    image: { title: 'Images',             add: 'Add Image',     empty: 'No images yet — add hero shots, mood boards, or detail references.' },
    ppt:   { title: 'PPT Concept Pitches', add: 'Add PPT Pitch', empty: 'No pitches yet — add your concept decks for sending post-discovery call.' },
  };
  const L = labels[assetType] || labels.pdf;

  return (
    <div>
      {/* Section header */}
      <div className="flex items-center justify-between flex-wrap gap-3 mb-4">
        <div>
          <h2 className="font-display text-xl ink tracking-tight">{L.title}</h2>
          <p className="text-[12px] ink-soft mt-0.5">
            {assetType === 'pdf'   && 'Documents you share with prospects — portfolios, fee schedules, process brochures.'}
            {assetType === 'video' && 'Testimonials, walkthroughs, and BTS clips. Paste a YouTube or Vimeo URL.'}
            {assetType === 'image' && 'Mood boards, project hero shots, and image references for design conversations.'}
            {assetType === 'ppt'   && 'Concept decks and pitch presentations. Send post-discovery call, before the formal proposal.'}
          </p>
        </div>
        <button
          onClick={() => setShowAdd(true)}
          className="text-[12px] font-medium px-3 py-2 rounded bg-terra text-white hover:opacity-90 flex items-center gap-1.5"
        >
          <Plus className="w-3.5 h-3.5" /> {L.add}
        </button>
      </div>

      {/* Phase 9.5.5 — Compact help accordion when assets exist. Empty-state
         path renders the full inline guide below. */}
      {typeAssets.length > 0 && (
        <EngagementAssetGuide assetType={assetType} variant="accordion" />
      )}

      {/* Filter bar */}
      <div className="bg-paper border border-line rounded-lg p-3 mb-4 flex items-center gap-3 flex-wrap">
        <div className="flex items-center gap-1.5">
          <Filter className="w-3.5 h-3.5 ink-faint" />
          <span className="text-[10px] font-mono uppercase tracking-wider ink-faint">Category</span>
          <select
            value={filterCategory}
            onChange={(e) => setFilterCategory(e.target.value)}
            className="text-[12px] ink bg-paper border border-line rounded px-2 py-1 outline-none focus:border-terra"
          >
            <option value="all">All</option>
            <option value="__uncat__">Uncategorized</option>
            {projectCategories.map((c) => <option key={c} value={c}>{c}</option>)}
          </select>
        </div>
        <div className="flex-1 min-w-[200px] flex items-center gap-1.5">
          <Search className="w-3.5 h-3.5 ink-faint" />
          <input
            type="text"
            value={search}
            onChange={(e) => setSearch(e.target.value)}
            placeholder="Search name, description, tags…"
            className="flex-1 text-[12px] ink bg-paper border border-line rounded px-2 py-1 outline-none focus:border-terra"
          />
        </div>
        <div className="text-[10px] ink-faint">
          {visible.length} of {typeAssets.length}
        </div>
      </div>

      {/* Grid */}
      {visible.length === 0 ? (
        typeAssets.length === 0 ? (
          /* Phase 9.5.5 — Empty state IS the full inline guide. The studio
             learns how to upload while seeing zero clutter. */
          <div>
            <EngagementAssetGuide assetType={assetType} variant="inline" />
            <div className="mt-3 flex justify-center">
              <button onClick={() => setShowAdd(true)} className="text-[12px] font-medium px-4 py-2 rounded bg-terra text-white hover:opacity-90 inline-flex items-center gap-1.5">
                <Plus className="w-3.5 h-3.5" /> {L.add}
              </button>
            </div>
          </div>
        ) : (
          /* Have assets, but filters returned zero matches */
          <div className="bg-paper border border-line border-dashed rounded-lg p-10 text-center">
            <p className="text-sm ink-soft">No matches — adjust the filter or search.</p>
          </div>
        )
      ) : (
        <EngagementAssetsSplitPanel
          assets={visible}
          assetType={assetType}
          versionChainMap={versionChainMap}
          allAssets={allAssets}
          onEdit={(asset) => setEditingAsset(asset)}
          onSend={(asset) => setSendingAsset(asset)}
          onAddVersion={(asset) => setAddingVersionFor(asset)}
          onEditVersion={(asset) => setEditingAsset(asset)}
        />
      )}

      {/* Modals */}
      {showAdd && (
        <AddEngagementAssetModal
          assetType={assetType}
          masters={masters}
          setMasters={setMasters}
          onClose={() => setShowAdd(false)}
        />
      )}
      {editingAsset && (
        <AddEngagementAssetModal
          assetType={editingAsset.type}
          masters={masters}
          setMasters={setMasters}
          existingAsset={editingAsset}
          onClose={() => setEditingAsset(null)}
        />
      )}
      {addingVersionFor && (
        <AddEngagementAssetModal
          assetType={addingVersionFor.type}
          masters={masters}
          setMasters={setMasters}
          newVersionOf={addingVersionFor}
          onClose={() => setAddingVersionFor(null)}
        />
      )}
      {sendingAsset && (
        <SendEngagementAssetModal
          asset={sendingAsset}
          masters={masters}
          setMasters={setMasters}
          currentProfile={currentProfile}
          onClose={() => setSendingAsset(null)}
        />
      )}
    </div>
  );
}

function EngagementAssetsSplitPanel({ assets, assetType, versionChainMap, allAssets, onEdit, onSend, onAddVersion, onEditVersion }) {
  const [activeId, setActiveId] = React.useState(assets[0]?.id || null);
  React.useEffect(() => {
    if (!assets.length) return;
    if (!activeId || !assets.some((a) => a.id === activeId)) setActiveId(assets[0].id);
  }, [assets, activeId]);
  const active = assets.find((a) => a.id === activeId) || assets[0];
  const activeChain = active && assetType === 'ppt' && versionChainMap
    ? (versionChainMap.get(active.parentId || active.id) || [active])
    : null;
  const Icon = active?.type === 'video' ? PlayCircle : active?.type === 'image' ? ImageIcon : active?.type === 'ppt' ? Presentation : FileText;

  return (
    <SplitPanelShell
      eyebrow="Assets"
      title="Engagement library"
      countLabel={`${assets.length} item${assets.length === 1 ? '' : 's'}`}
      left={assets.map((asset) => {
        const isActive = active?.id === asset.id;
        const chain = assetType === 'ppt' && versionChainMap ? (versionChainMap.get(asset.parentId || asset.id) || [asset]) : null;
        const assetIcon = asset.type === 'video' ? PlayCircle : asset.type === 'image' ? ImageIcon : asset.type === 'ppt' ? Presentation : FileText;
        const AssetIcon = assetIcon;
        return (
          <button
            key={asset.id}
            onClick={() => setActiveId(asset.id)}
            className={`w-full text-left rounded-lg px-3 py-3 border-l-4 transition-colors ${
              isActive ? 'bg-amber-50/70 border-terra' : 'border-transparent hover:bg-bone/70'
            }`}
          >
            <div className="flex items-start gap-3">
              <div className="w-9 h-9 rounded-lg bg-bone border border-line-soft flex items-center justify-center shrink-0">
                <AssetIcon className="w-4 h-4 ink-soft" />
              </div>
              <div className="min-w-0 flex-1">
                <div className="text-[14px] ink font-semibold truncate" title={asset.name}>{asset.name}</div>
                <div className="text-[12px] ink-soft truncate mt-0.5">
                  {asset.type?.toUpperCase()}{chain?.length > 1 ? ` · ${chain.length} versions` : ''}{asset.sendCount ? ` · sent ${asset.sendCount}x` : ''}
                </div>
              </div>
            </div>
          </button>
        );
      })}
      right={active ? (
        <div className="p-5">
          <div className="flex items-start justify-between gap-4 mb-4">
            <div className="min-w-0">
              <div className="text-[11px] font-mono uppercase tracking-widest ink-faint mb-1">
                {active.type?.toUpperCase()}{activeChain?.length > 1 ? ` · v${activeChain.length} of ${activeChain.length}` : ''}
              </div>
              <h3 className="text-2xl font-semibold ink tracking-tight leading-tight">{active.name}</h3>
              <p className="text-sm ink-soft mt-1 leading-relaxed">{active.description || 'No description added yet.'}</p>
            </div>
            <div className="w-10 h-10 rounded-xl bg-bone border border-line-soft flex items-center justify-center shrink-0">
              <Icon className="w-5 h-5 ink-soft" />
            </div>
          </div>
          <div className="rounded-xl bg-bone/50 border border-line-soft aspect-[16/9] flex items-center justify-center overflow-hidden mb-4">
            {active.thumbnailUrl || (active.type === 'image' && active.url) ? (
              <img src={active.thumbnailUrl || active.url} alt={active.name} className="w-full h-full object-cover" />
            ) : (
              <div className="text-center ink-faint">
                <Icon className="w-9 h-9 mx-auto mb-2" strokeWidth={1.5} />
                <div className="text-[11px] font-mono uppercase tracking-widest">{active.type || 'asset'} preview</div>
              </div>
            )}
          </div>
          <div className="flex flex-wrap gap-2 mb-4">
            {(active.tags || []).slice(0, 5).map((tag) => (
              <span key={tag} className="text-[11px] px-2 py-1 rounded bg-bone ink-soft">#{tag}</span>
            ))}
          </div>
          <div className="flex flex-wrap gap-2">
            <button onClick={() => onSend(active)} className="text-[12px] font-medium px-3 py-2 rounded bg-ink text-white hover:bg-terra flex items-center gap-1.5"><Send className="w-3.5 h-3.5" /> Send</button>
            {active.type === 'ppt' && <button onClick={() => onAddVersion(active)} className="text-[12px] font-medium px-3 py-2 rounded border border-line ink hover:bg-bone">New version</button>}
            {active.url && <a href={active.url} target="_blank" rel="noopener noreferrer" className="text-[12px] font-medium px-3 py-2 rounded border border-line ink hover:bg-bone">Open</a>}
            <button onClick={() => onEdit(active)} className="text-[12px] font-medium px-3 py-2 rounded border border-line ink hover:bg-bone">Edit</button>
          </div>
          {activeChain?.length > 1 && (
            <div className="mt-5 rounded-lg border border-line-soft overflow-hidden">
              <div className="px-3 py-2 bg-bone text-[11px] font-mono uppercase tracking-widest ink-faint">Versions</div>
              {activeChain.slice().reverse().map((version, idx) => (
                <button key={version.id} onClick={() => onEditVersion(version)} className="w-full text-left px-3 py-2 border-t border-line-soft hover:bg-bone flex items-center justify-between gap-3">
                  <span className="text-[12px] ink truncate">{version.name}</span>
                  <span className="text-[10px] font-mono ink-faint">v{activeChain.length - idx}</span>
                </button>
              ))}
            </div>
          )}
        </div>
      ) : null}
    />
  );
}

/* Card component — type-aware preview block + share actions + version history */
function EngagementAssetCard({ asset, versionChain, allAssets, onEdit, onSend, onAddVersion, onEditVersion }) {
  const [showVersions, setShowVersions] = React.useState(false);
  /* Send-version picker (PPT only) */
  const [showSendPicker, setShowSendPicker] = React.useState(false);

  const hasThumb = !!asset.thumbnailUrl;
  const hasUrl = asset.source === 'url' && !!asset.url;
  const sizeKB = asset.fileSize ? (asset.fileSize / 1024).toFixed(0) : null;
  const sizeMB = asset.fileSize ? (asset.fileSize / 1024 / 1024).toFixed(1) : null;
  const sizeDisplay = sizeKB && sizeKB > 1024 ? `${sizeMB} MB` : sizeKB ? `${sizeKB} KB` : '';

  /* Phase 9.8 — Version-chain awareness */
  const hasChain = Array.isArray(versionChain) && versionChain.length > 0;
  const versionNumber = hasChain ? versionChain.findIndex((v) => v.id === asset.id) + 1 : 0;
  const totalVersions = hasChain ? versionChain.length : 0;
  const olderVersions = hasChain ? versionChain.filter((v) => v.id !== asset.id).reverse() : [];

  return (
    <div className="bg-paper border border-line rounded-lg overflow-hidden hover:border-terra hover:shadow-sm transition-all flex flex-col">
      {/* Preview block */}
      <div className="relative bg-bone/40 aspect-[16/10] flex items-center justify-center overflow-hidden">
        {hasThumb ? (
          <img src={asset.thumbnailUrl} alt={asset.name} className="w-full h-full object-cover" onError={(e) => { e.currentTarget.style.display = 'none'; }} />
        ) : asset.type === 'image' && hasUrl ? (
          <img src={asset.url} alt={asset.name} className="w-full h-full object-cover" onError={(e) => { e.currentTarget.style.display = 'none'; }} />
        ) : (
          <div className="flex flex-col items-center gap-1.5 ink-faint">
            {asset.type === 'pdf' && <FileText className="w-8 h-8" strokeWidth={1.5} />}
            {asset.type === 'video' && <PlayCircle className="w-8 h-8" strokeWidth={1.5} />}
            {asset.type === 'image' && <ImageIcon className="w-8 h-8" strokeWidth={1.5} />}
            {asset.type === 'ppt' && <Presentation className="w-8 h-8" strokeWidth={1.5} />}
            <span className="text-[10px] font-mono uppercase tracking-wider">{asset.type}</span>
          </div>
        )}
        {/* Source chip */}
        <div className="absolute top-2 left-2 flex items-center gap-1">
          {asset.source === 'url' ? (
            <span className="text-[9px] font-mono uppercase tracking-wider bg-paper/90 ink px-1.5 py-0.5 rounded border border-line">URL</span>
          ) : (
            <span className="text-[9px] font-mono uppercase tracking-wider px-1.5 py-0.5 rounded border" style={{ background: '#FFE5D9', color: '#B85C1F', borderColor: '#B85C1F' }}>UPLOAD</span>
          )}
          {/* Phase 9.8 — Version pill for PPTs in a chain */}
          {hasChain && totalVersions > 1 && (
            <span className="text-[9px] font-mono uppercase tracking-wider bg-ink text-white px-1.5 py-0.5 rounded">
              v{versionNumber}
              {totalVersions > 1 && <span className="opacity-70"> · {totalVersions} total</span>}
            </span>
          )}
        </div>
        {/* Send count badge */}
        {asset.sendCount > 0 && (
          <div className="absolute top-2 right-2 text-[9px] font-mono bg-paper/90 ink px-1.5 py-0.5 rounded border border-line">
            sent {asset.sendCount}×
          </div>
        )}
      </div>

      {/* Body */}
      <div className="p-3 flex-1 flex flex-col">
        <div className="text-[12px] ink font-semibold leading-tight mb-1 line-clamp-2">{asset.name}</div>
        {asset.description && (
          <div className="text-[11px] ink-soft leading-snug mb-2 line-clamp-2">{asset.description}</div>
        )}

        {/* Meta row */}
        <div className="flex items-center gap-2 flex-wrap mb-2 text-[10px] ink-faint">
          {asset.projectCategory && <span className="font-mono uppercase tracking-wider">{asset.projectCategory}</span>}
          {sizeDisplay && <span>· {sizeDisplay}</span>}
          {asset.fileName && <span className="truncate max-w-[120px] font-mono" title={asset.fileName}>· {asset.fileName}</span>}
        </div>

        {/* Tags */}
        {asset.tags && asset.tags.length > 0 && (
          <div className="flex items-center gap-1 flex-wrap mb-2">
            {asset.tags.slice(0, 4).map((t) => (
              <span key={t} className="text-[9px] font-mono ink-soft bg-bone/60 px-1.5 py-0.5 rounded">#{t}</span>
            ))}
            {asset.tags.length > 4 && <span className="text-[9px] ink-faint">+{asset.tags.length - 4}</span>}
          </div>
        )}

        {/* Phase 9.8 — Version history expander (PPT, when chain has older versions) */}
        {hasChain && olderVersions.length > 0 && (
          <div className="mb-2">
            <button
              onClick={() => setShowVersions((v) => !v)}
              className="text-[10px] font-medium ink-soft hover:ink flex items-center gap-1"
            >
              <ChevronDown className={`w-3 h-3 transition-transform ${showVersions ? 'rotate-180' : ''}`} />
              Version history ({olderVersions.length} older)
            </button>
            {showVersions && (
              <div className="mt-2 space-y-1 bg-bone/30 border border-line-soft rounded p-2">
                {olderVersions.map((v, idx) => {
                  const vNum = totalVersions - idx - 1; /* reverse order */
                  return (
                    <div key={v.id} className="flex items-center gap-2 text-[11px]">
                      <span className="font-mono ink-soft shrink-0">v{vNum}</span>
                      <span className="ink truncate flex-1 min-w-0" title={v.name}>{v.name}</span>
                      <span className="text-[9px] ink-faint font-mono shrink-0">
                        {v.createdOn ? new Date(v.createdOn).toLocaleDateString() : ''}
                      </span>
                      {v.source === 'url' && v.url && (
                        <a href={v.url} target="_blank" rel="noopener noreferrer" className="ink-soft hover:ink shrink-0" title="Open"><ExternalLink className="w-2.5 h-2.5" /></a>
                      )}
                      <button onClick={() => onEditVersion && onEditVersion(v)} className="ink-soft hover:ink shrink-0" title="Edit"><Edit3 className="w-2.5 h-2.5" /></button>
                    </div>
                  );
                })}
              </div>
            )}
          </div>
        )}

        <div className="mt-auto flex items-center gap-1 pt-2 border-t border-line-soft flex-wrap">
          <button
            onClick={onEdit}
            className="text-[11px] font-medium ink-soft hover:ink px-2 py-1.5 rounded hover:bg-bone flex items-center gap-1"
            title="Edit asset"
          >
            <Edit3 className="w-3 h-3" /> Edit
          </button>
          {hasUrl && (
            <a
              href={asset.url}
              target="_blank"
              rel="noopener noreferrer"
              className="text-[11px] font-medium ink-soft hover:ink px-2 py-1.5 rounded hover:bg-bone flex items-center gap-1"
              title="Open in new tab"
            >
              <ExternalLink className="w-3 h-3" /> Open
            </a>
          )}
          {/* Phase 9.8 — Add new version (PPT only) */}
          {asset.type === 'ppt' && onAddVersion && (
            <button
              onClick={onAddVersion}
              className="text-[11px] font-medium ink-soft hover:ink px-2 py-1.5 rounded hover:bg-bone flex items-center gap-1"
              title="Add new version"
            >
              <Plus className="w-3 h-3" /> New version
            </button>
          )}

          {/* Send button — for PPT with chain, opens version picker; otherwise direct send */}
          <div className="ml-auto relative">
            {asset.type === 'ppt' && totalVersions > 1 ? (
              <>
                <button
                  onClick={() => setShowSendPicker((v) => !v)}
                  className="text-[11px] font-semibold text-white bg-ink hover:bg-terra px-2.5 py-1.5 rounded flex items-center gap-1"
                >
                  <Send className="w-3 h-3" /> Send <ChevronDown className="w-2.5 h-2.5" />
                </button>
                {showSendPicker && (
                  <div className="absolute right-0 bottom-full mb-1 bg-paper border border-line rounded shadow-lg z-10 min-w-[200px]">
                    <button
                      onClick={() => { setShowSendPicker(false); onSend(asset); }}
                      className="w-full text-left px-3 py-2 hover:bg-bone text-[11px] border-b border-line-soft"
                    >
                      <div className="font-medium ink">Latest (v{versionNumber})</div>
                      <div className="text-[9px] ink-faint font-mono truncate">{asset.name}</div>
                    </button>
                    {olderVersions.map((v, idx) => {
                      const vNum = totalVersions - idx - 1;
                      return (
                        <button
                          key={v.id}
                          onClick={() => { setShowSendPicker(false); onSend(v); }}
                          className="w-full text-left px-3 py-2 hover:bg-bone text-[11px] border-b border-line-soft last:border-b-0"
                        >
                          <div className="font-medium ink-soft">v{vNum}</div>
                          <div className="text-[9px] ink-faint font-mono truncate">{v.name}</div>
                        </button>
                      );
                    })}
                  </div>
                )}
              </>
            ) : (
              <button
                onClick={() => onSend(asset)}
                className="text-[11px] font-semibold text-white bg-ink hover:bg-terra px-2.5 py-1.5 rounded flex items-center gap-1"
              >
                <Send className="w-3 h-3" /> Send
              </button>
            )}
          </div>
        </div>
      </div>
    </div>
  );
}

/* Add / Edit modal — supports both URL paste and mock upload */
function AddEngagementAssetModal({ assetType, masters, setMasters, existingAsset, newVersionOf, onClose }) {
  const isEdit = !!existingAsset;
  /* Phase 9.8 — When adding a new version of a PPT, pre-fill from the parent
     except for the URL (the studio is supplying a fresh link). The name auto-
     suggests "Original Name v2" by counting existing versions. */
  const isNewVersion = !!newVersionOf;
  const suggestedVersionName = React.useMemo(() => {
    if (!isNewVersion) return '';
    const baseName = (newVersionOf.name || '').replace(/\s+v\d+\s*$/i, '').trim();
    /* Count existing versions in chain to suggest next number */
    const rootId = newVersionOf.parentId || newVersionOf.id;
    const chain = (masters.MasterEngagementAssets || []).filter((a) => a.id === rootId || a.parentId === rootId);
    const nextVer = chain.length + 1;
    return `${baseName} v${nextVer}`;
  }, [isNewVersion, newVersionOf, masters.MasterEngagementAssets]);

  const seed = existingAsset || (isNewVersion ? { ...newVersionOf, name: suggestedVersionName, url: '', fileName: '', fileSize: null, fileType: '', thumbnailUrl: '', sendCount: 0 } : null);

  const [name, setName] = React.useState(seed?.name || '');
  const [description, setDescription] = React.useState(seed?.description || '');
  const [source, setSource] = React.useState(seed?.source || 'url');
  const [url, setUrl] = React.useState(isNewVersion ? '' : (seed?.url || ''));
  const [thumbnailUrl, setThumbnailUrl] = React.useState(isNewVersion ? '' : (seed?.thumbnailUrl || ''));
  const [fileName, setFileName] = React.useState(isNewVersion ? '' : (seed?.fileName || ''));
  const [fileSize, setFileSize] = React.useState(isNewVersion ? null : (seed?.fileSize || null));
  const [fileType, setFileType] = React.useState(isNewVersion ? '' : (seed?.fileType || ''));
  const [projectCategory, setProjectCategory] = React.useState(seed?.projectCategory || '');
  const [tagsStr, setTagsStr] = React.useState((seed?.tags || []).join(', '));
  const [errors, setErrors] = React.useState({});

  const projectCategories = (masters.MasterProjectCategory || []).map((c) => c.value);
  const typeLabels = {
    pdf:   { title: isEdit ? 'Edit PDF' : 'Add PDF',           urlHint: 'Paste a Google Drive, Dropbox, or direct PDF link',            accept: '.pdf,application/pdf' },
    video: { title: isEdit ? 'Edit Video' : 'Add Video',       urlHint: 'Paste a YouTube, Vimeo, or direct video link',                 accept: 'video/*' },
    image: { title: isEdit ? 'Edit Image' : 'Add Image',       urlHint: 'Paste an image URL (Unsplash, Drive direct link, etc)',        accept: 'image/*' },
    ppt:   { title: isEdit ? 'Edit PPT Pitch' : (isNewVersion ? 'Add new version' : 'Add PPT Pitch'), urlHint: 'Paste a Drive link to your PDF export, or a YouTube/Loom walkthrough link', accept: '.pdf,.ppt,.pptx,.key,application/pdf' },
  };
  const T = typeLabels[assetType] || typeLabels.pdf;

  const handleFile = (e) => {
    const f = e.target.files && e.target.files[0];
    if (!f) return;
    setFileName(f.name);
    setFileSize(f.size);
    setFileType(f.type);
    /* For images, try to embed a thumbnail as data URL — but cap at 500KB to
       protect window.storage's 5MB total limit. */
    if (assetType === 'image' && f.size < 500 * 1024) {
      const reader = new FileReader();
      reader.onload = (ev) => setThumbnailUrl(ev.target?.result || '');
      reader.readAsDataURL(f);
    }
  };

  const submit = () => {
    const errs = {};
    if (!name.trim()) errs.name = 'Required';
    if (source === 'url' && !url.trim()) errs.url = 'Paste a link or switch to Upload';
    if (source === 'upload' && !fileName) errs.upload = 'Pick a file';
    if (Object.keys(errs).length > 0) { setErrors(errs); return; }

    const tags = tagsStr.split(',').map((t) => t.trim()).filter(Boolean);
    const nowIso = new Date().toISOString();

    if (isEdit) {
      setMasters((m) => ({
        ...m,
        MasterEngagementAssets: (m.MasterEngagementAssets || []).map((a) =>
          a.id === existingAsset.id
            ? { ...a, name: name.trim(), description: description.trim(), source, url: url.trim(), thumbnailUrl: thumbnailUrl.trim(), fileName, fileSize, fileType, projectCategory, tags, updatedOn: nowIso }
            : a
        ),
      }));
    } else {
      const nextId = ((masters.MasterEngagementAssets || []).reduce((mx, a) => Math.max(mx, a.id || 0), 10000)) + 1;
      const newAsset = {
        id: nextId,
        type: assetType,
        name: name.trim(),
        description: description.trim(),
        source,
        url: url.trim(),
        fileName,
        fileSize,
        fileType,
        thumbnailUrl: thumbnailUrl.trim(),
        projectCategory,
        tags,
        sendCount: 0,
        createdOn: nowIso,
        updatedOn: nowIso,
      };
      /* Phase 9.8 — PPT versioning: link new version to its root */
      if (isNewVersion && newVersionOf) {
        newAsset.parentId = newVersionOf.parentId || newVersionOf.id;
      }
      setMasters((m) => ({
        ...m,
        MasterEngagementAssets: [...(m.MasterEngagementAssets || []), newAsset],
      }));
    }
    onClose();
  };

  const handleDelete = () => {
    if (!isEdit) return;
    if (!window.confirm(`Delete "${existingAsset.name}"? This cannot be undone.`)) return;
    setMasters((m) => ({
      ...m,
      MasterEngagementAssets: (m.MasterEngagementAssets || []).filter((a) => a.id !== existingAsset.id),
    }));
    onClose();
  };

  return (
    <div className="fixed inset-0 bg-ink/60 flex items-center justify-center z-50 p-4" onClick={onClose}>
      <div className="bg-paper rounded-lg border border-line shadow-xl w-full max-w-lg p-5 max-h-[90vh] overflow-y-auto scrollbar-thin" onClick={(e) => e.stopPropagation()}>
        <div className="flex items-center justify-between mb-4">
          <div>
            <div className="text-[10px] font-mono uppercase tracking-widest ink-faint mb-0.5">{assetType.toUpperCase()}</div>
            <h3 className="font-display text-lg ink">{T.title}</h3>
          </div>
          <button onClick={onClose} className="ink-soft hover:ink"><X className="w-4 h-4" /></button>
        </div>

        {/* Name */}
        <div className="mb-3">
          <label className="block text-[10px] font-mono uppercase tracking-wider ink-faint mb-1">Name <span className="text-terra">*</span></label>
          <input
            type="text"
            value={name}
            onChange={(e) => { setName(e.target.value); if (errors.name) setErrors({ ...errors, name: '' }); }}
            placeholder="e.g. Studio Portfolio 2026"
            autoFocus
            className={`w-full text-sm ink bg-paper border rounded px-3 py-2 outline-none focus:border-terra ${errors.name ? 'border-terra' : 'border-line'}`}
          />
          {errors.name && <div className="text-[10px] text-terra mt-0.5">{errors.name}</div>}
        </div>

        {/* Description */}
        <div className="mb-3">
          <label className="block text-[10px] font-mono uppercase tracking-wider ink-faint mb-1">Description</label>
          <textarea
            value={description}
            onChange={(e) => setDescription(e.target.value)}
            rows={2}
            placeholder="Optional — when do you typically send this?"
            className="w-full text-sm ink bg-paper border border-line rounded px-3 py-2 outline-none focus:border-terra resize-none"
          />
        </div>

        {/* Source toggle */}
        <div className="mb-3">
          <label className="block text-[10px] font-mono uppercase tracking-wider ink-faint mb-1">Source</label>
          <div className="inline-flex items-center gap-0.5 bg-bone/60 border border-line-soft rounded p-0.5">
            <button
              onClick={() => setSource('url')}
              className={`text-[11px] font-medium px-2.5 py-1 rounded transition-colors flex items-center gap-1 ${source === 'url' ? 'bg-ink text-white' : 'ink-soft hover:ink'}`}
            >
              <LinkIcon className="w-3 h-3" /> URL link
            </button>
            <button
              onClick={() => setSource('upload')}
              className={`text-[11px] font-medium px-2.5 py-1 rounded transition-colors flex items-center gap-1 ${source === 'upload' ? 'bg-ink text-white' : 'ink-soft hover:ink'}`}
            >
              <Upload className="w-3 h-3" /> Upload file
            </button>
          </div>
        </div>

        {/* URL field */}
        {source === 'url' && (
          <div className="mb-3">
            <label className="block text-[10px] font-mono uppercase tracking-wider ink-faint mb-1">URL <span className="text-terra">*</span></label>
            <input
              type="url"
              value={url}
              onChange={(e) => { setUrl(e.target.value); if (errors.url) setErrors({ ...errors, url: '' }); }}
              placeholder={T.urlHint}
              className={`w-full text-sm ink bg-paper border rounded px-3 py-2 outline-none focus:border-terra ${errors.url ? 'border-terra' : 'border-line'}`}
            />
            {errors.url && <div className="text-[10px] text-terra mt-0.5">{errors.url}</div>}
            <div className="text-[10px] ink-faint mt-0.5">For Drive files, make sure the share setting allows "Anyone with link".</div>
          </div>
        )}

        {/* Upload field — mock */}
        {source === 'upload' && (
          <div className="mb-3">
            <label className="block text-[10px] font-mono uppercase tracking-wider ink-faint mb-1">File <span className="text-terra">*</span></label>
            <input
              type="file"
              accept={T.accept}
              onChange={handleFile}
              className="block w-full text-[11px] ink-soft file:mr-3 file:py-2 file:px-3 file:rounded file:border-0 file:text-[11px] file:font-semibold file:bg-bone file:ink hover:file:bg-line cursor-pointer"
            />
            {fileName && (
              <div className="text-[10px] ink-soft mt-1 font-mono">
                {fileName} · {((fileSize || 0) / 1024 / 1024).toFixed(2)} MB
              </div>
            )}
            <div className="bg-terra-soft border rounded p-2 mt-2 flex items-start gap-2" style={{ background: '#FFE5D9', borderColor: '#B85C1F' }}>
              <AlertCircle className="w-3.5 h-3.5 shrink-0 mt-0.5" style={{ color: '#B85C1F' }} />
              <div className="text-[10px] ink leading-relaxed">
                <strong>Mock upload (V1).</strong> The file itself isn't stored — only its name and size. When you send this asset, you'll need to attach the actual file manually in WhatsApp / Email. For a fully shareable link, use the URL option instead and host the file on Google Drive or Dropbox.
              </div>
            </div>
            {errors.upload && <div className="text-[10px] text-terra mt-0.5">{errors.upload}</div>}
          </div>
        )}

        {/* Thumbnail URL — optional, only for non-image types or when wanting custom cover */}
        {assetType !== 'image' && (
          <div className="mb-3">
            <label className="block text-[10px] font-mono uppercase tracking-wider ink-faint mb-1">Thumbnail URL (optional)</label>
            <input
              type="url"
              value={thumbnailUrl}
              onChange={(e) => setThumbnailUrl(e.target.value)}
              placeholder="Cover image URL — helps when sharing"
              className="w-full text-sm ink bg-paper border border-line rounded px-3 py-2 outline-none focus:border-terra"
            />
          </div>
        )}

        {/* Category */}
        <div className="grid grid-cols-2 gap-3 mb-3">
          <div>
            <label className="block text-[10px] font-mono uppercase tracking-wider ink-faint mb-1">Project Category</label>
            <select
              value={projectCategory}
              onChange={(e) => setProjectCategory(e.target.value)}
              className="w-full text-sm ink bg-paper border border-line rounded px-2 py-2 outline-none focus:border-terra"
            >
              <option value="">— Any —</option>
              {projectCategories.map((c) => <option key={c} value={c}>{c}</option>)}
            </select>
          </div>
          <div>
            <label className="block text-[10px] font-mono uppercase tracking-wider ink-faint mb-1">Tags</label>
            <input
              type="text"
              value={tagsStr}
              onChange={(e) => setTagsStr(e.target.value)}
              placeholder="comma, separated, tags"
              className="w-full text-sm ink bg-paper border border-line rounded px-2 py-2 outline-none focus:border-terra"
            />
          </div>
        </div>

        {/* Footer */}
        <div className="flex items-center gap-2 mt-4">
          {isEdit && (
            <button onClick={handleDelete} className="text-[12px] font-medium text-terra hover:opacity-80 px-2 py-2 rounded mr-auto">Delete</button>
          )}
          <button onClick={onClose} className={`text-[12px] font-medium ink-soft hover:ink px-3 py-2 rounded ${isEdit ? '' : 'ml-auto'}`}>Cancel</button>
          <button onClick={submit} className="text-[12px] font-medium px-4 py-2 rounded bg-terra text-white hover:opacity-90 flex items-center gap-1.5">
            <Check className="w-3.5 h-3.5" /> {isEdit ? 'Save' : 'Add'}
          </button>
        </div>
      </div>
    </div>
  );
}

/* === Phase 9.5.3 — Send Asset Modal =======================================
   Pick a lead (or type a phone/email manually) + channel + message → send.
   Records the send in MasterEngagementSends and bumps asset.sendCount.
   ============================================================================ */
function SendEngagementAssetModal({ asset, masters, setMasters, currentProfile, onClose }) {
  const [pickedLeadId, setPickedLeadId] = React.useState(null);
  const [manualPhone, setManualPhone] = React.useState('');
  const [manualEmail, setManualEmail] = React.useState('');
  const [manualName, setManualName] = React.useState('');
  const [channel, setChannel] = React.useState('whatsapp'); /* 'whatsapp' | 'email' | 'copy' */
  const [message, setMessage] = React.useState('');
  const [leadSearch, setLeadSearch] = React.useState('');

  const leads = (masters.MasterLeads || []);
  const studioSettings = (masters.MasterStudioSettings && masters.MasterStudioSettings[0]) || {};
  const studioName = studioSettings.studioName || 'Our Studio';

  /* Filtered leads for the picker — exclude terminal Lost/Not Fit */
  const eligibleLeads = leads.filter((l) => {
    const status = (masters.MasterLeadStatuses || []).find((s) => s.status === l.status);
    if (status?.isTerminal && !status?.isWin) return false;
    if (leadSearch.trim()) {
      const q = leadSearch.toLowerCase();
      return (l.name || '').toLowerCase().includes(q)
        || (l.mobile || '').toLowerCase().includes(q)
        || (l.email || '').toLowerCase().includes(q);
    }
    return true;
  }).slice(0, 20);

  const pickedLead = pickedLeadId ? leads.find((l) => l.id === pickedLeadId) : null;
  const isManual = pickedLeadId === '__manual__';
  const recipientName = pickedLead ? pickedLead.name : (isManual ? manualName : '');
  const recipientPhone = pickedLead ? pickedLead.mobile : (isManual ? manualPhone : '');
  const recipientEmail = pickedLead ? pickedLead.email : (isManual ? manualEmail : '');

  /* Default message when lead is picked */
  React.useEffect(() => {
    if (!recipientName) return;
    if (message.trim()) return; /* don't overwrite if user already typed */
    const first = (recipientName || '').split(' ')[0] || '';
    const greeting = first ? `Hi ${first}, ` : 'Hi, ';
    const url = asset.source === 'url' && asset.url ? asset.url : '';
    const filePart = asset.source === 'upload'
      ? `\n\n(Attaching ${asset.fileName || asset.name} separately.)`
      : '';
    let body;
    if (asset.type === 'pdf') {
      body = `${greeting}sharing our ${asset.name} for your reference. ${url ? `\n\n${url}` : ''}${filePart}\n\nDo go through it whenever you have a few minutes — happy to walk you through after you've looked.`;
    } else if (asset.type === 'video') {
      body = `${greeting}thought this might be useful — a quick video from us: ${asset.name}. ${url ? `\n\n${url}` : ''}${filePart}`;
    } else if (asset.type === 'ppt') {
      body = `${greeting}sharing our concept pitch for your project: ${asset.name}. ${url ? `\n\n${url}` : ''}${filePart}\n\nWould love your reactions — what you love, what feels off, and what to push further.`;
    } else {
      body = `${greeting}sharing a visual reference: ${asset.name}. ${url ? `\n\n${url}` : ''}${filePart}`;
    }
    body += `\n\n— ${studioName}`;
    setMessage(body);
  }, [recipientName, asset.id]); // eslint-disable-line react-hooks/exhaustive-deps

  const canSend = recipientName && message.trim() && (
    channel === 'copy' ? true
    : channel === 'whatsapp' ? !!recipientPhone
    : channel === 'email' ? !!recipientEmail
    : false
  );

  const recordSend = () => {
    const nextId = ((masters.MasterEngagementSends || []).reduce((mx, s) => Math.max(mx, s.id || 0), 20000)) + 1;
    const newSend = {
      id: nextId,
      assetId: asset.id,
      assetName: asset.name,
      assetType: asset.type,
      leadId: pickedLead ? pickedLead.id : null,
      leadName: recipientName,
      channel,
      sentAt: new Date().toISOString(),
      sentBy: currentProfile?.user?.name || 'Studio Team',
      recipientPhone: recipientPhone || '',
      recipientEmail: recipientEmail || '',
      message: message.trim().slice(0, 500),
    };
    setMasters((m) => ({
      ...m,
      MasterEngagementSends: [...(m.MasterEngagementSends || []), newSend],
      MasterEngagementAssets: (m.MasterEngagementAssets || []).map((a) =>
        a.id === asset.id ? { ...a, sendCount: (a.sendCount || 0) + 1, updatedOn: new Date().toISOString() } : a
      ),
    }));
  };

  const handleWhatsApp = async () => {
    recordSend();
    try {
      await sendWhatsAppViaBackend(recipientPhone, message);
      alert(`Sent on WhatsApp to ${recipientName}.`);
    } catch (error) {
      const wa = buildWhatsAppUrl(recipientPhone, message);
      if (wa) window.open(wa, '_blank');
      alert(`WhatsApp backend could not send directly: ${error.message}. I opened WhatsApp with the message ready to send.`);
    }
    onClose();
  };
  const handleEmail = () => {
    recordSend();
    const subject = encodeURIComponent(`From ${studioName} — ${asset.name}`);
    const body = encodeURIComponent(message);
    window.location.href = `mailto:${recipientEmail}?subject=${subject}&body=${body}`;
    onClose();
  };
  const handleCopy = async () => {
    recordSend();
    try {
      await navigator.clipboard.writeText(message);
    } catch (_) {
      const ta = document.createElement('textarea');
      ta.value = message;
      document.body.appendChild(ta);
      ta.select();
      try { document.execCommand('copy'); } catch (__) {}
      document.body.removeChild(ta);
    }
    onClose();
  };

  return (
    <div className="fixed inset-0 bg-ink/60 flex items-center justify-center z-50 p-4" onClick={onClose}>
      <div className="bg-paper rounded-lg border border-line shadow-xl w-full max-w-xl p-5 max-h-[90vh] overflow-y-auto scrollbar-thin" onClick={(e) => e.stopPropagation()}>
        <div className="flex items-start gap-3 mb-4">
          <div className="shrink-0 w-9 h-9 rounded-full flex items-center justify-center" style={{ background: '#FFE5D9', color: '#B85C1F' }}>
            <Send className="w-4 h-4" />
          </div>
          <div className="min-w-0 flex-1">
            <div className="text-[10px] font-mono uppercase tracking-widest ink-faint mb-0.5">Send {asset.type}</div>
            <h3 className="font-display text-lg ink leading-tight">{asset.name}</h3>
          </div>
          <button onClick={onClose} className="ink-soft hover:ink"><X className="w-4 h-4" /></button>
        </div>

        {/* Recipient picker */}
        <div className="mb-3">
          <label className="block text-[10px] font-mono uppercase tracking-wider ink-faint mb-1">Recipient</label>
          {!pickedLeadId && !isManual && (
            <div>
              <input
                type="text"
                value={leadSearch}
                onChange={(e) => setLeadSearch(e.target.value)}
                placeholder="Search leads by name, mobile, or email…"
                className="w-full text-sm ink bg-paper border border-line rounded px-3 py-2 outline-none focus:border-terra mb-2"
              />
              <div className="max-h-44 overflow-y-auto scrollbar-thin border border-line rounded">
                {eligibleLeads.length === 0 ? (
                  <div className="p-3 text-[11px] ink-faint">No matches — try manual entry.</div>
                ) : (
                  eligibleLeads.map((l) => (
                    <button
                      key={l.id}
                      onClick={() => setPickedLeadId(l.id)}
                      className="w-full text-left px-3 py-2 hover:bg-bone border-b border-line-soft last:border-b-0"
                    >
                      <div className="text-[12px] ink font-medium">{l.name}</div>
                      <div className="text-[10px] ink-soft font-mono">{l.mobile || '— no mobile —'} {l.email && `· ${l.email}`}</div>
                    </button>
                  ))
                )}
              </div>
              <button
                onClick={() => setPickedLeadId('__manual__')}
                className="text-[11px] font-medium ink-soft hover:ink mt-2 flex items-center gap-1"
              >
                <Plus className="w-3 h-3" /> Or enter contact manually
              </button>
            </div>
          )}
          {pickedLead && (
            <div className="bg-bone/40 border border-line rounded p-2.5 flex items-start gap-2">
              <div className="flex-1 min-w-0">
                <div className="text-[12px] ink font-medium">{pickedLead.name}</div>
                <div className="text-[10px] ink-soft font-mono">{pickedLead.mobile || '—'} {pickedLead.email && `· ${pickedLead.email}`}</div>
              </div>
              <button onClick={() => setPickedLeadId(null)} className="text-[10px] ink-soft hover:ink">Change</button>
            </div>
          )}
          {isManual && (
            <div className="space-y-2">
              <div className="flex items-center gap-2">
                <input type="text" value={manualName} onChange={(e) => setManualName(e.target.value)} placeholder="Recipient name" className="flex-1 text-sm ink bg-paper border border-line rounded px-3 py-1.5 outline-none focus:border-terra" />
                <button onClick={() => { setPickedLeadId(null); setManualName(''); setManualPhone(''); setManualEmail(''); }} className="text-[10px] ink-soft hover:ink">Back</button>
              </div>
              <input type="tel" value={manualPhone} onChange={(e) => setManualPhone(e.target.value)} placeholder="Mobile (for WhatsApp)" className="w-full text-sm ink bg-paper border border-line rounded px-3 py-1.5 outline-none focus:border-terra" />
              <input type="email" value={manualEmail} onChange={(e) => setManualEmail(e.target.value)} placeholder="Email (for Email channel)" className="w-full text-sm ink bg-paper border border-line rounded px-3 py-1.5 outline-none focus:border-terra" />
            </div>
          )}
        </div>

        {/* Channel picker */}
        <div className="mb-3">
          <label className="block text-[10px] font-mono uppercase tracking-wider ink-faint mb-1">Channel</label>
          <div className="inline-flex items-center gap-0.5 bg-bone/60 border border-line-soft rounded p-0.5">
            <button onClick={() => setChannel('whatsapp')} className={`text-[11px] font-medium px-2.5 py-1.5 rounded transition-colors flex items-center gap-1 ${channel === 'whatsapp' ? 'bg-ink text-white' : 'ink-soft hover:ink'}`}>
              <Send className="w-3 h-3" /> WhatsApp
            </button>
            <button onClick={() => setChannel('email')} className={`text-[11px] font-medium px-2.5 py-1.5 rounded transition-colors flex items-center gap-1 ${channel === 'email' ? 'bg-ink text-white' : 'ink-soft hover:ink'}`}>
              <FileText className="w-3 h-3" /> Email
            </button>
            <button onClick={() => setChannel('copy')} className={`text-[11px] font-medium px-2.5 py-1.5 rounded transition-colors flex items-center gap-1 ${channel === 'copy' ? 'bg-ink text-white' : 'ink-soft hover:ink'}`}>
              <Copy className="w-3 h-3" /> Copy
            </button>
          </div>
          {channel === 'whatsapp' && recipientName && !recipientPhone && (
            <div className="text-[10px] text-terra mt-1">No mobile number on this recipient — switch channel or add a number.</div>
          )}
          {channel === 'email' && recipientName && !recipientEmail && (
            <div className="text-[10px] text-terra mt-1">No email on this recipient — switch channel or add an email.</div>
          )}
        </div>

        {/* Message preview */}
        <div className="mb-3">
          <label className="block text-[10px] font-mono uppercase tracking-wider ink-faint mb-1">Message</label>
          <textarea
            value={message}
            onChange={(e) => setMessage(e.target.value)}
            rows={6}
            placeholder="Will auto-fill when you pick a recipient…"
            className="w-full text-sm ink bg-paper border border-line rounded px-3 py-2 outline-none focus:border-terra resize-y font-mono"
            style={{ fontSize: '12px', lineHeight: '1.5' }}
          />
          <div className="text-[10px] ink-faint mt-0.5">{message.length} characters</div>
        </div>

        {asset.source === 'upload' && (
          <div className="bg-bone/40 border border-line-soft rounded p-2.5 mb-3 flex items-start gap-2">
            <AlertCircle className="w-3.5 h-3.5 shrink-0 mt-0.5 ink-soft" />
            <div className="text-[10px] ink leading-relaxed">
              This asset was uploaded (no URL). The message above mentions the file by name — you'll need to attach <span className="font-mono">{asset.fileName || asset.name}</span> manually in your WhatsApp or Email after this opens.
            </div>
          </div>
        )}

        {/* Action */}
        <div className="flex items-center gap-2 mt-4">
          <button onClick={onClose} className="text-[12px] font-medium ink-soft hover:ink px-3 py-2 rounded mr-auto">Cancel</button>
          {channel === 'whatsapp' && (
            <button onClick={handleWhatsApp} disabled={!canSend} className={`text-[12px] font-semibold text-white px-4 py-2 rounded flex items-center gap-1.5 ${canSend ? 'bg-ink hover:bg-terra' : 'bg-line ink-faint cursor-not-allowed'}`}>
              <Send className="w-3.5 h-3.5" /> Open WhatsApp
            </button>
          )}
          {channel === 'email' && (
            <button onClick={handleEmail} disabled={!canSend} className={`text-[12px] font-semibold text-white px-4 py-2 rounded flex items-center gap-1.5 ${canSend ? 'bg-ink hover:bg-terra' : 'bg-line ink-faint cursor-not-allowed'}`}>
              <FileText className="w-3.5 h-3.5" /> Open Email
            </button>
          )}
          {channel === 'copy' && (
            <button onClick={handleCopy} disabled={!canSend} className={`text-[12px] font-semibold text-white px-4 py-2 rounded flex items-center gap-1.5 ${canSend ? 'bg-ink hover:bg-terra' : 'bg-line ink-faint cursor-not-allowed'}`}>
              <Copy className="w-3.5 h-3.5" /> Copy &amp; Log
            </button>
          )}
        </div>
      </div>
    </div>
  );
}

/* === Phase 9.5.4 — Sends Log Panel =========================================
   Timeline view of every send across all asset types. Filterable by asset
   type, channel, and date range.
   ============================================================================ */
function EngagementSendsLogPanel({ masters, setMasters }) {
  const [filterType, setFilterType] = React.useState('all');
  const [filterChannel, setFilterChannel] = React.useState('all');
  const [search, setSearch] = React.useState('');

  const sends = ((masters.MasterEngagementSends) || []).slice().sort((a, b) => {
    const da = new Date(a.sentAt).getTime();
    const db = new Date(b.sentAt).getTime();
    return db - da;
  });

  const filtered = sends.filter((s) => {
    if (filterType !== 'all' && s.assetType !== filterType) return false;
    if (filterChannel !== 'all' && s.channel !== filterChannel) return false;
    if (search.trim()) {
      const q = search.toLowerCase();
      return (s.assetName || '').toLowerCase().includes(q)
        || (s.leadName || '').toLowerCase().includes(q)
        || (s.sentBy || '').toLowerCase().includes(q);
    }
    return true;
  });

  /* Group by date for visual sectioning */
  const grouped = {};
  filtered.forEach((s) => {
    const d = new Date(s.sentAt);
    const key = d.toLocaleDateString();
    if (!grouped[key]) grouped[key] = [];
    grouped[key].push(s);
  });
  const orderedKeys = Object.keys(grouped);

  const channelIcons = {
    whatsapp: Send,
    email: FileText,
    copy: Copy,
  };
  const typeIcons = {
    pdf: FileText,
    video: Video,
    image: ImageIcon,
    ppt: Presentation,
  };

  return (
    <div>
      {/* Section header */}
      <div className="flex items-center justify-between flex-wrap gap-3 mb-4">
        <div>
          <h2 className="font-display text-xl ink tracking-tight">Sends Log</h2>
          <p className="text-[12px] ink-soft mt-0.5">
            Every asset send across all types, in reverse chronological order.
          </p>
        </div>
        <div className="text-[11px] ink-faint">
          {filtered.length} of {sends.length} sends
        </div>
      </div>

      {/* Filter bar */}
      <div className="bg-paper border border-line rounded-lg p-3 mb-4 flex items-center gap-3 flex-wrap">
        <div className="flex items-center gap-1.5">
          <Filter className="w-3.5 h-3.5 ink-faint" />
          <span className="text-[10px] font-mono uppercase tracking-wider ink-faint">Type</span>
          <select value={filterType} onChange={(e) => setFilterType(e.target.value)} className="text-[12px] ink bg-paper border border-line rounded px-2 py-1 outline-none focus:border-terra">
            <option value="all">All</option>
            <option value="pdf">PDFs</option>
            <option value="video">Videos</option>
            <option value="image">Images</option>
            <option value="ppt">PPT Pitches</option>
          </select>
        </div>
        <div className="flex items-center gap-1.5">
          <span className="text-[10px] font-mono uppercase tracking-wider ink-faint">Channel</span>
          <select value={filterChannel} onChange={(e) => setFilterChannel(e.target.value)} className="text-[12px] ink bg-paper border border-line rounded px-2 py-1 outline-none focus:border-terra">
            <option value="all">All</option>
            <option value="whatsapp">WhatsApp</option>
            <option value="email">Email</option>
            <option value="copy">Copy</option>
          </select>
        </div>
        <div className="flex-1 min-w-[200px] flex items-center gap-1.5">
          <Search className="w-3.5 h-3.5 ink-faint" />
          <input
            type="text"
            value={search}
            onChange={(e) => setSearch(e.target.value)}
            placeholder="Search asset, recipient, or sender…"
            className="flex-1 text-[12px] ink bg-paper border border-line rounded px-2 py-1 outline-none focus:border-terra"
          />
        </div>
      </div>

      {/* Timeline */}
      {filtered.length === 0 ? (
        <div className="bg-paper border border-line border-dashed rounded-lg p-10 text-center">
          <p className="text-sm ink-soft">No sends yet. Share an asset to log it here.</p>
        </div>
      ) : (
        <div className="space-y-5">
          {orderedKeys.map((dateKey) => (
            <div key={dateKey}>
              <div className="text-[10px] font-mono uppercase tracking-widest ink-faint mb-2">{dateKey}</div>
              <div className="space-y-2">
                {grouped[dateKey].map((s) => {
                  const TypeIcon = typeIcons[s.assetType] || FileText;
                  const ChannelIcon = channelIcons[s.channel] || Send;
                  const t = new Date(s.sentAt);
                  const timeStr = t.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
                  return (
                    <div key={s.id} className="bg-paper border border-line rounded-lg p-3 flex items-start gap-3">
                      <div className="shrink-0 w-8 h-8 rounded bg-bone/60 flex items-center justify-center">
                        <TypeIcon className="w-3.5 h-3.5 ink-soft" />
                      </div>
                      <div className="flex-1 min-w-0">
                        <div className="text-[12px] ink font-medium leading-tight truncate">{s.assetName}</div>
                        <div className="text-[11px] ink-soft mt-0.5">
                          to <span className="ink">{s.leadName}</span>
                          {s.recipientPhone && <span className="font-mono"> · {s.recipientPhone}</span>}
                          {s.recipientEmail && <span> · {s.recipientEmail}</span>}
                        </div>
                        <div className="text-[10px] ink-faint mt-1 flex items-center gap-2 flex-wrap">
                          <span className="font-mono">{timeStr}</span>
                          <span>· by {s.sentBy}</span>
                          <span className="inline-flex items-center gap-1 px-1.5 py-0.5 rounded bg-bone/60">
                            <ChannelIcon className="w-2.5 h-2.5" />
                            <span className="uppercase tracking-wider">{s.channel}</span>
                          </span>
                        </div>
                      </div>
                    </div>
                  );
                })}
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
}

/* ================================================================== */
/* =========== VENDOR PANEL SCREEN — Phase 5.6 ====================== */
/* =========== Phase 9.1.51 — wrapped with sub-tabs ================== */
/* ================================================================== */

function VendorPanelScreen({ masters, setMasters, projects, onAdd, onUpdate, onDelete, currentRoleCode, currentProfile, selectedVendorId, setSelectedVendorId, onJumpToProject }) {
  /* Phase 9.1.51 — sub-tab state. Default: 'vendors' (the original directory).
     Other tabs: 'labour' / 'material' / 'equipment' showing catalog tables. */
  const [vendorTab, setVendorTab] = React.useState('vendors');

  const vendors = masters.MasterVendors || [];
  const canEdit = currentProfile?.permissions?.canEditMasters || currentRoleCode === 'studio_owner' || currentRoleCode === 'pm_admin' || currentRoleCode === 'admin' || currentRoleCode === 'super_admin';
  const selectedVendor = selectedVendorId ? vendors.find((v) => v.id === selectedVendorId) : null;

  const projectsByVendor = aggregateProjectsByVendor(projects, masters);

  if (selectedVendor) {
    const aggregated = projectsByVendor.get(selectedVendor.id);
    return (
      <VendorDetailScreen
        vendor={selectedVendor}
        vendors={vendors}
        vendorProjects={(aggregated && aggregated.projects) || []}
        canEdit={canEdit}
        onUpdate={(updates) => onUpdate('MasterVendors', selectedVendor.id, updates)}
        onDelete={() => {
          const projectCount = (aggregated && aggregated.projects.length) || 0;
          if (projectCount > 0) {
            alert(`Cannot delete ${selectedVendor.value} — they're linked to ${projectCount} project${projectCount === 1 ? '' : 's'}. Remove from those projects first.`);
            return;
          }
          if (window.confirm(`Permanently remove ${selectedVendor.value} from the vendor master? This cannot be undone.`)) {
            onDelete('MasterVendors', selectedVendor.id);
            setSelectedVendorId(null);
          }
        }}
        onBack={() => setSelectedVendorId(null)}
        onJumpToProject={onJumpToProject}
      />
    );
  }

  /* Phase 9.1.51 — Sub-tab bar shared across all four views (Vendors / Labour / Material / Equipment) */
  const tabs = [
    { code: 'vendors',   label: 'Vendors',    icon: Briefcase },
    { code: 'labour',    label: 'Labour',     icon: Hammer },
    { code: 'material',  label: 'Material',   icon: Layers },
    { code: 'equipment', label: 'Equipment',  icon: Truck },
  ];
  const VendorSubTabBar = () => (
    <div className="border-b border-line bg-paper sticky top-0 z-10">
      <div className="px-6 flex items-center gap-1">
        {tabs.map((t) => {
          const Icon = t.icon;
          const isActive = vendorTab === t.code;
          return (
            <button
              key={t.code}
              onClick={() => setVendorTab(t.code)}
              className={`px-4 py-3 text-[12px] font-medium border-b-2 transition-colors flex items-center gap-1.5 ${
                isActive ? 'ink border-ink' : 'ink-soft hover:ink border-transparent'
              }`}
            >
              <Icon className="w-3.5 h-3.5" strokeWidth={isActive ? 2 : 1.7} />
              {t.label}
            </button>
          );
        })}
      </div>
    </div>
  );

  if (vendorTab === 'labour') {
    return (
      <div className="flex-1 overflow-auto scrollbar-thin">
        <VendorSubTabBar />
        <div className="p-6">
          <div className="mb-4">
            <div className="text-[10px] font-mono ink-faint uppercase tracking-widest mb-1.5">Vendors · Labour</div>
            <h2 className="font-display text-2xl ink tracking-tight leading-none mb-1">Labour Catalog</h2>
            <div className="text-sm ink-soft max-w-2xl">
              Trades and roles you can call on across projects. Inline-edit short fields; click any row for full details.
            </div>
          </div>
          <VendorCatalogTable
            tableName="MasterLabour"
            masters={masters}
            setMasters={setMasters}
            noun="Labour"
            defaultEmpty={{ columns: [], rows: [] }}
          />
        </div>
      </div>
    );
  }
  if (vendorTab === 'material') {
    return (
      <div className="flex-1 overflow-auto scrollbar-thin">
        <VendorSubTabBar />
        <div className="p-6">
          <div className="mb-4">
            <div className="text-[10px] font-mono ink-faint uppercase tracking-widest mb-1.5">Vendors · Material</div>
            <h2 className="font-display text-2xl ink tracking-tight leading-none mb-1">Material Catalog</h2>
            <div className="text-sm ink-soft max-w-2xl">
              Surfaces, fabrics, woods, stones, finishes — the library you spec from. Add columns to track what matters for your studio.
            </div>
          </div>
          <VendorCatalogTable
            tableName="MasterMaterials"
            masters={masters}
            setMasters={setMasters}
            noun="Material"
            defaultEmpty={{ columns: [], rows: [] }}
          />
        </div>
      </div>
    );
  }
  if (vendorTab === 'equipment') {
    return (
      <div className="flex-1 overflow-auto scrollbar-thin">
        <VendorSubTabBar />
        <div className="p-6">
          <div className="mb-4">
            <div className="text-[10px] font-mono ink-faint uppercase tracking-widest mb-1.5">Vendors · Equipment</div>
            <h2 className="font-display text-2xl ink tracking-tight leading-none mb-1">Equipment Catalog</h2>
            <div className="text-sm ink-soft max-w-2xl">
              Site tools, rental gear, and machinery. Track availability and rental rates here.
            </div>
          </div>
          <VendorCatalogTable
            tableName="MasterEquipment"
            masters={masters}
            setMasters={setMasters}
            noun="Equipment"
            defaultEmpty={{ columns: [], rows: [] }}
          />
        </div>
      </div>
    );
  }

  /* Default: original Vendors directory, now wrapped in a sub-tab shell */
  return (
    <div className="flex-1 overflow-auto scrollbar-thin">
      <VendorSubTabBar />
      <VendorPanelDirectory
        vendors={vendors}
        projectsByVendor={projectsByVendor}
        canEdit={canEdit}
        onSelect={setSelectedVendorId}
        onAddVendor={() => {
          const newId = Date.now();
          const newRow = {
            id: newId,
            value: 'New Vendor',
            initials: 'NV',
            accent: '#1A1815',
            vendorType: 'Contractor',
            primaryContact: '',
            primaryEmail: '',
            gstin: '',
            tradesProvided: [],
            notes: '',
            createdOn: new Date().toISOString().slice(0, 10),
          };
          onAdd('MasterVendors', newRow);
          setSelectedVendorId(newId);
        }}
      />
    </div>
  );
}

function VendorPanelDirectory({ vendors, projectsByVendor, canEdit, onSelect, onAddVendor }) {
  const [search, setSearch] = useState('');
  const [filterType, setFilterType] = useState('all');
  const filtered = vendors.filter((v) => {
    if (filterType !== 'all' && v.vendorType !== filterType) return false;
    const q = search.trim().toLowerCase();
    if (!q) return true;
    return v.value.toLowerCase().includes(q)
      || (v.primaryContact || '').toLowerCase().includes(q)
      || (v.primaryEmail || '').toLowerCase().includes(q)
      || (v.tradesProvided || []).some((t) => t.toLowerCase().includes(q));
  });

  return (
    <div className="flex-1 overflow-auto scrollbar-thin">
      <PageHeader
        icon={Briefcase}
        sublabel="VendorPanelScreen · MasterVendors"
        title="Vendors"
        description={`${vendors.length} vendor${vendors.length === 1 ? '' : 's'} in the directory. Each project links to vendors by ID — edit a vendor here, the change propagates everywhere.`}
        rightSlot={(
          <div className="flex items-center gap-2">
            <select
              value={filterType}
              onChange={(e) => setFilterType(e.target.value)}
              className="input-sm text-[11px]"
            >
              <option value="all">All types</option>
              <option value="Contractor">Contractor</option>
              <option value="Consultant">Consultant</option>
              <option value="Supplier">Supplier</option>
              <option value="PMC">PMC</option>
              <option value="Architect">Architect</option>
              <option value="Other">Other</option>
            </select>
            <div className="flex items-center gap-2 px-3 py-2 bg-bone rounded border border-line w-56">
              <Search className="w-3.5 h-3.5 ink-faint" />
              <input
                value={search}
                onChange={(e) => setSearch(e.target.value)}
                placeholder="Search…"
                className="bg-transparent outline-none text-sm w-full ink placeholder:ink-faint"
              />
            </div>
            {canEdit && (
              <button
                onClick={onAddVendor}
                className="flex items-center gap-1.5 text-[11px] font-mono uppercase tracking-wider px-3 py-2 bg-ink text-white rounded font-semibold hover:bg-terra"
              >
                <Plus className="w-3.5 h-3.5" /> New vendor
              </button>
            )}
          </div>
        )}
      />

      <div className="p-6" style={{ maxWidth: '1300px' }}>
        {filtered.length === 0 ? (
          <div className="bg-paper border border-line rounded-lg p-12 text-center">
            <Briefcase className="w-10 h-10 ink-faint mx-auto mb-3" strokeWidth={1.5} />
            <h3 className="font-display text-lg ink mb-1">{search || filterType !== 'all' ? 'No matches' : 'No vendors yet'}</h3>
            <p className="text-[11px] ink-soft">{search || filterType !== 'all' ? 'Try a different search or filter.' : 'Add your first vendor to get started.'}</p>
          </div>
        ) : (
          <div className="bg-paper border border-line rounded-lg overflow-hidden">
            <table className="w-full text-sm">
              <thead className="bg-bone border-b border-line">
                <tr>
                  <th className="text-left px-4 py-2.5 text-[10px] font-mono uppercase tracking-wider ink-faint">Vendor</th>
                  <th className="text-left px-4 py-2.5 text-[10px] font-mono uppercase tracking-wider ink-faint">Type</th>
                  <th className="text-left px-4 py-2.5 text-[10px] font-mono uppercase tracking-wider ink-faint">Trades</th>
                  <th className="text-left px-4 py-2.5 text-[10px] font-mono uppercase tracking-wider ink-faint">Contact</th>
                  <th className="text-left px-4 py-2.5 text-[10px] font-mono uppercase tracking-wider ink-faint">Projects</th>
                </tr>
              </thead>
              <tbody>
                {filtered.map((v) => {
                  const agg = projectsByVendor.get(v.id);
                  const projectCount = agg ? agg.projects.length : 0;
                  return (
                    <tr
                      key={v.id}
                      onClick={() => onSelect(v.id)}
                      className="border-b border-line-soft last:border-0 hover:bg-bone cursor-pointer"
                    >
                      <td className="px-4 py-3">
                        <div className="flex items-center gap-3">
                          <div
                            className="w-9 h-9 rounded flex items-center justify-center text-[11px] font-mono font-semibold text-white shrink-0"
                            style={{ background: v.accent || '#1A1815' }}
                          >
                            {v.initials || '?'}
                          </div>
                          <div className="min-w-0">
                            <div className="ink font-medium truncate">{v.value}</div>
                            {v.primaryEmail && <div className="text-[11px] font-mono ink-faint truncate">{v.primaryEmail}</div>}
                          </div>
                        </div>
                      </td>
                      <td className="px-4 py-3">
                        <span className="text-[10px] font-mono uppercase tracking-wider px-1.5 py-0.5 rounded bg-bone text-terra border border-terra">{v.vendorType}</span>
                      </td>
                      <td className="px-4 py-3 text-[11px] font-mono ink-soft">
                        {(v.tradesProvided || []).slice(0, 2).join(', ')}
                        {(v.tradesProvided || []).length > 2 && <span className="ink-faint"> +{v.tradesProvided.length - 2}</span>}
                      </td>
                      <td className="px-4 py-3 text-[12px] font-mono ink-soft">
                        {v.primaryContact || <span className="ink-faint italic">—</span>}
                      </td>
                      <td className="px-4 py-3">
                        <span className={`text-[12px] font-mono font-semibold ${projectCount > 0 ? 'ink' : 'ink-faint'}`}>
                          {projectCount}
                        </span>
                      </td>
                    </tr>
                  );
                })}
              </tbody>
            </table>
          </div>
        )}
      </div>
    </div>
  );
}

function VendorDetailScreen({ vendor, vendors, vendorProjects, canEdit, onUpdate, onDelete, onBack, onJumpToProject }) {
  const update = (updates) => onUpdate(updates);

  return (
    <div className="flex-1 overflow-auto scrollbar-thin">
      <div className="px-6 py-6" style={{ maxWidth: '1100px' }}>
        <button
          onClick={onBack}
          className="flex items-center gap-1 text-[11px] font-mono ink-soft hover:ink mb-3"
        >
          <ArrowLeft className="w-3.5 h-3.5" /> Back to Vendor Panel
        </button>

        {/* Header */}
        <div className="bg-paper border border-line rounded-lg p-5 mb-4">
          <div className="flex items-start gap-4 flex-wrap">
            <div
              className="w-16 h-16 rounded-md flex items-center justify-center text-base font-mono font-semibold text-white shrink-0"
              style={{ background: vendor.accent || '#1A1815' }}
            >
              {vendor.initials || '?'}
            </div>
            <div className="flex-1 min-w-0">
              {canEdit ? (
                <input
                  type="text"
                  value={vendor.value || ''}
                  onChange={(e) => update({ value: e.target.value })}
                  className="font-display text-2xl ink bg-transparent outline-none border-b border-transparent hover:border-line focus:border-terra leading-tight"
                  style={{ width: 'auto', minWidth: '300px' }}
                />
              ) : (
                <h2 className="font-display text-2xl ink tracking-tight leading-tight">{vendor.value}</h2>
              )}
              <div className="flex items-center gap-3 text-[11px] font-mono ink-faint mt-1 flex-wrap">
                <span className="uppercase tracking-wider">{vendor.vendorType}</span>
                <span>·</span>
                <span>ID #{vendor.id}</span>
                <span>·</span>
                <span>{vendorProjects.length} project{vendorProjects.length === 1 ? '' : 's'}</span>
              </div>
            </div>
            {canEdit && (
              <button
                onClick={onDelete}
                className="flex items-center gap-1 text-[10px] font-mono text-terra hover:ink uppercase tracking-wider px-3 py-1.5 border border-terra rounded hover:bg-terra-soft"
              >
                <Trash2 className="w-3 h-3" /> Remove
              </button>
            )}
          </div>
        </div>

        {/* Identity */}
        <SectionCard title="Identity & Type" icon={Briefcase}>
          <div className="grid grid-cols-2 gap-4">
            <FieldGroup label="Vendor Name">
              <DetailField canEdit={canEdit} value={vendor.value} onChange={(v) => update({ value: v })} placeholder="Company name" />
            </FieldGroup>
            <FieldGroup label="Type">
              {canEdit ? (
                <SelectField value={vendor.vendorType || 'Contractor'} onChange={(v) => update({ vendorType: v })} options={['Contractor', 'Consultant', 'Supplier', 'PMC', 'Architect', 'Other']} />
              ) : (
                <span className="text-sm ink">{vendor.vendorType}</span>
              )}
            </FieldGroup>
            <FieldGroup label="Initials">
              <DetailField canEdit={canEdit} value={vendor.initials} onChange={(v) => update({ initials: v })} placeholder="2 letters" />
            </FieldGroup>
            <FieldGroup label="Accent Color">
              {canEdit ? (
                <div className="flex items-center gap-2">
                  <input type="color" value={vendor.accent || '#1A1815'} onChange={(e) => update({ accent: e.target.value })} className="w-10 h-8 rounded border border-line cursor-pointer" />
                  <input type="text" value={vendor.accent || ''} onChange={(e) => update({ accent: e.target.value })} className="input-sm flex-1 text-[11px] font-mono" placeholder="#1A1815" />
                </div>
              ) : (
                <div className="flex items-center gap-2">
                  <div className="w-6 h-6 rounded border border-line" style={{ background: vendor.accent }} />
                  <span className="text-[11px] font-mono ink-soft">{vendor.accent}</span>
                </div>
              )}
            </FieldGroup>
          </div>
        </SectionCard>

        {/* Contact + GSTIN */}
        <SectionCard title="Contact & Tax" icon={ContactRound}>
          <div className="grid grid-cols-2 gap-4">
            <FieldGroup label="Phone">
              <DetailField canEdit={canEdit} value={vendor.primaryContact} onChange={(v) => update({ primaryContact: v })} placeholder="+91 …" />
            </FieldGroup>
            <FieldGroup label="Email">
              <DetailField canEdit={canEdit} value={vendor.primaryEmail} onChange={(v) => update({ primaryEmail: v })} placeholder="contact@vendor.in" />
            </FieldGroup>
            <FieldGroup label="GSTIN">
              <DetailField canEdit={canEdit} value={vendor.gstin} onChange={(v) => update({ gstin: v })} placeholder="27AABCA1234L1ZX" />
            </FieldGroup>
          </div>
        </SectionCard>

        {/* Trades */}
        <SectionCard title="Trades / Services Provided" icon={Hammer}>
          {(vendor.tradesProvided || []).length === 0 ? (
            <div className="text-[11px] ink-faint italic">No trades listed.</div>
          ) : (
            <div className="flex flex-wrap gap-1.5">
              {(vendor.tradesProvided || []).map((t, idx) => (
                <span key={idx} className="text-[10px] font-mono uppercase tracking-wider px-2 py-1 rounded ink-soft bg-bone border border-line inline-flex items-center gap-1.5">
                  {t}
                  {canEdit && (
                    <button
                      onClick={() => update({ tradesProvided: (vendor.tradesProvided || []).filter((_, i) => i !== idx) })}
                      className="opacity-50 hover:opacity-100"
                      title="Remove trade"
                    >
                      <X className="w-2.5 h-2.5" />
                    </button>
                  )}
                </span>
              ))}
            </div>
          )}
          {canEdit && (
            <button
              onClick={() => {
                const newTrade = prompt('Trade or service (e.g. "Civil", "Joinery", "Lighting Design")');
                if (newTrade && newTrade.trim()) update({ tradesProvided: [...(vendor.tradesProvided || []), newTrade.trim()] });
              }}
              className="text-[10px] font-mono text-terra hover:ink mt-2 flex items-center gap-1"
            >
              <Plus className="w-3 h-3" /> Add trade
            </button>
          )}
        </SectionCard>

        {/* Notes */}
        <SectionCard title="Master Notes" icon={MessageSquare}>
          {canEdit ? (
            <TextArea value={vendor.notes || ''} onChange={(v) => update({ notes: v })} placeholder="Reliability, payment terms, escalation contacts, anything reusable across projects…" rows={4} />
          ) : (
            <div className="text-sm ink whitespace-pre-line">{vendor.notes || <span className="ink-faint italic">No notes.</span>}</div>
          )}
        </SectionCard>

        {/* Project history with project-specific roles */}
        <SectionCard
          title="Projects Served"
          icon={Building2}
          count={vendorProjects.length}
        >
          {vendorProjects.length === 0 ? (
            <div className="text-[11px] ink-faint italic text-center py-3 bg-bone rounded">
              No projects link to this vendor yet.
            </div>
          ) : (
            <div className="space-y-1.5">
              {vendorProjects.map(({ project, projectRole, projectNotes }) => (
                <button
                  key={project.id}
                  onClick={() => onJumpToProject && onJumpToProject(project.id)}
                  className="w-full text-left p-3 bg-bone hover:bg-terra-soft border border-line-soft hover:border-terra rounded transition-colors group/p"
                >
                  <div className="flex items-start justify-between gap-3 flex-wrap">
                    <div className="flex-1 min-w-0">
                      <div className="ink font-medium text-[13px]">{project.name}</div>
                      <div className="text-[10px] font-mono ink-faint mt-0.5">
                        {project.id} · {project.currentStage || 'no stage'} · {project.progress || 0}%
                      </div>
                      {projectRole && (
                        <div className="text-[11px] text-terra mt-1"><span className="font-mono uppercase tracking-wider">role:</span> {projectRole}</div>
                      )}
                      {projectNotes && (
                        <div className="text-[10px] ink-soft mt-1 line-clamp-2">{projectNotes}</div>
                      )}
                    </div>
                    <ArrowRight className="w-3.5 h-3.5 ink-faint group-hover/p:text-terra shrink-0 mt-1" />
                  </div>
                </button>
              ))}
            </div>
          )}
        </SectionCard>

        <div className="text-center text-[10px] font-mono ink-faint pt-4 pb-8">
          Edits to this master record propagate to every project linked to {vendor.value}.
        </div>
      </div>
    </div>
  );
}

/* ================================================================== */
/* =========== APPROVALS PANEL — top-level cross-project view ======= */
/* =========== Phase 5.7 Feature 1 ================================== */
/* ================================================================== */

function ApprovalsPanelScreen({ masters, projects, currentRoleCode, currentProfile, onJumpToProject, onUpdateProject, embedded }) {
  // Flatten approvals across all projects, attaching project metadata
  // Then filter by role visibility just like the per-project tab does
  const flatApprovals = React.useMemo(() => {
    const out = [];
    projects.forEach((p) => {
      const approvals = (p._wizard && p._wizard.projectApprovals) || [];
      const visible = recordsForRole(approvals, currentRoleCode, 'approval');
      visible.forEach((a) => {
        out.push({
          ...a,
          _projectId: p.id,
          _projectName: p.name,
          _projectAccent: p.accent,
          _projectStage: p.currentStage,
        });
      });
    });
    return out;
  }, [projects, currentRoleCode]);

  // ===== Filter state =====
  const [filterStatus, setFilterStatus] = useState('pending'); // default to pending — most useful default
  const [filterProject, setFilterProject] = useState('all');
  const [filterRequester, setFilterRequester] = useState('all');
  const [sortBy, setSortBy] = useState('dueAsc'); // 'dueAsc' | 'dueDesc' | 'raisedDesc'
  const [search, setSearch] = useState('');

  // Derive distinct requester options from data
  const requesterOptions = React.useMemo(() => {
    const set = new Set();
    flatApprovals.forEach((a) => { if (a.requestedFrom) set.add(a.requestedFrom); });
    return Array.from(set).sort();
  }, [flatApprovals]);

  // Project options (only projects that actually have visible approvals)
  const projectOptions = React.useMemo(() => {
    const set = new Set();
    flatApprovals.forEach((a) => set.add(a._projectId));
    return projects.filter((p) => set.has(p.id));
  }, [flatApprovals, projects]);

  // ===== Apply filters + sort =====
  const filtered = React.useMemo(() => {
    let list = flatApprovals;
    if (filterStatus !== 'all') list = list.filter((a) => a.status === filterStatus);
    if (filterProject !== 'all') list = list.filter((a) => a._projectId === filterProject);
    if (filterRequester !== 'all') list = list.filter((a) => a.requestedFrom === filterRequester);
    if (search.trim()) {
      const q = search.trim().toLowerCase();
      list = list.filter((a) =>
        (a.title || '').toLowerCase().includes(q)
        || (a.typeName || '').toLowerCase().includes(q)
        || (a._projectName || '').toLowerCase().includes(q)
        || (a.requestedFrom || '').toLowerCase().includes(q)
      );
    }
    // Sort
    list = [...list];
    if (sortBy === 'dueAsc') {
      list.sort((a, b) => (a.dueDate || '9999').localeCompare(b.dueDate || '9999'));
    } else if (sortBy === 'dueDesc') {
      list.sort((a, b) => (b.dueDate || '0').localeCompare(a.dueDate || '0'));
    } else if (sortBy === 'raisedDesc') {
      list.sort((a, b) => (b.raisedOn || '0').localeCompare(a.raisedOn || '0'));
    }
    return list;
  }, [flatApprovals, filterStatus, filterProject, filterRequester, search, sortBy]);

  // ===== Aggregated counts for top metrics =====
  const today = new Date().toISOString().slice(0, 10);
  const totalPending = flatApprovals.filter((a) => a.status === 'pending').length;
  const overdue = flatApprovals.filter((a) => a.status === 'pending' && a.dueDate && a.dueDate < today).length;
  const dueThisWeek = flatApprovals.filter((a) => {
    if (a.status !== 'pending' || !a.dueDate) return false;
    const dueIn = (new Date(a.dueDate) - new Date(today)) / (1000 * 60 * 60 * 24);
    return dueIn >= 0 && dueIn <= 7;
  }).length;
  const approvedThisMonth = flatApprovals.filter((a) => {
    if (a.status !== 'approved' || !a.decisionDate) return false;
    return a.decisionDate.slice(0, 7) === today.slice(0, 7);
  }).length;

  // ===== Inline approval mutation (status update from this view) =====
  const updateApprovalInProject = (projectId, approvalId, updates) => {
    const project = projects.find((p) => p.id === projectId);
    if (!project) return;
    const w = project._wizard || {};
    const newApprovals = (w.projectApprovals || []).map((a) =>
      a.id === approvalId ? { ...a, ...updates } : a
    );
    const metrics = computeApprovalMetrics(newApprovals);
    onUpdateProject(projectId, {
      _wizard: { ...w, projectApprovals: newApprovals },
      pendingApprovals: metrics.pendingApprovals,
    });
  };

  return (
    <div className={embedded ? '' : 'flex-1 overflow-auto scrollbar-thin'}>
      {!embedded && (
        <div className="px-6 py-5 border-b border-line bg-paper">
          <div className="flex items-end justify-between flex-wrap gap-3">
            <div>
              <div className="flex items-center gap-2 mb-1">
                <Shield className="w-4 h-4 text-terra" />
                <span className="text-[11px] font-mono ink-faint uppercase tracking-wider">ApprovalsPanelScreen · cross-project</span>
              </div>
              <h1 className="font-display text-3xl ink tracking-tight leading-none">Approvals</h1>
              <div className="text-sm ink-soft mt-2 max-w-2xl">
                Every approval across every project, in one queue. Filter, sort, jump straight to the project to act.
              </div>
            </div>
          </div>
        </div>
      )}

      <div className={embedded ? '' : 'p-6'} style={embedded ? {} : { maxWidth: '1400px' }}>
        {/* Top metrics row */}
        <div className="grid grid-cols-2 md:grid-cols-4 gap-3 mb-5">
          <ApprovalsMetric icon={Circle} label="Pending" value={totalPending} accent="ink" sublabel="across studio" />
          <ApprovalsMetric icon={AlertCircle} label="Overdue" value={overdue} accent={overdue > 0 ? 'terra' : 'ink-faint'} sublabel="past due date" />
          <ApprovalsMetric icon={Calendar} label="Due this week" value={dueThisWeek} accent={dueThisWeek > 0 ? 'terra' : 'ink-faint'} sublabel="next 7 days" />
          <ApprovalsMetric icon={CheckCircle2} label="Approved this month" value={approvedThisMonth} accent="moss" sublabel={today.slice(0, 7)} />
        </div>

        {/* Filter bar */}
        <div className="bg-paper border border-line rounded-lg p-3 mb-4">
          <div className="flex items-center gap-2 flex-wrap">
            <div className="flex items-center gap-2 px-3 py-2 bg-bone rounded border border-line flex-1 min-w-[200px]">
              <Search className="w-3.5 h-3.5 ink-faint" />
              <input
                value={search}
                onChange={(e) => setSearch(e.target.value)}
                placeholder="Search approvals, projects, requesters…"
                className="bg-transparent outline-none text-sm w-full ink placeholder:ink-faint"
              />
            </div>
            <select value={filterStatus} onChange={(e) => setFilterStatus(e.target.value)} className="input-sm text-[11px]">
              <option value="all">All statuses</option>
              <option value="pending">Pending</option>
              <option value="approved">Approved</option>
              <option value="rejected">Rejected</option>
            </select>
            <select value={filterProject} onChange={(e) => setFilterProject(e.target.value)} className="input-sm text-[11px]" style={{ maxWidth: '180px' }}>
              <option value="all">All projects</option>
              {projectOptions.map((p) => (
                <option key={p.id} value={p.id}>{p.name}</option>
              ))}
            </select>
            <select value={filterRequester} onChange={(e) => setFilterRequester(e.target.value)} className="input-sm text-[11px]" style={{ maxWidth: '180px' }}>
              <option value="all">All requesters</option>
              {requesterOptions.map((r) => (
                <option key={r} value={r}>{r}</option>
              ))}
            </select>
            <select value={sortBy} onChange={(e) => setSortBy(e.target.value)} className="input-sm text-[11px]">
              <option value="dueAsc">Due date ↑</option>
              <option value="dueDesc">Due date ↓</option>
              <option value="raisedDesc">Recently raised</option>
            </select>
          </div>
          <div className="flex items-center justify-between mt-2 pt-2 border-t border-line-soft text-[10px] font-mono ink-faint">
            <span>Showing <span className="ink">{filtered.length}</span> of {flatApprovals.length} approvals</span>
            {(filterStatus !== 'all' || filterProject !== 'all' || filterRequester !== 'all' || search) && (
              <button
                onClick={() => { setFilterStatus('all'); setFilterProject('all'); setFilterRequester('all'); setSearch(''); }}
                className="text-terra hover:ink"
              >
                Clear filters
              </button>
            )}
          </div>
        </div>

        {/* Results */}
        {filtered.length === 0 ? (
          <div className="bg-paper border border-line rounded-lg p-12 text-center">
            <Shield className="w-10 h-10 ink-faint mx-auto mb-3" strokeWidth={1.5} />
            <h3 className="font-display text-lg ink mb-1">
              {flatApprovals.length === 0 ? 'No approvals visible' : 'No matches'}
            </h3>
            <p className="text-[11px] ink-soft max-w-sm mx-auto">
              {flatApprovals.length === 0
                ? <>Nothing to approve right now. Approvals raised on individual projects will appear here.</>
                : <>Try clearing filters or searching for something else.</>}
            </p>
          </div>
        ) : (
          <div className="bg-paper border border-line rounded-lg overflow-hidden">
            {filtered.map((a, idx) => (
              <ApprovalsPanelRow
                key={`${a._projectId}-${a.id}`}
                approval={a}
                isLast={idx === filtered.length - 1}
                onJumpToProject={() => onJumpToProject(a._projectId)}
                onCycleStatus={(newStatus) => {
                  const updates = { status: newStatus };
                  if (newStatus === 'approved' || newStatus === 'rejected') {
                    updates.decisionDate = new Date().toISOString().slice(0, 10);
                  }
                  updateApprovalInProject(a._projectId, a.id, updates);
                }}
              />
            ))}
          </div>
        )}
      </div>
    </div>
  );
}

/* === Top metric tile === */
function ApprovalsMetric({ icon: Icon, label, value, accent, sublabel }) {
  const accentClass = accent === 'terra' ? 'text-terra' : accent === 'moss' ? 'text-moss' : accent === 'ink-faint' ? 'ink-faint' : 'ink';
  return (
    <div className="bg-paper border border-line rounded-lg p-4">
      <div className="flex items-center gap-1.5 mb-1.5">
        <Icon className={`w-3.5 h-3.5 ${accentClass}`} strokeWidth={2} />
        <span className="text-[10px] font-mono uppercase tracking-wider ink-faint">{label}</span>
      </div>
      <div className={`font-display text-2xl ${accentClass} leading-none`}>{value}</div>
      {sublabel && <div className="text-[10px] font-mono ink-faint mt-1">{sublabel}</div>}
    </div>
  );
}

/* === Single row in the cross-project list === */
function ApprovalsPanelRow({ approval, isLast, onJumpToProject, onCycleStatus }) {
  const today = new Date().toISOString().slice(0, 10);
  const overdue = approval.status === 'pending' && approval.dueDate && approval.dueDate < today;
  const daysToDue = approval.dueDate
    ? Math.ceil((new Date(approval.dueDate) - new Date(today)) / (1000 * 60 * 60 * 24))
    : null;

  const statusConfig = {
    pending:  { label: 'Pending',  bg: 'bg-bone',       color: 'ink-soft',   icon: Circle },
    approved: { label: 'Approved', bg: 'bg-moss-soft',  color: 'text-moss',  icon: CheckCircle2 },
    rejected: { label: 'Rejected', bg: 'bg-terra-soft', color: 'text-terra', icon: X },
  };
  const cfg = statusConfig[approval.status] || statusConfig.pending;
  const StatusIcon = cfg.icon;

  const cycleStatus = () => {
    const next = { pending: 'approved', approved: 'rejected', rejected: 'pending' }[approval.status] || 'pending';
    onCycleStatus(next);
  };

  return (
    <div className={`flex items-start gap-3 px-4 py-3 hover:bg-bone group/row ${!isLast ? 'border-b border-line-soft' : ''}`}>
      {/* Status pill — clickable */}
      <button
        onClick={cycleStatus}
        className={`flex items-center gap-1.5 px-2 py-1 rounded text-[10px] font-mono uppercase tracking-wider shrink-0 ${cfg.bg} ${cfg.color} hover:opacity-80 font-semibold`}
        title="Click to cycle status"
        style={{ minWidth: '90px' }}
      >
        <StatusIcon className="w-3 h-3" strokeWidth={2.5} />
        {cfg.label}
      </button>

      {/* Title + meta */}
      <div className="flex-1 min-w-0">
        <div className="text-[13px] ink font-medium leading-snug">
          {approval.title || <span className="ink-faint italic">untitled</span>}
        </div>
        <div className="flex items-center gap-2 text-[10px] font-mono ink-faint mt-0.5 flex-wrap">
          <button
            onClick={onJumpToProject}
            className="hover:text-terra hover:underline flex items-center gap-1"
            title="Jump to project"
          >
            <span
              className="w-2 h-2 rounded-full inline-block"
              style={{ background: approval._projectAccent || '#9A938A' }}
            />
            {approval._projectName}
          </button>
          {approval.typeName && <span>· {approval.typeName}</span>}
          {approval.linkedStage && <span>· {approval.linkedStage}</span>}
          {approval.requestedFrom && <span>· from {approval.requestedFrom}</span>}
          {approval.clientFacing === 'yes' && (
            <span className="text-terra uppercase tracking-wider">· client-facing</span>
          )}
        </div>
      </div>

      {/* Due date */}
      {approval.dueDate && approval.status === 'pending' && (
        <div className={`text-right shrink-0 ${overdue ? 'text-terra' : 'ink-soft'}`}>
          <div className="text-[11px] font-mono">{formatDate(approval.dueDate)}</div>
          <div className={`text-[10px] ${overdue ? 'text-terra font-semibold' : 'ink-faint'}`}>
            {overdue ? `${Math.abs(daysToDue)}d overdue` : daysToDue === 0 ? 'Due today' : `in ${daysToDue}d`}
          </div>
        </div>
      )}
      {approval.status === 'approved' && approval.decisionDate && (
        <div className="text-right shrink-0">
          <div className="text-[10px] font-mono text-moss">approved</div>
          <div className="text-[10px] font-mono ink-faint">{formatDate(approval.decisionDate)}</div>
        </div>
      )}

      {/* Jump-to button on hover */}
      <button
        onClick={onJumpToProject}
        className="opacity-0 group-hover/row:opacity-100 p-1 ink-faint hover:text-terra shrink-0"
        title="Open in project"
      >
        <ArrowRight className="w-3.5 h-3.5" />
      </button>
    </div>
  );
}

/* ================================================================== */
/* =========== TASKS PANEL — top-level cross-project view =========== */
/* =========== Phase 5.7 Feature 2 ================================== */
/* ================================================================== */

function TasksPanelScreen({ masters, projects, currentRoleCode, currentProfile, onJumpToProject, onUpdateProject, embedded }) {
  // Identity of the current user (from role profile) — used for "My tasks" filter
  const currentUserName = currentProfile?.user?.name || '';

  // Flatten tasks across all projects, attaching project metadata + role visibility
  const flatTasks = React.useMemo(() => {
    const out = [];
    projects.forEach((p) => {
      const tasks = (p._wizard && p._wizard.projectTasks) || [];
      const visible = recordsForRole(tasks, currentRoleCode, 'task');
      visible.forEach((t) => {
        out.push({
          ...t,
          _projectId: p.id,
          _projectName: p.name,
          _projectAccent: p.accent,
          _projectStage: p.currentStage,
        });
      });
    });
    return out;
  }, [projects, currentRoleCode]);

  // ===== Filter state =====
  const [filterStatus, setFilterStatus] = useState('open'); // 'open' | 'todo' | 'in_progress' | 'done' | 'blocked' | 'all'
  const [filterProject, setFilterProject] = useState('all');
  const [filterAssignee, setFilterAssignee] = useState('all');
  const [showMine, setShowMine] = useState(false);
  const [showMyReview, setShowMyReview] = useState(false); /* Phase 5.8 Piece 4 — reviewer filter */
  const [delegateTarget, setDelegateTarget] = useState(null); /* Phase 5.8 Piece 3 — task currently being delegated */
  const [reminderTarget, setReminderTarget] = useState(null); /* Phase 5.8 Piece 5 — task currently being reminded */
  const [groupBy, setGroupBy] = useState('project'); // 'project' | 'assignee' | 'none'
  const [sortBy, setSortBy] = useState('dueAsc'); // 'dueAsc' | 'dueDesc' | 'createdDesc'
  const [search, setSearch] = useState('');

  /* === Phase 5.8 Piece 4 — Identify the current user as actor for review transitions === */
  const me = resolveCurrentTeamMember(currentProfile, masters);
  const actor = me ? { id: me.id, name: me.value } : { id: null, name: currentUserName || 'Unknown' };

  // Derived assignee options
  const assigneeOptions = React.useMemo(() => {
    const set = new Set();
    flatTasks.forEach((t) => {
      const name = t.assigneeName || t.assignee;
      if (name) set.add(name);
    });
    return Array.from(set).sort();
  }, [flatTasks]);

  // Project options (only those with visible tasks)
  const projectOptions = React.useMemo(() => {
    const set = new Set();
    flatTasks.forEach((t) => set.add(t._projectId));
    return projects.filter((p) => set.has(p.id));
  }, [flatTasks, projects]);

  // ===== Apply filters + sort =====
  const filtered = React.useMemo(() => {
    let list = flatTasks;
    if (filterStatus === 'open') {
      list = list.filter((t) => isTaskOpen(t));
    } else if (filterStatus === 'closed') {
      list = list.filter((t) => isTaskClosed(t));
    } else if (filterStatus !== 'all') {
      list = list.filter((t) => t.status === filterStatus);
    }
    if (filterProject !== 'all') list = list.filter((t) => t._projectId === filterProject);
    if (filterAssignee !== 'all') {
      list = list.filter((t) => (t.assigneeName || t.assignee || '') === filterAssignee);
    }
    if (showMine && currentUserName) {
      list = list.filter((t) => ((t.assigneeName || t.assignee || '').toLowerCase()) === currentUserName.toLowerCase());
    }
    if (showMyReview && actor.id) {
      list = list.filter((t) => t.status === 'submitted_for_review' && t.assignedById === actor.id);
    }
    if (search.trim()) {
      const q = search.trim().toLowerCase();
      list = list.filter((t) =>
        (t.title || '').toLowerCase().includes(q)
        || (t.description || '').toLowerCase().includes(q)
        || (t.linkedActivity || '').toLowerCase().includes(q)
        || (t._projectName || '').toLowerCase().includes(q)
        || (t.assigneeName || t.assignee || '').toLowerCase().includes(q)
      );
    }
    // Sort
    list = [...list];
    if (sortBy === 'dueAsc') {
      list.sort((a, b) => (a.dueDate || '9999').localeCompare(b.dueDate || '9999'));
    } else if (sortBy === 'dueDesc') {
      list.sort((a, b) => (b.dueDate || '0').localeCompare(a.dueDate || '0'));
    } else if (sortBy === 'createdDesc') {
      list.sort((a, b) => (b.createdOn || '0').localeCompare(a.createdOn || '0'));
    }
    return list;
  }, [flatTasks, filterStatus, filterProject, filterAssignee, showMine, showMyReview, currentUserName, actor.id, search, sortBy]);

  // ===== Top-row metrics =====
  const today = new Date().toISOString().slice(0, 10);
  const myTasks = currentUserName ? flatTasks.filter((t) => ((t.assigneeName || t.assignee || '').toLowerCase()) === currentUserName.toLowerCase() && isTaskOpen(t)).length : 0;
  const myReviewQueue = actor.id ? flatTasks.filter((t) => t.status === 'submitted_for_review' && t.assignedById === actor.id).length : 0;
  const totalOpen = flatTasks.filter((t) => isTaskOpen(t)).length;
  const overdue = flatTasks.filter((t) => isTaskOpen(t) && t.dueDate && t.dueDate < today).length;
  const blocked = flatTasks.filter((t) => t.status === 'blocked').length;
  const inReview = flatTasks.filter((t) => t.status === 'submitted_for_review').length;
  const completedThisWeek = flatTasks.filter((t) => {
    if (!isTaskClosed(t) || !t.completedOn) return false;
    const days = (new Date(today) - new Date(t.completedOn)) / (1000 * 60 * 60 * 24);
    return days >= 0 && days <= 7;
  }).length;
  // ===== Inline mutation: status toggle / done toggle =====
  const updateTaskInProject = (projectId, taskId, updates) => {
    const project = projects.find((p) => p.id === projectId);
    if (!project) return;
    const w = project._wizard || {};
    const newTasks = (w.projectTasks || []).map((t) =>
      t.id === taskId ? { ...t, ...updates } : t
    );
    const metrics = computeTaskMetrics(newTasks);
    onUpdateProject(projectId, {
      _wizard: { ...w, projectTasks: newTasks },
      overdueTasks: metrics.overdueTasks,
    });
  };

  /* Apply a transition (review-flow aware) to a task by id, in its source project. */
  const transitionTask = (task, transition, actor, extras = {}) => {
    const project = projects.find((p) => p.id === task._projectId);
    if (!project) return;
    const w = project._wizard || {};
    const sourceTask = (w.projectTasks || []).find((t) => t.id === task.id);
    if (!sourceTask) return;
    /* Apply any extras (rejection reason, submission note) to the source task BEFORE the transition,
       so the transition helper picks them up via task.* fields */
    const taskWithExtras = { ...sourceTask, ...extras };
    const updatedTask = applyTaskTransition(taskWithExtras, transition, actor);
    const newTasks = (w.projectTasks || []).map((t) => t.id === task.id ? updatedTask : t);
    const metrics = computeTaskMetrics(newTasks);
    onUpdateProject(task._projectId, {
      _wizard: { ...w, projectTasks: newTasks },
      overdueTasks: metrics.overdueTasks,
    });
  };

  /* Smart toggle — replaces old toggleDone. Decides whether to submit-for-review
     (delegated tasks) or self-close (self-assigned). */
  const smartCloseTask = (task) => {
    if (isTaskClosed(task)) {
      /* Reopen */
      transitionTask(task, 'reopen', actor);
      return;
    }
    if (taskNeedsReview(task)) {
      /* Delegated task — go to submitted_for_review (with optional note via prompt) */
      const note = window.prompt(
        'Mark this task done — it will go to your manager for review.\n\nOptional: short note about what was done:',
        ''
      );
      if (note === null) return; /* user cancelled */
      transitionTask(task, 'submit_for_review', actor, { submissionNote: note });
    } else {
      /* Self-assigned or legacy — straight to closed */
      transitionTask(task, 'self_close', actor);
    }
  };

  const approveTask = (task) => {
    transitionTask(task, 'approve', actor);
  };

  const rejectTask = (task) => {
    const reason = window.prompt(
      'Send back to the doer with a reason:\n\nWhat needs rework?',
      ''
    );
    if (reason === null) return;
    if (!reason.trim()) {
      alert('A rejection reason is required.');
      return;
    }
    transitionTask(task, 'reject', actor, { rejectionReason: reason });
  };

  /* === Phase 5.8 Piece 3 — Delegation handlers === */
  const openDelegateModal = (task) => {
    setDelegateTarget(task);
  };

  const findTeamMemberForTaskAssignment = (formData) => {
    const team = masters.MasterTeamMembers || [];
    return team.find((member) => member.id === formData.assigneeId)
      || team.find((member) => (member.value || '').toLowerCase() === (formData.assigneeName || formData.assignee || '').toLowerCase())
      || null;
  };

  const buildTaskDelegationWhatsAppMessage = (task, formData) => {
    const lines = [
      `New task assigned: ${task.title || 'Untitled task'}`,
      task._projectName ? `Project: ${task._projectName}` : '',
      task.linkedStage ? `Stage: ${task.linkedStage}` : '',
      task.linkedActivity ? `Activity: ${task.linkedActivity}` : '',
      formData.dueDate ? `Due: ${formatDate(formData.dueDate)}` : '',
      actor.name ? `Assigned by: ${actor.name}` : '',
      formData.delegationNote ? `Note: ${formData.delegationNote}` : '',
      '',
      'Please check Studio/OS for details and update status there.',
    ];
    return lines.filter((line) => line !== '').join('\n');
  };

  const sendDelegationWhatsApp = async (task, formData) => {
    const member = findTeamMemberForTaskAssignment(formData);
    const mobile = member?.mobile || member?.phone || member?.contact || '';
    if (!mobile) {
      window.alert(`Task delegated to ${formData.assigneeName}, but no mobile number is saved for this team member in MasterTeamMembers.`);
      return;
    }
    const message = buildTaskDelegationWhatsAppMessage(task, formData);
    try {
      await sendWhatsAppViaBackend(mobile, message);
      window.alert(`Task delegated and WhatsApp sent to ${formData.assigneeName}.`);
    } catch (error) {
      window.alert(`Task delegated, but WhatsApp could not be sent to ${formData.assigneeName} (${mobile}): ${error.message}`);
    }
  };

  const confirmDelegate = (formData) => {
    if (!delegateTarget) return;
    /* Merge form fields onto task before transition so applyTaskTransition picks them up */
    transitionTask(delegateTarget, 'delegate', actor, {
      assigneeId: formData.assigneeId,
      assigneeName: formData.assigneeName,
      assignee: formData.assignee,
      dueDate: formData.dueDate,
      delegationNote: formData.delegationNote,
    });
    sendDelegationWhatsApp(delegateTarget, formData);
    setDelegateTarget(null);
  };

  /* === Phase 5.8 Piece 5 — Reminder handlers === */
  const openReminderModal = (task) => setReminderTarget(task);
  const saveReminder = (updates) => {
    if (!reminderTarget) return;
    updateTaskInProject(reminderTarget._projectId, reminderTarget.id, updates);
    setReminderTarget(null);
  };
  const clearReminder = () => {
    if (!reminderTarget) return;
    updateTaskInProject(reminderTarget._projectId, reminderTarget.id, {
      remindAt: '',
      reminderDismissed: false,
    });
    setReminderTarget(null);
  };

  const cycleStatus = (task) => {
    /* Lightweight cycle for non-review states (todo, in_progress, blocked).
       For closed/review states, this is a no-op — use smartCloseTask / approveTask / rejectTask instead. */
    if (isTaskClosed(task) || task.status === 'submitted_for_review' || task.status === 'rejected_back_to_progress') {
      return;
    }
    const order = ['todo', 'in_progress', 'blocked'];
    const idx = order.indexOf(task.status);
    const next = order[(idx + 1) % order.length];
    updateTaskInProject(task._projectId, task.id, { status: next });
  };

  // ===== Grouping =====
  const grouped = React.useMemo(() => {
    if (groupBy === 'none') return [{ key: 'all', label: '', items: filtered }];
    if (groupBy === 'project') {
      const map = new Map();
      filtered.forEach((t) => {
        const k = t._projectId;
        if (!map.has(k)) map.set(k, { key: k, label: t._projectName, accent: t._projectAccent, stage: t._projectStage, items: [] });
        map.get(k).items.push(t);
      });
      return Array.from(map.values());
    }
    if (groupBy === 'assignee') {
      const map = new Map();
      filtered.forEach((t) => {
        const name = t.assigneeName || t.assignee;
        const k = name || '_unassigned';
        const label = name || 'Unassigned';
        if (!map.has(k)) map.set(k, { key: k, label, items: [] });
        map.get(k).items.push(t);
      });
      return Array.from(map.values()).sort((a, b) => a.label.localeCompare(b.label));
    }
    return [];
  }, [filtered, groupBy]);

  return (
    <div className={embedded ? '' : 'flex-1 overflow-auto scrollbar-thin'}>
      {!embedded && (
        <div className="px-6 py-5 border-b border-line bg-paper">
          <div className="flex items-end justify-between flex-wrap gap-3">
            <div>
              <div className="flex items-center gap-2 mb-1">
                <CheckSquare className="w-4 h-4 text-terra" />
                <span className="text-[11px] font-mono ink-faint uppercase tracking-wider">TasksPanelScreen · cross-project</span>
              </div>
              <h1 className="font-display text-3xl ink tracking-tight leading-none">Tasks</h1>
              <div className="text-sm ink-soft mt-2 max-w-2xl">
                Every task across every project. {currentUserName && <>Toggle <span className="ink font-semibold">My tasks</span> to filter to work assigned to <span className="ink font-semibold">{currentUserName}</span>.</>}
              </div>
            </div>
          </div>
        </div>
      )}

      <div className={embedded ? '' : 'p-6'} style={embedded ? {} : { maxWidth: '1400px' }}>
        {/* Top metrics row */}
        <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-6 gap-3 mb-5">
          {currentUserName && (
            <button
              onClick={() => { setShowMine(!showMine); if (!showMine) setShowMyReview(false); }}
              className={`text-left p-4 rounded-lg border transition-colors ${showMine ? 'bg-terra-soft border-terra' : 'bg-paper border-line hover:border-terra'}`}
            >
              <div className="flex items-center gap-1.5 mb-1.5">
                <Users className={`w-3.5 h-3.5 ${showMine ? 'text-terra' : 'ink-faint'}`} strokeWidth={2} />
                <span className="text-[10px] font-mono uppercase tracking-wider ink-faint">My open tasks</span>
              </div>
              <div className={`font-display text-2xl leading-none ${myTasks > 0 ? 'ink' : 'ink-faint'}`}>{myTasks}</div>
              <div className={`text-[10px] font-mono mt-1 ${showMine ? 'text-terra font-semibold' : 'ink-faint'}`}>
                {showMine ? '✓ filter active' : 'click to filter'}
              </div>
            </button>
          )}
          {actor.id && (
            <button
              onClick={() => { setShowMyReview(!showMyReview); if (!showMyReview) setShowMine(false); }}
              className={`text-left p-4 rounded-lg border transition-colors ${showMyReview ? 'bg-terra-soft border-terra' : 'bg-paper border-line hover:border-terra'}`}
              title="Tasks submitted for review where you are the reviewer"
            >
              <div className="flex items-center gap-1.5 mb-1.5">
                <Eye className={`w-3.5 h-3.5 ${showMyReview ? 'text-terra' : myReviewQueue > 0 ? 'text-terra' : 'ink-faint'}`} strokeWidth={2} />
                <span className="text-[10px] font-mono uppercase tracking-wider ink-faint">Awaiting your review</span>
              </div>
              <div className={`font-display text-2xl leading-none ${myReviewQueue > 0 ? 'ink' : 'ink-faint'}`}>{myReviewQueue}</div>
              <div className={`text-[10px] font-mono mt-1 ${showMyReview ? 'text-terra font-semibold' : 'ink-faint'}`}>
                {showMyReview ? '✓ filter active' : myReviewQueue > 0 ? 'click to review' : 'all clear'}
              </div>
            </button>
          )}
          <TasksMetric icon={Circle} label="Total open" value={totalOpen} accent="ink" sublabel="across studio" />
          <TasksMetric icon={AlertCircle} label="Overdue" value={overdue} accent={overdue > 0 ? 'terra' : 'ink-faint'} sublabel="past due date" />
          <TasksMetric icon={Lock} label="Blocked" value={blocked} accent={blocked > 0 ? 'terra' : 'ink-faint'} sublabel="needs unblocking" />
          <TasksMetric icon={CheckCircle2} label="Closed this week" value={completedThisWeek} accent="moss" sublabel="last 7 days" />
        </div>

        {/* Filter bar */}
        <div className="bg-paper border border-line rounded-lg p-3 mb-4">
          <div className="flex items-center gap-2 flex-wrap">
            <div className="flex items-center gap-2 px-3 py-2 bg-bone rounded border border-line flex-1 min-w-[200px]">
              <Search className="w-3.5 h-3.5 ink-faint" />
              <input
                value={search}
                onChange={(e) => setSearch(e.target.value)}
                placeholder="Search tasks, projects, assignees…"
                className="bg-transparent outline-none text-sm w-full ink placeholder:ink-faint"
              />
            </div>
            <select value={filterStatus} onChange={(e) => setFilterStatus(e.target.value)} className="input-sm text-[11px]">
              <option value="open">Open (active)</option>
              <option value="todo">To do</option>
              <option value="in_progress">In progress</option>
              <option value="blocked">Blocked</option>
              <option value="submitted_for_review">Awaiting review</option>
              <option value="rejected_back_to_progress">Rejected — rework</option>
              <option value="approved_closed">Approved · closed</option>
              <option value="closed">All closed</option>
              <option value="all">All statuses</option>
            </select>
            <select value={filterProject} onChange={(e) => setFilterProject(e.target.value)} className="input-sm text-[11px]" style={{ maxWidth: '180px' }}>
              <option value="all">All projects</option>
              {projectOptions.map((p) => (
                <option key={p.id} value={p.id}>{p.name}</option>
              ))}
            </select>
            <select value={filterAssignee} onChange={(e) => setFilterAssignee(e.target.value)} className="input-sm text-[11px]" style={{ maxWidth: '180px' }}>
              <option value="all">All assignees</option>
              {assigneeOptions.map((a) => (
                <option key={a} value={a}>{a}</option>
              ))}
            </select>
            <select value={groupBy} onChange={(e) => setGroupBy(e.target.value)} className="input-sm text-[11px]">
              <option value="project">Group by project</option>
              <option value="assignee">Group by assignee</option>
              <option value="none">No grouping</option>
            </select>
            <select value={sortBy} onChange={(e) => setSortBy(e.target.value)} className="input-sm text-[11px]">
              <option value="dueAsc">Due ↑</option>
              <option value="dueDesc">Due ↓</option>
              <option value="createdDesc">Recent</option>
            </select>
          </div>
          <div className="flex items-center justify-between mt-2 pt-2 border-t border-line-soft text-[10px] font-mono ink-faint">
            <span>Showing <span className="ink">{filtered.length}</span> of {flatTasks.length} tasks</span>
            {(filterStatus !== 'open' || filterProject !== 'all' || filterAssignee !== 'all' || showMine || showMyReview || search) && (
              <button
                onClick={() => { setFilterStatus('open'); setFilterProject('all'); setFilterAssignee('all'); setShowMine(false); setShowMyReview(false); setSearch(''); }}
                className="text-terra hover:ink"
              >
                Clear filters
              </button>
            )}
          </div>
        </div>

        {/* Results */}
        {filtered.length === 0 ? (
          <div className="bg-paper border border-line rounded-lg p-12 text-center">
            <CheckSquare className="w-10 h-10 ink-faint mx-auto mb-3" strokeWidth={1.5} />
            <h3 className="font-display text-lg ink mb-1">
              {flatTasks.length === 0 ? 'No tasks visible' : 'No matches'}
            </h3>
            <p className="text-[11px] ink-soft max-w-sm mx-auto">
              {flatTasks.length === 0
                ? <>Nothing on the queue right now. Tasks raised on individual projects will appear here.</>
                : <>Try clearing filters or switching status filter to <span className="ink font-semibold">All statuses</span>.</>}
            </p>
          </div>
        ) : (
          <TasksSplitPanel
            grouped={grouped}
            groupBy={groupBy}
            actorId={actor.id}
            canDelegate={canRoleDelegate(currentRoleCode)}
            onJumpToProject={onJumpToProject}
            onToggleDone={smartCloseTask}
            onCycleStatus={cycleStatus}
            onApprove={approveTask}
            onReject={rejectTask}
            onDelegate={openDelegateModal}
            onSetReminder={openReminderModal}
          />
        )}
      </div>

      {/* === Phase 5.8 Piece 3 — Delegation modal === */}
      {delegateTarget && (
        <DelegateTaskModal
          task={delegateTarget}
          masters={masters}
          currentProfile={currentProfile}
          onClose={() => setDelegateTarget(null)}
          onConfirm={confirmDelegate}
        />
      )}

      {/* === Phase 5.8 Piece 5 — Reminder picker === */}
      {reminderTarget && (
        <ReminderPickerModal
          task={reminderTarget}
          onClose={() => setReminderTarget(null)}
          onSave={saveReminder}
          onClear={clearReminder}
        />
      )}
    </div>
  );
}

function TasksSplitPanel({ grouped, groupBy, actorId, canDelegate, onJumpToProject, onToggleDone, onCycleStatus, onApprove, onReject, onDelegate, onSetReminder }) {
  const flat = React.useMemo(() => grouped.flatMap((g) => g.items || []), [grouped]);
  const [activeKey, setActiveKey] = React.useState(flat[0] ? `${flat[0]._projectId}-${flat[0].id}` : null);
  React.useEffect(() => {
    if (!flat.length) return;
    if (!activeKey || !flat.some((t) => `${t._projectId}-${t.id}` === activeKey)) {
      setActiveKey(`${flat[0]._projectId}-${flat[0].id}`);
    }
  }, [flat, activeKey]);

  const activeTask = flat.find((t) => `${t._projectId}-${t.id}` === activeKey) || flat[0];
  const today = new Date().toISOString().slice(0, 10);

  return (
    <SplitPanelShell
      eyebrow="Project tasks"
      title="Action queue"
      countLabel={`${flat.length} task${flat.length === 1 ? '' : 's'}`}
      left={grouped.map((group) => (
        <div key={group.key} className="mb-3 last:mb-0">
          {group.label && (
            <div className="flex items-center gap-2 px-2 py-2">
              {group.accent && <span className="w-2 h-2 rounded-full inline-block" style={{ background: group.accent }} />}
              <span className="text-[11px] font-mono uppercase tracking-widest ink-faint truncate">{group.label}</span>
              <span className="text-[10px] font-mono ink-faint ml-auto">{group.items.length}</span>
            </div>
          )}
          <div className="space-y-1">
            {group.items.map((task) => {
              const key = `${task._projectId}-${task.id}`;
              const isActive = activeKey === key;
              const overdue = isTaskOpen(task) && task.dueDate && task.dueDate < today;
              return (
                <button
                  key={key}
                  onClick={() => setActiveKey(key)}
                  className={`w-full text-left rounded-lg px-3 py-3 border-l-4 transition-colors ${
                    isActive ? 'bg-amber-50/70 border-terra' : 'border-transparent hover:bg-bone/70'
                  }`}
                >
                  <div className="flex items-start gap-2">
                    <span className={`mt-0.5 w-3.5 h-3.5 rounded-full border-2 shrink-0 ${isTaskClosed(task) ? 'bg-moss border-moss' : overdue ? 'border-terra' : 'border-line'}`} />
                    <div className="min-w-0 flex-1">
                      <div className={`text-[14px] font-semibold leading-snug ${isTaskClosed(task) ? 'line-through ink-soft' : 'ink'}`}>{task.title || 'Untitled task'}</div>
                      <div className="text-[12px] ink-soft truncate mt-0.5">
                        {[groupBy !== 'project' ? task._projectName : null, task.assigneeName || task.assignee || 'Unassigned'].filter(Boolean).join(' · ')}
                      </div>
                    </div>
                    {overdue && <span className="text-[10px] font-mono text-terra shrink-0">overdue</span>}
                  </div>
                </button>
              );
            })}
          </div>
        </div>
      ))}
      right={activeTask ? (
        <TaskSplitDetail
          task={activeTask}
          actorId={actorId}
          canDelegate={canDelegate}
          onJumpToProject={() => onJumpToProject(activeTask._projectId)}
          onToggleDone={() => onToggleDone(activeTask)}
          onCycleStatus={() => onCycleStatus(activeTask)}
          onApprove={() => onApprove(activeTask)}
          onReject={() => onReject(activeTask)}
          onDelegate={() => onDelegate(activeTask)}
          onSetReminder={() => onSetReminder(activeTask)}
        />
      ) : null}
    />
  );
}

function TaskSplitDetail({ task, actorId, canDelegate, onJumpToProject, onToggleDone, onCycleStatus, onApprove, onReject, onDelegate, onSetReminder }) {
  const today = new Date().toISOString().slice(0, 10);
  const overdue = isTaskOpen(task) && task.dueDate && task.dueDate < today;
  const cfg = taskStateConfig(task.status);
  const isDone = isTaskClosed(task);
  const isAwaitingReview = task.status === 'submitted_for_review';
  const isMyReview = isAwaitingReview && actorId && task.assignedById === actorId;
  const reviewLog = Array.isArray(task.reviewLog) ? task.reviewLog : [];

  return (
    <div className="p-5">
      <div className="flex items-start justify-between gap-4 mb-5">
        <div className="min-w-0">
          <div className="flex items-center gap-2 mb-2">
            <button
              onClick={onToggleDone}
              className={`w-5 h-5 rounded-full border-2 flex items-center justify-center shrink-0 ${
                isDone ? 'bg-moss border-moss' : overdue ? 'border-terra' : 'border-line'
              }`}
              title={isDone ? 'Reopen task' : 'Mark done'}
            >
              {isDone && <Check className="w-3 h-3 text-white" strokeWidth={3} />}
            </button>
            {overdue && <span className="text-[11px] font-mono uppercase tracking-wider px-2 py-1 rounded bg-terra-soft text-terra">Overdue</span>}
          </div>
          <h3 className="text-2xl font-semibold ink tracking-tight leading-tight">{task.title || 'Untitled task'}</h3>
          <div className="text-sm ink-soft mt-2 leading-relaxed">{task.description || 'No description added.'}</div>
        </div>
        <button onClick={onJumpToProject} className="text-[11px] font-medium px-3 py-2 rounded bg-ink text-white hover:bg-terra shrink-0">Open project</button>
      </div>

      <div className="grid grid-cols-1 sm:grid-cols-2 gap-4 mb-5">
        <SplitDetailField label="Project" value={task._projectName || '-'} />
        <SplitDetailField label="Stage" value={task.linkedStage || task._projectStage || '-'} />
        <SplitDetailField label="Assignee" value={task.assigneeName || task.assignee || 'Unassigned'} tone={task.assigneeName || task.assignee ? undefined : 'danger'} />
        <SplitDetailField label="Due" value={task.dueDate ? formatDate(task.dueDate) : '-'} tone={overdue ? 'danger' : undefined} />
      </div>

      <div className="rounded-lg bg-bone/50 border border-line-soft p-4 mb-4">
        <div className="text-[11px] font-mono uppercase tracking-widest ink-faint mb-3">Status</div>
        <button
          onClick={onCycleStatus}
          className={`inline-flex items-center gap-2 text-[11px] font-mono uppercase tracking-wider px-3 py-2 rounded ${cfg.bg} ${cfg.fg}`}
        >
          {cfg.label}
        </button>
      </div>

      {reviewLog.length > 0 && (
        <div className="rounded-lg border border-line-soft overflow-hidden mb-4">
          <div className="px-3 py-2 bg-bone text-[11px] font-mono uppercase tracking-widest ink-faint">Review history</div>
          {reviewLog.slice(-4).reverse().map((entry, idx) => (
            <div key={idx} className="px-3 py-2 border-t border-line-soft text-[12px] ink-soft">
              <span className="font-mono ink-faint">{entry.at ? formatDate(entry.at) : '-'}</span>
              <span className="mx-2">·</span>
              <span className="ink">{entry.event}</span>
              {entry.byName && <span> by {entry.byName}</span>}
            </div>
          ))}
        </div>
      )}

      <div className="flex flex-wrap gap-2">
        {isMyReview ? (
          <>
            <button onClick={onApprove} className="text-[12px] font-medium px-3 py-2 rounded bg-moss text-white hover:opacity-90">Approve</button>
            <button onClick={onReject} className="text-[12px] font-medium px-3 py-2 rounded border border-terra text-terra hover:bg-terra-soft">Reject</button>
          </>
        ) : (
          <button onClick={onToggleDone} className="text-[12px] font-medium px-3 py-2 rounded bg-ink text-white hover:bg-terra">{isDone ? 'Reopen' : 'Mark done'}</button>
        )}
        {canDelegate && !isDone && <button onClick={onDelegate} className="text-[12px] font-medium px-3 py-2 rounded border border-line ink hover:bg-bone">Delegate</button>}
        {!isDone && <button onClick={onSetReminder} className="text-[12px] font-medium px-3 py-2 rounded border border-line ink hover:bg-bone">Reminder</button>}
      </div>
    </div>
  );
}

/* === Top metric tile === */
function TasksMetric({ icon: Icon, label, value, accent, sublabel }) {
  const accentClass = accent === 'terra' ? 'text-terra' : accent === 'moss' ? 'text-moss' : accent === 'ink-faint' ? 'ink-faint' : 'ink';
  return (
    <div className="bg-paper border border-line rounded-lg p-4">
      <div className="flex items-center gap-1.5 mb-1.5">
        <Icon className={`w-3.5 h-3.5 ${accentClass}`} strokeWidth={2} />
        <span className="text-[10px] font-mono uppercase tracking-wider ink-faint">{label}</span>
      </div>
      <div className={`font-display text-2xl ${accentClass} leading-none`}>{value}</div>
      {sublabel && <div className="text-[10px] font-mono ink-faint mt-1">{sublabel}</div>}
    </div>
  );
}

/* === Single row === */
function TasksPanelRow({ task, isLast, showProject, actorId, canDelegate, onJumpToProject, onToggleDone, onCycleStatus, onApprove, onReject, onDelegate, onSetReminder }) {
  const [expanded, setExpanded] = useState(false);
  const today = new Date().toISOString().slice(0, 10);
  const overdue = isTaskOpen(task) && task.dueDate && task.dueDate < today;
  const daysToDue = task.dueDate
    ? Math.ceil((new Date(task.dueDate) - new Date(today)) / (1000 * 60 * 60 * 24))
    : null;
  const isDone = isTaskClosed(task);

  const cfg = taskStateConfig(task.status);
  /* Map iconName string → component (small local lookup) */
  const iconLookup = { Circle, Lock, Eye, RotateCcw, CheckCircle2 };
  const StatusIcon = iconLookup[cfg.iconName] || Circle;

  /* Review-flow state checks */
  const isAwaitingReview = task.status === 'submitted_for_review';
  const isInRework = task.status === 'rejected_back_to_progress';
  const isMyReview = isAwaitingReview && actorId && task.assignedById === actorId;
  const reviewLog = Array.isArray(task.reviewLog) ? task.reviewLog : [];
  const hasHistory = reviewLog.length > 0 || task.submissionNote || task.rejectionReason;

  /* Tooltip on the checkbox describes what'll happen */
  const checkboxTitle = isDone
    ? 'Reopen task'
    : taskNeedsReview(task)
      ? 'Mark done — sends to reviewer for approval'
      : 'Mark done';

  return (
    <div className={`group/row ${!isLast ? 'border-b border-line-soft' : ''}`}>
      <div className={`flex items-start gap-3 px-4 py-3 hover:bg-bone ${isDone ? 'opacity-60' : ''}`}>
        {/* Checkbox to toggle done */}
        <button
          onClick={onToggleDone}
          className={`mt-0.5 w-4 h-4 rounded border-2 flex items-center justify-center shrink-0 transition-colors ${
            isDone
              ? 'bg-moss border-moss'
              : 'border-line hover:border-terra'
          }`}
          title={checkboxTitle}
        >
          {isDone && <Check className="w-3 h-3 text-white" strokeWidth={3} />}
        </button>

        {/* Status pill — clickable to cycle (only for non-review states) */}
        <button
          onClick={onCycleStatus}
          className={`flex items-center gap-1.5 px-2 py-0.5 rounded text-[9px] font-mono uppercase tracking-wider shrink-0 ${cfg.bg} ${cfg.fg} hover:opacity-80 font-semibold mt-0.5`}
          title={isAwaitingReview || isInRework || isDone ? cfg.label : 'Click to cycle status'}
          style={{ minWidth: '96px' }}
        >
          <StatusIcon className="w-2.5 h-2.5" strokeWidth={2.5} />
          {cfg.shortLabel}
        </button>

        {/* Title + meta */}
        <div className="flex-1 min-w-0">
          <div className={`text-[13px] font-medium leading-snug ${isDone ? 'line-through ink-soft' : 'ink'}`}>
            {task.title || <span className="ink-faint italic">untitled</span>}
            {hasHistory && (
              <button
                onClick={(e) => { e.stopPropagation(); setExpanded(!expanded); }}
                className="ml-2 text-[10px] font-mono text-terra hover:ink"
                title="Toggle review history"
              >
                {expanded ? '▾ hide history' : `▸ history (${reviewLog.length})`}
              </button>
            )}
          </div>
          {task.description && !isDone && (
            <div className="text-[11px] ink-soft mt-0.5 line-clamp-2 leading-snug">{task.description}</div>
          )}
          {/* Show submission note inline when awaiting review */}
          {isAwaitingReview && task.submissionNote && (
            <div className="mt-1 px-2 py-1 bg-bone border-l-2 border-terra rounded-r text-[11px] ink-soft italic">
              <span className="font-mono uppercase text-terra text-[9px] tracking-wider">Doer note:</span> {task.submissionNote}
            </div>
          )}
          {/* Show rejection reason inline when in rework */}
          {isInRework && task.rejectionReason && (
            <div className="mt-1 px-2 py-1 bg-terra-soft border-l-2 border-terra rounded-r text-[11px] ink-soft italic">
              <span className="font-mono uppercase text-terra text-[9px] tracking-wider">Rejected:</span> {task.rejectionReason}
            </div>
          )}
          <div className="flex items-center gap-2 text-[10px] font-mono ink-faint mt-1 flex-wrap">
            {showProject && (
              <button
                onClick={onJumpToProject}
                className="hover:text-terra hover:underline flex items-center gap-1"
                title="Jump to project"
              >
                <span
                  className="w-2 h-2 rounded-full inline-block"
                  style={{ background: task._projectAccent || '#9A938A' }}
                />
                {task._projectName}
              </button>
            )}
            {task.linkedActivity && <span>{showProject ? '·' : ''} {task.linkedActivity}</span>}
            {task.linkedStage && <span>· {task.linkedStage}</span>}
            {/* Phase 6.2d — Assignee visibility: bold ink when allocated, red dot + label when not */}
            {(task.assigneeName || task.assignee) ? (
              <span className="flex items-center gap-1 ink font-bold">
                · <Users className="w-2.5 h-2.5" strokeWidth={2} /> {task.assigneeName || task.assignee}
              </span>
            ) : (
              <span className="flex items-center gap-1" title="Not yet allocated to any team member">
                <span>·</span>
                <span className="inline-block w-1.5 h-1.5 rounded-full bg-terra" />
                <span className="text-terra">not allocated</span>
              </span>
            )}
          </div>
        </div>

        {/* Start → Due window (Phase 9.0.28) */}
        {task.startDate && !isDone && (
          <div className="text-right shrink-0 ink-faint">
            <div className="text-[10px] font-mono uppercase">Start</div>
            <div className="text-[11px] font-mono ink-soft">{formatDate(task.startDate)}</div>
          </div>
        )}

        {/* Due date */}
        {task.dueDate && !isDone && (
          <div className={`text-right shrink-0 ${overdue ? 'text-terra' : 'ink-soft'}`}>
            <div className="text-[11px] font-mono">{formatDate(task.dueDate)}</div>
            <div className={`text-[10px] ${overdue ? 'text-terra font-semibold' : 'ink-faint'}`}>
              {overdue ? `${Math.abs(daysToDue)}d overdue` : daysToDue === 0 ? 'Due today' : daysToDue === 1 ? 'Due tomorrow' : `in ${daysToDue}d`}
            </div>
          </div>
        )}
        {isDone && task.closedAt && (
          <div className="text-right shrink-0">
            <div className="text-[10px] font-mono text-moss">closed</div>
            <div className="text-[10px] font-mono ink-faint">{formatDate(task.closedAt)}</div>
          </div>
        )}

        {/* Review actions — only visible to the reviewer when task is awaiting review */}
        {isMyReview && (
          <div className="flex items-center gap-1.5 shrink-0">
            <button
              onClick={onApprove}
              className="flex items-center gap-1 px-2.5 py-1 rounded text-[10px] font-mono uppercase tracking-wider bg-moss text-white hover:opacity-90 font-semibold"
              title="Approve and close this task"
            >
              <Check className="w-3 h-3" strokeWidth={2.5} /> Approve
            </button>
            <button
              onClick={onReject}
              className="flex items-center gap-1 px-2.5 py-1 rounded text-[10px] font-mono uppercase tracking-wider bg-paper text-terra border border-terra hover:bg-terra-soft font-semibold"
              title="Send back with reason"
            >
              <X className="w-3 h-3" strokeWidth={2.5} /> Reject
            </button>
          </div>
        )}
        {/* For non-reviewer viewing an in-review task, show waiting indicator */}
        {isAwaitingReview && !isMyReview && (
          <div className="text-right shrink-0">
            <div className="text-[10px] font-mono text-terra font-semibold">awaiting</div>
            <div className="text-[10px] font-mono ink-faint">review</div>
          </div>
        )}

        {/* Delegate / Reassign button — only for users who can delegate, on non-closed tasks */}
        {canDelegate && !isDone && (
          <button
            onClick={onDelegate}
            className="opacity-0 group-hover/row:opacity-100 p-1 ink-faint hover:text-terra shrink-0 mt-0.5"
            title={task.assigneeId ? 'Reassign task' : 'Delegate task'}
          >
            <ContactRound className="w-3.5 h-3.5" />
          </button>
        )}

        {/* Reminder button — visible whenever the task is open. If a reminder exists, show terra. */}
        {!isDone && onSetReminder && (
          <button
            onClick={onSetReminder}
            className={`p-1 hover:text-terra shrink-0 mt-0.5 ${
              task.remindAt && !task.reminderDismissed
                ? 'text-terra opacity-100'
                : 'ink-faint opacity-0 group-hover/row:opacity-100'
            }`}
            title={task.remindAt && !task.reminderDismissed
              ? `Reminder set for ${formatDate(task.remindAt)}`
              : 'Set reminder'}
          >
            <Bell className="w-3.5 h-3.5" />
          </button>
        )}

        {/* Jump-to button */}
        <button
          onClick={onJumpToProject}
          className="opacity-0 group-hover/row:opacity-100 p-1 ink-faint hover:text-terra shrink-0 mt-0.5"
          title="Open in project"
        >
          <ArrowRight className="w-3.5 h-3.5" />
        </button>
      </div>

      {/* Expanded review history — audit trail */}
      {expanded && hasHistory && (
        <div className="px-4 py-2 bg-bone border-t border-line-soft">
          <div className="text-[10px] font-mono uppercase tracking-wider ink-faint mb-1.5">Review history</div>
          <div className="space-y-1">
            {/* Show "assigned" entry as the implicit first event */}
            {task.assignedById && task.assignedAt && (
              <div className="flex items-start gap-2 text-[11px]">
                <span className="font-mono ink-faint shrink-0" style={{ minWidth: '80px' }}>{formatDate(task.assignedAt)}</span>
                <span className="font-mono uppercase tracking-wider text-terra text-[9px] mt-0.5 shrink-0" style={{ minWidth: '70px' }}>assigned</span>
                <span className="ink-soft flex-1">
                  {task.assigneeName || task.assignee || 'Unknown'} (delegated by manager)
                </span>
              </div>
            )}
            {reviewLog.map((entry, idx) => {
              const eventLabel = {
                submitted: 'submitted',
                approved: 'approved',
                rejected: 'rejected',
                self_closed: 'self-closed',
                reopened: 'reopened',
                delegated: 'delegated',
              }[entry.event] || entry.event;
              const eventColor = {
                submitted: 'text-terra',
                approved: 'text-moss',
                rejected: 'text-terra',
                self_closed: 'text-moss',
                reopened: 'ink-soft',
                delegated: 'ink-soft',
              }[entry.event] || 'ink-soft';
              return (
                <div key={idx} className="flex items-start gap-2 text-[11px]">
                  <span className="font-mono ink-faint shrink-0" style={{ minWidth: '80px' }}>{formatDate(entry.at)}</span>
                  <span className={`font-mono uppercase tracking-wider text-[9px] mt-0.5 shrink-0 ${eventColor}`} style={{ minWidth: '70px' }}>
                    {eventLabel}
                  </span>
                  <span className="ink-soft flex-1">
                    by {entry.byName || 'Unknown'}
                    {entry.notes && <span className="italic"> — “{entry.notes}”</span>}
                  </span>
                </div>
              );
            })}
          </div>
        </div>
      )}
    </div>
  );
}

