function ThemeSettingsBlock({ currentTheme, setCurrentTheme, activeThemePreset, setActiveThemePreset, canEdit, saveAction }) {
  const applyPreset = (preset) => {
    if (!canEdit) return;
    setCurrentTheme({ ...preset.colors });
    setActiveThemePreset(preset.code);
  };

  const updateToken = (key, value) => {
    if (!canEdit) return;
    setCurrentTheme((theme) => ({ ...theme, [key]: value }));
    setActiveThemePreset(null);
  };

  const resetToDefault = () => {
    if (!canEdit) return;
    setCurrentTheme({ ...defaultTheme });
    setActiveThemePreset('warm-studio');
  };

  const activePresetName = activeThemePreset
    ? (themePresets.find((preset) => preset.code === activeThemePreset)?.name || 'Custom palette')
    : 'Custom palette';

  const contrastChecks = [
    { fg: 'ink', bg: 'paper', label: 'Primary text on cards', min: 4.5 },
    { fg: 'ink-soft', bg: 'paper', label: 'Secondary text on cards', min: 3.0 },
    { fg: 'terra', bg: 'paper', label: 'Accent on cards', min: 3.0 },
  ];
  const failingChecks = contrastChecks
    .map((check) => ({
      ...check,
      ratio: contrastRatio(currentTheme[check.fg], currentTheme[check.bg]),
    }))
    .filter((check) => check.ratio < check.min);

  return (
    <SectionCard title="Theme & Colours" icon={Palette} action={saveAction}>
      <div className="flex items-start justify-between gap-4 mb-4 pb-4 border-b border-line-soft">
        <div>
          <div className="text-[12px] ink font-medium">Studio visual system</div>
          <div className="text-[11px] ink-soft mt-1 max-w-2xl leading-relaxed">
            Choose one quiet palette for the whole app. Changes save with the workspace state and are visible to L1, L2, and L3.
          </div>
        </div>
        <div className="flex items-center gap-2 shrink-0">
          <span className="hidden sm:inline-flex text-[10px] font-mono uppercase tracking-wider px-2 py-1 rounded bg-moss-soft text-moss">
            Active: {activePresetName}
          </span>
          <button
            onClick={resetToDefault}
            disabled={!canEdit}
            className="flex items-center gap-1.5 text-[11px] font-medium px-3 py-2 rounded border border-line ink-soft hover:ink hover:bg-bone disabled:opacity-50 disabled:hover:bg-transparent"
          >
            <RefreshCw className="w-3.5 h-3.5" />
            Reset
          </button>
        </div>
      </div>

      <div className="grid grid-cols-1 xl:grid-cols-3 gap-5">
        <div className="xl:col-span-2 space-y-5">
          <div>
            <div className="text-[11px] font-mono uppercase tracking-widest ink-faint mb-2">Presets</div>
            <div className="grid grid-cols-2 md:grid-cols-4 gap-2">
              {themePresets.map((preset) => {
                const isActive = activeThemePreset === preset.code;
                return (
                  <button
                    key={preset.code}
                    onClick={() => applyPreset(preset)}
                    disabled={!canEdit}
                    className={`text-left rounded-lg border p-3 transition-colors ${isActive ? 'border-terra' : 'border-line hover:border-ink'} ${!canEdit ? 'cursor-default opacity-75' : ''}`}
                    style={{ background: preset.colors.bone }}
                  >
                    <div className="rounded border p-2 mb-2" style={{ background: preset.colors.paper, borderColor: preset.colors.line }}>
                      <div className="text-sm font-semibold" style={{ color: preset.colors.ink }}>Aa</div>
                      <div className="flex items-center gap-1 mt-1.5">
                        <span className="w-3 h-3 rounded-full" style={{ background: preset.colors.terra }} />
                        <span className="w-3 h-3 rounded-full" style={{ background: preset.colors.moss }} />
                        <span className="w-3 h-3 rounded-full" style={{ background: preset.colors.clay }} />
                      </div>
                    </div>
                    <div className="text-[11px] font-semibold" style={{ color: preset.colors.ink }}>{preset.name}</div>
                    <div className="text-[9px] ink-faint truncate">{preset.subtitle}</div>
                  </button>
                );
              })}
            </div>
          </div>

          <div>
            <div className="text-[11px] font-mono uppercase tracking-widest ink-faint mb-2">Fine tuning</div>
            <div className={`space-y-4 ${!canEdit ? 'pointer-events-none opacity-70' : ''}`}>
              {themeTokenGroups.map((group) => (
                <div key={group.groupKey}>
                  <div className="text-[12px] ink font-semibold mb-1">{group.label}</div>
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-2">
                    {group.tokens.map((token) => (
                      <ThemeTokenRow
                        key={token.key}
                        token={token}
                        value={currentTheme[token.key]}
                        onChange={(value) => updateToken(token.key, value)}
                      />
                    ))}
                  </div>
                </div>
              ))}
            </div>
          </div>

          <div className={`text-[10px] font-mono rounded border px-3 py-2 ${failingChecks.length ? 'bg-terra-soft text-terra border-terra' : 'bg-moss-soft text-moss border-moss-soft'}`}>
            {failingChecks.length
              ? `${failingChecks.length} contrast check${failingChecks.length === 1 ? '' : 's'} need attention before this palette is ideal.`
              : 'Contrast check passed for the main text and accent pairs.'}
          </div>
        </div>

        <div className="xl:sticky xl:top-4 self-start">
          <ThemePreviewPane currentTheme={currentTheme} />
        </div>
      </div>
    </SectionCard>
  );
}

